window.HADITH_CACHE["bukhari_1"] = {"501":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْتَدِلُوا فِي السُّجُودِ وَلَا يَبْسُطْ ذِرَاعَيْهِ كَالْكَلْبِ وَإِذَا بَزَقَ فَلَا يَبْزُقَنَّ بَيْنَ يَدَيْهِ وَلَا عَنْ يَمِينِهِ فَإِنَّهُ يُنَاجِي رَبَّهُ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Yazid bin Ibrahim] berkata, telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seimbanglah dalam sujud dan janganlah seseorang meletakkan tangannya seperti anjing. Dan jika meludah, maka jangan sekali-kali ia meludah ke arah depan atau ke sebelah kanannya. Karena dia sedang berhadapan dengan Rabbnya.\""},"502":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ بْنِ بِلَالٍ قَالَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ سُلَيْمَانَ قَالَ صَالِحُ بْنُ كَيْسَانَ حَدَّثَنَا الْأَعْرَجُ عَبْدُ الرَّحْمَنِ وَغَيْرُهُ عَنْ أَبِي هُرَيْرَةَ وَنَافِعٌ مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُمَا حَدَّثَاهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا عَنْ الصَّلَاةِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Ayyub bin Sulaiman bin Bilal] berkata, telah menceritakan kepada kami [Abu Bakar] dari [Sulaiman] berkata, [Shalih bin Kaisan] telah menceritakan kepada kami [Al A'raj 'Abdurrahman], dan selainnya dari [Abu Hurairah] dan [Nafi'] mantan budak 'Abdullah bin 'Umar, dari ['Abdullah bin 'Umar] bahwa keduanya menceritakan kepadanya dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Jika udara sangat panas menyengat maka tundalah shalat, karena panas yang sangat menyengat itu berasal dari hembusan api neraka jahannam.\""},"503":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْمُهَاجِرِ أَبِي الْحَسَنِ سَمِعَ زَيْدَ بْنَ وَهْبٍ عَنْ أَبِي ذَرٍّ قَالَأَذَّنَ مُؤَذِّنُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَقَالَ أَبْرِدْ أَبْرِدْ أَوْ قَالَ انْتَظِرْ انْتَظِرْ وَقَالَ شِدَّةُ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ فَإِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا عَنْ الصَّلَاةِ حَتَّى رَأَيْنَا فَيْءَ التُّلُولِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Muhajir Abu Al Hasan] bahwa ia mendengar [Zaid bin Wahb] dari [Abu Dzar] berkata, \"Seorang mu'adzin Nabi shallallahu 'alaihi wasallam mengumandangkan adzan Zhuhur. Kemudian beliau bersabda: \"Tundalah, tundalah.\" Atau beliau katakan: \"Tunggulah, tunggulah.\" Beliau kemudian melanjutkan:: \"Panas yang menyengat ini berasal dari hembusan api jahannam. Jika udara sangat panas menyengat maka tundalah shalat hingga kita melihat bayangan suatu benda.\""},"504":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ الْمَدِينِيُّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ مِنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا بِالصَّلَاةِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ وَاشْتَكَتْ النَّارُ إِلَى رَبِّهَا فَقَالَتْ يَا رَبِّ أَكَلَ بَعْضِي بَعْضًا فَأَذِنَ لَهَا بِنَفَسَيْنِ نَفَسٍ فِي الشِّتَاءِ وَنَفَسٍ فِي الصَّيْفِ فَهُوَ أَشَدُّ مَا تَجِدُونَ مِنْ الْحَرِّ وَأَشَدُّ مَا تَجِدُونَ مِنْ الزَّمْهَرِيرِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah Al Mutsanna] berkata, telah menceritakan kepada kami [Sufyan] berkata, kami telah menghafalnya dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila panas sangat menyengat maka tudalah shalat hingga panasnya mereda. Sebab panas yang sangat menyengat itu berasal dari hembusan api jahannam. Neraka jahannam mengadu kepada Rabbnya seraya berkata, 'Wahai Rabb, sebagian kami telah makan sebagian yang lain! ', maka Allah pun memberinya izin dengan dua tarikan nafas; sekali saat musim dingin dan sekali saat musim panas. Maka apa yang kalian rasakan berupa udara panas berasal darinya, begitu juga udara dingin yang kalian rasakan berasal darinya.\""},"505":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْرِدُوا بِالظُّهْرِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَتَابَعَهُ سُفْيَانُ وَيَحْيَى وَأَبُو عَوَانَةَ عَنْ الْأَعْمَشِ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] berkata, telah menceritakan kepada kami [Bapakku] ia berkata, telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Sa'id] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tundalah shalat Zhuhur (hingg panas mereda), karena panas yang sangat menyengat berasal dari hembusan jahannam.\" Hadits ini dikuatkan oleh [Sufyan] dan [Yahya] dan [Abu 'Awanah] dari [Al A'masy]."},"506":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا مُهَاجِرٌ أَبُو الْحَسَنِ مَوْلَى لِبَنِي تَيْمِ اللَّهِ قَالَ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ عَنْ أَبِي ذَرٍّ الْغِفَارِيِّ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَرَادَ الْمُؤَذِّنُ أَنْ يُؤَذِّنَ لِلظُّهْرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْرِدْ ثُمَّ أَرَادَ أَنْ يُؤَذِّنَ فَقَالَ لَهُ أَبْرِدْ حَتَّى رَأَيْنَا فَيْءَ التُّلُولِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ شِدَّةَ الْ��َرِّ مِنْ فَيْحِ جَهَنَّمَ فَإِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا بِالصَّلَاةِوَقَالَ ابْنُ عَبَّاسٍ{ تَتَفَيَّأُ }تَتَمَيَّلُ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami dari [Muhajir Abu Al Hasan] mantan budak bani Taimillah, ia berkata, aku mendengar [Zaid bin Wahb] dari [Abu Dzar Al Ghifari] berkata, \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, ketika ada mu'adzin yang hendak mengumandangkan adzan Zhuhur, Nabi shallallahu 'alaihi wasallam bersabda: \"Tundalah.\" Sesaat kemudian mu'adzin itu kembali akan mengumandangkan adzan. Maka Nabi shallallahu 'alaihi wasallam pun kembali bersabda: \"Tundalah hingga kita melihat bayang-bayang bukit.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya panas yang sangat menyengat itu berasal dari hembusan api jahannam. Maka apabila udara sangat panas menyengat tundalah shalat (hingga panas) mereda.\" Ibnu 'Abbas berkata, \"Maksud dari firman Allah: tataqayya'u (Qs. An Nahl: 48) adalah condong.\""},"507":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ حِينَ زَاغَتْ الشَّمْسُ فَصَلَّى الظُّهْرَ فَقَامَ عَلَى الْمِنْبَرِ فَذَكَرَ السَّاعَةَ فَذَكَرَ أَنَّ فِيهَا أُمُورًا عِظَامًا ثُمَّ قَالَ مَنْ أَحَبَّ أَنْ يَسْأَلَ عَنْ شَيْءٍ فَلْيَسْأَلْ فَلَا تَسْأَلُونِي عَنْ شَيْءٍ إِلَّا أَخْبَرْتُكُمْ مَا دُمْتُ فِي مَقَامِي هَذَا فَأَكْثَرَ النَّاسُ فِي الْبُكَاءِ وَأَكْثَرَ أَنْ يَقُولَ سَلُونِي فَقَامَ عَبْدُ اللَّهِ بْنُ حُذَافَةَ السَّهْمِيُّ فَقَالَ مَنْ أَبِي قَالَ أَبُوكَ حُذَافَةُ ثُمَّ أَكْثَرَ أَنْ يَقُولَ سَلُونِي فَبَرَكَ عُمَرُ عَلَى رُكْبَتَيْهِ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا فَسَكَتَ ثُمَّ قَالَ عُرِضَتْ عَلَيَّ الْجَنَّةُ وَالنَّارُ آنِفًا فِي عُرْضِ هَذَا الْحَائِطِ فَلَمْ أَرَ كَالْخَيْرِ وَالشَّرِّ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Anas bin Malik], ketika matahari panas terik Rasulullah shallallahu 'alaihi wasallam keluar rumah melaksanakan shalat Zhuhur, kemudian beliau naik ke atas mimbar dan menyebutkan tentang hari kiamat. Beliau sebutkan bahwa pada saat itu terdapat perkara yang besar, kemudian beliau katakan: \"Siapa ingin bertanya maka bertanyalah. Dan tidaklah kalian bertanya kepadaku tentang sesuatu kecuali aku akan kabarkan kepada kalian selama aku masih berada di tempaku ini.\" Tiba-tiba para sahabat menangis, dan Nabi shallallahu 'alaihi wasallam terus mengulangi: \"Bertanyalah kepadaku.\" Maka berdirilah 'Abdullah bin Khudzafah As Sahmi seraya berkata, \"Siapakah ayahku?\" Beliau menjawab: \"Ayahmu Hudzafah.\" Kemudian Nabi shallallahu 'alaihi wasallam meminta lagi: \"Bertanyalah kepadaku.\" Maka bangkitlah 'Umar dari posisi duduk berlututnya lantas berkata, \"Kami ridla Allah sebagai Rabb, Islam sebagai agama dan Muhammad sebagai Nabi.\" Lalu Nabi shallallahu 'alaihi wasallam terdiam sejenak kemudian bersabda: \"Barusan diperlihatkan kepadaku surga dan neraka dari balik dinding ini, aku tidak lihat kebaikan sebagaimana keburukan.\""},"508":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو الْمِنْهَالِ عَنْ أَبِي بَرْزَةَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الصُّبْحَ وَأَحَدُنَا يَعْرِفُ جَلِيسَهُ وَيَقْرَأُ فِيهَا مَا بَيْنَ السِّتِّينَ إِلَى الْمِائَةِ وَيُصَلِّي الظُّهْرَ إِذَا زَالَتْ الشَّمْسُ وَالْعَصْرَ وَأَحَدُنَا يَذْهَبُ إِلَى أَقْصَى الْمَدِينَةِ رَجَعَ وَالشَّمْسُ حَيَّةٌ وَنَسِيتُ مَا قَالَ فِي الْمَغْرِبِ وَلَا يُبَالِي بِتَأْخِيرِ الْعِشَاءِ إِلَى ثُلُثِ اللَّيْلِ ثُمَّ قَالَ إِلَى شَطْرِ اللَّيْلِوَقَالَ مُعَاذٌ قَالَ شُعْبَةُ لَقِيتُهُ مَرَّةً فَقَالَ أَوْ ثُلُثِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Al Minhal] dari [Abu Barzah], bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat shubuh, dan salah seorang dari kami dapat mengetahui siapa orang yang ada di sisinya. Dalam shalat tersebut beliau membaca antara enam puluh hingga seratus ayat. Dan beliau shalat Zhuhur saat matahari sudah condong, shalat 'Ashar saat salah seorang dari kami pergi ke ujung kota dan matahari masih terasa panas sinarnya. Dan aku lupa apa yang dibaca beliau saat shalat Maghrib. Dan beliau sering mengakhirkan pelaksanaan shalat 'Isya hingga sepertiga malam lalu melaksanakannya sampai pertengahan malam.\" [Mu'adz] berkata, Syu'bah berkata; \"Aku pernah berjumpa denganya pada suatu hari, berkata, 'Atau sepertiga malam'.\""},"509":{"ar":"حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنِي غَالِبٌ الْقَطَّانُ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالظَّهَائِرِ فَسَجَدْنَا عَلَى ثِيَابِنَا اتِّقَاءَ الْحَرِّ","id":"Telah menceritakan kepada kami [Muhammad] -yakni Ibnu Muqatil-berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Khalid bin 'Abdurrahman] telah menceritakan kepadaku [Ghalib Al Qaththan] dari [Bakar bin 'Abdullah Al Muzani] dari [Anas bin Malik] ia berkata, \"Jika kami shalat di belakang Rasulullah shallallahu 'alaihi wasallam pada shalat Zhuhur saat udara panas, kami sujud beralaskan pakaian kami untuk menghindari panasnya pasir.\""},"510":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِالْمَدِينَةِ سَبْعًا وَثَمَانِيًا الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ فَقَالَ أَيُّوبُ لَعَلَّهُ فِي لَيْلَةٍ مَطِيرَةٍ قَالَ عَسَى","id":"Telah menceritakan kepada kami [Abu AN Nu'man] berkata, telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- dari ['Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu 'Abbas], bahwa Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat di Madinah sebanyak tujuh dan delapan, yaitu shalat Zhuhur, 'Ashar, Maghrib dan 'Isya'.\" Ayyub berkata, \"Barangkali hal itu ketika pada malam itu hujan.\" Ibnu Abbas berkata, \"Bisa jadi.\""},"511":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ هِشَامٍ عَنْ أَبِيهِ أَنَّ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْعَصْرَ وَالشَّمْسُ لَمْ تَخْرُجْ مِنْ حُجْرَتِهَاوَقَالَ أَبُو أُسَامَةَ عَنْ هِشَامٍ مِنْ قَعْرِ حُجْرَتِهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Anas bin 'Iyadl] dari [Hisyam] dari [Bapaknya] bahwa ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat 'Ashar sedangkan matahari belum berlalu dari kamarnya (rumah 'Aisyah).\" [Abu Umamah] menyebutkan dari [Hisyam], \"Dari dalam kamarnya (posisi cahayanya).\""},"512":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْعَصْرَ وَالشَّمْسُ فِي حُجْرَتِهَا لَمْ يَظْهَرْ الْفَيْءُ مِنْ حُجْرَتِهَا","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam shalat 'Ashar sementara matahari yang ada dikamarnya belum menampakkan bayang-bayang.\""},"513":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةَ الْعَصْرِ وَالشَّمْسُ طَالِعَةٌ فِي حُجْرَتِي لَمْ يَظْهَرْ الْفَيْءُ بَعْدُوَقَالَ مَالِكٌ وَيَحْيَى بْنُ سَعِيدٍ وَشُعَيْبٌ وَابْنُ أَبِي حَفْصَةَ وَالشَّمْسُ قَبْلَ أَنْ تَظْهَرَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat 'Ashar sementara matahari muncul dari dalam kamarku dan belum nampak bayang-bayang.\" [Malik] dan [Yahya bin Sa'id] dan [Syu'aib] dan [Ibnu Abu Hafsh] menyebutkan, \"Sementara matahari belum lagi nampak bayangannya.\""},"514":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا عَوْفٌ عَنْ سَيَّارِ بْنِ سَلَامَةَ قَالَدَخَلْتُ أَنَا وَأَبِي عَلَى أَبِي بَرْزَةَ الْأَسْلَمِيِّ فَقَالَ لَهُ أَبِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَكْتُوبَةَ فَقَالَ كَانَ يُصَلِّي الْهَجِيرَ الَّتِي تَدْعُونَهَا الْأُولَى حِينَ تَدْحَضُ الشَّمْسُ وَيُصَلِّي الْعَصْرَ ثُمَّ يَرْجِعُ أَحَدُنَا إِلَى رَحْلِهِ فِي أَقْصَى الْمَدِينَةِ وَالشَّمْسُ حَيَّةٌ وَنَسِيتُ مَا قَالَ فِي الْمَغْرِبِ وَكَانَ يَسْتَحِبُّ أَنْ يُؤَخِّرَ الْعِشَاءَ الَّتِي تَدْعُونَهَا الْعَتَمَةَ وَكَانَ يَكْرَهُ النَّوْمَ قَبْلَهَا وَالْحَدِيثَ بَعْدَهَا وَكَانَ يَنْفَتِلُ مِنْ صَلَاةِ الْغَدَاةِ حِينَ يَعْرِفُ الرَّجُلُ جَلِيسَهُ وَيَقْرَأُ بِالسِّتِّينَ إِلَى الْمِائَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami ['Auf] dari [Sayyar bin Salamah] berkata, \"Aku dan bapakku datang menemui [Abu Barzah Al Aslami]. Lalu bapakku berkata kepadanya, \"Bagaimana Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat yang diwajibkan?\" Abu Barzah menjawab, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur, yang kalian sebut sebagai waktu utama, saat matahari telah tergelincir, shalat 'Ashar ketika salah seorang dari kami kembali dengan kendaraannya di ujung Kota sementara matahari masih terasa panas sinarnya. Dan aku lupa apa yang dibaca beliau saat shalat Maghrib. Beliau lebih suka mengakhirkan shalat 'Isya yang kalian sebut dengan shalat 'atmah, dan beliau tidak suka tidur sebelum shalat Isya dan berbincang-bincang sesudahnya. Dan beliau melaksanakan shalat Shubuh ketika seseorang dapat mengetahui siapa yang ada di sebelahnya, beliau membaca enam hingga seratus ayat.\""},"515":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا نُصَلِّي الْعَصْرَ ثُمَّ يَخْرُجُ الْإِنْسَانُ إِلَى بَنِي عَمْرِو بْنِ عَوْفٍ فَنَجِدُهُمْ يُصَلُّونَ الْعَصْرَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas bin Malik] berkata, \"Kami pernah shalat 'Ashar kemudian orang-orang keluar menuju Bani 'Amru bin 'Auf, dan kami dapati mereka sedang melaksanakan shalat 'Ashar.\""},"516":{"ar":"حَدَّثَنَا ابْنُ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا أَبُو بَكْرِ بْنُ عُثْمَانَ بْنِ سَهْلِ بْنِ حُنَيْفٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ بْنَ سَهْلٍ يَقُولُصَلَّيْنَا مَعَ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ الظُّهْرَ ثُمَّ خَرَجْنَا حَتَّى دَخَلْنَا عَلَى أَنَسِ بْنِ مَالِكٍ فَوَجَدْنَاهُ يُصَلِّي الْعَصْرَ فَقُلْتُ يَا عَمِّ مَا هَذِهِ الصَّلَاةُ الَّتِي صَلَّيْتَ قَالَ الْعَصْرُ وَهَذِهِ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي كُنَّا نُصَلِّي مَعَهُ","id":"Telah menceritakan kepada kami [Ibnu Muqatil] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Abu Bakar bin Utsman bin Sahl bin Hunaif] berkata, \"Aku mendengar [Abu Umamah bin Sahl] berkata, \"Kami pernah shalat Zhuhur bersama 'Umar bin 'Abdul 'Aziz. Setelah selesai kami keluar mendatangi [Anas bin Malik], dan saat itu kami dapati mereka sedang melaksanakan shalat 'Ashar. Maka aku pun bertanya, \"Wahai paman, shalat apakah yang kamu kerjakan ini?\" Dia menjawab, \"Shalat 'Ashar. Saat seperti inilah shalat Rasulullah shallallahu 'alaihi wasallam yang pernah kami lakukan bersamanya.\""},"517":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْعَصْرَ وَالشَّمْسُ مُرْتَفِعَةٌ حَيَّةٌ فَيَذْهَبُ الذَّاهِبُ إِلَى الْعَوَالِي فَيَأْتِيهِمْ وَالشَّمْسُ مُرْتَفِعَةٌوَبَعْضُ الْعَوَالِي مِنْ الْمَدِينَةِ عَلَى أَرْبَعَةِ أَمْيَالٍ أَوْ نَحْوِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhrii] berkata, telah menceritakan kepadaku [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan shalat 'Ashar saat matahari masih meninggi. Dan jika ada seseorang pergi menemui keluarganya kemudian kembali, maka ia akan mendapati matahari masih tinggi. Sedangkan sebagian desa jaraknya dengan Madinah ada yang berjarak sampai empat mil atau sekitar itu.\""},"518":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا نُصَلِّي الْعَصْرَ ثُمَّ يَذْهَبُ الذَّاهِبُ مِنَّا إِلَى قُبَاءٍ فَيَأْتِيهِمْ وَالشَّمْسُ مُرْتَفِعَةٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Anas bin Malik] berkata, \"Kami pernah melakanakan shalat 'Ashar, dan jika salah seorang dari kami pergi ke Quba mendatangi mereka (penduduk), maka matahari masih tinggi.\""},"519":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي تَفُوتُهُ صَلَاةُ الْعَصْرِ كَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُقَالَ أَبُو عَبْد اللَّهِ{ يَتِرَكُمْ }وَتَرْتُ الرَّجُلَ إِذَا قَتَلْتَ لَهُ قَتِيلًا أَوْ أَخَذْتَ لَهُ مَالًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang kehilangan shalat 'Ashar (dengan berjama'ah) seperti orang yang kehilangan keluarga dan hartanya.\" Saat menafsirkan ayat: '(Dia sekali-kali tidak akan mengurangi) ' (Qs. Muhammad: 35) Abu Abdullah berkata, \"Bila kamu membunuh seseorang atau kamu mengambil hartanya.\""},"520":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ قَالَكُنَّا مَعَ بُرَيْدَةَ فِي غَزْوَةٍ فِي يَوْمٍ ذِي غَيْمٍ فَقَالَ بَكِّرُوا بِصَلَاةِ الْعَصْرِ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ صَلَاةَ الْعَصْرِ فَقَدْ حَبِطَ عَمَلُهُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Qilabah] dari [Al Malih] berkata, \"Kami pernah bersama [Buraidah] pada suatu peperangan saat cuaca mendung, lalu ia berkata, \"Segeralah laksanakan shalat 'Ashar! Karena Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa meninggalkan shalat 'Ashar sungguh hapuslah amalnya.\""},"521":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةً يَعْنِي الْبَدْرَ فَقَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تُضَامُّونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ{ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }قَالَ إِسْمَاعِيلُ افْعَلُوا لَا تَفُوتَنَّكُمْ","id":"Telah menceritakan kepada kami [Al Humaidi] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah] berkata, telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Jarir bin 'Abdullah] berkata, \"Pada suatu malam kami pernah bersama Nabi shallallahu 'alaihi wasallam, beliau lalu melihat ke arah bulan purnama. Kemudian beliau bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan purnama ini. Dan kalian tidak akan saling berdesakan dalam melihat-Nya. Maka jika kalian mampu untuk tidak terlewatkan untuk melaksanakan shalat sebelum terbit matahri dan sebelum terbenamnya, maka lakukanlah.\" Beliau kemudian membaca ayat: '(Dan bertasbihlah sambil memuji Rabbmu sebelum terbit matahari dan sebelum terbenamnya) ' (Qs. Qaaf: 39). Isma'il menyebutkan, \"Kerjakanlah dan sekali-kali jangan sampai kalian terlewatkan.\""},"522":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَتَعَاقَبُونَ فِيكُمْ مَلَائِكَةٌ بِاللَّيْلِ وَمَلَائِكَةٌ بِالنَّهَارِ وَيَجْتَمِعُونَ فِي صَلَاةِ الْفَجْرِ وَصَلَاةِ الْعَصْرِ ثُمَّ يَعْرُجُ الَّذِينَ بَاتُوا فِيكُمْ فَيَسْأَلُهُمْ وَهُوَ أَعْلَمُ بِهِمْ كَيْفَ تَرَكْتُمْ عِبَادِي فَيَقُولُونَ تَرَكْنَاهُمْ وَهُمْ يُصَلُّونَ وَأَتَيْنَاهُمْ وَهُمْ يُصَلُّونَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para Malaikat malam dan Malaikat siang silih berganti mendatangi kalian. Dan mereka berkumpul saat shalat Fajar (Subuh) dan 'Ashar. Kemudian Malaikat yang menjaga kalian naik ke atas hingga Allah Ta'ala bertanya kepada mereka, dan Allah lebih mengetahui keadaan mereka (para hamba-Nya), 'Dalam keadaan bagaimana kalian tinggalkan hamba-hambaKu? ' Para Malaikat menjawab, 'Kami tinggalkan mereka dalam keadaan sedang mendirikan shalat. Begitu juga saat kami mendatangi mereka, mereka sedang mendirikan shalat'.\""},"523":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَدْرَكَ أَحَدُكُمْ سَجْدَةً مِنْ صَلَاةِ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَلْيُتِمَّ صَلَاتَهُ وَإِذَا أَدْرَكَ سَجْدَةً مِنْ صَلَاةِ الصُّبْحِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَلْيُتِمَّ صَلَاتَهُ","id":"Telah menceritakan kepada kami [Abu An Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seeorang dari kalian mendapatkan sujud shalat 'Ashar sebelum terbenam matahari maka sempurnakanlah, dan jika mendapatkan sujud shalat Subuh sebelum terbit matahari maka sempurnakanlah.\""},"524":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا بَقَاؤُكُمْ فِيمَا سَلَفَ قَبْلَكُمْ مِنْ الْأُمَمِ كَمَا بَيْنَ صَلَاةِ الْعَصْرِ إِلَى غُرُوبِ الشَّمْسِ أُوتِيَ أَهْلُ التَّوْرَاةِ التَّوْرَاةَ فَعَمِلُوا حَتَّى إِذَا انْتَصَفَ النَّهَارُ عَجَزُوا فَأُعْطُوا قِيرَاطًا قِيرَاطًا ثُمَّ أُوتِيَ أَهْلُ الْإِنْجِيلِ الْإِنْجِيلَ فَعَمِلُوا إِلَى صَلَاةِ الْعَصْرِ ثُمَّ عَجَزُوا فَأُعْطُوا قِيرَاطًا قِيرَاطًا ثُمَّ أُوتِينَا الْقُرْآنَ فَعَمِلْنَا إِلَى غُرُوبِ الشَّمْسِ فَأُعْطِينَا قِيرَاطَيْنِ قِيرَاطَيْنِ فَقَالَ أَهْلُ الْكِتَابَيْنِ أَيْ رَبَّنَا أَعْطَيْتَ هَؤُلَاءِ قِيرَاطَيْنِ قِيرَاطَيْنِ وَأَعْطَيْتَنَا قِيرَاطًا قِيرَاطًا وَنَحْنُ كُنَّا أَكْثَرَ عَمَلًا قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ هَلْ ظَلَمْتُكُمْ مِنْ أَجْرِكُمْ مِنْ شَيْءٍ قَالُوا لَا قَالَ فَهُوَ فَضْلِي أُوتِيهِ مَنْ أَشَاءُ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah Al Uwaisi] berkata, telah menceritakan kepadaku [Ibrahim bin Sa'ad] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [Bapaknya] ia mengabarkan kepadanya, bahwa dia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya keberadaan kalian dibandingakan ummat-ummat sebelum kalian seperti masa antara shalat 'Ashar dan terbenamnya matahari. Ahlu Taurat diberikan Kitab Taurat, kemudian mereka mengamalkannya hingga apabila sampai pertengahan siang hari mereka menjadi lemah (tidak kuat sehingga melalaikannya). Maka mereka diberi pahala satu qirath satu qirath. Kemudian Ahlu Injil diberikan Kitab Injil, lalu mereka mengamalkannya hingga waktu shalat 'Ashar, dan mereka pun melemah. Maka merekapun diberi pahala satu qirath satu qirath. Sedangkan kita diberikan Al Qur'an, lalu kita mengamalkannya hingga matahari terbenam, maka kita diberi pahala dua qirath dua qirath. kedua Ahlul Kitab tersebut berkata, 'Wahai Rabb kami, bagaimana Engkau memberikan mereka dua qirath dua qirath dan Engkau beri kami satu qirath satu qirath. Padahal kami lebih banyak beramal! ' Beliau melanjutkan kisahnya: \"Maka Allah 'azza wajalla bertanya: 'Apakah Aku menzhalimi sesuatu dari bagian pahala kalian? ' Mereka menjawab, 'Tidak'. Maka Allah 'azza wajalla berfirman: 'Itulah karunia-Ku yang Aku berikan kepada siapa yang Aku kehendaki'.\""},"525":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُسْلِمِينَ وَالْيَهُودِ وَالنَّصَارَى كَمَثَلِ رَجُلٍ اسْتَأْجَرَ قَوْمًا يَعْمَلُونَ لَهُ عَمَلًا إِلَى اللَّيْلِ فَعَمِلُوا إِلَى نِصْفِ النَّهَارِ فَقَالُوا لَا حَاجَةَ لَنَا إِلَى أَجْرِكَ فَاسْتَأْجَرَ آخَرِينَ فَقَالَ أَكْمِلُوا بَقِيَّةَ يَوْمِكُمْ وَلَكُمْ الَّذِي شَرَطْتُ فَعَمِلُوا حَتَّى إِذَا كَانَ حِينَ صَلَاةِ الْعَصْرِ قَالُوا لَكَ مَا عَمِلْنَا فَاسْتَأْجَرَ قَوْمًا فَعَمِلُوا بَقِيَّةَ يَوْمِهِمْ حَتَّى غَابَتْ الشَّمْسُ وَاسْتَكْمَلُوا أَجْرَ الْفَرِيقَيْنِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpaman Kaum Muslimin, Yahudi dan Nashara seperti seseorang yang memperkerjakan suatu Kaum, mereka harus bekerja untuknya hingga malam hari, sementara mereka hanya beramal hingga sianghari. Mereka berkata, 'Kami tidak patut menerima upah darimu. Akhirnya orang itu memperkerjakan Kaum yang lain dan berkata, 'Sempurnakanlah sisa hari yang ada, nanti kalian mendapatkan bagian upah sesuai persyaratanku.' Maka mereka mengerjakan pekerjaan hingga hanya sampai waktu 'Ashar, mereka lalu berkata, 'Kami kembalikan pekerjaan kepadamu.' Lalu orang itu memperkerjakan Kaum yang lain lagi. Maka Kaum tersebut bekerja menuntaskan sisa hari sampai matahari terbenam. Jadilah Kaum ini menyempurnakan pahala dua Kaum sebelumnya.\""},"526":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا أَبُو النَّجَاشِيِّ صُهَيْبٌ مَوْلَى رَافِعِ بْنِ خَدِيجٍ قَالَ سَمِعْتُ رَافِعَ بْنَ خَدِيجٍ يَقُولُكُنَّا نُصَلِّي الْمَغْرِبَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْصَرِفُ أَحَدُنَا وَإِنَّهُ لَيُبْصِرُ مَوَاقِعَ نَبْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Mihran] berkata, telah menceritakan kepada kami [Al Walid] berkata, telah menceritakan kepada kami [Al Awza'i] berkata, telah menceritakan kepada kami [Abu An Najasyi Shuhaib] mantan budak Rafi' bin Khadij, ia berkata, \"Aku pernah mendengar [Rafi' bin Khadij] berkata, \"Kami pernah shalat Maghrib bersama Nabi shallallahu 'alaihi wasallam, ketika salah seorang dari kami berlalu pergi, maka ia masih dapat melihat tempat sandal kami.\""},"527":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ الْحَسَنِ بْنِ عَلِيٍّقَالَ قَدِمَ الْحَجَّاجُ فَسَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ فَقَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الظُّهْرَ بِالْهَاجِرَةِ وَالْعَصْرَ وَالشَّمْسُ نَقِيَّةٌ وَالْمَغْرِبَ إِذَا وَجَبَتْ وَالْعِشَاءَ أَحْيَانًا وَأَحْيَانًا إِذَا رَآهُمْ اجْتَمَعُوا عَجَّلَ وَإِذَا رَآهُمْ أَبْطَوْا أَخَّرَ وَالصُّبْحَ كَانُوا أَوْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهَا بِغَلَسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] dari [Muhammad bin 'Amru bin Al Hasan bin 'Ali] berkata, \"Al Hajjaj pernah menunda pelaksanaan shalat, maka kami bertanya kepada [Jabir bin 'Abdullah]. Maka dia menjawab, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur ketika matahari telah condong, shalat 'Ashar saat matahari masih terasa panas sinarnya, shalat Maghrib ketika matahari telah terbenam, dan shalat 'Isya terkadang beliau mengikuti kedaan jama'ah; jika beliau lihat sudah berkumpul maka beliau segerakan, dan jika mereka belum berkumpul maka beliau akhirkan. Sementara untuk shalat Subuh, mereka atau beliau melaksanakannya saat pagi masih gelap.\""},"528":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَغْرِبَ إِذَا تَوَارَتْ بِالْحِجَابِ","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] berkata, telah menceritakan kepada kami [Yazid bin Abu 'Ubaid] dari [Salamah] berkata, \"Kami pernah shalat Maghrib bersama Nabi shallallahu 'alaihi wasallam ketika matahari sudah tenggelam tidak terlihat.\""},"529":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعًا جَمِيعًا وَثَمَانِيًا جَمِيعًا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, ['Amru bin Dinar] berkata, Aku pernah mendengar [Jabir bin Zaid] dari ['Abdullah bin 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat tujuh rakaat dengan jama' dan delapan rakaat dengan jama'.\""},"530":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ هُوَ عَبْدُ اللَّهِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ الْحُسَيْنِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُغَفَّلٍ الْمُزَنِيُّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَغْلِبَنَّكُمْ الْأَعْرَابُ عَلَى اسْمِ صَلَاتِكُمْ الْمَغْرِبِ قَالَ الْأَعْرَابُ وَتَقُولُ هِيَ الْعِشَاءُ","id":"Telah menceritakan kepada kami [Abu Ma'mar] -yaitu 'Abdullah bin 'Amru- berkata, telah menceritakan kepada kami ['Abdul Warits] dari [Al Husain] berkata, telah menceritakan kepada kami ['Abdullah bin Buraidah] berkata, telah menceritakan kepadaku ['Abdullah bin Mughaffal Al Muzani], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian dikalahkan oleh orang Badui dalam menamakan (melaksanakan) shalat Maghrib kalian.\" 'Abdullah bin Mughaffal Al Muzani berkata, \"Orang Badui menyebut Maghrib dengan 'Isya (kerena mereka menunda pelaksanaan Maghrib hingga masuk waktu 'Isya).\""},"531":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ سَالِمٌ أَخْبَرَنِي عَبْدُ اللَّهِ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً صَلَاةَ الْعِشَاءِ وَهِيَ الَّتِي يَدْعُو النَّاسُ الْعَتَمَةَ ثُمَّ انْصَرَفَ فَأَقْبَلَ عَلَيْنَا فَقَالَ أَرَأَيْتُمْ لَيْلَتَكُمْ هَذِهِ فَإِنَّ رَأْسَ مِائَةِ سَنَةٍ مِنْهَا لَا يَبْقَى مِمَّنْ هُوَ عَلَى ظَهْرِ الْأَرْضِ أَحَدٌ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhri], [Salim] berkata, ['Abdullah] mengabarkan kepadaku, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah memimpin kami melaksanakan shalat 'Isya pada waktu yang orang-orang menyebutnya dengan sebutan 'Atamah. Selesai shalat beliau berpaling dan menghadap ke arah kami seraya bertanya: \"Tidakkah kalian melihat malam kalian ini? Ketahuilah, sesungguhnya pada setiap seratus tahun tidak ada seorang pun yang hidup di atas bumi akan tersisa.\""},"532":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو هُوَ ابْنُ الْحَسَنِ بْنِ عَلِيٍّ قَالَ سَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِعَنْ صَلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ يُصَلِّي الظُّهْرَ بِالْهَاجِرَةِ وَالْعَصْرَ وَالشَّمْسُ حَيَّةٌ وَالْمَغْرِبَ إِذَا وَجَبَتْ وَالْعِشَاءَ إِذَا كَثُرَ النَّاسُ عَجَّلَ وَإِذَا قَلُّوا أَخَّرَ وَالصُّبْحَ بِغَلَسٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Muhammad bin 'Amru] -yaitu Ibnu Al Hasan bin 'Ali- ia berkata, \"Kami pernah bertanya kepada [Jabir bin 'Abdullah] tentang shalatnya Nabi shallallahu 'alaihi wasallam. Ia lalu menjawab, \"Beliau melaksanakan shalat Zhuhur jika matahari sudah condong, shalat 'Ashar saat matahari masih terasa panasnya (masih terang), shalat Maghrib ketika matahari sudah tenggelam, sedangkan shalat 'Isya; jika orang-orang sudah berkumpul maka beliau segerakan, dan jika belum maka beliau akhirkan. Dan waktu untuk shalat Subuh saat pagi masih gelap.\""},"533":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُ قَالَتْأَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً بِالْعِشَاءِ وَذَلِكَ قَبْلَ أَنْ يَفْشُوَ الْإِسْلَامُ فَلَمْ يَخْرُجْ حَتَّى قَالَ عُمَرُ نَامَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ فَقَالَ لِأَهْلِ الْمَسْجِدِ مَا يَنْتَظِرُهَا أَحَدٌ مِنْ أَهْلِ الْأَرْضِ غَيْرَكُمْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] bahwa ['Aisyah] mengabarkan kepadanya, ia katakan, \"Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan shalat 'Isya ketika malam telah masuk sepertiga akhir malam ('Atamah), dan itu terjadi ketika Islam belum luas tersebar. Beliau tidak juga keluar hingga 'Umar berkata, 'Para wanita dan anak-anak sudah tidur! ' Maka beliau pun keluar dan bersabda kepada orang-orang yang ada di Masjid: \"Tidak ada seorangpun dari penduduk bumi yang menunggu shalat ini selain kalian.\""},"534":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ أَخْبَرَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَكُنْتُ أَنَا وَأَصْحَابِي الَّذِينَ قَدِمُوا مَعِي فِي السَّفِينَةِ نُزُولًا فِي بَقِيعِ بُطْحَانَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ فَكَانَ يَتَنَاوَبُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ صَلَاةِ الْعِشَاءِ كُلَّ لَيْلَةٍ نَفَرٌ مِنْهُمْ فَوَافَقْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَصْحَابِي وَلَهُ بَعْضُ الشُّغْلِ فِي بَعْضِ أَمْرِهِ فَأَعْتَمَ بِالصَّلَاةِ حَتَّى ابْهَارَّ اللَّيْلُ ثُمَّ خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِهِمْ فَلَمَّا قَضَى صَلَاتَهُ قَالَ لِمَنْ حَضَرَهُ عَلَى رِسْلِكُمْ أَبْشِرُوا إِنَّ مِنْ نِعْمَةِ اللَّهِ عَلَيْكُمْ أَنَّهُ لَيْسَ أَحَدٌ مِنْ النَّاسِ يُصَلِّي هَذِهِ السَّاعَةَ غَيْرُكُمْ أَوْ قَالَ مَا صَلَّى هَذِهِ السَّاعَةَ أَحَدٌ غَيْرُكُمْ لَا يَدْرِي أَيَّ الْكَلِمَتَيْنِ قَالَ قَالَ أَبُو مُوسَى فَرَجَعْنَا فَفَرِحْنَا بِمَا سَمِعْنَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala] berkata, telah mengabarkan kepada kami [Abu Umamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Aku dan sahabat-sahabatku yang pernah ikut dalam perahu singgah pada tanah lapang yang memiliki aliran air, sedangkan Nabi shallallahu 'alaihi wasallam berada di Madinah. Di antara mereka ada beberapa orang yang saling bergantian mengikuti Nabi shallallahu 'alaihi wasallam shalat 'Isya di setiap malamnya. Hingga pada suatu malam, aku dan para sahabatku menjumpai Nabi shallallahu 'alaihi wasallam yang saat itu sedang sibuk dengan urusannya, sehingga beliau mengakhirkan pelaksanaan shalatr 'Isya hingga pada pertengahan malam. Maka Nabi shallallahu 'alaihi wasallam keluar untuk menunaikan shalat bersama mereka. Selesai shalat beliau bersabda kepada orang-orang yang hadir: \"Tetaplah kalian di tempat kalian, dan bergemberilah. Sesungguhnya termasuk dari nikmat Allah kepada kalian adalah didapatinya seorang pun saat ini yang melaksanakan shalat (Isya) selain kalian.\" Atau Beliau bersabda: \"Tidak ada yang melaksanakan shalat pada waktu seperti ini kecuali kalian.\" Namun ia terlupa mana dari dua kalimat ini yang dikatakan beliau. Abu Burdah berkata, Abu Musa, \"Maka kami kembali dengan gembira dengan apa yang kami dengar dari Rasulullah shallallahu 'alaihi wasallam.\""},"535":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ قَالَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي الْمِنْهَالِ عَنْ أَبِي بَرْزَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْرَهُ النَّوْمَ قَبْلَ الْعِشَاءِ وَالْحَدِيثَ بَعْدَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami ['Abdul Wahhab Ats Tsaqafi] berkata, telah menceritakan kepada kami [Khalid Al Hadza'] dari [Abu Al Minhal] dari [Abu Barzah], bahwa Rasulullah shallallahu 'alaihi wasallam tidak suka tidur sebelum shalat 'Isya dan berbincang-bincang setelahnya.\""},"536":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ هُوَ ابْنُ بِلَالٍ قَالَ حَدَّثَنِي أَبُو بَكْرٍ عَنْ سُلَيْمَانَ هُوَ ابْنُ بِلَالٍ قَالَ حَدَّثَنَا صَالِحُ بْنُ كَيْسَانَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ قَالَتْأَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعِشَاءِ حَتَّى نَادَاهُ عُمَرُ الصَّلَاةَ نَامَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ فَقَالَ مَا يَنْتَظِرُهَا أَحَدٌ مِنْ أَهْلِ الْأَرْضِ غَيْرُكُمْ قَالَ وَلَا يُصَلَّى يَوْمَئِذٍ إِلَّا بِالْمَدِينَةِ وَكَانُوا يُصَلُّونَ فِيمَا بَيْنَ أَنْ يَغِيبَ الشَّفَقُ إِلَى ثُلُثِ اللَّيْلِ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Ayyub bin Sulaiman] -yaitu Ibnu Bilal- ia berkata, telah menceritakan kepadaku [Abu Bakar] dari [Sulaiman] -yaitu Ibnu Bilal- berkata, telah menceritakan kepada kami [Shalih bin Kaisan] telah mengabarkan kepadaku [Ibnu Syihab] dari ['Urwahl] bahwa ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengakhirkan shalat 'Isya hingga sepertiga malam yang akhir. Lalu 'Umar pun berseru kepada beliau, \"(Laksanakanlah) shalat, sebab para wanita dan anak-anak telah terlelap tidur.\" Maka keluarlah beliau seraya berkata: \"Tidak ada seorangpun dari penduduk bumi yang menunggu shalat Isya ini selain kalian.\" Beliau tidaklah melaksanakan shalat seperti ini kecuali di Madinah. Dan mereka melaksnakan shalat antara hilangnya syafaq (cahaya kemerahan di langit) hingga sepertiga awal dari malam.\""},"537":{"ar":"حَدَّثَنَا مَحْمُودٌ يَعْنِي ابْنَ غَيْلَانَ قَالَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي نَافِعٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شُغِلَ عَنْهَا لَيْلَةً فَأَخَّرَهَا حَتَّى رَقَدْنَا فِي الْمَسْجِدِ ثُمَّ اسْتَيْقَظْنَا ثُمَّ رَقَدْنَا ثُمَّ اسْتَيْقَظْنَا ثُمَّ خَرَجَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ لَيْسَ أَحَدٌ مِنْ أَهْلِ الْأَرْضِ يَنْتَظِرُ الصَّلَاةَ غَيْرُكُمْوَكَانَ ابْنُ عُمَرَ لَا يُبَالِي أَقَدَّمَهَا أَمْ أَخَّرَهَا إِذَا كَانَ لَا يَخْشَى أَنْ يَغْلِبَهُ النَّوْمُ عَنْ وَقْتِهَا وَكَانَ يَرْقُدُ قَبْلَهَا قَالَ ابْنُ جُرَيْجٍ قُلْتُ لِعَطَاءٍ وَقَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ أَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً بِالْعِشَاءِ حَتَّى رَقَدَ النَّاسُ وَاسْتَيْقَظُوا وَرَقَدُوا وَاسْتَيْقَظُوا فَقَامَ عُمَرُ بْنُ الْخَطَّابِ فَقَالَ الصَّلَاةَ قَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍ فَخَرَجَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنِّي أَنْظُرُ إِلَيْهِ الْآنَ يَقْطُرُ رَأْسُهُ مَاءً وَاضِعًا يَدَهُ عَلَى رَأْسِهِ فَقَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ أَنْ يُصَلُّوهَا هَكَذَا فَاسْتَثْبَتُّ عَطَاءً كَيْفَ وَضَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَأْسِهِ يَدَهُ كَمَا أَنْبَأَهُ ابْنُ عَبَّاسٍ فَبَدَّدَ لِي عَطَاءٌ بَيْنَ أَصَابِعِهِ شَيْئًا مِنْ تَبْدِيدٍ ثُمَّ وَضَعَ أَطْرَافَ أَصَابِعِهِ عَلَى قَرْنِ الرَّأْسِ ثُمَّ ضَمَّهَا يُمِرُّهَا كَذَلِكَ عَلَى الرَّأْسِ حَتَّى مَسَّتْ إِبْهَامُهُ طَرَفَ الْأُذُنِ مِمَّا يَلِي الْوَجْهَ عَلَى الصُّدْغِ وَنَاحِيَةِ اللِّحْيَةِ لَا يُقَصِّرُ وَلَا يَبْطُشُ إِلَّا كَذَلِكَ وَقَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ أَنْ يُصَلُّوا هَكَذَا","id":"Telah menceritakan kepada kami [Mahmud] -yaitu Ibnu Ghailan- berkata, telah mengabarkan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepadaku [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Nafi'] berkata, telah menceritakan kepada kami ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam pernah suatu malam disibukkan dengan urusan sehingga mengakhirkan shalat 'Isya. Dan karenanya kami tertidur di dalam masjid. Lalu kami terbangun, lalu tertidur, lalu terbangun lagi hingga akhirnya Rasulullah shallallahu 'alaihi wasallam keluar menemui kami seraya bersabda: \"Tidak ada seorangpun dari penduduk bumi yang menunggu shalat seperti ini selain kalian.\" Dan Ibnu 'Umar tidak mempermasalahkan apakah Beliau memajukannya atau mengakhirkan. Pelaksanakaannya. Dan Ibnu Umar tidur dahulu sebelum shalat Isya. [Ibnu Juraij] berkata, \"Aku bertanya kepada ['Atha'], lalu dia berkata, \"Aku mendengar [Ibnu 'Abbas] berkata, \"Pernah suatu malam Rasulullah shallallahu 'alaihi wasallam mengakhirkan shalat 'Isya hingga banyak orang tertidur, kemudian mereka terbangun, lalu tertidur lagi, kemudian terbangun lagi.\" 'Umar bin Al Khaththab lalu berdiri dan berkata, \"Shalat.\" 'Atha' berkata, Ibnu 'Abbas, \"Maka Nabi shallallahu 'alaihi wasallam kemudian keluar dengan meletakkan tangan pada kepala, seakan aku melihat rambut beliau basah meneteskan air. Beliau kemudiaan bersabda: \"Seandainya tidak memberatkan ummatku, niscaya aku akan perintahkan mereka melaksanakan shalat 'Isya seperti waktu sekarang ini.\" Aku (Ibnu Juraij) kemudian menanyakan kepada 'Atha untuk memastikan kenapa Nabi shallallahu 'alaihi wasallam meletakkan tangannya di kepalanya seabgaimana yang diberitakan oleh Ibnu 'Abbas. Maka 'Atha merenggangkan sedikit jari-jarinya kemudian meletakkan ujung jarinya di atas sisi kepala, kemudian ia menekannya sambil menggerakkan ke sekeliling kepala hingga ibu jarinya menyentuh ujung telinga yang dimulai dari pelipis hingga pangkal jenggot. Dia melakukannya tidak pelan juga tidak cepat, kecuali sedang seperti itu. Lalu Beliau bersabda: \"Seandainya tidak memberatkan ummatku, niscaya aku akan perintahkan mereka melaksanakan shalat seperti waktu sekarang ini.\""},"538":{"ar":"حَدَّثَنَا عَبْدُ الرَّحِيمِ الْمُحَارِبِيُّ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَخَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْعِشَاءِ إِلَى نِصْفِ اللَّيْلِ ثُمَّ صَلَّى ثُمَّ قَالَ قَدْ صَلَّى النَّاسُ وَنَامُوا أَمَا إِنَّكُمْ فِي صَلَاةٍ مَا انْتَظَرْتُمُوهَاوَزَادَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي حُمَيْدٌ سَمِعَ أَنَسَ بْنَ مَالِكٍ قَالَ كَأَنِّي أَنْظُرُ إِلَى وَبِيصِ خَاتَمِهِ لَيْلَتَئِذٍ","id":"Telah menceritakan kepada kami ['Abdurrahim Al Muharibi] berkata, telah menceritakan kepada kami [Zaidah] dari [Humaid Ath Thawil] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam pernah mengakhirkan shalat 'Isya hingga pertengahan malam, setelah melaksanakan shalat beliau bersabda: \"Manusia semuanya sudah selesai shalat lalu mereka tidur. Dan kalian akan senantiasa dalam hitungan shalat selama kalian menunggu pelaksanaannya.\" [Ibnu Abu Maryam] menambahkan; telah mengabarkan kepada kami [Yahya bin Ayyub] telah menceritakan kepadaku [Humaid] dia mendengar [Anas bin Malik] berkata, \"Pada malam itu aku seolah melihat cahaya cincin Beliau.\""},"539":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا قَيْسٌ قَالَ لِي جَرِيرُ بْنُ عَبْدِ اللَّهِكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ نَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ فَقَالَ أَمَا إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا لَا تُضَامُّونَ أَوْ لَا تُضَاهُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَالَ فَ{ سَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا }","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Isma'il] telah menceritakan kepada kami [Qais], [Jarir bin 'Abdullah] berkata kepadaku, \"Kami sedang bersama Nabi shallallahu 'alaihi wasallam saat beliau melihat rembulan di malam purnama. Kemudian beliau bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan purnama ini. Dan kalian tidak akan saling berdesakan dalam melihatnya. Maka jika kalian mampu untuk tidak terlewatkan melaksanakan shalat sebelum terbit matahari dan sebelum terbenamnya, maka lakukanlah, \" Kemudian beliau membaca: '(Maka bertasbihlah sambil memuji Rabbmu sebelum terbit matahari dan sebelum terbenamnya) ' (Qs. Qaaf: 38)."},"540":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا هَمَّامٌ حَدَّثَنِي أَبُو جَمْرَةَ عَنْ أَبِي بَكْرِ بْنِ أَبِي مُوسَى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى الْبَرْدَيْنِ دَخَلَ الْجَنَّةَوَقَالَ ابْنُ رَجَاءٍ حَدَّثَنَا هَمَّامٌ عَنْ أَبِي جَمْرَةَ أَنَّ أَبَا بَكْرِ بْنَ عَبْدِ اللَّهِ بْنِ قَيْسٍ أَخْبَرَهُ بِهَذَا حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَبُو جَمْرَةَ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] berkata, telah menceritakan kepada kami [Hammam] telah menceritakan kepadaku [Abu Jamrah] dari [Abu Bakar bin Abu Musa] dari [Bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat pada dua waktu dingin, maka dia akan masuk surga.\" [Ibnu Raja'] berkata; telah menceritakan kepada kami [Hammam] dari [Abu Jamrah] bahwa [Abu Bakar bin 'Abdullah bin Qais] telah mengabarkan kepadanya seperti ini.\" Dan telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Habban] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Abu Jamrah] dari [Abu Bakar bin 'Abdullah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam seperti ini.\""},"541":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ زَيْدَ بْنَ ثَابِتٍ حَدَّثَهُأَنَّهُمْ تَسَحَّرُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامُوا إِلَى الصَّلَاةِ قُلْتُ كَمْ بَيْنَهُمَا قَالَ قَدْرُ خَمْسِينَ أَوْ سِتِّينَ يَعْنِي آيَةً","id":"Telah menceritakan kepada kami ['Amru bin 'Ashim] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas bin Malik] bahwa [Zaid bin Tsabit] telah menceritakan kepadanya, bahwa mereka pernah sahur bersama Nabi shallallahu 'alaihi wasallam, kemudian mereka berdiri untuk melaksanakan shalat.\" Aku bertanya, \"Berapa jarak antara sahur dengan shalat subuh?\" Dia menjawab, \"Antara lima puluh hingga enam puluh ayat.\""},"542":{"ar":"حَدَّثَنَا حَسَنُ بْنُ صَبَّاحٍ سَمِعَ رَوْحَ بْنَ عُبَادَةَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَيْدَ بْنَ ثَابِتٍ تَسَحَّرَا فَلَمَّا فَرَغَا مِنْ سَحُورِهِمَا قَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ فَصَلَّى قُلْنَا لِأَنَسٍ كَمْ كَانَ بَيْنَ فَرَاغِهِمَا مِنْ سَحُورِهِمَا وَدُخُولِهِمَا فِي الصَّلَاةِ قَالَ قَدْرُ مَا يَقْرَأُ الرَّجُلُ خَمْسِينَ آيَةً","id":"Telah menceritakan kepada kami [Hasan bin Shabbah] telah mendengar [Rauh bin 'Ubadah] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam dan Zaid bin Tsabit makan sahur bersama. Setelah keduanya selesai makan sahur, beliau lalu bangkit melaksanakan shalat.\" Kami bertanya kepada Anas, \"Berapa rentang waktu antara selesainya makan sahur hingga keduanya melaksanakan shalat?\" Anas bin Malik menjawab, \"Kira-kira waktu seseorang membaca lima puluh ayat.\""},"543":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ عَنْ أَخِيهِ عَنْ سُلَيْمَانَ عَنْ أَبِي حَازِمٍ أَنَّهُ سَمِعَ سَهْلَ بْنَ سَعْدٍ يَقُولُكُنْتُ أَتَسَحَّرُ فِي أَهْلِي ثُمَّ يَكُونُ سُرْعَةٌ بِي أَنْ أُدْرِكَ صَلَاةَ الْفَجْرِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":". Telah menceritakan kepada kami [Isma'il bin Abu Uwais] dari [Saudaranya] dari [Sulaiman] dari [Abu Hazm] bahwa dia mendengar [Sahl bin Sa'd] berkata, \"Suatu kali aku pernah makan sahur bersama keluargaku, kemudian aku bersegera agar dapat melaksanakan shalat Subuh bersama Rasulullah shallallahu 'alaihi wasallam.\""},"544":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ أَخْبَرَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُ قَالَتْكُنَّ نِسَاءُ الْمُؤْمِنَاتِ يَشْهَدْنَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْفَجْرِ مُتَلَفِّعَاتٍ بِمُرُوطِهِنَّ ثُمَّ يَنْقَلِبْنَ إِلَى بُيُوتِهِنَّ حِينَ يَقْضِينَ الصَّلَاةَ لَا يَعْرِفُهُنَّ أَحَدٌ مِنْ الْغَلَسِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah mengabarkan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syuhab] berkata, telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah] mengabarkan kepadanya, ia mengatakan, \"Kami, wanita-wanita Mukminat, pernah ikut shalat fajar bersama Rasulullah shallallahu 'alaihi wasallam dengan menutup wajahnya dengan kerudung, kemudian kembali ke rumah mereka masing-masing setelah selesai shalat tanpa diketahui oleh seorangpun karena hari masih gelap.\""},"545":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ وَعَنْ بُسْرِ بْنِ سَعِيدٍ وَعَنْ الْأَعْرَجِ يُحَدِّثُونَهُ عَنْ أَبِي هُرَيْر��ةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصُّبْحِ رَكْعَةً قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَ الصُّبْحَ وَمَنْ أَدْرَكَ رَكْعَةً مِنْ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَ الْعَصْرَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari ['Atha bin Yasar], dan dari [Busr bin Sa'id], dan dari [Al A'raj] mereka semua menceritakan dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan satu rakaat dari shalat subuh sebelum terbit matahari berarti dia mendapatkan subuh. Dan siapa yang mendapatkan satu rakaat dari shalat 'Ashar sebelum terbenam matahari berarti dia telah mendapatkan 'Ashar.\""},"546":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَةً مِنْ الصَّلَاةِ فَقَدْ أَدْرَكَ الصَّلَاةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan satu rakaat dari shalat berarti dia telah mendapatkan shalat.\""},"547":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَشَهِدَ عِنْدِي رِجَالٌ مَرْضِيُّونَ وَأَرْضَاهُمْ عِنْدِي عُمَرُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الصُّبْحِ حَتَّى تَشْرُقَ الشَّمْسُ وَبَعْدَ الْعَصْرِ حَتَّى تَغْرُبَحَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ قَتَادَةَ سَمِعْتُ أَبَا الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَنِي نَاسٌ بِهَذَا","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Abu Al Aliyah] dari [Ibnu 'Abbas] berkata, \"Orang-orang yang diridlai mempersaksikan kepadaku dan di antara mereka yang paling aku ridlai adalah ['Umar], (mereka semua mengatakan) bahwa Nabi shallallahu 'alaihi wasallam melarang shalat setelah Shubuh hingga matahari terbit, dan setelah 'Ashar sampai matahari terbenam.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Qatadah] aku mendengar [Abu Al Aliyah] dari [Ibnu 'Abbas] berkata, \"Orang-orang (para sahabat) menceritakan hadits ini kepadaku.\""},"548":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي قَالَ أَخْبَرَنِي ابْنُ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحَرَّوْا بِصَلَاتِكُمْ طُلُوعَ الشَّمْسِ وَلَا غُرُوبَهَاوَقَالَ حَدَّثَنِي ابْنُ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا طَلَعَ حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تَرْتَفِعَ وَإِذَا غَابَ حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تَغِيبَ تَابَعَهُ عَبْدَةُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] berkata, telah mengabarkan kepadaku [Bapakku] berkata, telah mengabarkan kepadaku [Ibnu 'Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian sengaja melaksanakan shalat ketika matahari sedang terbit dan juga ketika terbenamnya.\" Dan telah menceritakan kepadaku Ibnu 'Umar berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika matahari sedang terbit maka tundalah shalat hingga telah meninggi, dan jika matahari sedang terbenam maka tundalah shalat hingga menghilang.\" Hadits ini juga kuatkan oleh ['Abdah]."},"549":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعَتَيْنِ وَعَنْ لِبْسَتَيْنِ وَعَنْ صَلَاتَيْنِ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ وَبَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَعَنْ اشْتِمَالِ الصَّمَّاءِ وَعَنْ الِاحْتِبَاءِ فِي ثَوْبٍ وَاحِدٍ يُفْضِي بِفَرْجِهِ إِلَى السَّمَاءِ وَعَنْ الْمُنَابَذَةِ وَالْمُلَامَسَةِ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Khubaib bin 'Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari dua macam jual beli, dua cara berpakaian dan dua shalat. Beliau melarang shalat setelah Shubuh sampai terbit matahari dan setelah 'Ashar sampai matahari terbenam. Melarang dari pakaian shama` dan duduk ihtiba` dengan satu kain sehingga menghadapkan kemaluannya ke langit. Dan beliau juga melarang dari jual beli Al Munabadzah dan Al Mulasamah.\" "},"550":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَحَرَّى أَحَدُكُمْ فَيُصَلِّي عِنْدَ طُلُوعِ الشَّمْسِ وَلَا عِنْدَ غُرُوبِهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian sengaja shalat ketika matahari sedang terbit dan atau ketika saat terbenam.\""},"551":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ الْجُنْدَعِيُّ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَلَاةَ بَعْدَ الصُّبْحِ حَتَّى تَرْتَفِعَ الشَّمْسُ وَلَا صَلَاةَ بَعْدَ الْعَصْرِ حَتَّى تَغِيبَ الشَّمْسُ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Atha bin Yazid Al Junda'i] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat setelah Shubuh hingga matahari meninggi dan tidak ada shalat setelah 'Ashar hingga matahari menghilang.\""},"552":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ حُمْرَانَ بْنَ أَبَانَ يُحَدِّثُ عَنْ مُعَاوِيَةَ قَالَإِنَّكُمْ لَتُصَلُّونَ صَلَاةً لَقَدْ صَحِبْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا رَأَيْنَاهُ يُصَلِّيهَا وَلَقَدْ نَهَى عَنْهُمَا يَعْنِي الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Aban] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu At Tiyah] berkata, aku mendengar [Humran bin Aban] menceritakan dari [Mu'awiyyah] berkata, \"Sungguh kalian telah mengerjakan suatu shalat (yang dilarang). Kami telah mendampingi Rasulullah shallallahu 'alaihi wasallam, dan kami tidak pernah melihat beliau melaksanakannya. Beliau telah melarang keduanya, yaitu dua rakaat setelah shalat 'Ashar.\""},"553":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ خُبَيْبٍ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاتَيْنِ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ وَبَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah menceritakan kepada kami ['Abdah] dari ['Ubaidullah] dari [Khubaib] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari dua macam shalat; dua rakaat setelah Shubuh hingga terbit matahari dan dua rakaat setelah 'Ashar hingga matahari terbenam.\""},"554":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَأُصَلِّي كَمَا رَأَيْتُ أَصْحَابِي يُصَلُّونَ لَا أَنْهَى أَحَدًا يُصَلِّي بِلَيْلٍ وَلَا نَهَارٍ مَا شَاءَ غَيْرَ أَنْ لَا تَحَرَّوْا طُلُوعَ الشَّمْسِ وَلَا غُرُوبَهَا","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] berkata, \"Aku melaksanakan shalat sebagaimana aku melihat para sahabatku melaksanakannya. Aku tidak melarang seorangpun untuk melaksanakan shalat baik di malam hari maupun di siang hari, kecuali bila kalian sengaja mengerjakannya saat matahari sedang terbit atau ketika sedang terbenamnya.\""},"555":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ قَالَ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ عَائِشَةَ قَالَتْوَالَّذِي ذَهَبَ بِهِ مَا تَرَكَهُمَا حَتَّى لَقِيَ اللَّهَ وَمَا لَقِيَ اللَّهَ تَعَالَى حَتَّى ثَقُلَ عَنْ الصَّلَاةِ وَكَانَ يُصَلِّي كَثِيرًا مِنْ صَلَاتِهِ قَاعِدًا تَعْنِي الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهِمَا وَلَا يُصَلِّيهِمَا فِي الْمَسْجِدِ مَخَافَةَ أَنْ يُثَقِّلَ عَلَى أُمَّتِهِ وَكَانَ يُحِبُّ مَا يُخَفِّفُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami ['Abdul Wahid bin Aiman] berkata, telah menceritakan kepadaku [Bapakku] bahwa dia mendengar ['Aisyah] berkata, \"Demi Dzat yang telah mewafatkan beliau, beliau tidak pernah meninggalkan keduanya hingga beliau berjuma Allah, dan tidaklah beliau bertemu Allah hingga terasa berat mengerjakan shalat (tua). Beliau sering mengerjakan shalat dengan duduk, yakni dua rakaat setelah 'Ashar. Namun Nabi shallallahu 'alaihi wasallam tidak mengerjakannya di masjid karena khawatir akan memberatkan ummatnya, sebab beliau lebih suka meringankan mereka.\""},"556":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامٌ قَالَ أَخْبَرَنِي أَبِي قَالَتْ عَائِشَةُابْنَ أُخْتِي مَا تَرَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّجْدَتَيْنِ بَعْدَ الْعَصْرِ عِنْدِي قَطُّ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Hisyam] berkata, telah mengabarkan kepadaku [Bapakku] - [Aisyah] berkata; yaitu anak saudara perempuanku-, \"Nabi shallallahu 'alaihi wasallam tidak pernah meninggalkan dua rakaat setelah shalat 'Ashar.\""},"557":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الشَّيْبَانِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْرَكْعَتَانِ لَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَعُهُمَا سِرًّا وَلَا عَلَانِيَةً رَكْعَتَانِ قَبْلَ صَلَاةِ الصُّبْحِ وَرَكْعَتَانِ بَعْدَ الْعَصْرِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Asy Syaibani] berkata, telah menceritakan kepada kami ['Abdurrahman bin Al Aswad] dari [Bapaknya] dari ['Aisyah] berkata, \"Dua rakaat yang tidak pernah Rasulullah shallallahu 'alaihi wasallam tinggalkan baik secara sembunyi-sembunyi maupun terang-terangan adalah dua rakaat sebelum Shubuh dan dua rakaat setelah 'Ashar.\""},"558":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ رَأَيْتُ الْأَسْوَدَ وَمَسْرُوقًا شَهِدَا عَلَى عَائِشَةَ قَالَتْمَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينِي فِي يَوْمٍ بَعْدَ الْعَصْرِ إِلَّا صَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata, Aku melihat [Al Aswad] dan [Masruq] bersaksi atas ['Aisyah] ia berkata, \"Tidaklah Nabi shallallahu 'alaihi wasallam mendatangiku dalam suatu hari setelah 'Ashar kecuali beliau shalat dua rakaat.\""},"559":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى هُوَ ابْنُ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ أَنَّ أَبَا الْمَلِيحِ حَدَّثَهُ قَالَ كُنَّا مَعَ بُرَيْدَةَفِي يَوْمٍ ذِي غَيْمٍ فَقَالَ بَكِّرُوا بِالصَّلَاةِ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ صَلَاةَ الْعَصْرِ حَبِطَ عَمَلُهُ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] -yaitu Ibnu Abu Katsir- dari [Abu Qilabah] bahwa [Abu Al Malih] menceritakan kepadanya, ia berkata, \"Kami pernah bersama [Buraidah] pada suatu hari yang mendung, ia lalu berkata, \"Segeralah laksanakan shalat, karena Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa meninggalkan shalat 'Ashar, sungguh telah hapuslah amalnya.\""},"560":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَ حَدَّثَنَا حُصَيْنٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَسِرْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَقَالَ بَعْضُ الْقَوْمِ لَوْ عَرَّسْتَ بِنَا يَا رَسُولَ اللَّهِ قَالَ أَخَافُ أَنْ تَنَامُوا عَنْ الصَّلَاةِ قَالَ بِلَالٌ أَنَا أُوقِظُكُمْ فَاضْطَجَعُوا وَأَسْنَدَ بِلَالٌ ظَهْرَهُ إِلَى رَاحِلَتِهِ فَغَلَبَتْهُ عَيْنَاهُ فَنَامَ فَاسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ طَلَعَ حَاجِبُ الشَّمْسِ فَقَالَ يَا بِلَالُ أَيْنَ مَا قُلْتَ قَالَ مَا أُلْقِيَتْ عَلَيَّ نَوْمَةٌ مِثْلُهَا قَطُّ قَالَ إِنَّ اللَّهَ قَبَضَ أَرْوَاحَكُمْ حِينَ شَاءَ وَرَدَّهَا عَلَيْكُمْ حِينَ شَاءَ يَا بِلَالُ قُمْ فَأَذِّنْ بِالنَّاسِ بِالصَّلَاةِ فَتَوَضَّأَ فَلَمَّا ارْتَفَعَتْ الشَّمْسُ وَابْيَاضَّتْ قَامَ فَصَلَّى","id":"Telah menceritakan kepada kami ['Imran bin Maisarah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Hushain] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] berkata, \"Kami pernah berjalan bersama Nabi shallallahu 'alaihi wasallam pada suatu malam. Sebagian kaum lalu berkata, \"Wahai Rasulullah, sekiranya Tuan mau istirahat sebentar bersama kami?\" Beliau menjawab: \"Aku khawatir kalian tertidur sehingga terlewatkan shalat.\" Bilal berkata, \"Aku akan membangunkan kalian.\" Maka merekapun berbaring, sedangkan Bilal bersandar pada hewan tunggannganya, tapi rasa kantuknya mengalahkannya dan akhirnya iapun tertidur. Ketika Nabi shallallahu 'alaihi wasallam terbangun ternyata matahari sudah terbit, maka beliau pun bersabda: \"Wahai Bilal, mana bukti yang kau ucapkan!\" Bilal menjawab: \"Aku belum pernah sekalipun merasakan kantuk seperti ini sebelumnya.\" Beliau lalu bersabda: \"Sesungguhnya Allah Azza Wa Jalla memegang ruh-ruh kalian sesuai kehendak-Nya dan mengembalikannya kepada kalian sekehendak-Nya pula. Wahai Bilal, berdiri dan adzanlah (umumkan) kepada orang-orang untuk shalat!\" kemudian beliau berwudlu, ketika matahari meninggi dan tampak sinar putihnya, beliau pun berdiri melaksanakan shalat.\""},"561":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ عُمَرَ بْنَ الْخَطَّابِ جَاءَ يَوْمَ الْخَنْدَقِ بَعْدَ مَا غَرَبَتْ الشَّمْسُ فَجَعَلَ يَسُبُّ كُفَّارَ قُرَيْشٍ قَالَ يَا رَسُولَ اللَّهِ مَا كِدْتُ أُصَلِّي الْعَصْرَ حَتَّى كَادَتْ الشَّمْسُ تَغْرُبُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا صَلَّيْتُهَا فَقُمْنَا إِلَى بُطْحَانَ فَتَوَضَّأَ لِلصَّلَاةِ وَتَوَضَّأْنَا لَهَا فَصَلَّى الْعَصْرَ بَعْدَ مَا غَرَبَتْ الشَّمْسُ ثُمَّ صَلَّى بَعْدَهَا الْمَغْرِبَ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Jabir bin 'Abdullah], bahwa 'Umar bin Al Khaththab datang pada hari peperangan Khandaq setelah matahari terbenam hingga ia mengumpat orang-orang kafir Quraisy, lalu ia berkata, \"Wahai Rasulullah, aku belum melaksanakan shaat 'Ashar hingga matahari hampir terbenam!\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Demi Allah, aku juga belum melakasanakannya.\" Kemudian kami berdiri menuju aliran air (sungai), beliau berwudlu dan kami pun ikut berwudlu, kemudian beliau melaksanakan shalat 'Ashar setelah matahari terbenam, dan setelah itu dilanjutkan dengan shalat Maghrib.\""},"562":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ وَمُوسَى بْنُ إِسْمَاعِيلَ قَالَا حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَسِيَ صَلَاةً فَلْيُصَلِّ إِذَا ذَكَرَهَا لَا كَفَّارَةَ لَهَا إِلَّا ذَلِكَ{ وَأَقِمْ الصَّلَاةَ لِذِكْرِي }قَالَ مُوسَى قَالَ هَمَّامٌ سَمِعْتُهُ يَقُولُ بَعْدُ وَأَقِمْ الصَّلَاةَ للذِّكْرَى قَالَ أَبُو عَبْد اللَّهِ وَقَالَ حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] dan [Musa bin Isma'il] keduanya berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa lupa suatu shalat, maka hendaklah dia melaksanakannya ketika dia ingat. Karena tidak ada tebusannya kecuali itu. Allah berfirman: '(Dan tegakkanlah shalat untuk mengingat-Ku) ' (Qs. Thaahaa: 14). Musa berkata, Hammam berkata, \"Setelah itu aku mendengar beliau mengucapkan: '(Dan tegakkanlah shalat untuk mengingat-Ku) ' Abu 'Abdullah berkata; [Habban] berkata, telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"563":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى الْقَطَّانُ أَخْبَرَنَا هِشَامٌ قَالَ حَدَّثَنَا يَحْيَى هُوَ ابْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَعَلَ عُمَرُ يَوْمَ الْخَنْدَقِ يَسُبُّ كُفَّارَهُمْ وَقَالَ مَا كِدْتُ أُصَلِّي الْعَصْرَ حَتَّى غَرَبَتْ قَالَ فَنَزَلْنَا بُطْحَانَ فَصَلَّى بَعْدَ مَا غَرَبَتْ الشَّمْسُ ثُمَّ صَلَّى الْمَغْرِبَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya Al Qaththan] telah mengabarkan kepada kami [Hisyam] berkata, telah menceritakan kepada kami [Yahya] -yaitu Ibnu Abu Katsir- dari [Abu Salamah] dari [Jabir bin 'Abdullah] berkata, \"Pada peperangan Khandaq 'Umar bin Al Khaththab mengumpat orang-orang kafir, lalu ia berkata, \"Hampir saja aku tidak melaksanakan shalat 'Ashar kecuali setelah Matahari hampir tenggelam.\" Umar melanjutkan, \"Maka kami berdiri menuju aliran air (sungai), kemudian beliau melaksanakan shalat 'Ashar setelah matahari terbenam, dan dilanjutkan dengan shalat Maghrib.\""},"564":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عَوْفٌ قَالَ حَدَّثَنَا أَبُو الْمِنْهَالِ قَالَ انْطَلَقْتُ مَعَ أَبِي إِلَى أَبِي بَرْزَةَ الْأَسْلَمِيِّ فَقَالَ لَهُ أَبِي حَدِّثْنَاكَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَكْتُوبَةَ قَالَ كَانَ يُصَلِّي الْهَجِيرَ وَهِيَ الَّتِي تَدْعُونَهَا الْأُولَى حِينَ تَدْحَضُ الشَّمْسُ وَيُصَلِّي الْعَصْرَ ثُمَّ يَرْجِعُ أَحَدُنَا إِلَى أَهْلِهِ فِي أَقْصَى الْمَدِينَةِ وَالشَّمْسُ حَيَّةٌ وَنَسِيتُ مَا قَالَ فِي الْمَغْرِبِ قَالَ وَكَانَ يَسْتَحِبُّ أَنْ يُؤَخِّرَ الْعِشَاءَ قَالَ وَكَانَ يَكْرَهُ النَّوْمَ قَبْلَهَا وَالْحَدِيثَ بَعْدَهَا وَكَانَ يَنْفَتِلُ مِنْ صَلَاةِ الْغَدَاةِ حِينَ يَعْرِفُ أَحَدُنَا جَلِيسَهُ وَيَقْرَأُ مِنْ السِّتِّينَ إِلَى الْمِائَةِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami ['Auf] berkata, telah menceritakan kepada kami [Abu Al Minhal] berkata, \"Aku dan bapakku pergi berangkat menemui [Abu Barzah Al Aslami], bapakku lalu berkata kepadanya, \"Bagaimana Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat yang Maktubah (Wajib)?\" Abu Barzah menjawab, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur yang kalian sebut sebagai waktu utama saat Matahari tergelincir, shalat 'Ashar ketika seseorang dari kami pulang menemui keluarganya di ujung Kota, maka matahari masih terasa panas sinarnya. Dan aku lupa apa yang dibaca beliau saat shalat Maghrib. Dan beliau lebih suka mengakhirkan pelaksanaan shalat 'Isya yang kalian sebut sebagai waktu 'Atamah, beliau tidak suka tidur sebelum 'Isya dan berbincang-bincang setelahnya. Dan beliau melaksanakan shalat Shubuh ketika salah seorang dari kami dapat mengetahui siapa yang berada di sampingnya, beliau membaca antara enam hingga seratus ayat.\""},"565":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ قَالَ حَدَّثَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ قَالَ انْتَظَرْنَا الْحَسَنَ وَرَاثَ عَلَيْنَا حَتَّى قَرُبْنَا مِنْ وَقْتِ قِيَامِهِ فَجَاءَ فَقَالَ دَعَانَا جِيرَانُنَا هَؤُلَاءِ ثُمَّ قَالَ قَالَ أَنَسُ بْنُ مَالِكٍانْتَظَرْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ حَتَّى كَانَ شَطْرُ اللَّيْلِ يَبْلُغُهُ فَجَاءَ فَصَلَّى لَنَا ثُمَّ خَطَبَنَا فَقَالَ أَلَا إِنَّ النَّاسَ قَدْ صَلَّوْا ثُمَّ رَقَدُوا وَإِنَّكُمْ لَمْ تَزَالُوا فِي صَلَاةٍ مَا انْتَظَرْتُمْ الصَّلَاةَ قَالَ الْحَسَنُ وَإِنَّ الْقَوْمَ لَا يَزَالُونَ بِخَيْرٍ مَا انْتَظَرُوا الْخَيْرَ قَالَ قُرَّةُ هُوَ مِنْ حَدِيثِ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abu 'Ali Al Hanafi] telah menceritakan kepada kami [Qurrah bin Khalid] berkata, \"Kami pernah menunggu [Al Hasan] hingga memperlambat kami hingga sudah dekat dengan waktu ditegakkannya shalat. Lalu dia datang dan berkata, \"Kami diundang tetangga kami.\" Kemudian dia melanjutkan, [Anas bin Malik] menyebutkan, \"Pada suatu malam kami pernah menunggu Nabi shallallahu 'alaihi wasallam hingga sampai pertengahan malam. Lalu Beliau shalat bersama kami kemudian menyampaikan khuthbah kepada kami, sabda beliau: \"Manusia sudah selesai melaksanakan shalat lalu mereka tidur. Dan kalian akan senantiasa dalam hitungan shalat selagi kalian menunggu pelaksanaannya.\" Al Hasan berkata, \"Sesungguhnya suatu kaum senantiasa akan berada dalam kebaikan selagi mereka mananti kebaikan.\" Qurrah berkata, \"Ini adalah hadits dari Anas, dari Nabi shallallahu 'alaihi wasallam.\""},"566":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ وَأَبُو بَكْرٍ ابْنُ أَبِي حَثْمَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْعِشَاءِ فِي آخِرِ حَيَاتِهِ فَلَمَّا سَلَّمَ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَرَأَيْتَكُمْ لَيْلَتَكُمْ هَذِهِ فَإِنَّ رَأْسَ مِائَةٍ لَا يَبْقَى مِمَّنْ هُوَ الْيَوْمَ عَلَى ظَهْرِ الْأَرْضِ أَحَدٌ فَوَهِلَ النَّاسُ فِي مَقَالَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَا يَتَحَدَّثُونَ مِنْ هَذِهِ الْأَحَادِيثِ عَنْ مِائَةِ سَنَةٍ وَإِنَّمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْقَى مِمَّنْ هُوَ الْيَوْمَ عَلَى ظَهْرِ الْأَرْضِ يُرِيدُ بِذَلِكَ أَنَّهَا تَخْرِمُ ذَلِكَ الْقَرْنَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah menceritakan kepadaku [Salim bin 'Abdullah bin 'Umar] dan [Abu Bakar Ibnu Abu Hatsmah] bahwa ['Abdullah bin 'Umar] berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat 'Isya pada suatu malam di akhir hayatnya. Selesai salam, Nabi shallallahu 'alaihi wasallam berdiri dan berkata, \"Tidakkah kalian melihat malam kalian ini? Ketahuilah, sesungguhnya setelah seratus tahun tidak akan ada orang pun di muka bumi ini yang tersisa dari mereka yang hadir pada malam ini.\" Kemudian orang-orang mengalami kerancuan dalam memahami pernyataan Rasulullah shallallahu 'alaihi wasallam tersebut hingga mereka memperbincangkannya, yakni apa yang maksud dengan seratus tahun tersebut?\" 'Abdullah bin 'Umar berkata, \"Sesungguhnya maksud sabda Nabi, 'Tidak akan ada orang yang tersisa di atas bumi ini' adalah berakhirnya generasi tersebut'.\""},"567":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبِي حَدَّثَنَا أَبُو عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍأَنَّ أَصْحَابَ الصُّفَّةِ كَانُوا أُنَاسًا فُقَرَاءَ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ عِنْدَهُ طَعَامُ اثْنَيْنِ فَلْيَذْهَبْ بِثَالِثٍ وَإِنْ أَرْبَعٌ فَخَامِسٌ أَوْ سَادِسٌ وَأَنَّ أَبَا بَكْرٍ جَاءَ بِثَلَاثَةٍ فَانْطَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَشَرَةٍ قَالَ فَهُوَ أَنَا وَأَبِي وَأُمِّي فَلَا أَدْرِي قَالَ وَامْرَأَتِي وَخَادِمٌ بَيْنَنَا وَبَيْنَ بَيْتِ أَبِي بَكْرٍ وَإِنَّ أَبَا بَكْرٍ تَعَشَّى عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ لَبِثَ حَيْثُ صُلِّيَتْ الْعِشَاءُ ثُمَّ رَجَعَ فَلَبِثَ حَتَّى تَعَشَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ بَعْدَ مَا مَضَى مِنْ اللَّيْلِ مَا شَاءَ اللَّهُ قَالَتْ لَهُ امْرَأَتُهُ وَمَا حَبَسَكَ عَنْ أَضْيَافِكَ أَوْ قَالَتْ ضَيْفِكَ قَالَ أَوَمَا عَشَّيْتِيهِمْ قَالَتْ أَبَوْا حَتَّى تَجِيءَ قَدْ عُرِضُوا فَأَبَوْا قَالَ فَذَهَبْتُ أَنَا فَاخْتَبَأْتُ فَقَالَ يَا غُنْثَرُ فَجَدَّعَ وَسَبَّ وَقَالَ كُلُوا لَا هَنِيئًا فَقَالَ وَاللَّهِ لَا أَطْعَمُهُ أَبَدًا وَايْمُ اللَّهِ مَا كُنَّا نَأْخُذُ مِنْ لُقْمَةٍ إِلَّا رَبَا مِنْ أَسْفَلِهَا أَكْثَرُ مِنْهَا قَالَ يَعْنِي حَتَّى شَبِعُوا وَصَارَتْ أَكْثَرَ مِمَّا كَانَتْ قَبْلَ ذَلِكَ فَنَظَرَ إِلَيْهَا أَبُو بَكْرٍ فَإِذَا هِيَ كَمَا هِيَ أَوْ أَكْثَرُ مِنْهَا فَقَالَ لِامْرَأَتِهِ يَا أُخْتَ بَنِي فِرَاسٍ مَا هَذَا قَالَتْ لَا وَقُرَّةِ عَيْنِي لَهِيَ الْآنَ أَكْثَرُ مِنْهَا قَبْلَ ذَلِكَ بِثَلَاثِ مَرَّاتٍ فَأَكَلَ مِنْهَا أَبُو بَكْرٍ وَقَالَ إِنَّمَا كَانَ ذَلِكَ مِنْ الشَّيْطَانِ يَعْنِي يَمِينَهُ ثُمَّ أَكَلَ مِنْهَا لُقْمَةً ثُمَّ حَمَلَهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَصْبَحَتْ عِنْدَهُ وَكَانَ بَيْنَنَا وَبَيْنَ قَوْمٍ عَقْدٌ فَمَضَى الْأَجَلُ فَفَرَّقَنَا اثْنَا عَشَرَ رَجُلًا مَعَ كُلِّ رَجُلٍ مِنْهُمْ أُنَاسٌ اللَّهُ أَعْلَمُ كَمْ مَعَ كُلِّ رَجُلٍ فَأَكَلُوا مِنْهَا أَجْمَعُونَ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Mu'tamin bin Sulaiman] berkata, telah menceritakan kepada kami [bapakku] berkata, telah menceritakan kepada kami [Abu 'Utsman] dari ['Abdurrahman bin Abu Bakar], bahwa para Ashhabush Shuffah adalah orang-orang yang berasal dari kalangan fakir miskin. Nabi Shallallahu 'alaihi wa Sallam bersabda: \"Barangsiapa memiliki makanan cukup untuk dua orang, maka ajaklah orang yang ketiga. Jika memiliki makanan untuk empat orang hendaklah mengajak orang yang kelima atau keenam.\" Maka Abu Bakar datang dengan membawa makanan yang cukup untuk tiga orang. Nabi Shallallahu 'alaihi wa Sallam lalu datang dengan membawa makanan yang cukup untuk sepuluh orang.\"  'Abdurrahman bin Abu Bakar berkata, \"Mereka itu adalah aku, bapakku, ibuku, -perawi berkata; aku tidak tahu ia mengatakan- isteriku dan pelayan yang biasa membantu kami dan keluarga Abu Bakar. Saat itu Abu Bakar makan malam di sisi Nabi Shallallahu 'alaihi wa Sallam hingga waktu isya, dan ia tetap di sana hingga shalat dilaksanakan. Ketika Abu Bakar pulang di waktu yang sudah malam isterinya (ibuku) berkata, \"Apa yang menghalangimu untuk menjamu tamu-tamumu?\" Abu Bakar balik bertanya, \"Kenapa tidak engkau jamu mereka?\" Isterinya menjawab, \"Mereka enggan untuk makan hingga engkau kembali, padahal mereka sudah ditawari.\" 'Abdurrahman berkata, \"Kemudian aku pergi dan bersembunyi.\" Abu Bakar lantas berkata, \"Wahai Ghuntsar (kalimat celaan)!\" Abu Bakar terus saja marah dan mencela (aku). Kemudian ia berkata (kepada tamu-tamunya), \"Makanlah kalian semua.\" Kemudian tamunya mengatakan, \"Selamanya kami tidak akan makan. Demi Allah, tidaklah kami ambil satu suap kecuali makanan tersebut justru bertambah semakin banyak dari yang semula.\" 'Abdurrahman berkata, \"Mereka kenyang semua, dan makanan tersebut menjadi tiga kali lebih banyak dari yang semula. Abu Bakar memandangi makanan tersebut tetap utuh bahkan lebih banyak lagi. Kemudian ia berkata kepada isterinya, \"Wahai saudara perempuan Bani Firas, bagaimana ini?\" Isterinya menjawab, \"Tak masalah, bahkan itu suatu kebahagiaan, ia bertambah tiga kali lipatnya.\" Abu Bakar kemudian memakannya seraya berkata, \"Itu pasti dari setan-yakni sumpah yang ia ucapkan-.\" Kemudian ia memakan satu suap lantas membawanya ke hadapan Nabi Shallallahu 'alaihi wa Sallam. Waktu itu antara kami mempunyai perjanjian dengan suatu kaum dan masanya pun telah habis. Kemudian kami membagi orang-orang menjadi dua belas orang, dan setiap dari mereka diikuti oleh beberapa orang -dan Allah yang lebih tahu berapa jumlah mereka-. Kemudian mereka menyantap makanan tersebut hingga kenyang.\""},"568":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَذَكَرُوا النَّارَ وَالنَّاقُوسَ فَذَكَرُوا الْيَهُودَ وَالنَّصَارَى فَأُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَأَنْ يُوتِرَ الْإِقَامَةَ","id":"Telah menceritakan kepada kami ['Imran bin Maisarah] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Khalid Al Hadza'] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Orang-orang menyebut-nyebut tentang api dan lonceng (dalam mengusulkan cara memanggil shalat). Lalu ada juga di antara mereka yang mengusulkan seperti kebiasaan orang-orang Yahudi dan Nahrani. Maka Bilal diperintahkan untuk mengumandangkan adzan dengan dua kali dua kali dan iqamat dengan bilangan ganjil.\""},"569":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي نَافِعٌ أَنَّ ابْنَ عُمَرَ كَانَ يَقُولُكَانَ الْمُسْلِمُونَ حِينَ قَدِمُوا الْمَدِينَةَ يَجْتَمِعُونَ فَيَتَحَيَّنُونَ الصَّلَاةَ لَيْسَ يُنَادَى لَهَا فَتَكَلَّمُوا يَوْمًا فِي ذَلِكَ فَقَالَ بَعْضُهُمْ اتَّخِذُوا نَاقُوسًا مِثْلَ نَاقُوسِ النَّصَارَى وَقَالَ بَعْضُهُمْ بَلْ بُوقًا مِثْلَ قَرْنِ الْيَهُودِ فَقَالَ عُمَرُ أَوَلَا تَبْعَثُونَ رَجُلًا يُنَادِي بِالصَّلَاةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بِلَالُ قُمْ فَنَادِ بِالصَّلَاةِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Nafi'] bahwa [Ibnu 'Umar] berkata, \"Ketika Kaum Muslimin tiba di Madinah, mereka berkumpul untuk shalat dengan cara memperkirakan waktunya, dan tidak ada panggilan untuk pelaksanaan shalat. Suatu hari mereka memperbincangkan masalah tersebut, di antara mereka ada yang mengusulkan lonceng seperi loncengnya Kaum Nashrani dan sebagaian lain mengusulkan untuk meniup terampet sebagaimana Kaum Yahudi. Maka 'Umar pun berkata, \"Mengapa tidak kalian suruh seseorang untuk mengumandangkan panggilan shalat?\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Wahai Bilal, bangkit dan serukanlah panggilan shalat.\""},"570":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سِمَاكِ بْنِ عَطِيَّةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَأُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَأَنْ يُوتِرَ الْإِقَامَةَ إِلَّا الْإِقَامَةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Simak bin 'Athiyyah] dari [Ayyub] dari [Abu Qalabah] dari [Anas bin Malik] berkata, \"Bilal diperintahkan untuk mengumandangkan kalimat adzan dengan genap (dua kali dua kali) dan mengganjilkan iqamat, kecuali kalimat iqamat 'Qad qaamatish shalah (shalat telah dikumandangkan) '.\""},"571":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ قَالَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ قَالَ أَخْبَرَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا كَثُرَ النَّاسُ قَالَ ذَكَرُوا أَنْ يَعْلَمُوا وَقْتَ الصَّلَاةِ بِشَيْءٍ يَعْرِفُونَهُ فَذَكَرُوا أَنْ يُورُوا نَارًا أَوْ يَضْرِبُوا نَاقُوسًا فَأُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَأَنْ يُوتِرَ الْإِقَامَةَ","id":"Telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Salam- berkata, telah mengabarkan kepada kami ['Abdul Wahhab Ats Tsaqafi] berkata, telah mengabarkan kepada kami [Khalid Al Hadza'] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Ketika manusia sudah banyak (yang masuk Islam), ada yang mengusulkan cara memberitahu masuknya waktu shalat dengan sesuatu yang mereka bisa pahami. Maka ada yang mengusulkan dengan menyalakan api dan ada juga yang mengusulkan dengan memukul lonceng. Lalu diperintahlah Bilal untuk mengumandangkan kalimat adzan dengan genap (dua kali dua kali) dan mengganjilkan iqamat.\""},"572":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَأَنْ يُوتِرَ الْإِقَامَةَقَالَ إِسْمَاعِيلُ فَذَكَرْتُ لِأَيُّوبَ فَقَالَ إِلَّا الْإِقَامَةَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Bilal diperintahkan untuk mengumandangkan kalimat adzan dengan genap (dua kali dua kali) dan mengganjilkan iqamat.\" [Isma'il] berkata, \"Aku sampaikan masalah ini kepada [Ayyub], lalu ia berkata, 'Kecuali kalimat iqamat 'Qad qaamatish shalah (shalat telah dikumandangkan) '.\""},"573":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نُودِيَ لِلصَّلَاةِ أَدْبَرَ الشَّيْطَانُ وَلَهُ ضُرَاطٌ حَتَّى لَا يَسْمَعَ التَّأْذِينَ فَإِذَا قَضَى النِّدَاءَ أَقْبَلَ حَتَّى إِذَا ثُوِّبَ بِالصَّلَاةِ أَدْبَرَ حَتَّى إِذَا قَضَى التَّثْوِيبَ أَقْبَلَ حَتَّى يَخْطِرَ بَيْنَ الْمَرْءِ وَنَفْسِهِ يَقُولُ اذْكُرْ كَذَا اذْكُرْ كَذَا لِمَا لَمْ يَكُنْ يَذْكُرُ حَتَّى يَظَلَّ الرَّجُلُ لَا يَدْرِي كَمْ صَلَّى","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika panggilan shalat (adzan) dikumandangkan maka setan akan lari sambil mengeluarkan kentut hingga ia tidak mendengar suara adzan. Apabila panggilan adzan telah selesai maka setan akan kembali. Dan bila iqamat dikumandangkan setan kembali berlari dan jika iqamat telah selesai dikumandangkan dia kembali lagi, lalu menyelinap masuk kepada hati seseorang seraya berkata, 'Ingatlah ini dan itu'. Dan terus saja dia melakukan godaan ini hingga seseorang tidak menyadari berapa rakaat yang sudah dia laksanakan dalam shalatnya.\""},"574":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ الْأَنْصَارِيِّ ثُمَّ الْمَازِنِيِّ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَ لَهُإِنِّي أَرَاكَ تُحِبُّ الْغَنَمَ وَالْبَادِيَةَ فَإِذَا كُنْتَ فِي غَنَمِكَ أَوْ بَادِيَتِكَ فَأَذَّنْتَ بِالصَّلَاةِ فَارْفَعْ صَوْتَكَ بِالنِّدَاءِ فَإِنَّهُ لَا يَسْمَعُ مَدَى صَوْتِ الْمُؤَذِّنِ جِنٌّ وَلَا إِنْسٌ وَلَا شَيْءٌ إِلَّا شَهِدَ لَهُ يَوْمَ الْقِيَامَةِ قَالَ أَبُو سَعِيدٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abdurrahman bin Abdullah bin 'Abdurrahman bin Abu Sha'sha'ah Al Anshari Al Mazini] dari [Bapaknya] bahwa ia mengabarkan kepadanya, bahwa [Abu Sa'id Al Khudri] berkata kepadanya, \"Aku lihat kamu suka kambing dan lembah (pengenmbalaan). Jika kamu sedang mengembala kambingmu atau berada di lembah, lalu kamu mengumandangkan adzan shalat, maka keraskanlah suaramu. Karena tidak ada yang mendengar suara mu'adzin, baik manusia, jin atau apapun dia, kecuali akan menjadi saksi pada hari kiamat.\" Abu Sa'id berkata, \"Aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"575":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا غَزَا بِنَا قَوْمًا لَمْ يَكُنْ يَغْزُو بِنَا حَتَّى يُصْبِحَ وَيَنْظُرَ فَإِنْ سَمِعَ أَذَانًا كَفَّ عَنْهُمْ وَإِنْ لَمْ يَسْمَعْ أَذَانًا أَغَارَ عَلَيْهِمْ قَالَ فَخَرَجْنَا إِلَى خَيْبَرَ فَانْتَهَيْنَا إِلَيْهِمْ لَيْلًا فَلَمَّا أَصْبَحَ وَلَمْ يَسْمَعْ أَذَانًا رَكِبَ وَرَكِبْتُ خَلْفَ أَبِي طَلْحَةَ وَإِنَّ قَدَمِي لَتَمَسُّ قَدَمَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَخَرَجُوا إِلَيْنَا بِمَكَاتِلِهِمْ وَمَسَاحِيهِمْ فَلَمَّا رَأَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا مُحَمَّدٌ وَاللَّهِ مُحَمَّدٌ وَالْخَمِيسُ قَالَ فَلَمَّا رَآهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam jika memerangi suaku kaum bersama kami, maka beliau tidak menyerang kaum tersebut hingga datangnya waktu shubuh (menunggu). Jika mendengar suara adzan, beliau mengurungkannya. Namun bila tidak terdengar suara adzan maka beliau menyerangnya.\" Anas bin Malik berkata, \"Maka pada suatu hari kami keluar untuk menyerbu perkampungan Khaibar, kami lantas menunggu hingga malam hari. Ketika datang waktu pagi dan beliau tidak mendengar suara adzan, maka beliau menaiki tunggangannya sementara aku membonceng di belakang Abu Thalhah. Sungguh kakiku menyentuh kaki Nabi shallallahu 'alaihi wasallam.\" Anas bin Malik melanjutkan kisahnya, \"Penduduk Khaibar keluar ke arah kami dengan membawa keranjang dan sekop-sekop mereka, ketika mereka melihat Nabi shallallahu 'alaihi wasallam, maka mereka berkata, \"Muhammad! Demi Allah, Muhammad dan pasukannya (datang)!\" Kata Anas, \"Ketika Rasulullah shallallahu 'alaihi wasallam melihat mereka, beliau bersabda: \"Allahu Akbar, Allahu Akbar, hancurlah Khaibar! Sesungguhnya kami, apabila mendatangi perkampungan suatu kaum, maka amat buruklah pagi hari yang dialami orang-orang yang diperingatkan tersebut) ' (Qs. Ash Shaffaat: 177)."},"576":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ النِّدَاءَ فَقُولُوا مِثْلَ مَا يَقُولُ الْمُؤَذِّنُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Atha bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian mendengar adzan, maka jawablah seperti apa yang diucapkan mu'adzin.\""},"577":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ قَالَ حَدَّثَنِي عِيسَى بْنُ طَلْحَةَ أَنَّهُ سَمِعَ مُعَاوِيَةَيَوْمًا فَقَالَ مِثْلَهُ إِلَى قَوْلِهِ وَأَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Muhammad bin Ibrahim bin Al Harits] berkata, telah menceritakan kepadaku ['Isa bin Thalhah], bahwa pada suatu hari dia mendengar [Mu'awiyyah] mengucapkan seperti (apa yang diucapkan mu'adzin) hingga ucapannya: \"Wa asyhadu anna Muhammadar Rasulullah.\""},"578":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ رَاهَوَيْهِ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى نَحْوَهُ قَالَ يَحْيَى وَحَدَّثَنِي بَعْضُ إِخْوَانِنَا أَنَّهُ قَالَلَمَّا قَالَ حَيَّ عَلَى الصَّلَاةِ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ وَقَالَ هَكَذَا سَمِعْنَا نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ","id":"Telah menceritakan kepada kami [Ishaq bin Rahawaih] berkata, telah menceritakan kepada kami [Wahab bin Jarir] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] seperti itu, Yahya berkata, dan telah menceritakan kepadaku [Sebagian saudara kami] bahwa dia berkata, \"Jika mu'adzin mengucapkan, 'Hayya 'Alash shalah '(Marilah melaksanakan shalat) ', dia menjawab, \"Laa Haula Walaa Quwwata Illaa Billah '(Tidak ada daya dan kekuatan melainkan dengan izin Allah) '. Dia berkata, \"Demikianlah kami mendengar Nabi kalian shallallahu 'alaihi wasallam bersabda.\""},"579":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يَسْمَعُ النِّدَاءَ اللَّهُمَّ رَبَّ هَذِهِ الدَّعْوَةِ التَّامَّةِ وَالصَّلَاةِ الْقَائِمَةِ آتِ مُحَمَّدًا الْوَسِيلَةَ وَالْفَضِيلَةَ وَابْعَثْهُ مَقَامًا مَحْمُودًا الَّذِي وَعَدْتَهُ حَلَّتْ لَهُ شَفَاعَتِي يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami ['Ali bin 'Ayyasy] berkata, telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] dari [Muhammad Al Munkadir] dari [Jabir bin 'Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berdo'a setelah mendengar adzan: ALLAHUMMA RABBA HAADZIHID DA'WATIT TAMMAH WASHSHALAATIL QAA'IMAH. AATI MUHAMMADANIL WASIILATA WALFADLIILAH WAB'ATSHU MAQAAMAM MAHMUUDANIL LADZII WA'ADTAH (Ya Allah. Rabb Pemilik seruan yang sempurna ini, dan Pemilik shalat yang akan didirikan ini, berikanlah wasilah (perantara) dan keutamaan kepada Muhammad. Bangkitkanlah ia pada kedudukan yang terpuji sebagaimana Engkau telah jannjikan) '. Maka ia berhak mendapatkan syafa'atku pada hari kiamat.\""},"580":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ يَعْلَمُ النَّاسُ مَا فِي النِّدَاءِ وَالصَّفِّ الْأَوّ��لِ ثُمَّ لَمْ يَجِدُوا إِلَّا أَنْ يَسْتَهِمُوا عَلَيْهِ لَاسْتَهَمُوا وَلَوْ يَعْلَمُونَ مَا فِي التَّهْجِيرِ لَاسْتَبَقُوا إِلَيْهِ وَلَوْ يَعْلَمُونَ مَا فِي الْعَتَمَةِ وَالصُّبْحِ لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Sumayya] mantan budak Abu Bakar, dari [Shalih] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya manusia mengetahui apa (kebaikan) yang terdapat pada adzan dan shaf awal, lalu mereka tidak akan mendapatkannya kecuali dengan cara mengundi, niscaya tmereka akan melakukannya. Dan seandainya mereka mengetahui kebaikan yang terdapat dalam bersegera (menuju shalat), niscaya mereka akan berlomba-lomba. Dan seandainya mereka mengetahui kebaikan yang terdapat pada shalat 'Isya dan Shubuh, niscaya mereka akan mendatanginya walaupun harus dengan merangkak.\""},"581":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ وَعَبْدِ الْحَمِيدِ صَاحِبِ الزِّيَادِيِّ وَعَاصِمٍ الْأَحْوَلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَ خَطَبَنَا ابْنُ عَبَّاسٍفِي يَوْمٍ رَدْغٍ فَلَمَّا بَلَغَ الْمُؤَذِّنُ حَيَّ عَلَى الصَّلَاةِ فَأَمَرَهُ أَنْ يُنَادِيَ الصَّلَاةُ فِي الرِّحَالِ فَنَظَرَ الْقَوْمُ بَعْضُهُمْ إِلَى بَعْضٍ فَقَالَ فَعَلَ هَذَا مَنْ هُوَ خَيْرٌ مِنْهُ وَإِنَّهَا عَزْمَةٌ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad] dari [Ayyub] dan ['Abdul Hamid] sahabat Az Zayadi, dan ['Ashim Al Ahwal] dari ['Abdullah bin Al Harits] berkata, \"Pada suatu hari ketika jalan penuh dengan air dan lumpur (becek) akibat hujan, [Ibnu 'Abbas] pernah menyampaikan khuthbah kepada kami. Ketika mu'adzin sampai pada ucapan: 'Hayya 'Alash shalaah (Marilah mendirikan shalat) ' ia perintahkan mu'adzin tersebut untuk menyerukan: 'Shalatlah di tempat tinggal masing-masing'. Lalu orang-orang saling memandang satu sama lain karena heran. Maka Abdullah bin Al Harits pun berkata, \"Hal yang demikian ini pernah dilakukan oleh orang yang lebih baik darinya, dan itu merupakan kewajiban Mu'akkad (yang ditekankan).\""},"582":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُنَادِيَ ابْنُ أُمِّ مَكْتُومٍ ثُمَّ قَالَ وَكَانَ رَجُلًا أَعْمَى لَا يُنَادِي حَتَّى يُقَالَ لَهُ أَصْبَحْتَ أَصْبَحْتَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [Bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bilal mengumandangkan adzan saat masih malam, maka makan dan minumlah sampai kalian mendengar adzan Ibnu Ummi Maktum.\" Perawi berkata, \"Ibnu UmmuiMaktum adalah seorang sahabat yang buta, ia tidak akan mengumandangkan adzan (shubuh) hingga ada orang yang mengatakan kepadanya, 'Sudah shubuh, sudah shubuh'.\""},"583":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَخْبَرَتْنِي حَفْصَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اعْتَكَفَ الْمُؤَذِّنُ لِلصُّبْحِ وَبَدَا الصُّبْحُ صَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ أَنْ تُقَامَ الصَّلَاةُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar] berkata, [Hafshah] mengabarkan kepadaku, bahwa Rasulullah shallallahu 'alaihi wasallam jika mu'adzin telah selesai mengumandangkan adzan Shubuh, beliau melaksanakan shalat dua rakaat ringan sebelum mendirikan shalat Shubuh.\""},"584":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي رَكْعَتَيْنِ خَفِيفَتَيْنِ بَيْنَ النِّدَاءِ وَالْإِقَامَةِ مِنْ صَلَاةِ الصُّبْحِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari ['Aisyah], bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat sunnat dua rakaat ringan antara adzan dan iqamat dalam shalat Shubuh.\""},"585":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُنَادِي بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُنَادِيَ ابْنُ أُمِّ مَكْتُومٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bilal mengumandangkan adzan saat masih malam. Maka makan dan minumlah sampai ada seruan adzan oleh Ibnu Ummi Maktum.\""},"586":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْنَعَنَّ أَحَدَكُمْ أَوْ أَحَدًا مِنْكُمْ أَذَانُ بِلَالٍ مِنْ سَحُورِهِ فَإِنَّهُ يُؤَذِّنُ أَوْ يُنَادِي بِلَيْلٍ لِيَرْجِعَ قَائِمَكُمْ وَلِيُنَبِّهَ نَائِمَكُمْ وَلَيْسَ أَنْ يَقُولَ الْفَجْرُ أَوْ الصُّبْحُ وَقَالَ بِأَصَابِعِهِ وَرَفَعَهَا إِلَى فَوْقُ وَطَأْطَأَ إِلَى أَسْفَلُ حَتَّى يَقُولَ هَكَذَاوَقَالَ زُهَيْرٌ بِسَبَّابَتَيْهِ إِحْدَاهُمَا فَوْقَ الْأُخْرَى ثُمَّ مَدَّهَا عَنْ يَمِينِهِ وَشِمَالِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Sulaiman At Taimi] dari [Abu 'Utsman Al Hindi] dari ['Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Adzannya Bilal tidaklah menghalangi seorang dari kalian, atau seseorang dari makan sahurnya, karena dia mengumandangkan adzan saat masih malam supaya orang yang masih shalat malam dapat pulang untuk mengingatkan mereka yang masih tidur. Dan Bilal adzan tidak bermaksud memberitahukan masuknya waktu fajar atau shubuh.\" Beliau berkata dengan isyarat jarinya, beliau angkat ke atas dan menurunkannya kembali hingga berkata seperti ini.\" Zuhair menyebutkan, \"Beliau berisyarat dengan kedua jari telunjuknya, salah satu jarinya beliau letakkan di atas yang lainnya, kemudian membentangkannya ke kanan dan kirinya.\""},"587":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ أَخْبَرَنَا أَبُو أُسَامَةَ قَالَ عُبَيْدُ اللَّهِ حَدَّثَنَا عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ وَعَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ح و حَدَّثَنِي يُوسُفُ بْنُ عِيسَى الْمَرْوَزِيُّ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُؤَذِّنَ ابْنُ أُمِّ مَكْتُومٍ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah mengabarkan kepada kami [Abu Usamah] berkata, ['Ubaidullah] menceritakan kepada kami dari [Al Qasim bin Muhammad] dari ['Aisyah], dan dari [Nafi'] dari [Ibnu 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Yusuf bin 'Isa Al Marwazi] berkata, telah menceritakan kepada kami [Al Fadll bin Musa] berkata, telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Al Qasim bin Muhammad] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Bilal mengumandangkan adzan saat masih malam, maka makan dan minumlah sampai ada seruan adzan oleh Ibnu Ummi Maktum.\""},"588":{"ar":"حَدَّثَنَا إِسْحَاقُ الْوَاسِطِيُّ قَالَ حَدَّثَنَا خَالِدٌ عَنْ الْجُرَيْرِيِّ عَنْ ابْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ ثَلَاثًا لِمَنْ شَاءَ","id":"Telah menceritakan kepada kami [Ishaq Al Washithi] berkata, telah menceritakan kepada kami [Khalid] dari [Al Jurairi] dari [Abu Burdah] dari ['Abdullah bin Mughaffal Al Muzni], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di dua adzan (adzan dan iqamat) ada shalat sunah -beliau ucapkan tiga kali- bagi yang mau.\""},"589":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَمْرَو بْنَ عَامِرٍ الْأَنْصَارِيَّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ الْمُؤَذِّنُ إِذَا أَذَّنَ قَامَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْتَدِرُونَ السَّوَارِيَ حَتَّى يَخْرُجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ كَذَلِكَ يُصَلُّونَ الرَّكْعَتَيْنِ قَبْلَ الْمَغْرِبِ وَلَمْ يَكُنْ بَيْنَ الْأَذَانِ وَالْإِقَامَةِ شَيْءٌقَالَ عُثْمَانُ بْنُ جَبَلَةَ وَأَبُو دَاوُدَ عَنْ شُعْبَةَ لَمْ يَكُنْ بَيْنَهُمَا إِلَّا قَلِيلٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] berkata, aku mendengar ['Amru bin 'Amir Al Anshari] dari [Anas bin Malik] berkata, \"Jika seorang mu'adzin sudah mengumandangkan adzan (Maghrib), maka para sahabat Nabi shallallahu 'alaihi wasallam berebut mendekati tiang-tiang (untuk shalat sunnat) sampai Nabi shallallahu 'alaihi wasallam keluar, sementara mereka tetap dalam keadaan menunaikan shalat sunnat dua rakaat sebelum Maghrib. Dan di antara adzan dan iqamat Maghrib sangatlah sedikit (waktunya).\" ['Utsman bin Jailah] dan [Abu Daud] menyebutkan dari [Syu'bah], \"Antara keduanya (adzan dan iqamat) tidak ada waktu kecuali sedikit.\""},"590":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَكَتَ الْمُؤَذِّنُ بِالْأُولَى مِنْ صَلَاةِ الْفَجْرِ قَامَ فَرَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِ بَعْدَ أَنْ يَسْتَبِينَ الْفَجْرُ ثُمَّ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُ لِلْإِقَامَةِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah] berkata, \"Jika mu'adzin selesai mengumandangkan adzan pertama dari adzan shalat Shubuh, Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat dua rakaat ringan sebelum melaksanakan shalat fajar, yaitu ketika fajar sudah jelas masuknya. Kemudian beliau berbaring pada sisi kanan badannya hingga mu'adzin mendatangi beliau untuk mengumandangkan iqamat.\""},"591":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنَا كَهْمَسُ بْنُ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ ثُمَّ قَالَ فِي الثَّالِثَةِ لِمَنْ شَاءَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid] berkata, telah menceritakan kepada kami [Kahmas bin Hasan] dari ['Abdullah bin Buraidah] dari ['Abdullah bin Mughaffal] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara dua adzan (adzan dan iqamah) ada shalat (sunah).\" Kemudian pada ucapan beliau yang ketiga kalinya, beliau menambahkan: \"Bagi yang mau.\""},"592":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفَرٍ مِنْ قَوْمِي فَأَقَمْنَا عِنْدَهُ عِشْرِينَ لَيْلَةً وَكَانَ رَحِيمًا رَفِيقًا فَلَمَّا رَأَى شَوْقَنَا إِلَى أَهَالِينَا قَالَ ارْجِعُوا فَكُونُوا فِيهِمْ وَعَلِّمُوهُمْ وَصَلُّوا فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Mu'allaa bin Asad] berkata, telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Abu Qilabah] dari [Malik bin Al Huwairits], \"Aku mendatangi Nabi shallallahu 'alaihi wasallam dalam rombongan kaumku, kami lalu tinggal di sisi beliau selama dua puluh hari. Beliau adalah seorang yang sangat penuh kasih dan sayang. Ketika beliau melihat ada kerinduan kami kepada keluarga kami, beliau bersabda: \"Kembalilah kalian kepada mereka, bergabunglah bersama mereka, ajari mereka dan shalat bersama mereka. Jika waktu shalat telah tiba, maka hendaklah salah seorang dari kalian mengumandangkan adzan dan hendaklah yang mengimami shalat kalian adalah yang paling tua di antara kalian.\""},"593":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْمُهَاجِرِ أَبِي الْحَسَنِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ أَبِي ذَرٍّ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَرَادَ الْمُؤَذِّنُ أَنْ يُؤَذِّنَ فَقَالَ لَهُ أَبْرِدْ ثُمَّ أَرَادَ أَنْ يُؤَذِّنَ فَقَالَ لَهُ أَبْرِدْ ثُمَّ أَرَادَ أَنْ يُؤَذِّنَ فَقَالَ لَهُ أَبْرِدْ حَتَّى سَاوَى الظِّلُّ التُّلُولَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Muhajir Abu Al Hasan] dari [Zaid bin Wahb] dari [Abu Dzar Al Ghifari] berkata, \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan. Ketika ada mu'adzin yang hendak mengumandangkan adzan, beliau berkata kepadanya: \"Tundalah.\" Sesaat kemudian mu'adzin itu kembali akan melakukan adzan, beliau kembali berkata,: \"Tundalah.\" Kemudian ketika mu'adzin itu kembali hendak melakukan adzan untuk ketiga kalinya, beliau kembali berkata: \"Tundalah hingga kita melihat bayang-bayang bukit.\" Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya panas yang sangat menyengat itu berasal dari hembusan api jahannam.\""},"594":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَى رَجُلَانِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدَانِ السَّفَرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنْتُمَا خَرَجْتُمَا فَأَذِّنَا ثُمَّ أَقِيمَا ثُمَّ لِيَؤُمَّكُمَا أَكْبَرُكُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari [Khalid Al Hadzdza'] dari [Abu Qilabah] dari [Malik bin Al Huwairits] berkata, \"Dua orang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam, keduanya ingin melakukan suatu perjalanan. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Jika kalian berdua sudah keluar, maka (bila hendak shalat) adzan dan iqamatlah. Dan yang menjadi Imam hendaklah yang paling tua di antara kalian.\""},"595":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ قَالَ حَدَّثَنَا مَالِكٌأَتَيْنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ مُتَقَارِبُونَ فَأَقَمْنَا عِنْدَهُ عِشْرِينَ يَوْمًا وَلَيْلَةً وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِيمًا رَفِيقًا فَلَمَّا ظَنَّ أَنَّا قَدْ اشْتَهَيْنَا أَهْلَنَا أَوْ قَدْ اشْتَقْنَا سَأَلَنَا عَمَّنْ تَرَكْنَا بَعْدَنَا فَأَخْبَرْنَاهُ قَالَ ارْجِعُوا إِلَى أَهْلِيكُمْ فَأَقِيمُوا فِيهِمْ وَعَلِّمُوهُمْ وَمُرُوهُمْ وَذَكَرَ أَشْيَاءَ أَحْفَظُهَا أَوْ لَا أَحْفَظُهَا وَصَلُّوا كَمَا رَأَيْتُمُونِي أُصَلِّي فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami ['Abdul Wahhab] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] berkata, telah menceritakan kepada kami [Malik], \"Kami datang menemui Nabi shallallahu 'alaihi wasallam, saat itu kami adalah para pemuda yang usianya sebaya. Maka kami tinggal bersama beliau selama dua puluh hari dua puluh malam. Beliau adalah seorang yang sangat penuh kasih dan lembut. Ketika beliau menganggap bahwa kami telah ingin, atau merindukan keluarga kami, beliau bertanya kepada kami tentang orang yang kami tinggalkan. Maka kami pun mengabarkannya kepada beliau. Kemudian beliau bersabda: \"Kembalilah kepada keluarga kalian dan tinggallah bersama mereka, ajarilah mereka dan perintahkan (untuk shalat).\" Beliau lantas menyebutkan sesuatu yang aku pernah ingat lalu lupa. Beliau mengatakan: \"Shalatlah kalian seperti kalian melihat aku shalat. Maka jika waktu shalat sudah tiba, hendaklah salah seorang dari kalian mengumandangkan adzan, dan hendaklah yang menjadi Imam adalah yang paling tua di antara kalian.\""},"596":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ أَخْبَرَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ حَدَّثَنِي نَافِعٌ قَالَأَذَّنَ ابْنُ عُمَرَ فِي لَيْلَةٍ بَارِدَةٍ بِضَجْنَانَ ثُمَّ قَالَ صَلُّوا فِي رِحَالِكُمْ فَأَخْبَرَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ مُؤَذِّنًا يُؤَذِّنُ ثُمَّ يَقُولُ عَلَى إِثْرِهِ أَلَا صَلُّوا فِي الرِّحَالِ فِي اللَّيْلَةِ الْبَارِدَةِ أَوْ الْمَطِيرَةِ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah mengabarkan kepada kami [Yahya] dari ['Ubaidullah bin 'Umar] berkata, telah menceritakan kepadaku [Nafi'] berkata, \" [Ibnu 'Umar] pernah adzan di malam yang dingin di bukit Dlajnan. Kemudian ia berkata, \"Shalatlah di tempat tinggal kalian!\" Lalu dia mengabarkan kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam pernah memerintahkan seorang mu'adzin untuk mengumandangkan adzan, kemudian berseru setelah selesai adzan, \"Hendaklah kalian shalat di tempat tinggal kalian pada malam yang dingin, atau saat turun hujan dalam perjalanan.\""},"597":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ قَالَ أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ قَالَ حَدَّثَنَا أَبُو الْعُمَيْسِ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْأَبْطَحِ فَجَاءَهُ بِلَالٌ فَآذَنَهُ بِالصَّلَاةِ ثُمَّ خَرَجَ بِلَالٌ بِالْعَنَزَةِ حَتَّى رَكَزَهَا بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْأَبْطَحِ وَأَقَامَ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah mengabarkan kepada kami [Ja'far bin 'Aun] berkata, telah menceritakan kepada kami [Abu Al 'Umais] dari ['Aun bin Abu Juhaifah] dari [Bapaknya] berkata, \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam di Abthah, lalu Bilal datang dan memberitahukan kepada beliau bahwa waktu shalat telah tiba. Kemudian Bilal keluar dengan membawa sebatang kayu (tongkat) dan menancapkannya di depan Rasulullah shallallahu 'alaihi wasallam, Beliau kemudian melaksanakan shalat di tempat tersebut.\""},"598":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِأَنَّهُ رَأَى بِلَالًا يُؤَذِّنُ فَجَعَلْتُ أَتَتَبَّعُ فَاهُ هَهُنَا وَهَهُنَا بِالْأَذَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari ['Aun] dari [Bapaknya], bahwa dia melihat Bilal mengumandangkan adzan. Aku lalu memperhatikan mulutnya bergerak ke sana dan ke sini saat mengumandangkan adzan.\""},"599":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَبَيْنَمَا نَحْنُ نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ سَمِعَ جَلَبَةَ رِجَالٍ فَلَمَّا صَلَّى قَالَ مَا شَأْنُكُمْ قَالُوا اسْتَعْجَلْنَا إِلَى الصَّلَاةِ قَالَ فَلَا تَفْعَلُوا إِذَا أَتَيْتُمْ الصَّلَاةَ فَعَلَيْكُمْ بِالسَّكِينَةِ فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا فَاتَكُمْ فَأَتِمُّوا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] ia berkata, \"Ketika kami shalat bersama Nabi shallallahu 'alaihi wasallam, beliau mendengar suara gaduh orang-orang. Maka setelah selesai, beliau bertanya: \"Ada apa dengan kalian?\" Mereka menjawab, \"Kami tergesa-gesa mendatangi shalat.\" Beliau pun bersabda: \"Janganlah kalian berbuat seperti itu. Jika kalian mendatangi shalat maka datanglah dengan tenang, apa yang kalian dapatkan dari shalat maka ikutilah, dan apa yang kalian tertinggal maka sempurnakanlah.\""},"600":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ الْإِقَامَةَ فَامْشُوا إِلَى الصَّلَاةِ وَعَلَيْكُمْ بِالسَّكِينَةِ وَالْوَقَارِ وَلَا تُسْرِعُوا فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا فَاتَكُمْ فَأَتِمُّوا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] berkata, telah menceritakan kepada kami dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, dan dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendengar iqamat dikumandangkan, maka berjalanlah menuju shalat dan hendaklah kalian berjalan dengan tenang berwibawa dan jangan tergesa-gesa. Apa yang kalian dapatkan dari shalat maka ikutilah, dan apa yang kalian tertinggal maka sempurnakanlah.\""},"601":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ قَالَ كَتَبَ إِلَيَّ يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَقُومُوا حَتَّى تَرَوْنِي","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam] berkata, [Yahya bin Abu Katsir] telah menulis kepadaku surat dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika iqamah telah dikumandangkan maka janganlah berdiri hingga kalian melihat aku.\""},"602":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَقُومُوا حَتَّى تَرَوْنِي وَعَلَيْكُمْ بِالسَّكِينَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika iqamah telah dikumandangkan maka janganlah berdiri hingga kalian melihat aku, dan hendaklah kalian melakukannya dengan tenang.\""},"603":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ وَقَدْ أُقِيمَتْ الصَّلَاةُ وَعُدِّلَتْ الصُّفُوفُ حَتَّى إِذَا قَامَ فِي مُصَلَّاهُ انْتَظَرْنَا أَنْ يُكَبِّرَ انْصَرَفَ قَالَ عَلَى مَكَانِكُمْ فَمَكَثْنَا عَلَى هَيْئَتِنَا حَتَّى خَرَجَ إِلَيْنَا يَنْطِفُ رَأْسُهُ مَاءً وَقَدْ اغْتَسَلَ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin Abdullah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah], bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam keluar sementara iqamat sudah dikumandangkan dan shaf-shaf sudah diluruskan, hingga ketika beliau telah berdiri di tempat shalatnya dan kami menunggunya untuk segera takbir, beliau berlalu sambil berkata: \"Tetaplah di tempat kalian.\" Maka kami tetap berdiri di tempat semula hingga beliau kembali kepada kami dengan kela basah karena sebab mandi.\""},"604":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَأُقِيمَتْ الصَّلَاةُ فَسَوَّى النَّاسُ صُفُوفَهُمْ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَقَدَّمَ وَهُوَ جُنُبٌ ثُمَّ قَالَ عَلَى مَكَانِكُمْ فَرَجَعَ فَاغْتَسَلَ ثُمَّ خَرَجَ وَرَأْسُهُ يَقْطُرُ مَاءً فَصَلَّى بِهِمْ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] berkata, \"Suatu hari iqamat sudah dikumandangkan dan orang-orang sudah merapikan shaf-shaf mereka, lalu Rasulullah shallallahu 'alaihi wasallam keluar dan maju ke depan untuk memimpin shalat padahal waktu itu beliau sedang junub. Beliau lantas berkata; \"Tetaplah di tempat kalian.\" Beliau pun kembali ke rumah untuk mandi dan datang kepada kami dalam keadaan kepalanya basah, kemudian beliau shalat bersama mereka.\""},"605":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى قَالَ سَمِعْتُ أَبَا سَلَمَةَ يَقُولُ أَخْبَرَنَا جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ عُمَرُ بْنُ الْخَطَّابِ يَوْمَ الْخَنْدَقِ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا كِدْتُ أَنْ أُصَلِّيَ حَتَّى كَادَتْ الشَّمْسُ تَغْرُبُ وَذَلِكَ بَعْدَ مَا أَفْطَرَ الصَّائِمُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا صَلَّيْتُهَا فَنَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بُطْحَانَ وَأَنَا مَعَهُ فَتَوَضَّأَ ثُمَّ صَلَّى يَعْنِي الْعَصْرَ بَعْدَ مَا غَرَبَتْ الشَّمْسُ ثُمَّ صَلَّى بَعْدَهَا الْمَغْرِبَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] berkata, Aku mendengar [Abu Salamah] berkata, telah mengabarkan kepada kami [Jabir bin 'Abdullah], bahwa Nabi shallallahu 'alaihi wasallam didatangi oleh 'Umar bin Al Khaththab saat terjadinya pernag Khandaq. Umar berkata, \"Wahai Rasulullah! Demi Allah, aku belum melaksanakan shalat 'Ashar kecuali setelahg Matahari hampir tenggelam. Dan itu ketika orang-orang yang berpuasa telah berbuka!\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Demi Allah, aku juga belum melakasanakannya.\" Kemudian beliau turun menuju aliran air (sungai), dan aku ikut bersama beliau. Belau lalu berwudlu dan shalat, yaitu shalat Ashar setelah matahari terbenam. Kemudian dilanjutkan dengan melaksanakan shalat Maghrib.\""},"606":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأُقِيمَتْ الصَّلَاةُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَاجِي رَجُلًا فِي جَانِبِ الْمَسْجِدِ فَمَا قَامَ إِلَى الصَّلَاةِ حَتَّى نَامَ الْقَوْمُ","id":"Telah menceritakan kepada kami [Abu Ma'mar Abdullah bin 'Amru] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] dari [Anas bin Malik] berkata, \"Pada suatu hari ketika iqamat sudah dibacakan, Nabi shallallahu 'alaihi wasallam masih berbicara dengan seseorang di sisi masjid. Beliau belum juga melaksanakan shalat hingga sebagian para sahabat tertidur.\""},"607":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا حُمَيْدٌ قَالَ سَأَلْتُ ثَابِتًا الْبُنَانِيَّ عَنْ الرَّجُلِ يَتَكَلَّمُ بَعْدَ مَا تُقَامُ الصَّلَاةُ فَحَدَّثَنِي عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأُقِيمَتْ الصَّلَاةُ فَعَرَضَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَحَبَسَهُ بَعْدَ مَا أُقِيمَتْ الصَّلَاةُ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] berkata, telah menceritakan kepada kami ['Abdul A'la] berkata, telah menceritakan kepada kami [Humaid] berkata, \"Aku bertanya kepada [Tsabit Al Bunani] tentang seorang laki-laki yang berbincang-bincang setelah iqamat dikumandangan. Maka ia pun menceritakan kepadaku dari [Anas bin Malik] ia berkata, \"Ketika iqamah telah dikumandangkan Nabi shallallahu 'alaihi wasallam dihampiri oleh seorang laki-laki hingga menghalanginya dari menunaikan shalat.\""},"608":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ هَمَمْتُ أَنْ آمُرَ بِحَطَبٍ فَيُحْطَبَ ثُمَّ آمُرَ بِالصَّلَاةِ فَيُؤَذَّنَ لَهَا ثُمَّ آمُرَ رَجُلًا فَيَؤُمَّ النَّاسَ ثُمَّ أُخَالِفَ إِلَى رِجَالٍ فَأُحَرِّقَ عَلَيْهِمْ بُيُوتَهُمْ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ يَعْلَمُ أَحَدُهُمْ أَنَّهُ يَجِدُ عَرْقًا سَمِينًا أَوْ مِرْمَاتَيْنِ حَسَنَتَيْنِ لَشَهِدَ الْعِشَاءَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sungguh aku ingin memerintahkan seseorang mengumpulkan kayu bakar kemudian aku perintahkan seseorang untuk adzan dan aku perintahkan seseorang untuk memimpin orang-orang shalat. Sedangkan aku akan mendatangi orang-orang (yang tidak ikut shalat berjama'ah) lalu aku bakar rumah-rumah mereka. Demi Dzat yang jiwaku berada di tangan-Nya, seandainya seseorang di antara kalian mengetahui bahwa ia akan memperaleh daging yang gemuk, atau dua potongan daging yang bagus, pasti mereka akan mengikuti shalat 'Isya berjama'ah.\""},"609":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْجَمَاعَةِ تَفْضُلُ صَلَاةَ الْفَذِّ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat berjama'ah lebih utama dibandingkan shalat sendirian dengan dua puluh tujuh derajat.\""},"610":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا اللَّيْثُ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صَلَاةُ الْجَمَاعَةِ تَفْضُلُ صَلَاةَ الْفَذِّ بِخَمْسٍ وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Al Laits] telah menceritakan kepadaku [Ibnu Al Had] dari ['Abdullah bin Khabbab] dari [Abu Sa'id Al Khudri], bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Shalat berjama'ah lebih utama dibandingkan shalat sendirian dengan dua puluh lima derajat.\""},"611":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ أَبَا صَالِحٍ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الرَّجُلِ فِي الْجَمَاعَةِ تُضَعَّفُ عَلَى صَلَاتِهِ فِي بَيْتِهِ وَفِي سُوقِهِ خَمْسًا وَعِشْرِينَ ضِعْفًا وَذَلِكَ أَنَّهُ إِذَا تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ خَرَجَ إِلَى الْمَسْجِدِ لَا يُخْرِجُهُ إِلَّا الصَّلَاةُ لَمْ يَخْطُ خَطْوَةً إِلَّا رُفِعَتْ لَهُ بِهَا دَرَجَةٌ وَحُطَّ عَنْهُ بِهَا خَطِيئَةٌ فَإِذَا صَلَّى لَمْ تَزَلْ الْمَلَائِكَةُ تُصَلِّي عَلَيْهِ مَا دَامَ فِي مُصَلَّاهُ اللَّهُمَّ صَلِّ عَلَيْهِ اللَّهُمَّ ارْحَمْهُ وَلَا يَزَالُ أَحَدُكُمْ فِي صَلَاةٍ مَا انْتَظَرَ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Al A'masy] berkata, aku mendengar [Abu Shalih] berkata, Aku mendengar [Abu Hurairah] berkata: \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seorang laki-laki dengan berjama'ah dibanding shalatnya di rumah atau di pasarnya lebih utama (dilipat gandakan) pahalanya dengan dua puluh lima kali lipat. Yang demikian itu karena bila dia berwudlu dengan menyempurnakan wudlunya lalu keluar dari rumahnya menuju masjid, dia tidak keluar kecuali untuk melaksanakan shalat berjama'ah, maka tidak ada satu langkahpun dari langkahnya kecuali akan ditinggikan satu derajat, dan akan dihapuskan satu kesalahannya. Apabila dia melaksanakan shalat, maka Malaikat akan turun untuk mendo'akannya selama dia masih berada di tempat shalatnya, 'Ya Allah ampunilah dia. Ya Allah rahmatilah dia'. Dan seseorang dari kalian senantiasa dihitung dalam keadaan shalat selama dia menanti palaksanaan shalat.\""},"612":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَفْضُلُ صَلَاةُ الْجَمِيعِ صَلَاةَ أَحَدِكُمْ وَحْدَهُ بِخَمْسٍ وَعِشْرِينَ جُزْءًا وَتَجْتَمِعُ مَلَائِكَةُ اللَّيْلِ وَمَلَائِكَةُ النَّهَارِ فِي صَلَاةِ الْفَجْرِ ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ فَاقْرَءُوا إِنْ شِئْتُمْ{ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }قَالَ شُعَيْبٌ وَحَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ تَفْضُلُهَا بِسَبْعٍ وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat berjama'ah lebih utama dibanding shalatnya salah seorang dari kalian dengan sendirian dengan dua puluh lima bagian. Dan Malaikat malam dan Malaikat siang berkumpul pada shalat fajar.\" Abu Hurairah kemudian berkata, \"Jika mau silahkan baca: '(Sesungguhnya shalat fajar disaksikan (oleh para Malaikat) ' (Qs. Al Israa: 78). [Syu'aib] berkata; telah menceritakan kepadaku [Nafi'] dari ['Abdullah bin 'Umar] ia berkata, \"(Shalat berjama'ah) dilebihkan dengan dua puluh tujuh derajat.\""},"613":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ سَالِمًا قَالَ سَمِعْتُ أُمَّ الدَّرْدَاءِ تَقُولُ دَخَلَ عَلَيَّ أَبُو الدَّرْدَاءِوَهُوَ مُغْضَبٌ فَقُلْتُ مَا أَغْضَبَكَ فَقَالَ وَاللَّهِ مَا أَعْرِفُ مِنْ أُمَّةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا إِلَّا أَنَّهُمْ يُصَلُّونَ جَمِيعًا","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] berkata, aku mendengar [Salim] berkata, \"Aku mendengar [Ummu Darda'] berkata, \" [Abu Darda'] datang menemuiku dalam keadaan marah. Aku lalu bertanya kepadanya, 'Apa yang membuatmu marah? ' Maka dia menjawab, \"Demi Allah, tidak ada yang aku kenal dari umat Muhammad kecuali bahwa mereka selalu shalat berjama'ah.\""},"614":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْظَمُ النَّاسِ أَجْرًا فِي الصَّلَاةِ أَبْعَدُهُمْ فَأَبْعَدُهُمْ مَمْشًى وَالَّذِي يَنْتَظِرُ الصَّلَاةَ حَتَّى يُصَلِّيَهَا مَعَ الْإِمَامِ أَعْظَمُ أَجْرًا مِنْ الَّذِي يُصَلِّي ثُمَّ يَنَامُ","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala] berkata, telah menceritakan kepada kami [Abu Usmah] dari [Buraid bin 'Abdullah] dari [Abu Burdah] dari [Abu Musa] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang paling banyak mendapatkan pahala dalam shalat adalah mereka yang paling jauh (jarak rumahnya ke masjid), karena paling jauh dalam perjalanannya menuju masjid. Dan orang yang menunggu shalat hingga dia melaksanakan shalat bersama imam lebih besar pahalanya dari orang yang melaksanakan shalat kemudian tidur.\""},"615":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ يَمْشِي بِطَرِيقٍ وَجَدَ غُصْنَ شَوْكٍ عَلَى الطَّرِيقِ فَأَخَّرَهُ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُ ثُمَّ قَالَ الشُّهَدَاءُ خَمْسَةٌ الْمَطْعُونُ وَالْمَبْطُونُ وَالْغَرِيقُ وَصَاحِبُ الْهَدْمِ وَالشَّهِيدُ فِي سَبِيلِ اللَّهِ وَقَالَ لَوْ يَعْلَمُ النَّاسُ مَا فِي النِّدَاءِ وَالصَّفِّ الْأَوَّلِ ثُمَّ لَمْ يَجِدُوا إِلَّا أَنْ يَسْتَهِمُوا لَاسْتَهَمُوا عَلَيْهِ وَلَوْ يَعْلَمُونَ مَا فِي التَّهْجِيرِ لَاسْتَبَقُوا إِلَيْهِ وَلَوْ يَعْلَمُونَ مَا فِي الْعَتَمَةِ وَالصُّبْحِ لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Sumayya] mantan budak Abu Bakar bin 'Abdurrahman, dari [Abu Shalih As Saman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika seorang laki-laki berjalan pada suatu jalan dan menemukan dahan berduri lalu ia membuangnya maka Allah menyanjungnya dan mengampuni dosanya.\" Kemudian beliau bersabda: \"Orang yangmati syahid itu ada lima; orang yang mati karena penyakit kusta, orang yang mati karena sakit perut, orang yang mati kerena tenggelam, orang yang mati karena tertimpa reruntuhan dan orang yang terbunuh di jalan Allah.\" Beliau melanjutkan sabdanya: \"Seandainya manusia mengetahui apa (kebaikan) yang terdapat pada adzan dan shaf awal, lalu mereka tidak dapat meraihnya kecuali dengan cara mengundi tentulah mereka akan mengundi. Dan seandainya mereka mengetahui apa yang terdapat pada bersegera menuju shalat, tentulah mereka akan berlomba-lomba. Dan seandainya mereka mengetahui kebaikan yang terdapat pada shalat 'Atamah (shalat 'Isya') dan Shubuh, tentulah mereka akan mendatanginya walaupun harus dengan merangkak.\""},"616":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بَنِي سَلِمَةَ أَلَا تَحْتَسِبُونَ آثَارَكُمْوَقَالَ مُجَاهِدٌ فِي قَوْلِهِ{ وَنَكْتُبُ مَا قَدَّمُوا وَآثَارَهُمْ }قَالَ خُطَاهُمْ وَقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي حُمَيْدٌ حَدَّثَنِي أَنَسٌ أَنَّ بَنِي سَلِمَةَ أَرَادُوا أَنْ يَتَحَوَّلُوا عَنْ مَنَازِلِهِمْ فَيَنْزِلُوا قَرِيبًا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعْرُوا الْمَدِينَةَ فَقَالَ أَلَا تَحْتَسِبُونَ آثَارَكُمْ قَالَ مُجَاهِدٌ خُطَاهُمْ آثَارُهُمْ أَنْ يُمْشَى فِي الْأَرْضِ بِأَرْجُلِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Hawsyab] berkata, telah menceritakan kepada kami ['Abdul Wahhab] berkata, telah menceritakan kepada kami [Humaid] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Bani Salamah, tidakkah kalian mengharap pahala dari langkah-langkah kalian?\" Mujahid ketika menerangkan firman Allah: '(Dan Kami menuliskan apa yang mereka kerjakan dan bekas-bekas yang mereka tinggalkan) ' (Qs. Yasin: 12) mengatakan, \"Yakni langkah-langkah mereka.\" [Ibnu Abu Maryam] berkata; telah mengabarkan kepada kami [Yahya bin Ayyub] telah menceritakan kepadaku [Humaid] telah menceritakan kepadaku [Anas] ia berkata, \"Bani Salamah pernah berkeinginan untuk pindah dari tempat tinggal mereka dan mendekat dengan Nabi shallallahu 'alaihi wasallam. Namun Rasulullah shallallahu 'alaihi wasallam tidak memperkenankan mereka mengosongkan Madinah dengan bersabda: \"Tidakkah kalian mengharap pahala dari langkah-langkah kalian?\" Mujahid berkata, \"Langkah-langkah mereka adalah bekas-bekas perjalanan mereka di muka bumi ketika berjalan dengan kaki mereka.\""},"617":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ صَلَاةٌ أَثْقَلَ عَلَى الْمُنَافِقِينَ مِنْ الْفَجْرِ وَالْعِشَاءِ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا لَقَدْ هَمَمْتُ أَنْ آمُرَ الْمُؤَذِّنَ فَيُقِيمَ ثُمَّ آمُرَ رَجُلًا يَؤُمُّ النَّاسَ ثُمَّ آخُذَ شُعَلًا مِنْ نَارٍ فَأُحَرِّقَ عَلَى مَنْ لَا يَخْرُجُ إِلَى الصَّلَاةِ بَعْدُ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] berkata, telah telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepadaku [Abu Shalih] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat yang lebih berat bagi orang-orang Munafik kecuali shalat shubuh dan 'Isya. Seandainya mereka mengetahui (kebaikan) yang ada pada keduanya tentulah mereka akan mendatanginya walau harus dengan merangkak. Sungguh, aku berkeinginan untuk memerintahkan seorang mu'adzin sehingga shalat ditegakkan dan aki perintahkan seseorang untuk memimpin orang-orang shalat, lalu aku menyalakan api dan membakar (rumah-rumah) orang yang tidak keluar untuk shalat berjama'ah (tanpa alasan yang benar).\""},"618":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَضَرَتْ الصَّلَاةُ فَأَذِّنَا وَأَقِيمَا ثُمَّ لِيَؤُمَّكُمَا أَكْبَرُكُمَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza'] dari [Abu Qilabah] dari [Malik bin Al Huwairits] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika telah datang waktu shalat maka adzan dan iqamatlah, kemudian hendaklah yang mengimami shalat adalah yang paling tua di antara kalian berdua.\""},"619":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَلَائِكَةُ تُصَلِّي عَلَى أَحَدِكُمْ مَا دَامَ فِي مُصَلَّاهُ مَا لَمْ يُحْدِثْ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ لَا يَزَالُ أَحَدُكُمْ فِي صَلَاةٍ مَا دَامَتْ الصَّلَاةُ تَحْبِسُهُ لَا يَمْنَعُهُ أَنْ يَنْقَلِبَ إِلَى أَهْلِهِ إِلَّا الصَّلَاةُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para Malaikat berdo'a untuk salah seorang dari kalian selama dia masih pada posisi shalatnya dan belum berhadats, 'Ya Allah ampunilah dia. Ya Allah rahmatilah dia'. Dan seseorang dari kalian senantiasa dihitung dalam keadaan shalat selama dia menanti palaksanaan shalat. Dimana tidak ada yang menghalangi dia untuk kembali kepada keluarganya kecuali shalat itu.\""},"620":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ بُنْدَارٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعَةٌ يُظِلُّهُمْ اللَّهُ فِي ظِلِّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ الْإِمَامُ الْعَادِلُ وَشَابٌّ نَشَأَ فِي عِبَادَةِ رَبِّهِ وَرَجُلٌ قَلْبُهُ مُعَلَّقٌ فِي الْمَسَاجِدِ وَرَجُلَانِ تَحَابَّا فِي اللَّهِ اجْتَمَعَا عَلَيْهِ وَتَفَرَّقَا عَلَيْهِ وَرَجُلٌ طَلَبَتْهُ امْرَأَةٌ ذَاتُ مَنْصِبٍ وَجَمَالٍ فَقَالَ إِنِّي أَخَافُ اللَّهَ وَرَجُلٌ تَصَدَّقَ أَخْفَى حَتَّى لَا تَعْلَمَ شِمَالُهُ مَا تُنْفِقُ يَمِينُهُ وَرَجُلٌ ذَكَرَ اللَّهَ خَالِيًا فَفَاضَتْ عَيْنَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar Bundar] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepadaku [Khubaib bin 'Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ada tujuh golongan manusia yang akan mendapat naungan Allah pada hari yang tidak ada naungan kecuali naungan-Nya; pemimpin yang adil, seorang pemuda yang menyibukkan dirinya dengan 'ibadah kepada Rabbnya, seorang laki-laki yang hatinya terpaut dengan masjid, dua orang laki-laki yang saling mencintai karena Allah; mereka tidak bertemu kecuali karena Allah dan berpisah karena Allah, seorang laki-laki yang diajak berbuat maksiat oleh seorang wanita kaya lagi cantik lalu dia berkata, 'Aku takut kepada Allah', dan seorang yang bersedekah dengan menyembunyikannya hingga tangan kirinya tidak mengetahui apa yang diinfakkan oleh tangan kanannya, serta seorang laki-laki yang berdzikir kepada Allah dengan mengasingkan diri hingga kedua matanya basah karena menangis.\""},"621":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ قَالَ سُئِلَ أَنَسُ بْنُ مَالِكٍهَلْ اتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا فَقَالَ نَعَمْ أَخَّرَ لَيْلَةً صَلَاةَ الْعِشَاءِ إِلَى شَطْرِ اللَّيْلِ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ بَعْدَ مَا صَلَّى فَقَالَ صَلَّى النَّاسُ وَرَقَدُوا وَلَمْ تَزَالُوا فِي صَلَاةٍ مُنْذُ انْتَظَرْتُمُوهَا قَالَ فَكَأَنِّي أَنْظُرُ إِلَى وَبِيصِ خَاتَمِهِ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] berkata, \" [Anas bin Malik] ditanya, 'Apakah Rasulullah ada mengenakan cincin? ' Maka dia menjawab, \"Ya. Beliau pernah mengakhirkan shalat Isya hingga pertengahan malam, kemudian selesai shalat beliau menghadap ke arah kami seraya bersabda: \"Manusia sudah selesai shalat dan tidur, sementara kalian akan senantiasa dalam hitungan shalat kalian menunggu pelaksanaannya.\" Anas bin Malik berkata, \"Sungguh saat itu aku melihat kilau sinar cincin beliau.\""},"622":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ مُطَرِّفٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ غَدَا إِلَى الْمَسْجِدِ وَرَاحَ أَعَدَّ اللَّهُ لَهُ نُزُلَهُ مِنْ الْجَنَّةِ كُلَّمَا غَدَا أَوْ رَاحَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Muhammad bin Mutharrif] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa datang ke masjid di pagi dan sore hari, maka Allah akan menyediakan baginya tempat tinggal yang baik di surga setiap kali dia berangkat ke masjid di pagi dan sore hari.\""},"623":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ ابْنِ بُحَيْنَةَ قَالَ مَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ قَالَ ح و حَدَّثَنِي عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ بِشْرٍ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي سَعْدُ بْنُ إِبْرَاهِيمَ قَالَ سَمِعْتُ حَفْصَ بْنَ عَاصِمٍ قَالَسَمِعْتُ رَجُلًا مِنْ الْأَزْدِ يُقَالُ لَهُ مَالِكُ ابْنُ بُحَيْنَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا وَقَدْ أُقِيمَتْ الصَّلَاةُ يُصَلِّي رَكْعَتَيْنِ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَاثَ بِهِ النَّاسُ وَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ أَرْبَعًا الصُّبْحَ أَرْبَعًاتَابَعَهُ غُنْدَرٌ وَمُعَاذٌ عَنْ شُعْبَةَ فِي مَالِكٍ وَقَالَ ابْنُ إِسْحَاقَ عَنْ سَعْدٍ عَنْ حَفْصٍ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ وَقَالَ حَمَّادٌ أَخْبَرَنَا سَعْدٌ عَنْ حَفْصٍ عَنْ مَالِكٍ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Bapaknya] dari [Hafsh bin 'Ashim] dari ['Abdullah bin Malik Ibnu Buhainah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah melewati Rasulullah. (dalam jalur lain disebutkan) Telah menceritakan kepadaku ['Abdurrahman] -yakni Ibnu Bisyr- berkata, telah menceritakan kepada kami [Bahz bin Asad] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku [Sa'd bin Ibrahim] berkata, aku mendengar [Hafsh bin 'Ashim] berkata, aku mendengar seorang laki-laki dari Al Azdi yang dikenal dengan [Malik Ibnu Buhainah] berkata, bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihat seorang laki-laki shalat dua rakaat padahal iqamah telah dikumandangkan. Setelah selesai shalat, Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Apakah kamu shalat Shubuh empat rakaat? Apakah kamu shalat Shubuh empat rakaat?\" Hadits ini dikuatkan oleh [Ghundar] dan [Mu'adz] dari [Syu'bah] dalam riwayat [Malik]. Dan [Ibnu Ishaq] berkata dari [Sa'd] dari [Hafsh] dari ['Abdullah bin Buhainah]. Dan [Hammad] berkata, telah mengabarkan kepada kami [Sa'd] dari [Hafsh] dari [Malik].\""},"624":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ كُنَّا عِنْدَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَذَكَرْنَا الْمُوَاظَبَةَ عَلَى الصَّلَاةِ وَالتَّعْظِيمَ لَهَا قَالَتْلَمَّا مَرِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَضَهُ الَّذِي مَاتَ فِيهِ فَحَضَرَتْ الصَّلَاةُ فَأُذِّنَ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَقِيلَ لَهُ إِنَّ أَبَا بَكْرٍ رَجُلٌ أَسِيفٌ إِذَا قَامَ فِي مَقَامِكَ لَمْ يَسْتَطِعْ أَنْ يُصَلِّيَ بِالنَّاسِ وَأَعَادَ فَأَعَادُوا لَهُ فَأَعَادَ الثَّالِثَةَ فَقَالَ إِنَّكُنَّ صَوَاحِبُ يُوسُفَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَخَرَجَ أَبُو بَكْرٍ فَصَلَّى فَوَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَفْسِهِ خِفَّةً فَخَرَجَ يُهَادَى بَيْنَ رَجُلَيْنِ كَأَنِّي أَنْظُرُ رِجْلَيْهِ تَخُطَّانِ مِنْ الْوَجَعِ فَأَرَادَ أَبُو بَكْرٍ أَنْ يَتَأَخَّرَ فَأَوْمَأَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ مَكَانَكَ ثُمَّ أُتِيَ بِهِ حَتَّى جَلَسَ إِلَى جَنْبِهِ قِيلَ لِلْأَعْمَشِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَبُو بَكْرٍ يُصَلِّي بِصَلَاتِهِ وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ أَبِي بَكْرٍ فَقَالَ بِرَأْسِهِ نَعَمْرَوَاهُ أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ الْأَعْمَشِ بَعْضَهُ وَزَادَ أَبُو مُعَاوِيَةَ جَلَسَ عَنْ يَسَارِ أَبِي بَكْرٍ فَكَانَ أَبُو بَكْرٍ يُصَلِّي قَائِمًا","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] berkata, \"Kami pernah bersama ['Aisyah] ketika kami menceritakan tentang masalah menekuni shalat berjama'ah dan mengutamakannya. Maka Aisyah pun berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang sakit yang membawa pada ajalnya, waktu shalat tiba dan dikumandangkanlah adzan. Beliau lalu bersabda (kepada para isterinya): \"Suruhlah Abu Bakar untuk memimpin shalat bersama orang-orang.\" Lalu dikatakan kepada beliau, \"Sesungguhnya Abu Bakr adalah orang yang lemah dan mudah menangis (saat membaca Al Qur'an). Dia tidak akan mampu menggantikan posisi Tuan untuk memimpin orang-orang shalat.\" Beliau kembali mengulangi ucapannya, dan mereka juga memberi jawaban yang sama. Hal itu terus berulang hingga tiga kali, akhirnya beliau pun bersabda: \"Kalian ini seperti isteri-isteri Yusuf! Perintahkanlah Abu Bakr agar memimpin shalat.\" Maka keluarlah Abu Bakr memimpin shalat jama'ah. Beliau kemudian merasa agak segar badannya, sehingga beliau keluar ke masjid dengan diapit oleh dua orang, seolah aku kedua kaki beliau menyentuh tanah karena sakit. Melihat kehadiran beliau, Abu Bakar berniat untuk mundur namun Nabi shallallahu 'alaihi wasallam mencegahnya dengan isyarat agar ia tetap pada posisinya. Kemudian beliau di dudukkan di sisi Abu Bakar.\" Dikatakan kepada Al A'masy, \"Apakah beliau shalat kemudian Abu Bakar shalat mengikuti shalatnya beliau, dan orang-orang shalat dengan mengikuti shalatnya Abu Bakar?\" Lalu Al A'masy menjawab 'Ya' dengan anggukkan kepalanya.\" [Abu Daud] juga meriwayatkannya dari [Syu'bah] dari [Al A'masy] sebagiannya, dan [Abu Mu'awiyah] menambahkan, \"Beliau shalat dengan duduk di sebelah kiri Abu Bakar, sementara Abu Bakr shalat dengan berdiri.\""},"625":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ قَالَ قَالَتْ عَائِشَةُلَمَّا ثَقُلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاشْتَدَّ وَجَعُهُ اسْتَأْذَنَ أَزْوَاجَهُ أَنْ يُمَرَّضَ فِي بَيْتِي فَأَذِنَّ لَهُ فَخَرَجَ بَيْنَ رَجُلَيْنِ تَخُطُّ رِجْلَاهُ الْأَرْضَ وَكَانَ بَيْنَ الْعَبَّاسِ وَرَجُلٍ آخَرَقَالَ عُبَيْدُ اللَّهِ فَذَكَرْتُ ذَلِكَ لِابْنِ عَبَّاسٍ مَا قَالَتْ عَائِشَةُ فَقَالَ لِي وَهَلْ تَدْرِي مَنْ الرَّجُلُ الَّذِي لَمْ تُسَمِّ عَائِشَةُ قُلْتُ لَا قَالَ هُوَ عَلِيُّ بْنُ أَبِي طَالِبٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Ubaidullah bin 'Abdullah] berkata, ['Aisyah] berkata, \"Ketika sakit Nabi shallallahu 'alaihi wasallam semakin parah dan berat, beliau minta izin kepada para isterinya untuk dirawat di rumahku. Lalu beliau pun diizinkan. Beliau kemudian keluar dengan dipapah oleh dua orang laki-laki sementara keduan kakinya berjalan di tanah. Kedua laki-laki itu adalah 'Abbas dan seorang lagi.\" 'Ubaidullah berkata, \"Apa yang dikisahkan oleh Aisyah itu kemudian aku ceritakan kepada ['Abdullah bin 'Abbas], maka dia pun berkata kepadaku, \"Tahukah kamu, siapakah lelaki lain yang tidak disebutkan namanya oleh 'Aisyah itu? ' Aku jawab, \"Tidak.\" Ibnu Abbas berkata, \"Dia adalah 'Ali bin Abu Thalib.\""},"626":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَأَذَّنَ بِالصَّلَاةِ فِي لَيْلَةٍ ذَاتِ بَرْدٍ وَرِيحٍ ثُمَّ قَالَ أَلَا صَلُّوا فِي الرِّحَالِ ثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ الْمُؤَذِّنَ إِذَا كَانَتْ لَيْلَةٌ ذَاتُ بَرْدٍ وَمَطَرٍ يَقُولُ أَلَا صَلُّوا فِي الرِّحَالِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'], bahwa [Ibnu 'Umar] pernah mengumandangkan adzan pada suatu hari yang dingin dan berangin. Kemudian ia berkata, \"Shalatlah di tempat tinggal kalian.\" Ia melanjutkan perkataannya, \"Jika malam sangat dingin dan hujan Rasulullah shallallahu 'alaihi wasallam memerintahkan seorang mu'adzin untuk mengucapkan: \"Hendaklah kalian shalat di tempat tinggal kalian.\""},"627":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ الْأَنْصَارِيِّ أَنَّ عِتْبَانَ بْنَ مَالِكٍكَانَ يَؤُمُّ قَوْمَهُ وَهُوَ أَعْمَى وَأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ إِنَّهَا تَكُونُ الظُّلْمَةُ وَالسَّيْلُ وَأَنَا رَجُلٌ ضَرِيرُ الْبَصَرِ فَصَلِّ يَا رَسُولَ اللَّهِ فِي بَيْتِي مَكَانًا أَتَّخِذُهُ مُصَلَّى فَجَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ فَأَشَارَ إِلَى مَكَانٍ مِنْ الْبَيْتِ فَصَلَّى فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Mahmud bin Ar Rabi' Al Anshari] bahwa ['Itban bin Malik] selalu menjadi imam shalat bagi kaumnya. Dan pada suatu hari dia berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, sering terjadi malam yang gelap gulita dan jalanan becek sedangkan aku orang yang sudah lemah penglihatan. Untuk itu aku mohon shalatlah Tuan pada suatu tempat di rumahku yang akan aku jadikan tempat shalat. Maka Rasulullah shallallahu 'alaihi wasallam mendatanginya di rumahnya. Beliau lalu berkata: \"Mana tempat yang kau sukai untuk aku shalat padanya.\" Maka dia menunjuk suatu tempat di rumahnya, Rasulullah shallallahu 'alaihi wasallam kemudian shalat pada tempat tersebut.\""},"628":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ صَاحِبُ الزِّيَادِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الْحَارِثِ قَالَ خَطَبَنَا ابْنُ عَبَّاسٍفِي يَوْمٍ ذِي رَدْغٍ فَأَمَرَ الْمُؤَذِّنَ لَمَّا بَلَغَ حَيَّ عَلَى الصَّلَاةِ قَالَ قُلْ الصَّلَاةُ فِي الرِّحَالِ فَنَظَرَ بَعْضُهُمْ إِلَى بَعْضٍ فَكَأَنَّهُمْ أَنْكَرُوا فَقَالَ كَأَنَّكُمْ أَنْكَرْتُمْ هَذَا إِنَّ هَذَا فَعَلَهُ مَنْ هُوَ خَيْرٌ مِنِّي يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا عَزْمَةٌ وَإِنِّي كَرِهْتُ أَنْ أُحْرِجَكُمْوَعَنْ حَمَّادٍ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ ابْنِ عَبَّاسٍ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ كَرِهْتُ أَنْ أُؤَثِّمَكُمْ فَتَجِيئُونَ تَدُوسُونَ الطِّينَ إِلَى رُكَبِكُمْ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami ['Abdul Hamid] sahabatnya Az Zayadi, ia berkata, aku mendengar ['Abdullah bin Al Harits] berkata, \"Pada suatu hari ketika jalan penuh dengan air dan lumpur akibat hujan, [Ibnu 'Abbas] menyampaikan khuthbah kepada kami. Saat mu'adzin mengucapkan 'Hayya 'Alashshalaah' (Marilah mendirikan shalat) ia perintahkan kepadanya untuk mengucapkan: 'Shalatlah di tempat tinggal masing-masing'. Maka orang-orang pun saling memandang satu sama lain seakan mereka mengingkarinya. Maka Ibnu 'Abbas berkata, \"Seakan kalian mengingkari masalah ini. Sesungguhnya hal yang demikian ini pernah dilakukan oleh orang yang lebih baik dariku, yakni Nabi shallallahu 'alaihi wasallam. Dan sesungguhnya itu merupakan kewajiban ('azimah) dan aku enggan untuk mengungkapkannya kepada kalian.\" Dan dari [Hammad] dari ['Ashim] dari ['Abdullah bin Al Harits] dari [Ibnu 'Abbas] seperti itu. Hanya saja ia menambahkan bahwa Ibnu Abbas berkata, \"Aku tidak mau untuk membuat kalian berdosa, kalian mendatangi shalat sementara lutut kaki kalian penuh dengan lumpur.\""},"629":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ سَأَلْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ فَقَالَجَاءَتْ سَحَابَةٌ فَمَطَرَتْ حَتَّى سَالَ السَّقْفُ وَكَانَ مِنْ جَرِيدِ النَّخْلِ فَأُقِيمَتْ الصَّلَاةُ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ فِي الْمَاءِ وَالطِّينِ حَتَّى رَأَيْتُ أَثَرَ الطِّينِ فِي جَبْهَتِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] berkata, \"Aku bertanya kepada [Abu Sa'id Al Khudri] (tentang Lailatul Qadar).\" Ia lalu menjawab, \"Pada suatu hari ada banyak awan (mendung) lalu turun hujan lebat hingga atap Masjid menjadi bocor oleh air hujan. Waktu itu atap masih terbuat dari daun pohon kurma. Ketika shalat dilaksanakan, aku melihat Rasulullah shallallahu 'alaihi wasallam sujud di atas air dan lumpur hingga tampak sisa tanah becek pada dahi beliau.\""},"630":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَجُلٌ مِنْ الْأَنْصَارِ إِنِّي لَا أَسْتَطِيعُ الصَّلَاةَ مَعَكَ وَكَانَ رَجُلًا ضَخْمًا فَصَنَعَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فَدَعَاهُ إِلَى مَنْزِلِهِ فَبَسَطَ لَهُ حَصِيرًا وَنَضَحَ طَرَفَ الْحَصِيرِ فَصَلَّى عَلَيْهِ رَكْعَتَيْنِ فَقَالَ رَجُلٌ مِنْ آلِ الْجَارُودِ لِأَنَسِ بْنِ مَالِكٍ أَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى قَالَ مَا رَأَيْتُهُ صَلَّاهَا إِلَّا يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Anas bin Sirin] berkata, aku mendengar [Anas bin Malik] berkata, \"Seorang laki-laki Anshar berkata, \"Aku tidak dapat shalat bersama Tuan.\" Lelaki tersebut seorang yang besar badannya. Dia menyiapkan makanan untuk Nabi shallallahu 'alaihi wasallam, lalu dia mengundang beliau datang ke rumahnya, kemudian dia menghamparkan tikar dan memercikinya dengan air untuk beliau gunakan shalat. Setelah itu beliau shalat dua rakaat di atas tikar tersebut.\" Seorang lelaki dari keluarga Al Jarud berkata kepada Anas bin Malik, \"Apakah Nabi shallallahu 'alaihi wasallam tadi melaksanakan shalat Dluha?\" Anas bin Malik menjawab, \"Aku belum pernah melihat beliau mengerjakannya kecuali pada hari itu.\""},"631":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا وُضِعَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, telah menceritakan [bapakku] kepadaku, katanya: \"Aku mendengar ['Aisyah radliallahu 'anhu] berkata,, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila makan malam sudah dihidangkan sedangkan shalat jama'ah sudah dibacakan iqamatnya, maka dahulukanlah makan\"."},"632":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قُدِّمَ الْعَشَاءُ فَابْدَءُوا بِهِ قَبْلَ أَنْ تُصَلُّوا صَلَاةَ الْمَغْرِبِ وَلَا تَعْجَلُوا عَنْ عَشَائِكُمْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam: \"Apabila makan malam sudah dihidangkan, maka makanlah terlebih dahulu sebelum kalian melaksankan shalat Maghrib. Dan janganlah kalian tergesa-gesa dalam menyelesaikan makan kalian\"."},"633":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَ عَشَاءُ أَحَدِكُمْ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِ وَلَا يَعْجَلْ حَتَّى يَفْرُغَ مِنْهُوَكَانَ ابْنُ عُمَرَ يُوضَعُ لَهُ الطَّعَامُ وَتُقَامُ الصَّلَاةُ فَلَا يَأْتِيهَا حَتَّى يَفْرُغَ وَإِنَّهُ لَيَسْمَعُ قِرَاءَةَ الْإِمَامِ وَقَالَ زُهَيْرٌ وَوَهْبُ بْنُ عُثْمَانَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ أَحَدُكُمْ عَلَى الطَّعَامِ فَلَا يَعْجَلْ حَتَّى يَقْضِيَ حَاجَتَهُ مِنْهُ وَإِنْ أُقِيمَتْ الصَّلَاةُ رَوَاهُ إِبْرَاهِيمُ بْنُ الْمُنْذِرِ عَنْ وَهْبِ بْنِ عُثْمَانَ وَوَهْبٌ مَدِينِيٌّ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhu] berkata,; Telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"Apabila makan malam seseorang dari kalian sudah dihidangkan sedangkan shalat sudah didirikan, maka dahulukanlah makan malam dan janganlah tergesa-gesa hingga dia menuntaskannya\". Ibnu 'Umar juga pernah dihidangkan padanya suatu makanan sedangkan shalat sedang dilaksanakan, namun dia tidak mengikuti shalat tersebut hingga selesai, padahal saat itu dia juga mendengar bacaan imam. Berkata [Zuhair] dan [Wahab bin 'Utsman] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhu] berkata,; Telah bersabda Nabi shallallahu 'alaihi wasallam: \"Apabila seseorang dari kalian sedang makan janganlah dia tergesa-gesa hingga dia menyelesaikan kebutuhan (makan) nya sekalipun shalat jama'ah sedang dilaksanakan\". Diriwayatkan oleh [Ibrahim bin Al Mundzir] dari [Wahab bin 'Utsman], dan Wahab adalah penduduk Madinah."},"634":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَنَّ أَبَاهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ ذِرَاعًا يَحْتَزُّ مِنْهَا فَدُعِيَ إِلَى الصَّلَاةِ فَقَامَ فَطَرَحَ السِّكِّينَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada kami [Ibrahim] dari [Shalih] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Ja'far bin 'Amru bin Umayyah] bahwanya [bapaknya] telah berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam memakan daging paha lalu memotongnya. Kemudian beliau diserukan untuk shalat. Maka Beliau berdiri lalu meletakkan pisau kemudian shalat tanpa berwudlu' lagi\"."},"635":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ سَأَلْتُ عَائِشَةَمَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ فِي بَيْتِهِ قَالَتْ كَانَ يَكُونُ فِي مِهْنَةِ أَهْلِهِ تَعْنِي خِدْمَةَ أَهْلِهِ فَإِذَا حَضَرَتْ الصَّلَاةُ خَرَجَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] dari [Al Aswad] berkata, \"Aku pernah bertanya kepada ['Aisyah] tentang apa yang dikerjakan Nabi shallallahu 'alaihi wasallam ketika berada di rumah. Maka 'Aisyah pun menjawab, \"Beliau selalu membantu keluarganya, jika datang waktu shalat maka beliau keluar untuk melaksanakannya.\""},"636":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ قَالَ جَاءَنَا مَالِكُ بْنُ الْحُوَيْرِثِ فِي مَسْجِدِنَا هَذَا فَقَالَإِنِّي لَأُصَلِّي بِكُمْ وَمَا أُرِيدُ الصَّلَاةَ أُصَلِّي كَيْفَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَقُلْتُ لِأَبِي قِلَابَةَ كَيْفَ كَانَ يُصَلِّي قَالَ مِثْلَ شَيْخِنَا هَذَا قَالَ وَكَانَ شَيْخًا يَجْلِسُ إِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ قَبْلَ أَنْ يَنْهَضَ فِي الرَّكْعَةِ الْأُولَى","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] berkata, \" [Malik bin Al Huwairits] datang menemui kami di Masjid kami ini, ia lalu berkata, \"Aku akan melaksanakan shalat dengan kalian. Dan aku tidak ingin mengerjakan suatu shalat selain cara shalat yang pernah aku lihat Nabi shallallahu 'alaihi wasallam melaksanakannya.\" Aku pun bertanya kepada kepada Abu Qilabah, \"Bagaimanakah cara shalat Nabi shallallahu 'alaihi wasallam?\" Ia menjawab, \"Seperti guru kita ini. Setelah mengangkat kepalanya dari sujud, ia duduk sebentar sebelum bangkit di rakaat pertama.\""},"637":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ حَدَّثَنِي أَبُو بُرْدَةَ عَنْ أَبِي مُوسَى قَالَمَرِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاشْتَدَّ مَرَضُهُ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ قَالَتْ عَائِشَةُ إِنَّهُ رَجُلٌ رَقِيقٌ إِذَا قَامَ مَقَامَكَ لَمْ يَسْتَطِعْ أَنْ يُصَلِّيَ بِالنَّاسِ قَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَعَادَتْ فَقَالَ مُرِي أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَإِنَّكُنَّ صَوَاحِبُ يُوسُفَ فَأَتَاهُ الرَّسُولُ فَصَلَّى بِالنَّاسِ فِي حَيَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] berkata, telah menceritakan kepada kami [Husain] dari [Zai'dah] dari ['Abdul Malik bin 'Umair] berkata, telah menceritakan kepadaku [Abu Burdah] dari [Abu Musa] ia berkata, \"Ketika sakit Nabi shallallahu 'alaihi wasallam semakin parah, beliau berkata, \"Suruhlah Abu Bakar untuk memimpin shalat orang-orang.\" 'Aisyah berkata, \"Sesungguhnya Abu Bakar adalah seorang laki-laki yang lemah (hatinya; mudah menangis) jika harus menggantikan posisi Tuan, dia tidak akan mampu untuk memimpin shalat bersama orang-orang.\" Beliau berkata lagi: \"Suruhlah Abu Bakar untuk memimpin shalat orang-orang.\" 'Aisyah kembali mengulangi jawabannya. Maka beliau pun bersabda: \"Suruhlah Abu Bakar untuk memimpin shalat orang-orang. Kalian ini seperti isteri-isteri Yusuf!\" Rasulullah shallallahu 'alaihi wasallam kemudian mendatangi Abu Bakar dan shalat bersama manusia di akhir masa hidupnya.\""},"638":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي مَرَضِهِ مُرُوا أَبَا بَكْرٍ يُصَلِّي بِالنَّاسِ قَالَتْ عَائِشَةُ قُلْتُ إِنَّ أَبَا بَكْرٍ إِذَا قَامَ فِي مَقَامِكَ لَمْ يُسْمِعْ النَّاسَ مِنْ الْبُكَاءِ فَمُرْ عُمَرَ فَلْيُصَلِّ لِلنَّاسِ فَقَالَتْ عَائِشَةُ فَقُلْتُ لِحَفْصَةَ قُولِي لَهُ إِنَّ أَبَا بَكْرٍ إِذَا قَامَ فِي مَقَامِكَ لَمْ يُسْمِعْ النَّاسَ مِنْ الْبُكَاءِ فَمُرْ عُمَرَ فَلْيُصَلِّ لِلنَّاسِ فَفَعَلَتْ حَفْصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ إِنَّكُنَّ لَأَنْتُنَّ صَوَاحِبُ يُوسُفَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ لِلنَّاسِ فَقَالَتْ حَفْصَةُ لِعَائِشَةَ مَا كُنْتُ لِأُصِيبَ مِنْكِ خَيْرًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] Ummul Mikminin, bahwasanya ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata saat sakit menjelang kewafatannya: \"Suruhlah Abu Bakar untuk memimpin shalat orang-orang.\" 'Aisyah berkata, \"Aku lalu berkata, \"Jika Abu Bakar menggantikan posisi Tuan, maka suaranya tidak akan bisa didengar oleh orang-orang karena tangisnya. Sebaiknya suruhah Umar untuk memimpin shalat orang-orang.\" 'Aisyah berkata, \"Aku lalu sampaikan kepada Hafshah, \"Katakanlah kepada Beliau, 'Jika Abu Bakar menggantikan posisi Tuan, maka suaranya tidak akan dapat didengar oleh orang-orang karena tanagisannya, maka perintahlah Umar untuk memimpin shalat orang-orang'. Maka Hafshah pun melaksanakannya. Kemudian bersabdalah Rasulullah shallallahu 'alaihi wasallam: \"Celakalah kalian!. Sungguh kalian ini seperti isteri-isterinya Yusuf. Suruhlah Abu Bakar untuk memimpin shalat orang-orang.\" Hafshah kemudian berkata kepada 'Aisyah, \"Sungguh aku tidak mendapatkan kebaikan darimu.\""},"639":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ الْأَنْصَارِيُّ وَكَانَ تَبِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَدَمَهُ وَصَحِبَهُأَنَّ أَبَا بَكْرٍ كَانَ يُصَلِّي لَهُمْ فِي وَجَعِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي تُوُفِّيَ فِيهِ حَتَّى إِذَا كَانَ يَوْمُ الِاثْنَيْنِ وَهُمْ صُفُوفٌ فِي الصَّلَاةِ فَكَشَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتْرَ الْحُجْرَةِ يَنْظُرُ إِلَيْنَا وَهُوَ قَائِمٌ كَأَنَّ وَجْهَهُ وَرَقَةُ مُصْحَفٍ ثُمَّ تَبَسَّمَ يَضْحَكُ فَهَمَمْنَا أَنْ نَفْتَتِنَ مِنْ الْفَرَحِ بِرُؤْيَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَكَصَ أَبُو بَكْرٍ عَلَى عَقِبَيْهِ لِيَصِلَ الصَّفَّ وَظَنَّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَارِجٌ إِلَى الصَّلَاةِ فَأَشَارَ إِلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَتِمُّوا صَلَاتَكُمْ وَأَرْخَى السِّتْرَ فَتُوُفِّيَ مِنْ يَوْمِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Anas bin Malik Al Anshari] salah seorang dari sahabat yang pernah mengikuti, melayani dan mendampingi Rasulullah shallallahu 'alaihi wasallam. Bahwa Abu Bakar pernah mengimami mereka shalat di saat sakitnya Nabi shallallahu 'alaihi wasallam yang membawanya pada kewafatannya. Hingga pada suatu hari, pada hari Senin, saat orang-orang sudah berada pada barisan (shaf) shalat, Nabi shallallahu 'alaihi wasallam menyingkap tabir kamar dan memandang ke arah kami sambil berdiri, sementara wajah beliau pucat seperti kertas. Beliau tersenyum dan tertawa. Hampir saja kami terkena fitnah (keluar dari barisan) karena sangat gembiranya melihat Nabi shallallahu 'alaihi wasallam. Abu Bakar lalu berkeinginan untuk berbalik masuk ke dalam barisan shaf karena menduga Nabi shallallahu 'alaihi wasallam akan keluar untuk shalat. Namun Nabi shallallahu 'alaihi wasallam memberi isyarat kepada kami agar: \"Teruskanlah shalat kalian.\" Setelah itu beliau menutup tabir dan wafat pada hari itu juga.\""},"640":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمْ يَخْرُجْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا فَأُقِيمَتْ الصَّلَاةُ فَذَهَبَ أَبُو بَكْرٍ يَتَقَدَّمُ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحِجَابِ فَرَفَعَهُ فَلَمَّا وَضَحَ وَجْهُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نَظَرْنَا مَنْظَرًا كَانَ أَعْجَبَ إِلَيْنَا مِنْ وَجْهِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ وَضَحَ لَنَا فَأَوْمَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ إِلَى أَبِي بَكْرٍ أَنْ يَتَقَدَّمَ وَأَرْخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحِجَابَ فَلَمْ يُقْدَرْ عَلَيْهِ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami ['Abdul 'Aziz] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam telah tiga hari tidak keluar rumah untuk shalat. Dan selama itu shalat dilaksanakan dengan Abu Bakar maju sebagai imam memimpin shalat. Suatu hari Nabi Allah shallallahu 'alaihi wasallam menyingkap tabir kamar dan mengangkatnya. Tatkala tampak wajah Nabi shallallahu 'alaihi wasallam, sungguh belum pernah kami memandang wajah beliau yang lebih menakjubkan kami, selain wajahnya saat waktu itu menampakkan kepada kami. Lalu Nabi shallallahu 'alaihi wasallam memberi isyarat dengan tangannya kepada Abu Bakar lalu kembali menutup tabirnya dan masuk. Dan sejak saat itu kami tidak lagi melihat beliau hingga wafat.\""},"641":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ أَنَّهُ أَخْبَرَهُ عَنْ أَبِيهِ قَالَلَمَّا اشْتَدَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعُهُ قِيلَ لَهُ فِي الصَّلَاةِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ قَالَتْ عَائِشَةُ إِنَّ أَبَا بَكْرٍ رَجُلٌ رَقِيقٌ إِذَا قَرَأَ غَلَبَهُ الْبُكَاءُ قَالَ مُرُوهُ فَيُصَلِّي فَعَاوَدَتْهُ قَالَ مُرُوهُ فَيُصَلِّي إِنَّكُنَّ صَوَاحِبُ يُوسُفَتَابَعَهُ الزُّبَيْدِيُّ وَابْنُ أَخِي الزُّهْرِيِّ وَإِسْحَاقُ بْنُ يَحْيَى الْكَلْبِيُّ عَنْ الزُّهْرِيِّ وَقَالَ عُقَيْلٌ وَمَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حَمْزَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dari [Hamzah bin 'Abdullah] ia mengabarkan kepadanya dari [Bapaknya] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam semakin parah sakitnya, dan disampaikan kepadanya tentang shalat berjama'ah. Maka beliau berkata, \"Suruhlah Abu Bakar untuk memimpin shalat orang-orang.\" 'Aisyah berkata, \"Abu Bakar itu hatinya sangat lembut, jika membaca Al Qur'an maka ia akan menangis.\" Beliau berkata lagi: \"Suruhlah dia untuk memimpin shalat.\" Lalu 'Aisyah kembali mengulanggi jawabannya. Maka beliau pun bersabda: \"Suruhlah dia untuk memimpin shalat. Kalian ini seperti isteri-isteri Yusuf!\" Hadits ini dikuatkan oleh [Az Zubaidi], [Ibnu Akhi Az Zuhri] dan [Ishaq bin Yahya Al Kalbi] dari [Az Zuhri]. ['Uqail] dan [Ma'mar] menyebutkan dari [Az Zuhri] dari [Hamzah] dari Nabi shallallahu 'alaihi wasallam.\""},"642":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى قَالَ حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ أَنْ يُصَلِّيَ بِالنَّاسِ فِي مَرَضِهِ فَكَانَ يُصَلِّي بِهِمْ قَالَ عُرْوَةُ فَوَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفْسِهِ خِفَّةً فَخَرَجَ فَإِذَا أَبُو بَكْرٍ يَؤُمُّ النَّاسَ فَلَمَّا رَآهُ أَبُو بَكْرٍ اسْتَأْخَرَ فَأَشَارَ إِلَيْهِ أَنْ كَمَا أَنْتَ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِذَاءَ أَبِي بَكْرٍ إِلَى جَنْبِهِ فَكَانَ أَبُو بَكْرٍ يُصَلِّي بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ أَبِي بَكْرٍ","id":"Telah menceritakan kepada kami [Zakaria bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Numair] berkata, telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan Abu Bakar unruk memimpin shalat jama'ah bersama orang-orang saat beliau sakit. Maka Abu Bakar pun memimpin shalat mereka.\" 'Urwah berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam merasakan ringan pada tubuhnya, beliau pun keluar sementara Abu Bakar sedang mengimami orang-orang shalat. Ketika Abu Bakar melihat beliau datang, dia pun berkeinginan untuk mundur. Tetapi beliau memberi isyarat kepadanya (dengan katanya): \"Tetaplah kamu pada posisimu.\" Lalu Rasulullah shallallahu 'alaihi wasallam duduk di samping Abu Bakar, sehingga dia shalat mengikuti shalat Rasulullah shallallahu 'alaihi wasallam dan orang-orang mengikuti shalatnya Abu Bakar.\""},"643":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبَ إِلَى بَنِي عَمْرِو بْنِ عَوْفٍ لِيُصْلِحَ بَيْنَهُمْ فَحَانَتْ الصَّلَاةُ فَجَاءَ الْمُؤَذِّنُ إِلَى أَبِي بَكْرٍ فَقَالَ أَتُصَلِّي لِلنَّاسِ فَأُقِيمَ قَالَ نَعَمْ فَصَلَّى أَبُو بَكْرٍ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ فِي الصَّلَاةِ فَتَخَلَّصَ حَتَّى وَقَفَ فِي الصَّفِّ فَصَفَّقَ النَّاسُ وَكَانَ أَبُو بَكْرٍ لَا يَلْتَفِتُ فِي صَلَاتِهِ فَلَمَّا أَكْثَرَ النَّاسُ التَّصْفِيقَ الْتَفَتَ فَرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَشَارَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ امْكُثْ مَكَانَكَ فَرَفَعَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ يَدَيْهِ فَحَمِدَ اللَّهَ عَلَى مَا أَمَرَهُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ذَلِكَ ثُمَّ اسْتَأْخَرَ أَبُو بَكْرٍ حَتَّى اسْتَوَى فِي الصَّفِّ وَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَلَمَّا انْصَرَفَ قَالَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ أَنْ تَثْبُتَ إِذْ أَمَرْتُكَ فَقَالَ أَبُو بَكْرٍ مَا كَانَ لِابْنِ أَبِي قُحَافَةَ أَنْ يُصَلِّيَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لِي رَأَيْتُكُمْ أَكْثَرْتُمْ التَّصْفِيقَ مَنْ رَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيُسَبِّحْ فَإِنَّهُ إِذَا سَبَّحَ الْتُفِتَ إِلَيْهِ وَإِنَّمَا التَّصْفِيقُ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Hazim bin Dinar] dari [Sahal bin Sa'd As Sa'idi], bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam pergi menemui Bani 'Amru bin 'Auf untuk menyelesaikan masalah di antara mereka. Kemudian tiba waktu shalat, lalu ada seorang mu'adzin menemui Abu Bakar seraya berkata, \"Apakah engkau mau memimpin shalat berjama'ah sehingga aku bacakan iqamatnya?\" Abu Bakar menjawab, \"Ya.\" Maka Abu Bakar memimpin shalat. Tak lama kemudian datang Rasulullah shallallahu 'alaihi wasallam sedangkan orang-orang sedang melaksanakan shalat. Lalu beliau bergabung dan masuk ke dalam shaf. Orang-orang kemudian memberi isyarat dengan bertepuk tangan namun Abu Bakar tidak bereaksi dan tetap meneruskan shalatnya. Ketika suara tepukan semakin banyak, Abu Bakar berbalik dan ternyata dia melihat ada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam memberi isyarat yang maksudnya: 'Tetaplah kamu pada posisimu'. Abu Bakar mengangkat kedua tangannya lalu memuji Allah atas perintah Rasulullah shallallahu 'alaihi wasallam tersebut. Kemudian Abu Bakar mundur dan masuk dalam barisan shaf lalu Rasulullah shallallahu 'alaihi wasallam maju dan melanjutkan shalat. Setelah shalat selesai, beliau bersabda: \"Wahai Abu Bakar, apa yang menghalangimu ketika aku perintahkan agar kamu tetap pada posisimu?\" Abu Bakar menjawab, \"Tidaklah patut bagi anak Abu Qahafah untuk memimpin shalat di depan Rasulullah\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mengapa kalian tadi banyak bertepuk tangan?. Barangsiapa menjadi makmum lalu merasa ada kekeliruan dalam shalat, hendaklah dia membaca tasbih. Karena jika dibacakan tasbih, dia (imam) akan memperhatikannya. Sedangkan tepukan untuk wanita.\""},"644":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَقَدِمْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ فَلَبِثْنَا عِنْدَهُ نَحْوًا مِنْ عِشْرِينَ لَيْلَةً وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِيمًا فَقَالَ لَوْ رَجَعْتُمْ إِلَى بِلَادِكُمْ فَعَلَّمْتُمُوهُمْ مُرُوهُمْ فَلْيُصَلُّوا صَلَاةَ كَذَا فِي حِينِ كَذَا وَصَلَاةَ كَذَا فِي حِينِ كَذَا وَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Malik bin Al Huwairits] berkata, \"Kami pernah mendatangi Nabi shallallahu 'alaihi wasallam, saat itu kami adalah para pemuda dan kami tinggal bersama beliau selama dua puluh malam. Kami dapati Nabi shallallahu 'alaihi wasallam adalah orang yang sangat penyayang. Beliau bersabda kepada kami: \"Jika kalian kembali kepada ke negeri kalian, maka jarilah mereka, dan perintahkanlah mereka shalat ini pada waktu begini, shalat ini pada waktu begini. Dan apabila telah datang waktu shalat, maka hendaklah seseorang dari kalian adzan dan hendaklah yang mengimami shalat adalah yang paling tua di antara kalian.\""},"645":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ قَالَ سَمِعْتُ عِتْبَانَ بْنَ مَالِكٍ الْأَنْصارِيَّ قَالَاسْتَأْذَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذِنْتُ لَهُ فَقَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ مِنْ بَيْتِكَ فَأَشَرْتُ لَهُ إِلَى الْمَكَانِ الَّذِي أُحِبُّ فَقَامَ وَصَفَفْنَا خَلْفَهُ ثُمَّ سَلَّمَ وَسَلَّمْنَا","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Mahmud bin Ar Rabi'] berkata, \"Aku mendengar ['Itban bin Malik Al Anshari] berkata, \"Nabi shallallahu 'alaihi wasallam meminta izin masuk ke rumahku, lalu aku izinkan. Beliau kemudian bersabda: \"Mana tempat yang kau sukai dari rumahmu hingga aku bisa shalat di sana?\" Maka aku memberi isyarat kepada satu tempat yang aku sukai. Beliau lalu berdiri shalat dan kami berbaris mengikuti di belakang beliau, setelah salam beliau kamipun memberi salam.\""},"646":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ دَخَلْتُ عَلَى عَائِشَةَ فَقُلْتُأَلَا تُحَدِّثِينِي عَنْ مَرَضِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ بَلَى ثَقُلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَصَلَّى النَّاسُ قُلْنَا لَا هُمْ يَنْتَظِرُونَكَ قَالَ ضَعُوا لِي مَاءً فِي الْمِخْضَبِ قَالَتْ فَفَعَلْنَا فَاغْتَسَلَ فَذَهَبَ لِيَنُوءَ فَأُغْمِيَ عَلَيْهِ ثُمَّ أَفَاقَ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَلَّى النَّاسُ قُلْنَا لَا هُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ قَالَ ضَعُوا لِي مَاءً فِي الْمِخْضَبِ قَالَتْ فَقَعَدَ فَاغْتَسَلَ ثُمَّ ذَهَبَ لِيَنُوءَ فَأُغْمِيَ عَلَيْهِ ثُمَّ أَفَاقَ فَقَالَ أَصَلَّى النَّاسُ قُلْنَا لَا هُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ فَقَالَ ضَعُوا لِي مَاءً فِي الْمِخْضَبِ فَقَعَدَ فَاغْتَسَلَ ثُمَّ ذَهَبَ لِيَنُوءَ فَأُغْمِيَ عَلَيْهِ ثُمَّ أَفَاقَ فَقَالَ أَصَلَّى النَّاسُ فَقُلْنَا لَا هُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ وَالنَّاسُ عُكُوفٌ فِي الْمَسْجِدِ يَنْتَظِرُونَ النَّبِيَّ عَلَيْهِ السَّلَام لِصَلَاةِ الْعِشَاءِ الْآخِرَةِ فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَبِي بَكْرٍ بِأَنْ يُصَلِّيَ بِالنَّاسِ فَأَتَاهُ الرَّسُولُ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ أَنْ تُصَلِّيَ بِالنَّاسِ فَقَالَ أَبُو بَكْرٍ وَكَانَ رَجُلًا رَقِيقًا يَا عُمَرُ صَلِّ بِالنَّاسِ فَقَالَ لَهُ عُمَرُ أَنْتَ أَحَقُّ بِذَلِكَ فَصَلَّى أَبُو بَكْرٍ تِلْكَ الْأَيَّامَ ثُمَّ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ مِنْ نَفْسِهِ خِفَّةً فَخَرَجَ بَيْنَ رَجُلَيْنِ أَحَدُهُمَا الْعَبَّاسُ لِصَلَاةِ الظُّهْرِ وَأَبُو بَكْرٍ يُصَلِّي بِالنَّاسِ فَلَمَّا رَآهُ أَبُو بَكْرٍ ذَهَبَ لِيَتَأَخَّرَ فَأَوْمَأَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَنْ لَا يَتَأَخَّرَ قَالَ أَجْلِسَانِي إِلَى جَنْبِهِ فَأَجْلَسَاهُ إِلَى جَنْبِ أَبِي بَكْرٍ قَالَ فَجَعَلَ أَبُو بَكْرٍ يُصَلِّي وَهُوَ يَأْتَمُّ بِصَلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ بِصَلَاةِ أَبِي بَكْرٍ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌقَالَ عُبَيْدُ اللَّهِ فَدَخَلْتُ عَلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ فَقُلْتُ لَهُ أَلَا أَعْرِضُ عَلَيْكَ مَا حَدَّثَتْنِي عَائِشَةُ عَنْ مَرَضِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَاتِ فَعَرَضْتُ عَلَيْهِ حَدِيثَهَا فَمَا أَنْكَرَ مِنْهُ شَيْئًا غَيْرَ أَنَّهُ قَالَ أَسَمَّتْ لَكَ الرَّجُلَ الَّذِي كَانَ مَعَ الْعَبَّاسِ قُلْتُ لَا قَالَ هُوَ عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Za'idah] dari [Musa bin Abu Aisyah] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] berkata, \"Aku masuk menemui ['Aisyah] aku lalu berkata kepadanya, \"Maukah engkau menceritakan kepadaku tentang peristiwa yang pernah terjadi ketika Rasulullah shallallahu 'alaihi wasallam sedang sakit?\" 'Aisyah menjawab, \"Ya. Pernah suatu hari ketika sakit Nabi shallallahu 'alaihi wasallam semakin berat, beliau bertanya: \"Apakah orang-orang sudah shalat?\" Kami menjawab, \"Belum, mereka masih menunggu tuan.\" Beliau pun bersabda: \"Kalau begitu, bawakan aku air dalam bejana.\" Maka kamipun melaksanakan apa yang diminta beliau. Beliau lalu mandi, lalu berusaha berdiri dan berangkat, namun beliau jatuh pingsan. Ketika sudah sadarkan diri, beliau kembali bertanya: \"Apakah orang-orang sudah shalat?\" Kami menjawab, \"Belum wahai Rasulullah, mereka masih menunggu tuan.\" Kemudian beliau berkata lagi: \"Bawakan aku air dalam bejana.\" Beliau lalu duduk dan mandi. Kemudian beliau berusaha untuk berdiri dan berangkat, namun beliau jatuh pingsan lagi. Ketika sudah sadarkan diri kembali, beliau berkata: \"Apakah orang-orang sudah shalat?\" Kami menjawab lagi, \"Belum wahai Rasulullah, mereka masih menunggu tuan.\" Kemudian beliau berkata lagi: \"Bawakan aku air dalam bejana.\" Beliau lalu duduk dan mandi. Kemudian beliau berusaha untuk berdiri dan berangkat, namun beliau jatuh dan pingsan lagi. Ketika sudah sadarkan diri, beliau pun bersabda: \"Apakah orang-orang sudah shalat?\" Saat itu orang-orang sudah menunggu Nabi shallallahu 'alaihi wasallam di masjid untuk shalat 'Isya di waktu yang akhir. Lalu Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk menemui Abu Bakar dan memintanya untuk mengimami shalat. Maka utusan tersebut menemui Abu Bakar dan berkata, kepadanya, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah memerintahkan anda untuk mengimami shalat jama'ah!\" Lalu Abu Bakar -orang yang hatinya lembut- berkata, \"Wahai 'Umar, pimpinlah orang-orang melaksanakan shalat.\" Umar menjawab, \"Anda lebih berhak dalam masalah ini.\" Maka Abu Bakar memimpin shalat pada hari-hari sakitnya Nabi shallallahu 'alaihi wasallam tersebut. kemduian ketika Nabi shallallahu 'alaihi wasallam mendapati tubuhnya lebih segar, beliau pun keluar rumah sambil berjalan dipapah oleh dua orang laki-laki, satu diantaranya adalah 'Abbas untuk melaksanakan shalat Zhuhur. Ketika itu Abu Bakar sedang mengimami shalat, ketika ia melihat beliau datang, Abu Bakar berkehendak untuk mundur dari posisinya namun Nabi shallallahu 'alaihi wasallam memberi isyarat supaya dia tidak mundur. Kemudian beliau bersabda: \"Dudukkanlah aku disampingnya.\" Maka kami mendudukkan beliau di samping Abu Bakar.\" Perawi berkata, \"Maka jadilah Abu Bakar shalat dengan mengikuti shalatnya Nabi shallallahu 'alaihi wasallam sementara orang-orang mengikuti shalatnya Abu Bakar, dan saat itu Nabi shallallahu 'alaihi wasallam shalat sambil duduk\". 'Ubaidullah berkata, \"Aku menemui ' [Abdullah bin 'Abbas] dan berkata kepadanya, \"Maukan anda saya ceritakan sebuah hadits tentang sakitnya Rasulullah shallallahu 'alaihi wasallam seperti yang disampaikan 'Aisyah?\" Dia menjawab, \"Sampaikanlah!\" Maka aku ceritakan hadits yang disampaikan 'Aisyah. 'Abdullah bin 'Abbas tidak mengingkari sedikitpun apa yang aku ceritakan selain dia bertanya kepadaku, \"Apakah 'Aisyah menyebutkan nama laki-laki yang bersama 'Abbas? Aku menjawab, \"Tidak.\" Ia pun berkata, \"Dia adalah 'Ali bin Abu Thalib.\""},"647":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهَا قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ وَهُوَ شَاكٍ فَصَلَّى جَالِسًا وَصَلَّى وَرَاءَهُ قَوْمٌ قِيَامًا فَأَشَارَ إِلَيْهِمْ أَنْ اجْلِسُوا فَلَمَّا انْصَرَفَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] Ummul Mukminin, bahwa ia berkata, \"Saat sakit Rasulullah shallallahu 'alaihi wasallam pernah shalat di rumahnya sambil duduk. Dan segolongan kaum shalat di belakang beliau dengan berdiri. Maka beliau memberi isyarat kepada mereka agar duduk. Ketika shalat sudah selesai beliau bersabda: \"Sesungguhnya imam dijadikan untuk diikuti, apabila dia rukuk maka rukuklah kalian, bila dia mengangkat kepalanya maka angkatlah kepala kalian. Dan bila dia shalat dengan duduk, maka shalatlah kalian dengan duduk.\""},"648":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ فَرَسًا فَصُرِعَ عَنْهُ فَجُحِشَ شِقُّهُ الْأَيْمَنُ فَصَلَّى صَلَاةً مِنْ الصَّلَوَاتِ وَهُوَ قَاعِدٌ فَصَلَّيْنَا وَرَاءَهُ قُعُودًا فَلَمَّا انْصَرَفَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا صَلَّى قَائِمًا فَصَلُّوا قِيَامًا فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ وَإِذَا صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا أَجْمَعُونَقَالَ أَبُو عَبْد اللَّهِ قَالَ الْحُمَيْدِيُّ قَوْلُهُ إِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا هُوَ فِي مَرَضِهِ الْقَدِيمِ ثُمَّ صَلَّى بَعْدَ ذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا وَالنَّاسُ خَلْفَهُ قِيَامًا لَمْ يَأْمُرْهُمْ بِالْقُعُودِ وَإِنَّمَا يُؤْخَذُ بِالْآخِرِ فَالْآخِرِ مِنْ فِعْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pada suatu hari mengendarai kudanya lalu terjatuh dan terhempas pada bagian lambungnya yang kanan. Karena sebab itu beliau pernah melaksanakan shalat sambil duduk di antara shalat-shalatnya. Maka kamipun shalat di belakang Beliau dengan duduk. Ketika selesai Beliau bersabda: \"Sesungguhnya imam dijadikan untuk diikuti, jika ia shalat dengan berdiri maka shalatlah kalian dengan berdiri. Jika ia rukuk maka rukuklah kalian, jika ia mengangkat kepalanya maka angkatlah kepala kalian. Dan jika ia mengucapkan SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah merndengar orang yang memuji-Nya) ', maka ucapkanlah; RABBANAA WA LAKAL HAMDU (Ya Rabb kami, milik Engkaulah segala pujian) '. Dan jika ia shalat dengan berdiri maka shalatlah kalian dengan berdiri, dan jika ia shalat dengan duduk maka shalatlah kalian semuanya dengan duduk.\" Abu 'Abdullah berkata, Al Humaidi ketika menerangkan sabda Nabi shallallahu 'alaihi wasallam 'Dan bila dia shalat dengan duduk maka shalatlah kalian dengan duduk' dia berkata, \"Kejadian ini adalah saat sakitnya Nabi shallallahu 'alaihi wasallam di waktu yang lampau. Kemudian setelah itu Nabi shallallahu 'alaihi wasallam shalat dengan duduk sedangkan orang-orang shalat di belakangnya dengan berdiri, dan beliau tidak memerintahkan mereka agar duduk. Dan sesungguhnya yang dijadikan ketentuan adalah berdasarkan apa yang paling akhir dan terakhir dari perbuatan Nabi shallallahu 'alaihi wasallam.\""},"649":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو إِسْحَاقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنِي الْبَرَاءُ وَهُوَ غَيْرُ كَذُوبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ لَمْ يَحْنِ أَحَدٌ مِنَّا ظَهْرَهُ حَتَّى يَقَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدًا ثُمَّ نَقَعُ سُجُودًا بَعْدَهُحَدَّثَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَاقَ نَحْوَهُ بِهَذَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] berkata, telah menceritakan kepadaku [Abu Ishaq] berkata, telah menceritakan kepadaku ['Abdullah bin Yazid] berkata, telah menceritakan kapadaku [Al Bara'] -dan ia bukanlah pendusta- ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mengucapkan 'SAMI'ALLAHU LIMAN HAMIDAH', tidak ada seorangpun dari kami yang membungkukkan punggungnya sebelum Nabi shallallahu 'alaihi wasallam benar-benar (meletakkan kepalanya) bersimpuh dalam sujud, barulah setelah itu kami bersujud.\" Telah menceritakan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Abu Ishaq] dengan hadits yang seperti ini.\""},"650":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَا يَخْشَى أَحَدُكُمْ أَوْ لَا يَخْشَى أَحَدُكُمْ إِذَا رَفَعَ رَأْسَهُ قَبْلَ الْإِمَامِ أَنْ يَجْعَلَ اللَّهُ رَأْسَهُ رَأْسَ حِمَارٍ أَوْ يَجْعَلَ اللَّهُ صُورَتَهُ صُورَةَ حِمَارٍ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] berkata, telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad], \"Aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidakkah salah seornag dari kalian takut, atau apakah salah seorang dari kalian tidak takut, jika ia mengangkat kepalanya sebelum Imam, Allah akan menjadikan kepalanya seperti kepala keledai, atau Allah akan menjadikan rupanya seperti bentuk keledai?\""},"651":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَلَمَّا قَدِمَ الْمُهَاجِرُونَ الْأَوَّلُونَ الْعُصْبَةَ مَوْضِعٌ بِقُبَاءٍ قَبْلَ مَقْدَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَؤُمُّهُمْ سَالِمٌ مَوْلَى أَبِي حُذَيْفَةَ وَكَانَ أَكْثَرَهُمْ قُرْآنًا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidullah] dari [Nafi'] dari ['Abdullah bin 'Umar] berkata, \"Ketika robongan Muhajirin yang pertama sampai di 'Ushbah, suatu tempat di Quba', sebelum kedatangan Rasulullah shallallahu 'alaihi wasallam, yang mengimami shalat mereka adalah Salim mantan budak Abu Hudzaifah. Dia adalah seorang sahabat yang paling banyak bacaan (hafalan) Al Qur'annya di antara mereka.\""},"652":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي أَبُو التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمَعُوا وَأَطِيعُوا وَإِنْ اسْتُعْمِلَ حَبَشِيٌّ كَأَنَّ رَأْسَهُ زَبِيبَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Abu At Tayyah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dengar dan taatlah kalian, sekalipun yang memimpin kalian adalah seorang budak Habasyi yang berambut keriting seperti buah kismis.\""},"653":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ سَهْلٍ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى الْأَشْيَبُ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُصَلُّونَ لَكُمْ فَإِنْ أَصَابُوا فَلَكُمْ وَإِنْ أَخْطَئُوا فَلَكُمْ وَعَلَيْهِمْ","id":"Telah menceritakan kepada kami [Al Fadll bin Sahal] berkata, telah menceritakan kepada kami [Al Hasan bin Musa Al Asyyab] berkata, telah menceritakan kepada kami ['Abdurrahman bin 'Abdullah bin Dinar] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para imam shalat memimpin kalian. Maka jika dia benar, mereka mendapat pahala dan kalian juga mendapatkan bagian pahalanya. Namun bila dia salah kalian tetap mendapatkan pahala dan mereka mendapatkan dosa.\""},"654":{"ar":"قَالَ أَبُو عَبْد اللَّهِ وَقَالَ لَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ خِيَارٍ أَنَّهُ دَخَلَ عَلَى عُثْمَانَ بْنِ عَفَّانَ رَضِيَ اللَّهُ عَنْهُوَهُوَ مَحْصُورٌ فَقَالَ إِنَّكَ إِمَامُ عَامَّةٍ وَنَزَلَ بِكَ مَا نَرَى وَيُصَلِّي لَنَا إِمَامُ فِتْنَةٍ وَنَتَحَرَّجُ فَقَالَ الصَّلَاةُ أَحْسَنُ مَا يَعْمَلُ النَّاسُ فَإِذَا أَحْسَنَ النَّاسُ فَأَحْسِنْ مَعَهُمْ وَإِذَا أَسَاءُوا فَاجْتَنِبْ إِسَاءَتَهُمْوَقَالَ الزُّبَيْدِيُّ قَالَ الزُّهْرِيُّ لَا نَرَى أَنْ يُصَلَّى خَلْفَ الْمُخَنَّثِ إِلَّا مِنْ ضَرُورَةٍ لَا بُدَّ مِنْهَا","id":"Abu Abdullah berkata; [Muhammad bin Yusuf] berkata kepada kami, telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari ['Ubaidullah bin 'Adi bin Khiyar], bahwa dia masuk menemui ['Utsman bin 'Affan] saat ia terkepung seraya berkata, \"Engkau adalah pemimpin Kaum Muslimin namun tuan tengah mengalami kejadian seperti yang kita saksikan. Sedangkan shalat akan dipimpin oleh imam yang terkena fitnah dan kami jadi khawatir terkena dosa.\" Maka 'Utsman bin 'Affan pun berkata, \"Shalat adalah amal terbaik yang dilakukan manusia. Oleh karena itu apabila orang-orang melakukan kebaikan (dengan mendirikan shalat), maka berbuat baiklah (shalat) bersama mereka. Dan jika mereka berbuat keburukan (kesalahan), maka jauhilah keburukan mereka.\" Az Zubaidi berkata, Az Zuhri berkata, \"Kami tidak membenarkan shalat bermakmum di belakang seorang banci kecuali dalam keadaan sangat terpaksa.\""},"655":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي ذَرٍّ اسْمَعْ وَأَطِعْ وَلَوْ لِحَبَشِيٍّ كَأَنَّ رَأْسَهُ زَبِيبَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Aban] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Abu At Tayyah] bahwa dia mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam pernah berkata kepada Abu Dzar: \"Dengar dan taatlah sekalipun terhadap seorang budak Habasyi yang berambut keriting seperti buah anggur kering.\""},"656":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ فِي بَيْتِ خَالَتِي مَيْمُونَةَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ ثُمَّ جَاءَ فَصَلَّى أَرْبَعَ رَكَعَاتٍ ثُمَّ نَامَ ثُمَّ قَامَ فَجِئْتُ فَقُمْتُ عَنْ يَسَارِهِ فَجَعَلَنِي عَنْ يَمِينِهِ فَصَلَّى خَمْسَ رَكَعَاتٍ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ نَامَ حَتَّى سَمِعْتُ غَطِيطَهُ أَوْ قَالَ خَطِيطَهُ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepadaku [Syu'bah] dari [Al Hakam] berkata, \"Aku mendengar [Sa'id bin Jubair] dari [Ibnu 'Abbas] berkata, \"Aku pernah menginap di rumah bibiku, Maimunah. Rasulullah shallallahu 'alaihi wasallam pergi shalat 'Isya kemudian kembali ke rumah dan shalat sunnat empat rakaat, kemudian beliau tidur. Saat tengah malam beliau bangun dan shalat malam, aku lalu datang untuk ikut shalat bersama beliau dan berdiri di samping kiri beliau. Kemudian beliau menggeserku ke sebelah kanannya, lalu beliau shalat lima rakaat, kemudian dua rakaat, kemudian tidur hingga aku mendengar suara dengkur Beliau. Setelahitu beliau Kemudian Beliau keluar untuk shalat (shubuh).\""},"657":{"ar":"حَدَّثَنَا أَحْمَدُ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنَا عَمْرٌو عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَنِمْتُ عِنْدَ مَيْمُونَةَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا تِلْكَ اللَّيْلَةَ فَتَوَضَّأَ ثُمَّ قَامَ يُصَلِّي فَقُمْتُ عَلَى يَسَارِهِ فَأَخَذَنِي فَجَعَلَنِي عَنْ يَمِينِهِ فَصَلَّى ثَلَاثَ عَشْرَةَ رَكْعَةً ثُمَّ نَامَ حَتَّى نَفَخَ وَكَانَ إِذَا نَامَ نَفَخَ ثُمَّ أَتَاهُ الْمُؤَذِّنُ فَخَرَجَ فَصَلَّى وَلَمْ يَتَوَضَّأْقَالَ عَمْرٌو فَحَدَّثْتُ بِهِ بُكَيْرًا فَقَالَ حَدَّثَنِي كُرَيْبٌ بِذَلِكَ","id":"Telah menceritakan kepada kami [Ahmad] berkata, telah menceritakan kepadaku [Ibnu Wahb] berkata, telah menceritakan kepada kami ['Amru] dari ['Abdu Rabbih bin Sa'id] dari [Makhramah bin Sulaiman] dari [Kuraib] mantan budak Ibnu 'Abbas, dari [Ibnu 'Abbas] ia berkata, \"Suatu malam aku pernah tidur di sisi Maimunah, sementara Nabi shallallahu 'alaihi wasallam tidur di sebelahnya pada malam itu. Rasulullah shallallahu 'alaihi wasallam kemudian berwudlu lalu berdiri menunaikan shalat. Maka aku datang dan berdiri shalat di samping kiri beliau. Namun beliau memegangku dan menggeserku ke sebelah kanannya. Setelah itu beliau shalat tiga belas rakaat, kemudian tidur hingga terdengar nafasnya. Dan memang beliau apabila tidur (terdengar suara) nafas beliau. Kemudian seorang mu'adzin datang kepada beliau, maka beliau pun keluar untuk menunaikan shalat (Shubuh) tanpa berwudlu lagi.\" 'Amru berkata, \"Aku ceritakan riwayat ini kepada [Bukair], lalu ia berkata, \"Kuraib juga telah menceritakan kepadaku seperti itu.\""},"658":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ عِنْدَ خَالَتِي فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فَقُمْتُ أُصَلِّي مَعَهُ فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَ بِرَأْسِي فَأَقَامَنِي عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepadaku [Isma'il bin Ibrahim] dari [Ayyub] dari ['Abdullah bin Sa'id bin Jubair] dari [Bapaknya] dari [Ibnu 'Abbas] ia berkata, \"Aku pernah menginap di rumah bibiku. Kemudian Rasulullah shallallahu 'alaihi wasallam shalat malam. Maka aku datang untuk ikut shalat bersama beliau, aku berdiri di samping kirinya, lalu beliau memegang kepalaku dan menggeserku ke sebelah kanannya.\""},"659":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ مُعَاذَ بْنَ جَبَلٍ كَانَ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَرْجِعُ فَيَؤُمُّ قَوْمَهُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru] dari [Jabir bin 'Abdullah], bahwa Mu'adz bin Jabal pernah shalat bersama Nabi shallallahu 'alaihi wasallam, kemudian dia kembali pulang dan mengimami shalat kaumnya.\""},"660":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَكَانَ مُعَاذُ بْنُ جَبَلٍ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَرْجِعُ فَيَؤُمُّ قَوْمَهُ فَصَلَّى الْعِشَاءَ فَقَرَأَ بِالْبَقَرَةِ فَانْصَرَفَ الرَّجُلُ فَكَأَنَّ مُعَاذًا تَنَاوَلَ مِنْهُ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ فَتَّانٌ فَتَّانٌ فَتَّانٌ ثَلَاثَ مِرَارٍ أَوْ قَالَ فَاتِنًا فَاتِنًا فَاتِنًا وَأَمَرَهُ بِسُورَتَيْنِ مِنْ أَوْسَطِ الْمُفَصَّلِقَالَ عَمْرٌو لَا أَحْفَظُهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru] berkata, Aku mendengar [Jabir bin 'Abdullah] berkata, \"Mu'adz bin Jabal pernah shalat bersama Nabi shallallahu 'alaihi wasallam, dia lalu kembali pulang dan mengimami kaumnya shalat 'Isya dengan membaca surah Al Baqarah. Kemudian ada seorang laki-laki keluar dan pergi, Mu'adz seakan menyebut orang tersebut dengan keburukan. Kejadian ini kemudian sampai kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Apa engkau akan membuat fitnah? Apa engkau akan membuat fitnah? Apa engkau akan membuat membuat fitnah?\" Beliau ucapkanhingga tiga kali. Atau kata beliau: \"Apakah kamu menjadi pembuat fitnah? Apakah kamu menjadi pembuat fitnah? Apakah kamu menjadi pembuat fitnah?\" Lalu beliau memerintahkannya (Mu'adz) untuk membaca dua surah saja dari pertengahan Al Mufashshal.\" Amru berkata, 'Namun aku tidak hafal kedua surat tersebut.\" "},"661":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ سَمِعْتُ قَيْسًا قَالَ أَخْبَرَنِي أَبُو مَسْعُودٍأَنَّ رَجُلًا قَالَ وَاللَّهِ يَا رَسُولَ اللَّهِ إِنِّي لَأَتَأَخَّرُ عَنْ صَلَاةِ الْغَدَاةِ مِنْ أَجْلِ فُلَانٍ مِمَّا يُطِيلُ بِنَا فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَوْعِظَةٍ أَشَدَّ غَضَبًا مِنْهُ يَوْمَئِذٍ ثُمَّ قَالَ إِنَّ مِنْكُمْ مُنَفِّرِينَ فَأَيُّكُمْ مَا صَلَّى بِالنَّاسِ فَلْيَتَجَوَّزْ فَإِنَّ فِيهِمْ الضَّعِيفَ وَالْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Isma'il] berkata, \"Aku mendengar [Qais] berkata, telah mengabarkan kepada ku [Abu Mas'ud] bahwa ada seseorang berkata, \"Wahai Rasulullah, demi Allah! Aku mengakhirkan shalat shubuh berjama'ah karena fulan yang memanjangkan bacaan dalam shalat bersama kami.\" Maka aku belum pernah melihat Rasulullah shallallahu 'alaihi wasallam marah dalam memberi pelajaran melebihi marahnya pada hari itu. Beliau kemudian bersabda: \"Sungguh di antara kalian ada orang yang dapat menyebabkan orang lain berlari memisahkan diri. Maka bila seseorang dari kalian memimpin shalat bersama orang banyak hendaklah dia melaksanakannya dengan ringan. Karena di antara mereka ada orang yang lemah, lanjut usia dan orang yang punya keperluan.\""},"662":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ لِلنَّاسِ فَلْيُخَفِّفْ فَإِنَّ مِنْهُمْ الضَّعِيفَ وَالسَّقِيمَ وَالْكَبِيرَ وَإِذَا صَلَّى أَحَدُكُمْ لِنَفْسِهِ فَلْيُطَوِّلْ مَا شَاءَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seseorang dari kalian memimpin shalat orang banyak, hendaklah dia meringankannya. Karena di antara mereka ada orang yang lemah, orang yang sakit dan orang berusia lanjut. Namun bila dia shalat sendiri silahkan dia panjangkan sesukanya.\""},"663":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنِّي لَأَتَأَخَّرُ عَنْ الصَّلَاةِ فِي الْفَجْرِ مِمَّا يُطِيلُ بِنَا فُلَانٌ فِيهَا فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُهُ غَضِبَ فِي مَوْضِعٍ كَانَ أَشَدَّ غَضَبًا مِنْهُ يَوْمَئِذٍ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّ مِنْكُمْ مُنَفِّرِينَ فَمَنْ أَمَّ النَّاسَ فَلْيَتَجَوَّزْ فَإِنَّ خَلْفَهُ الضَّعِيفَ وَالْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Mas'ud] berkata, \"Seorang laki-laki berkata, \"Wahai Rasulullah, sungguh aku tidak ikut shalat shubuh berjama'ah disebabkan fulan yang memanjangkan bacaan saar shalat bersama kami.\" Maka Rasulullah shallallahu 'alaihi wasallam marah, dan aku belum pernah melihat beliau marah sebelumnya melebihi marahnya pada hari itu. Kemudian Beliau bersabda: \"Wahai sekalian manusia, sungguh di antara kalian ada orang yang dapat menyebabkan orang lain berlari memisahkan diri. Maka barangsiapa memimpin shalat bersama orang banyak hendaklah dia melaksanakannya dengan ringan. Karena di belakang dia ada orang yang lemah, orang tua yang lanjut usia dan orang yang punya keperluan.\""},"664":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا مُحَارِبُ بْنُ دِثَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ قَالَأَقْبَلَ رَجُلٌ بِنَاضِحَيْنِ وَقَدْ جَنَحَ اللَّيْلُ فَوَافَقَ مُعَاذًا يُصَلِّي فَتَرَكَ نَاضِحَهُ وَأَقْبَلَ إِلَى مُعَاذٍ فَقَرَأَ بِسُورَةِ الْبَقَرَةِ أَوْ النِّسَاءِ فَانْطَلَقَ الرَّجُلُ وَبَلَغَهُ أَنَّ مُعَاذًا نَالَ مِنْهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَا إِلَيْهِ مُعَاذًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ أَوْ أَفَاتِنٌ ثَلَاثَ مِرَارٍ فَلَوْلَا صَلَّيْتَ بِسَبِّحِ اسْمَ رَبِّكَ وَالشَّمْسِ وَضُحَاهَا وَاللَّيْلِ إِذَا يَغْشَى فَإِنَّهُ يُصَلِّي وَرَاءَكَ الْكَبِيرُ وَالضَّعِيفُ وَذُو الْحَاجَةِأَحْسِبُ هَذَا فِي الْحَدِيثِ قَالَ أَبُو عَبْد اللَّهِ وَتَابَعَهُ سَعِيدُ بْنُ مَسْرُوقٍ وَمِسْعَرٌ وَالشَّيْبَانِيُّ قَالَ عَمْرٌو وَعُبَيْدُ اللَّهِ بْنُ مِقْسَمٍ وَأَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَرَأَ مُعَاذٌ فِي الْعِشَاءِ بِالْبَقَرَةِ وَتَابَعَهُ الْأَعْمَشُ عَنْ مُحَارِبٍ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Muharib bin Ditsar] berkata, Aku mendengar [Jabir bin 'Abdullah Al Anshari] berkata, \"Seoranglaki-laki datang dengan membawa dua unta yang baru saja diberinya minum saat malam sudah gelap gulita. Laki-laki itu kemudian tinggalkan untanya dan ikut shalat bersama Mu'adz. Dalam shalatnya Mu'adz membaca surah Al Baqarah atau surah An Nisaa' sehingga laki-laki tersebut meninggalkan Mu'adz. Maka sampailah kepadanya berita bahwa Mu'adz mengecam tindakannya. Akhirnya laki-laki tersebut mendatangi Nabi shallallahu 'alaihi wasallam dan mengadukan persoalannya kepada beliau. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Mu'adz, apakah kamu membuat fitnah?\" Atau kata Beliau: \"Apakah kamu menjadi pembuat fitnah? -Beliau ulangi perkataannya tersebut hingga tiga kali- \"Mengapa kamu tidak membaca saja surat 'Sabbihisma rabbika', atau dengan 'Wasysyamsi wa dluhaahaa' atau 'Wallaili idzaa yaghsyaa'? Karena yang ikut shalat di belakangmu mungkin ada orang yang lanjut usia, orang yang lemah atau orang yang punya keperluan.\" Perawi berkata, \"Menurutku sampai inilah kalimat hadits ini.\" Abu 'Abdullah berkata; hadits ini dikuatkan oleh [Sa'id bin Masruq] dan [Mis'ar] dan [Asy Syaibani]. [Amru] dan [Ubaidullah bin Miqsam] dan [Abu Az Zubair] dari [Jabir] bahwa dalam shalat Isya Mu'adz membaca surat Al Baqarah. Dan hadits ini dikuatkan oleh [Al A'masy] dari [Muharib].\""},"665":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوجِزُ الصَّلَاةَ وَيُكْمِلُهَا","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami [Abdul Warits] berkata, telah menceritakan kepada kami ['Abdul 'Aziz] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam shalat dengan pendek dan sempurna.\" "},"666":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَبِي قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي لَأَقُومُ فِي الصَّلَاةِ أُرِيدُ أَنْ أُطَوِّلَ فِيهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ فِي صَلَاتِي كَرَاهِيَةَ أَنْ أَشُقَّ عَلَى أُمِّهِتَابَعَهُ بِشْرُ بْنُ بَكْرٍ وَابْنُ الْمُبَارَكِ وَبَقِيَّةُ عَنْ الْأَوْزَاعِيِّ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari bapaknya [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku pernah ingin memanjangkan shalat, namun aku mendengar tangisan bayi. Maka aku pendekkan shalatku karena khawatir akan memberatkan ibunya.\" Hadits ini dikuatkan oleh [Bisyr bin Bakar] dan [Ibnu Al Mubarak] dan [Baqiyyah] dari [Al Auza'i]."},"667":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُمَا صَلَّيْتُ وَرَاءَ إِمَامٍ قَطُّ أَخَفَّ صَلَاةً وَلَا أَتَمَّ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ كَانَ لَيَسْمَعُ بُكَاءَ الصَّبِيِّ فَيُخَفِّفُ مَخَافَةَ أَنْ تُفْتَنَ أُمُّهُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] berkata, telah menceritakan kepada kami [Syarik bin 'Abdullah] berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Belum pernah aku shalat di belakang seorang Imam pun yang lebih ringan dan lebih sempurna shalatnya daripada Nabi shallallahu 'alaihi wasallam. Jika mendengar tangisan bayi, maka beliau ringankan shalatnya karena khawatir ibunya akan terkena fitnah.\""},"668":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي لَأَدْخُلُ فِي الصَّلَاةِ وَأَنَا أُرِيدُ إِطَالَتَهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ فِي صَلَاتِي مِمَّا أَعْلَمُ مِنْ شِدَّةِ وَجْدِ أُمِّهِ مِنْ بُكَائِهِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Sa'id] berkata, telah menceritakan kepada kami [Qatadah] bahwa [Anas bin Malik] menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Saat aku shalat dan ingin memanjangkan bacaanku, tiba-tiba aku mendengar tangian bayi sehingga aku pun memendekkan shalatku, sebab aku tahu ibunya akan susah dengan adanya tangisan tersebut.\""},"669":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي لَأَدْخُلُ فِي الصَّلَاةِ فَأُرِيدُ إِطَالَتَهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ مِمَّا أَعْلَمُ مِنْ شِدَّةِ وَجْدِ أُمِّهِ مِنْ بُكَائِهِوَقَالَ مُوسَى حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Sa'id] dari [Qatadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Saat aku shalat dan ingin memanjangkan bacaanku, tiba-tiba aku mendengar tangian bayi sehingga aku pun memendekkan shalatku, sebab aku tahu ibunya akan susah dengan adanya tangisan tersebut.\" [Musa] berkata, telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam seperti ini juga.\""},"670":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَأَبُو النُّعْمَانِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ مُعَاذٌ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَأْتِي قَوْمَهُ فَيُصَلِّي بِهِمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Abu An Nu'man] keduanya berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari ['Amru bin Dinar] dari [Jabir bin 'Abdullah] berkata, \"Mu'adz bin Jabal pernah shalat bersama Nabi shallallahu 'alaihi wasallam, kemudian dia pulang menemui kaumnya dan shalat mengimami mereka.\""},"671":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا مَرِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَضَهُ الَّذِي مَاتَ فِيهِ أَتَاهُ بِلَالٌ يُوذِنُهُ بِالصَّلَاةِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ قُلْتُ إِنَّ أَبَا بَكْرٍ رَجُلٌ أَسِيفٌ إِنْ يَقُمْ مَقَامَكَ يَبْكِي فَلَا يَقْدِرُ عَلَى الْقِرَاءَةِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ فَقُلْتُ مِثْلَهُ فَقَالَ فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ إِنَّكُنَّ صَوَاحِبُ يُوسُفَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ فَصَلَّى وَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهَادَى بَيْنَ رَجُلَيْنِ كَأَنِّي أَنْظُرُ إِلَيْهِ يَخُطُّ بِرِجْلَيْهِ الْأَرْضَ فَلَمَّا رَآهُ أَبُو بَكْرٍ ذَهَبَ يَتَأَخَّرُ فَأَشَارَ إِلَيْهِ أَنْ صَلِّ فَتَأَخَّرَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ وَقَعَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى جَنْبِهِ وَأَبُو بَكْرٍ يُسْمِعُ النَّاسَ التَّكْبِيرَتَابَعَهُ مُحَاضِرٌ عَنْ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdullah bin Daud] berkata, telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam dalam kondisi sakit yang membawa kepada kematiannya, Bilal datang menemui beliau mengabarkan bahwa waktu shalat telah datang. Beliau lalu berkata: \"Kalian suruhlah Abu Bakar untuk memimpin shalat.\" Aku berkata, \"Sesungguhnya Abu Bakar orang yang lemah lembut, jika ia menggantikan posisi tuan, maka dia akan menangis dan tidak akan bisa membaca Al Qur'an.\" Beliau berkata lagi: \"Kalian suruhlah Abu Bakar untuk memimpin shalat.\" Aku lalu menyampaikan jawaban yang sama. Maka pada ketiga atau keempat kalinya beliau bersabda: \"Sungguh kalian ini seperti isteri-isterinya Yusuf. Suruhlah Abu Bakar untuk memimpin shalat.\" Akhirnya Abu Bakar pun shalat (sebagai Imam). Kemudian Nabi shallallahu 'alaihi wasallam keluar dengan diapit oleh dua orang laki-laki dan seolah aku melihat beliau berjalan dengan menyeret kakinya di atas tanah. Ketika Abu Bakar melihat kedatangan beliau, dia pun berniat mundur. Tetapi beliau memberi isyarat kepadanya seolah berkata: \"Tetaplah shalat.\" Abu Bakar kemudian bergeser dan Nabi shallallahu 'alaihi wasallam duduk disampingnya, lalu Abu Bakar memperdengarkan suara takbir kepada jama'ah.\" Hadits ini juga diperkuat oleh [Muhadlir] dari [Al A'masy]."},"672":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْلَمَّا ثَقُلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ بِلَالٌ يُوذِنُهُ بِالصَّلَاةِ فَقَالَ مُرُوا أَبَا بَكْرٍ أَنْ يُصَلِّيَ بِالنَّاسِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا بَكْرٍ رَجُلٌ أَسِيفٌ وَإِنَّهُ مَتَى مَا يَقُمْ مَقَامَكَ لَا يُسْمِعُ النَّاسَ فَلَوْ أَمَرْتَ عُمَرَ فَقَالَ مُرُوا أَبَا بَكْرٍ يُصَلِّي بِالنَّاسِ فَقُلْتُ لِحَفْصَةَ قُولِي لَهُ إِنَّ أَبَا بَكْرٍ رَجُلٌ أَسِيفٌ وَإِنَّهُ مَتَى يَقُمْ مَقَامَكَ لَا يُسْمِعُ النَّاسَ فَلَوْ أَمَرْتَ عُمَرَ قَالَ إِنَّكُنَّ لَأَنْتُنَّ صَوَاحِبُ يُوسُفَ مُرُوا أَبَا بَكْرٍ أَنْ يُصَلِّيَ بِالنَّاسِ فَلَمَّا دَخَلَ فِي الصَّلَاةِ وَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفْسِهِ خِفَّةً فَقَامَ يُهَادَى بَيْنَ رَجُلَيْنِ وَرِجْلَاهُ يَخُطَّانِ فِي الْأَرْضِ حَتَّى دَخَلَ الْمَسْجِدَ فَلَمَّا سَمِعَ أَبُو بَكْرٍ حِسَّهُ ذَهَبَ أَبُو بَكْرٍ يَتَأَخَّرُ فَأَوْمَأَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى جَلَسَ عَنْ يَسَارِ أَبِي بَكْرٍ فَكَانَ أَبُو بَكْرٍ يُصَلِّي قَائِمًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَاعِدًا يَقْتَدِي أَبُو بَكْرٍ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مُقْتَدُونَ بِصَلَاةِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahin] dari [Al Aswad] dari ['Aisyah], \"Ketika sakit Rasulullah shallallahu 'alaihi wasallam semakin parah, Bilal datang menemui beliau mengabarkan bahwa waktu shalat telah tiba. Beliau lalu berkata: \"Kalian suruhlah Abu Bakar untuk memimpin shalat jama'ah bersama orang banyak.\" Aku lalu berkata, \"Wahai Rasulullah, sesungguhnya Abu Bakar seorang laki-laki yang lemah lembut, jika ia menggantikan tuan, maka suaranya tidak akan bisa didengar oleh orang-orang. Alangkah lebih baik bila tuan menyuruh 'Umar.\" Maka beliau pun bersabda: \"Suruhlah Abu Bakar untuk memimpin shalat bersama orang-orang.\" Kemudian aku sampaikan kepada Hafshah, \"Katakanlah kepada beliau 'Abu Bakar adalah seorang laki-laki yang lemah lembut, jika ia menggantikan posisi tuan, maka ia tidak akan dapat memperdengarkan suara bacaannya kepada orang-orang. Alangkah lebih baik bila tuan menyuruh 'Umar', sebab Abu Bakar mudah menangis (dalam shalat). Untuk itu, sebaiknya suruhlah 'Umar untuk memimpin shalat orang-orang.\" Maka bersabdalah Rasulullah shallallahu 'alaihi wasallam: \"Sungguh kalian ini seperti isteri-isterinya Yusuf. Suruhlah Abu Bakar shalat bersama orang-orang.\" Kemudian ketika Abu Bakar sudah memulai shalat, tubuh beliau telah nampak enak, beliau pun keluar rumah dengan diapit oleh dua orang laki-laki. Dan seolah aku melihat beliau berjalan dengan menyeret kakinya di atas tanah, hingga masuk ke dalam masjid. Tatkala Abu Bakar mendengar kedatangan beliau maka ia pun berkeinginan untuk mundur. Namun Rasulullah shallallahu 'alaihi wasallam memberi isyarat kepadanya. Lalu tibalah Rasulullah shallallahu 'alaihi wasallam hingga beliau duduk di samping kiri Abu Bakar. Abu Bakar shalat dengan bediri sedangkan Rasulullah shallallahu 'alaihi wasallam shalat dengan duduk, Abu Bakar shalat mengikuti shalatnya Rasulullah shallallahu 'alaihi wasallam, dan orang-orang mengikuti shalatnya Abu Bakar.\""},"673":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَيُّوبَ بْنِ أَبِي تَمِيمَةَ السَّخْتِيَانِيِّ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ اثْنَتَيْنِ فَقَالَ لَهُ ذُو الْيَدَيْنِ أَقَصُرَتْ الصَّلَاةُ أَمْ نَسِيتَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَدَقَ ذُو الْيَدَيْنِ فَقَالَ النَّاسُ نَعَمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى اثْنَتَيْنِ أُخْرَيَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik bin Anas] dari [Ayyub bin Abu Tamimah As Sakhtiyani] dari [Muhammad bin Sirin] dari [Abu Hurairah] berkata, \"Ketika Rasulullah telah selesai dari shalat dua rakaat, Dzul Yadain berkata kepada beliau, \"Wahai Rasulullah, shalatnya sengaja diqashar atau tuan yang lupa?\" Rasulullah shallallahu 'alaihi wasallam lalu berkata: \"Apakah benar yang dikatakan Dzul Yadain?\" Orang-orang menjawab: \"Benar.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bediri dan mengerjakan shalat dua rakaat yang kurang kemudian salam. Kemudian beliau takbir lalu sujud seperti sujudnya (yang biasa) atau lebih lama lagi.\""},"674":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ رَكْعَتَيْنِ فَقِيلَ صَلَّيْتَ رَكْعَتَيْنِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam mengerjakan shalat Zhuhur dua rakaat. Lalu dikatakan kepada beliau, \"Tuan shalat hanya dua rakaat!\" Maka beliau mengerjakan shalat dua rakaat yang kurang kemudian salam, setelah itu beliau sujud dua kali.\""},"675":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي مَرَضِهِ مُرُوا أَبَا بَكْرٍ يُصَلِّي بِالنَّاسِ قَالَتْ عَائِشَةُ قُلْتُ إِنَّ أَبَا بَكْرٍ إِذَا قَامَ فِي مَقَامِكَ لَمْ يُسْمِعْ النَّاسَ مِنْ الْبُكَاءِ فَمُرْ عُمَرَ فَلْيُصَلِّ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ لِلنَّاسِ قَالَتْ عَائِشَةُ لِحَفْصَةَ قُولِي لَهُ إِنَّ أَبَا بَكْرٍ إِذَا قَامَ فِي مَقَامِكَ لَمْ يُسْمِعْ النَّاسَ مِنْ الْبُكَاءِ فَمُرْ عُمَرَ فَلْيُصَلِّ لِلنَّاسِ فَفَعَلَتْ حَفْصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ إِنَّكُنَّ لَأَنْتُنَّ صَوَاحِبُ يُوسُفَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ لِلنَّاسِ قَالَتْ حَفْصَةُ لِعَائِشَةَ مَا كُنْتُ لِأُصِيبَ مِنْكِ خَيْرًا","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] Ummul Mukminin, bahwa Rasulullah shallallahu 'alaihi wasallam berkata saat dalam kondisi sakitnya: \"Suruhlah Abu Bakar untuk memimpin shalat orang-orang.\" 'Aisyah berkata, \"Aku lalu berkata, \"Jika Abu Bakar menggantikan posisi tuan, tidak akan mampu memperdengarkan suara bacaannya kepada orang banyak karena dia mudah menangis (dalam shalat). Sebaiknya suruhlah 'Umar untuk memimpin orang-orang shalat berjama'ah.\" Beliau bersabda: \"Suruhlah Abu Bakar memimpin shalat.\" 'Aisyah lalu berkata kepada Hafshah, \"Katakanlah kepada Beliau, 'Jika Abu Bakar menggantikan posisi tuan, maka dia tidak akan mampu memperdengarkan suara bacaannya kepada orang banyak karena dia sering menangis (dalam shalat). Untuk itu, suruhlah 'Umar untuk memimpin orang-orang shalat berjama'ah.\" Maka Hafshah melaksanakannya. Kemudian bersabdalah Rasulullah shallallahu 'alaihi wasallam: \"Celakalah kalian! Sungguh kalian ini seperti isteri-isteri Yusuf. Suruhlah Abu Bakar memimpin orang-orang shalat.\" Hafshah lantas kepada 'Aisyah, \"Sungguh aku tidak mendapatkan kebaikan darimu.\""},"676":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَمْرُو بْنُ مُرَّةَ قَالَ سَمِعْتُ سَالِمَ بْنَ أَبِي الْجَعْدِ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتُسَوُّنَّ صُفُوفَكُمْ أَوْ لَيُخَالِفَنَّ اللَّهُ بَيْنَ وُجُوهِكُمْ","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin 'Abdul Malik] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku ['Amru bin Murrah] berkata, Aku mendengar [Salim bin Abu Al Ja'd] berkata, Aku mendengar [An Nu'man bin Basyir] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Luruskanlah shaf kalian, atau Allah akan memalingkan wajah-wajah kalian.\""},"677":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقِيمُوا الصُّفُوفَ فَإِنِّي أَرَاكُمْ خَلْفَ ظَهْرِي","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] dari ['Abdul 'Aziz bin Shuhaib] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Luruskanlah shaf, sesungguhnya aku dapat melihat kalian dari balik punggungku.\""},"678":{"ar":"حَدَّثَ��َا أَحْمَدُ ابْنُ أَبِي رَجَاءٍ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَأُقِيمَتْ الصَّلَاةُ فَأَقْبَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَجْهِهِ فَقَالَ أَقِيمُوا صُفُوفَكُمْ وَتَرَاصُّوا فَإِنِّي أَرَاكُمْ مِنْ وَرَاءِ ظَهْرِي","id":"Telah menceritakan kepada kami [Ahmad Ibnu Abu Raja'] berkata, telah menceritakan kepada kami [Mu'awiyyah bin 'Amru] berkata, telah menceritakan kepada kami [Za'idah bin Qudamah] berkata, telah menceritakan kepada kami [Humaid Ath Thawil] telah menceritakan kepada kami [Anas bin Malik] ia berkata, \"Ketika iqamah shalat telah dikumandangkan, Rasulullah shallallahu 'alaihi wasallam berbalik menghadapkan mukanya kepada kami seraya bersabda: \"Luruskanlah shaf dan rapatkanlah, sesungguhnya aku dapat melihat kalian dari balik punggungku.\""},"679":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّهَدَاءُ الْغَرِقُ وَالْمَطْعُونُ وَالْمَبْطُونُ وَالْهَدِمُ وَقَالَ وَلَوْ يَعْلَمُونَ مَا فِي التَّهْجِيرِ لَاسْتَبَقُوا وَلَوْ يَعْلَمُونَ مَا فِي الْعَتَمَةِ وَالصُّبْحِ لَأَتَوْهُمَا وَلَوْ حَبْوًا وَلَوْ يَعْلَمُونَ مَا فِي الصَّفِّ الْمُقَدَّمِ لَاسْتَهَمُوا","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Orang-orang yang mati syahid itu adalah; orang yang mati kerena tenggelam, karena penyakit kusta, karena sakit perut, dan orang yang mati karena tertimpa reruntuhan.\" Beliau juga bersabda: \"Seandainya mereka mengetahui kebaikan yang terdapat dalam bersegera menuju shalat, tentulah mereka akan berlomba-limba. Dan seandainya mereka mengetahui kebaikan yang terdapat pada waktu 'atamah (shalat 'Isya) dan shubuh, tentulah mereka akan mendatanginya meskipun dengan merangkak, dan seandainya mereka mengetahui kebaikan yang ada pada shaf pertama tentulah mereka akan berlomba meraihnya.\""},"680":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَلَا تَخْتَلِفُوا عَلَيْهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا لَكَ الْحَمْدُ وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا أَجْمَعُونَ وَأَقِيمُوا الصَّفَّ فِي الصَّلَاةِ فَإِنَّ إِقَامَةَ الصَّفِّ مِنْ حُسْنِ الصَّلَاةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dijadikannya Imam adalah untuk diikuti, maka janganlah kalian menyelisihnya. Jika ia rukuk maka rukuklah kalian, jika ia mengucapkan 'SAMI'ALLAHU LIMAN HAMIDAH' maka ucapkanlah, 'RABBANAA LAKAL HAMDU'. Jika ia sujud maka sujudlah kalian, jika ia shalat dengan duduk maka shalatlah kalian semuanya dengan duduk, dan luruskanlah shaf, karena lurusnya shaf merupakan bagian dari sempurnanya shalat.\""},"681":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَوُّوا صُفُوفَكُمْ فَإِنَّ تَسْوِيَةَ الصُّفُوفِ مِنْ إِقَامَةِ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Luruskanlah shaf kalian, karena lurusnya shaf adalah bagian dari ditegakkannya shalat.\""},"682":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ قَالَ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى قَالَ أَخْبَرَنَا سَعِيدُ بْنُ عُبَيْدٍ الطَّائِيُّ عَنْ بُشَيْرِ بْنِ يَسَارٍ الْأَنْصَارِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّهُ قَدِمَ الْمَدِينَةَ فَقِيلَ لَهُ مَا أَنْكَرْتَ مِنَّا مُنْذُ يَوْمِ عَهِدْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَنْكَرْتُ شَيْئًا إِلَّا أَنَّكُمْ لَا تُقِيمُونَ الصُّفُوفَوَقَالَ عُقْبَةُ بْنُ عُبَيْدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ قَدِمَ عَلَيْنَا أَنَسُ بْنُ مَالِكٍ الْمَدِينَةَ بِهَذَا","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] berkata, telah mengabarkan kepada kami [Al Fadll bin Musa] berkata, telah mengabarkan kepada kami [Sa'id bin 'Ubaid Ath Tha'i] dari [Busyair bin Yasar Al Anshari] dari [Anas bin Malik], bahwa dia datang ke Madinah, lalu dikatakan kepadanya, \"Apakah ada sesuatu yang kamu ingkari dari perbuatan kami sejak kamu hidup bersama Rasulullah shallallahu 'alaihi wasallam?\" Anas bin Malik menjawab, \"Tidak ada sesuatu yang aku ingkari dari kalian kecuali kalian tidak meluruskan shaf dalam shalat.\" ['Uqbah bin 'Ubaid] berkata dari [Busyair bin Yasar] bahwa [Anas bin Malik] mendatangi kami di Madinah seperti keterangan riwayat ini.\""},"683":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقِيمُوا صُفُوفَكُمْ فَإِنِّي أَرَاكُمْ مِنْ وَرَاءِ ظَهْرِيوَكَانَ أَحَدُنَا يُلْزِقُ مَنْكِبَهُ بِمَنْكِبِ صَاحِبِهِ وَقَدَمَهُ بِقَدَمِهِ","id":"Telah menceritakan kepada kami ['Amru bin Khalid] berkata, telah menceritakan kepada kami [Zuhair] dari [Humaid] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Luruskanlah shaf-shaf kalian, sesungguhnya aku dapat melihat kalian dari balik punggungku.\" Dan setiap orang dari kami merapatkan bahunya kepada bahu temannya, dan kakinya pada kaki temannya.\""},"684":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا دَاوُدُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَأْسِي مِنْ وَرَائِي فَجَعَلَنِي عَنْ يَمِينِهِ فَصَلَّى وَرَقَدَ فَجَاءَهُ الْمُؤَذِّنُ فَقَامَ وَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Daud] dari ['Amru bin Dinar] dari [Kuraib] mantan budak Ibnu 'Abbas, dari [Ibnu 'Abbas] berkata, \"Pada suatu malam aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam, dan aku berdiri di samping kirinya. Rasulullah shallallahu 'alaihi wasallam kemudian memegang kepalaku dari arah belakangku, lalu menempatkan aku di sebelah kanannya. Beliau kemudian shalat dan tidur setelahnya. Setelah itu datang mu'adzin kepada beliau, maka beliau pun berangkat shalat dengan tidak berwudlu lagi.\""},"685":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْحَاقَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَلَّيْتُ أَنَا وَيَتِيمٌ فِي بَيْتِنَا خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمِّي أُمُّ سُلَيْمٍ خَلْفَنَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Sufyan] dari [Ishaq] dari [Anas bin Malik] ia berkata, \"Aku dan seorang anak yatim yang tinggal di rumah kami, pernah ikut shalat di belakang Nabi shallallahu 'alaihi wasallam. Sementara ibuku, Ummu Sulaim, shalat di belakang kami.\""},"686":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقُمْتُ لَيْلَةً أُصَلِّي عَنْ يَسَارِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ بِيَدِي أَوْ بِعَضُدِي حَتَّى أَقَامَنِي عَنْ يَمِينِهِ وَقَالَ بِيَدِهِ مِنْ وَرَائِي","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami ['Ashim] dari [Asy Sya'bi] dari [Ibnu 'Abbas] radliallahu 'anhu berkata, \"Pada suatu malam aku pernah shalat di samping kanan Nabi shallallahu 'alaihi wasallam, beliau lalu memegang tanganku atau bahuku kemudian memindahkan aku ke sebelah kirinya.\" Ibnu 'Abbas berkata, \"Beliau memegangku dengan menggunakan tangannya dari arah belakangku.\""},"687":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا عَبْدَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فِي حُجْرَتِهِ وَجِدَارُ الْحُجْرَةِ قَصِيرٌ فَرَأَى النَّاسُ شَخْصَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ أُنَاسٌ يُصَلُّونَ بِصَلَاتِهِ فَأَصْبَحُوا فَتَحَدَّثُوا بِذَلِكَ فَقَامَ اللَّيْلَةَ الثَّانِيَةَ فَقَامَ مَعَهُ أُنَاسٌ يُصَلُّونَ بِصَلَاتِهِ صَنَعُوا ذَلِكَ لَيْلَتَيْنِ أَوْ ثَلَاثًا حَتَّى إِذَا كَانَ بَعْدَ ذَلِكَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَخْرُجْ فَلَمَّا أَصْبَحَ ذَكَرَ ذَلِكَ النَّاسُ فَقَالَ إِنِّي خَشِيتُ أَنْ تُكْتَبَ عَلَيْكُمْ صَلَاةُ اللَّيْلِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami ['Abdah] dari [Yahya bin Sa'id Al Anshari] dari ['Amrah] dari ['Aisyah] berkata, \"Pada suatu malam Rasulullah shallallahu 'alaihi wasallam pernah shalat di kamarnya, saat itu dinding kamar beliau tidak terlalu tinggi (pendek) hingga orang-orang pun melihat Nabi shallallahu 'alaihi wasallam berdiri shalat sendirian. Orang-orang itu pun berdiri dan shalat di belakang beliau, hingga pada pagi harinya orang-orang saling memperbincangkan kejadian tersebut. Kemudian pada malam keduanya beliau kembali shalat, dan orang-orangpun mengikuti shalat beliau kembali. Mereka melakukan ini selama dua atau tiga malam hingga setelah malam itu, Rasulullah shallallahu 'alaihi wasallam duduk di rumahnya dan tidak keluar melaksanakan shalat seperti malam sebelumnya. Pada pagi harinya orang-orang mempertanyakannya, lalu beliau bersabda: \"Aku khawatir bila shalat malam itu ditetapkan sebagai kewajiban atas kalian.\""},"688":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَهُ حَصِيرٌ يَبْسُطُهُ بِالنَّهَارِ وَيَحْتَجِرُهُ بِاللَّيْلِ فَثَابَ إِلَيْهِ نَاسٌ فَصَلَّوْا وَرَاءَهُ","id":"telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Al Maqburi] dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah], bahwa Nabi shallallahu 'alaihi wasallam memiliki tikar yang di waktu siang digelar, sedang pada waktu malam dijadikannya seperti dinding yang menutupi Beliau dari orang lain. Saat sedang shalat, orang-orang berkumpul ikut shalat di belakang Beliau.\""},"689":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ حُجْرَةً قَالَ حَسِبْتُ أَنَّهُ قَالَ مِنْ حَصِيرٍ فِي رَمَضَانَ فَصَلَّى فِيهَا لَيَالِيَ فَصَلَّى بِصَلَاتِهِ نَاسٌ مِنْ أَصْحَابِهِ فَلَمَّا عَلِمَ بِهِمْ جَعَلَ يَقْعُدُ فَخَرَجَ إِلَيْهِمْ فَقَالَ قَدْ عَرَفْتُ الَّذِي رَأَيْتُ مِنْ صَنِيعِكُمْ فَصَلُّوا أَيُّهَا النَّاسُ فِي بُيُوتِكُمْ فَإِنَّ أَفْضَلَ الصَّلَاةِ صَلَاةُ الْمَرْءِ فِي بَيْتِهِ إِلَّا الْمَكْتُوبَةَقَالَ عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مُوسَى سَمِعْتُ أَبَا النَّضْرِ عَنْ بُسْرٍ عَنْ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"telah menceritakan kepada kami ['Abdul A'la bin Hammad] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Salim Abu An Nadlr] dari [Busr bin Sa'id] dari [Zaid bin Tsabit], bahwa Rasulullah shallallahu 'alaihi wasallam membuat satu ruangan.\" Busr berkata, \"Aku menduga Zaid bin Tsabit berkata, 'Membuat tikar pada bulan Ramadan, lalu beliau melaksakan shalat malam di (kamar atau tikar) tersebut dalam beberapa malam. Kemudian para sahabat mengikuti shalat beliau. Ketika mengetahui apa yang mereka lakukan beliau pun berdiam di rumah, setelah itu beliau keluar seraya berkata kepada mereka: \"Sungguh aku telah mengetahui sebagaimana aku lihat apa yang kalian lakukan. Wahai manusia, shalatlah kalian di rumah-rumah kalian, sesungguhnya shalat yang paling utama adalah shalatnya seseorang yang dilakukannya di rumahnya, kecuali shalat fardlu.\" ['Affan] berkata, telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Musa] aku mendengar [Abu An Nadlr] dari [Busr] dari [Zaid] dari Nabi shallallahu 'alaihi wasallam.\""},"690":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ الْأَنْصَارِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ فَرَسًا فَجُحِشَ شِقُّهُ الْأَيْمَنُ قَالَ أَنَسٌ رَضِيَ اللَّهُ عَنْهُ فَصَلَّى لَنَا يَوْمَئِذٍ صَلَاةً مِنْ الصَّلَوَاتِ وَهُوَ قَاعِدٌ فَصَلَّيْنَا وَرَاءَهُ قُعُودًا ثُمَّ قَالَ لَمَّا سَلَّمَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Anas bin Malik Al Anshari], bahwa pada suatu hari Rasulullah shallallahu 'alaihi wasallam mengendarai kudanya dan terjatuh terhempas pada lambung kanannya.\" Anas? radliallahu 'anhu berkata, \"Maka pada suatu hari Beliau shalat mengimami kami di antara shalat-shalatnya dengan duduk. Maka kamipun shalat di belakang Beliau dengan duduk. Beliau kemudian bersabda: \"Sesungguhnya imam dijadikan untuk diikuti. Jika ia shalat dengan berdiri maka shalatlah kalian dengan berdiri, jika ia rukuk maka rukuklah kalian, jika ia mengangkat kepala maka angkatlah kepala kalian, jika ia sujud maka sujudlah kalian, jika ia mengucapkan SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar orang yang memuji-Nya) ', maka ucapkanlah oleh kalian: 'RABBANAA WA LAKAL HAMDU (Ya Rabb kami, milik Engkaulah segala pujian) '.\""},"691":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَخَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ فَرَسٍ فَجُحِشَ فَصَلَّى لَنَا قَاعِدًا فَصَلَّيْنَا مَعَهُ قُعُودًا ثُمَّ انْصَرَفَ فَقَالَ إِنَّمَا الْإِمَامُ أَوْ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا لَكَ الْحَمْدُ وَإِذَا سَجَدَ فَاسْجُدُوا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam jatuh dari kudanya hingga beliau pun cedera. Beliau lalu shalat mengimami kami dengan duduk, dan kami juga shalat dengan duduk. Setelah selesai beliau bersabda: \"Sesungguhnya imam, atau dijadikannya imam adalah untuk diikuti. Jika ia takbir maka bertakbirlah kalian, jika ia rukuk maka rukuklahkalian, jika ia mengangkat kepala maka angkatlah kepala kalian, jika ia mengucapkan 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar orang yang memuji-Nya), maka ucapkanlah oleh kalian 'RABBANAA LAKAL HAMDU (Ya Rabb kami, milik Engkaulah segala pujian), dan jika ia sujud maka sujudlah kalian.\""},"692":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا أَجْمَعُونَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] berkata, telah menceritakan kepadaku [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dijadikannya Imam itu untuk diikuti, jika ia takbir maka bertakbirlah kalian, jika ia rukuk maka rukuklah kalian, jika ia mengucapkan 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar orang yang memuji-Nya) ', maka ucapkanlah oleh kalian 'RABBANAA WA LAKAL HAMDU (Ya Rabb kami, milik Engkaulah segala pujian) ', jika ia sujud maka suudlah kalian, dan jika ia shalat dengan duduk maka shalatlah kalian semua dengan duduk.\""},"693":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْفَعُ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ إِذَا افْتَتَحَ الصَّلَاةَ وَإِذَا كَبَّرَ لِلرُّكُوعِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَهُمَا كَذَلِكَ أَيْضًا وَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ وَكَانَ لَا يَفْعَلُ ذَلِكَ فِي السُّجُودِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [Bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam mengangkat tangannya sejajar dengan pundaknya ketika memulai shalat, ketika takbir untuk rukuk dan ketika bangkit dari rukuk dengan mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH RABBANAA WA LAKAL HAMDU (Semoga Allah mendengar orang yang memuji-Nya. Ya Rabb kami, milik Engkaulah segala pujian) '. Beliau tidak melakukan seperti itu ketika akan sujud.\""},"694":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ فِي الصَّلَاةِ رَفَعَ يَدَيْهِ حَتَّى يَكُونَا حَذْوَ مَنْكِبَيْهِ وَكَانَ يَفْعَلُ ذَلِكَ حِينَ يُكَبِّرُ لِلرُّكُوعِ وَيَفْعَلُ ذَلِكَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَيَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَلَا يَفْعَلُ ذَلِكَ فِي السُّجُودِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepadaku [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar] radliallahu 'anhuma berkata, \"Aku melihat jika Rasulullah shallallahu 'alaihi wasallam berdiri shalat, beliau mengangkat kedua tangannya hingga sejajar dengan pundaknya. Beliau melakukan seperti itu ketika takbir untuk rukuk dan bangkit dari rukuk dengan mengangkat kepalanya sambil mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar orang yang memuji-Nya) '. Namun beliau tidak melakukan seperti itu ketika akan sujud.\""},"695":{"ar":"حَدَّثَنَا إِسْحَاقُ الْوَاسِطِيُّ قَالَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ أَنَّهُ رَأَى مَالِكَ بْنَ الْحُوَيْرِثِإِذَا صَلَّى كَبَّرَ وَرَفَعَ يَدَيْهِ وَإِذَا أَرَادَ أَنْ يَرْكَعَ رَفَعَ يَدَيْهِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَ يَدَيْهِ وَحَدَّثَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ هَكَذَا","id":"Telah menceritakan kepada kami [Ishaq Al Wasithi] berkata, telah menceritakan kepada kami [Khalid bin 'Abdullah] dari [Khalid] dari [Abu Qilabah] bahwa dia melihat [Malik Al Huwairits] ketika shalat, dia bertakbir dan mengangkat kedua tangannya, apabila hendak rukuk mengangkat tangannya, dan ketika mengangkat kepalanya dari rukuk dia juga mengangkat kedua tangannya. Lalu dia menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam berbuat seperti itu.\""},"696":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنَا سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَتَحَ التَّكْبِيرَ فِي الصَّلَاةِ فَرَفَعَ يَدَيْهِ حِينَ يُكَبِّرُ حَتَّى يَجْعَلَهُمَا حَذْوَ مَنْكِبَيْهِ وَإِذَا كَبَّرَ لِلرُّكُوعِ فَعَلَ مِثْلَهُ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَعَلَ مِثْلَهُ وَقَالَ رَبَّنَا وَلَكَ الْحَمْدُ وَلَا يَفْعَلُ ذَلِكَ حِينَ يَسْجُدُ وَلَا حِينَ يَرْفَعُ رَأْسَهُ مِنْ السُّجُودِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepada kami [Salim bin 'Abdullah] bahwa ['Abdullah bin 'Umar] radliallahu 'anhuma berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam memulai shalat dengan bertakbir. Beliau mengangkat kedua tangannya ketika bertakbir hingga meletakkan kedua tangannya sejajar dengan pundaknya. Ketika takbir untuk rukuk beliau juga melakukan seperti itu, jika mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar siapa yang memuji-Nya) ', beliau juga melakukan seperti itu sambil mengucapkan: 'RABBANAA WA LAKAL HAMDU (Ya Rabb kami, milik Engkaulah segala pujian) '. Namun Beliau tidak melakukan seperti itu ketika akan sujud dan ketika mengangkat kepalanya dari sujud.\""},"697":{"ar":"حَدَّثَنَا عَيَّاشٌ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَكَانَ إِذَا دَخَلَ فِي الصَّلَاةِ كَبَّرَ وَرَفَعَ يَدَيْهِ وَإِذَا رَكَعَ رَفَعَ يَدَيْهِ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَفَعَ يَدَيْهِ وَإِذَا قَامَ مِنْ الرَّكْعَتَيْنِ رَفَعَ يَدَيْهِ وَرَفَعَ ذَلِكَ ابْنُ عُمَرَ إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ ابْنُ طَهْمَانَ عَنْ أَيُّوبَ وَمُوسَى بْنِ عُقْبَةَ مُخْتَصَرًا","id":"Telah menceritakan kepada kami ['Ayyasy] berkata, telah menceritakan kepada kami ['Abdul A'la] berkata, telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] bahwa [Ibnu 'Umar] ketika memulai shalat, dia bertakbir dengan mengangkat kedua tangannya, dan ketika rukuk mengangkat kedua tangannya, dan ketika mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH mengangkat kedua tangannya, dan ketika berdiri dari dua rakaat mengangkat kedua tangannya. Lalu Ibnu 'Umar mengatakan bahwa Nabi shallallahu 'alaihi wasallam melakukan seperti itu.\" Dan diriwayatkan oleh [Hammad bin Salamah] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan pula oleh [Ibnu Thahman] dari [Ayyub] dan [Musa bin 'Uqbah] secara ringkas.\""},"698":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَ النَّاسُ يُؤْمَرُونَ أَنْ يَضَعَ الرَّجُلُ الْيَدَ الْيُمْنَى عَلَى ذِرَاعِهِ الْيُسْرَى فِي الصَّلَاةِ قَالَ أَبُو حَازِمٍ لَا أَعْلَمُهُ إِلَّا يَنْمِي ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ إِسْمَاعِيلُ يُنْمَى ذَلِكَ وَلَمْ يَقُلْ يَنْمِي","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Abu Hazim] dari [Sahl bin Sa'd] berkata, \"Orang-orang diperintahkan agar meletakkan tangan kanannya di atas lengan kiri dalam shalat.\" Abu Hazim berkata, \"Aku tidak mengetahui dia Sahl kecuali bahwa dia menyandarkan hal tersebut kepada Nabi shallallahu 'alaihi wasallam. Isma'il berkata, \"Hadits ini dimarfu'kan kepada Nabi shallallahu 'alaihi wasallam dan bukan mengatakan dia mengambil dari Nabi shallallahu 'alaihi wasallam.\""},"699":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلْ تَرَوْنَ قِبْلَتِي هَا هُنَا وَاللَّهِ مَا يَخْفَى عَلَيَّ رُكُوعُكُمْ وَلَا خُشُوعُكُمْ وَإِنِّي لأَرَاكُمْ وَرَاءَ ظَهْرِي","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian melihat arah kiblatku ini? Demi Allah, tidak ada yang tersembunyi bagiku rukuk dan juga khusyu' kalian, karena aku dapat melihat kalian dari belakang punggungku.\""},"700":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقِيمُوا الرُّكُوعَ وَالسُّجُودَ فَوَاللَّهِ إِنِّي لَأَرَاكُمْ مِنْ بَعْدِي وَرُبَّمَا قَالَ مِنْ بَعْدِ ظَهْرِي إِذَا رَكَعْتُمْ وَسَجَدْتُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] berkata, Aku mendengar [Qatadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Luruskanlah dalam rukuk dan sujud. Demi Allah, aku dapat melihat kalian dari belakangku.\" Seakan beliau mengatakan: \"Aku dapat melihat kalian dari belakangku ketika kalian rukuk dan sujud.\""},"701":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا كَانُوا يَفْتَتِحُونَ الصَّلَاةَ بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakar dan 'Umar? radliallahu 'anhuma, mereka memulai shalat dengan membaca: 'ALHAMDU LILLAHI RABBIL 'AALAMIIN.\""},"702":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ قَالَ حَدَّثَنَا أَبُو زُرْعَةَ قَالَ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْكُتُ بَيْنَ التَّكْبِيرِ وَبَيْنَ الْقِرَاءَةِ إِسْكَاتَةً قَالَ أَحْسِبُهُ قَالَ هُنَيَّةً فَقُلْتُ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ إِسْكَاتُكَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ مَا تَقُولُ قَالَ أَقُولُ اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ نَقِّنِي مِنْ الْخَطَايَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ اللَّهُمَّ اغْسِلْ خَطَايَايَ بِالْمَاءِ وَالثَّلْجِ وَالْبَرَدِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami ['Umarah bin Al Qa'qa'] berkata, telah menceritakan kepada kami [Abu Zur'ah] berkata, telah menceritakan kepada kami [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiam antara takbir dan bacaan Al Qur'an.\" Abu Zur'ah berkata, Aku mengira Abu Hurairah berkata, 'Berhenti sebentar, lalu aku berkata, \"Wahai Rasulullah, demi bapak dan ibuku! Tuan berdiam antara takbir dan bacaan. Apa yang tuan baca diantaranya?. Beliau bersabda: \"Aku membaca; ALLAHUMMA BAA'ID BAINII WA BAINA KHATHAAYAAYA KAMAA BAA'ADTA BAINAL MASYRIQI WAL MAGHRIB. ALLAHUMMA NAQQINII MIN KHATHAAYAAYA KAMAA YUNAQQATS TSAUBUL ABYADLU MINAD DANAS. ALLAHUMMAGHSILNII MIN KHATHAAYAAYA BILMAA'I WATSTSALJI WAL BARAD (Ya Allah, jauhkanlah antara aku dan kesalahanku sebagaimana Engkau menjauhkan antara timur dan barat. Ya Allah, sucikanlah kesalahanku sebagaimana pakaian yang putih disucikan dari kotoran. Ya Allah, cucilah kesalahanku dengan air, salju dan es yang dingin).\""},"703":{"ar":"بَاب حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا نَافِعُ بْنُ عُمَرَ قَالَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةَ الْكُسُوفِ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ قَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ قَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَسَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ انْصَرَفَ فَقَالَ قَدْ دَنَتْ مِنِّي الْجَنَّةُ حَتَّى لَوْ اجْتَرَأْتُ عَلَيْهَا لَجِئْتُكُمْ بِقِطَافٍ مِنْ قِطَافِهَا وَدَنَتْ مِنِّي النَّارُ حَتَّى قُلْتُ أَيْ رَبِّ وَأَنَا مَعَهُمْ فَإِذَا امْرَأَةٌ حَسِبْتُ أَنَّهُ قَالَ تَخْدِشُهَا هِرَّةٌ قُلْتُ مَا شَأْنُ هَذِهِ قَالُوا حَبَسَتْهَا حَتَّى مَاتَتْ جُوعًا لَا أَطْعَمَتْهَا وَلَا أَرْسَلَتْهَا تَأْكُلُ قَالَ نَافِعٌ حَسِبْتُ أَنَّهُ قَالَ مِنْ خَشِيشِ أَوْ خَشَاشِ الْأَرْضِ","id":"Bab. Telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah mengabarkan kepada kami [Nafi' bin 'Umar] berkata, telah menceritakan kepadaku [Ibnu Abu Mulaikah] dari [Asma' binti Abu Bakar Ash Shiddiiq] bahwa Nabi shallallahu 'alaihi wasallam pernah mengerjakan shalat gerhana, maka Beliau berdiri dan dipanjangkan (lama) berdirinya, kemudian rukuk maka dipanjangkannya rukuk, kemudian berdiri lagi dan dipanjangkan berdirinya, kemudian rukuk maka dipanjangkannya rukuk, kemudian bangkit (dari rukuk), kemudian sujud dan memanjangkan sujudnya, kemudian mengangkat (kepala dari sujud), kemudian sujud dan memanjangkan sujudnya, kemudian berdiri lagi dan memanjangkan berdirinya, kemudian rukuk maka dipanjangkannya rukuk, kemudian berdiri (bangkit dari rukuk) dan dipanjangkan berdirinya, kemudian rukuk maka dipanjangkannya rukuk, kemudian bangkit (dari rukuk), kemudian sujud maka dipanjangkannya sujud, kemudian mengangkat (kepala dari sujud), lalu sujud dan dipanjangkannya sujud, selesai salam beliau bersabda: \"Telah didekatkan surga kepadaku hingga seandainya aku dibenarkan (berani) untuk mengambilnya tentu aku akan bawakan kepada kalian kurma dari kurma-kurma didalamnya. Dan didekatkan juga neraka kepadaku hingga aku berkata, 'Wahai Rabb, aku bersama mereka. Tiba-tiba aku melihat seorang wanita'. Aku (Nafi') menduga beliau mengatakan, \"Dicakar-cakar oleh seekor kucing. Aku bertanya, 'Apa yang menyebabkan demikian? Mereka menjawab, 'Wanita tersebut menahan kucing tersebut hingga mati karena kelaparan karena dia tidak memberinya makan atau membiarkan kucing tersebut pergi mencari makan.' Nafi' berkata, \"Aku menduga beliau mengatakan, \"Mencari makan dari serangga di permukaan tanah'.\""},"704":{"ar":"حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ قَالَ قُلْنَا لِخَبَّابٍأَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ نَعَمْ قُلْنَا بِمَ كُنْتُمْ تَعْرِفُونَ ذَاكَ قَالَ بِاضْطِرَابِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Al A'masy] dari ['Umarah] dari [Abu Ma'mar] berkata, \"Kami bertanya kepada [Khabbab], apakah Rasulullah shallallahu 'alaihi wasallam membaca surah dalam shalat Zhuhur dan 'Ashar?\" Dia menjawab, \"Ya.\" Kami tanyakan lagi, \"Bagaimana kalian bisa mengetahuinya?\" Dia menjawab, \"Dari gerakan jenggot Beliau.\""},"705":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يَخْطُبُ قَالَ حَدَّثَنَا الْبَرَاءُ وَكَانَ غَيْرَ كَذُوبٍأَنَّهُمْ كَانُوا إِذَا صَلَّوْا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَامُوا قِيَامًا حَتَّى يَرَوْنَهُ قَدْ سَجَدَ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Syu'ah] berkata, [Abu Ishaq] memberitakan kepada kami bahwa dia berkata, \"Aku mendengar ['Abdullah bin Yazid] berkhutbah; [Al Bara`] menceritakan kepada kami -dan ia bukan seorang pendusta-, \"Para sahabat jika shalat bersama Nabi shallallahu 'alaihi wasallam, jika beliau mengangkat kepalanya dari rukuk, para sahabat tetap berdiri sampai mereka melihat beliau telah sujud.\""},"706":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ قَالَ إِنِّي أُرِيتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari ['Abdullah bin 'Abbas] berkata, \"Pernah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam, kemudian beliau melaksanakan shalat gerhana. Orang-orang berkata, \"Wahai Rasulullah, kami lihat tuan mengambil sesuatu saat di posisimu, lalu tuan mundur kembali?\" Beliau menjawab: \"Aku diperlihatkan surga, lalu aku diberikan setandan anggur. Jika aku mengambilnya niscaya kalian akan memakannya yang akan mengakibatkan terabaikannya urusan dunia.\""},"707":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ قَالَ حَدَّثَنَا فُلَيْحٌ قَالَ حَدَّثَنَا هِلَالُ بْنُ عَلِيٍّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَلَّى لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَقِيَ الْمِنْبَرَ فَأَشَارَ بِيَدَيْهِ قِبَلَ قِبْلَةِ الْمَسْجِدِ ثُمَّ قَالَ لَقَدْ رَأَيْتُ الْآنَ مُنْذُ صَلَّيْتُ لَكُمْ الصَّلَاةَ الْجَنَّةَ وَالنَّارَ مُمَثَّلَتَيْنِ فِي قِبْلَةِ هَذَا الْجِدَارِ فَلَمْ أَرَ كَالْيَوْمِ فِي الْخَيْرِ وَالشَّرِّ ثَلَاثًا","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] berkata, telah menceritakan kepada kami [Fulaih] berkata, telah menceritakan kepada kami [Hilal bin 'Ali] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam pernah memimpin shalat kami, kemudian Beliau naik ke atas mimbar lalu memberi isyarat (menunjuk) dengan tangannya ke arah kiblat masjid seraya bersabda: \"Sejak aku memimpin shalat kalian hingga sekarang, aku diperlihatkan surga dan neraka secara bersamaan di hadapan dinding ini. Dan aku belum pernah melihat kebaikan dan keburukan seperti hari ini.\" Beliau mengucapkannya tiga kali."},"708":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عَرُوبَةَ قَالَ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَالُ أَقْوَامٍ يَرْفَعُونَ أَبْصَارَهُمْ إِلَى السَّمَاءِ فِي صَلَاتِهِمْ فَاشْتَدَّ قَوْلُهُ فِي ذَلِكَ حَتَّى قَالَ لَيَنْتَهُنَّ عَنْ ذَلِكَ أَوْ لَتُخْطَفَنَّ أَبْصَارُهُمْ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah mengabarkan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Ibnu Abu 'Arubah] berkata, telah menceritakan kepada kami [Qatadah] bahwa [Anas bin Malik] ia menceritakan kepada mereka, ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Kenapa orang-orang mengarahkan pandangan mereka ke langit ketika mereka sedang shalat? Suara beliau semakin tinggi hingga beliau bersabda: \"Hendaklah mereka menghentikannya atau Allah benar-benar akan menyambar penglihatan mereka.\""},"709":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ قَالَ حَدَّثَنَا أَشْعَثُ بْنُ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الِالْتِفَاتِ فِي الصَّلَاةِ فَقَالَ هُوَ اخْتِلَاسٌ يَخْتَلِسُهُ الشَّيْطَانُ مِنْ صَلَاةِ الْعَبْدِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Al Ahwash] berkata, telah menceritakan kepada kami [Asy'ats bin Sulaim] dari [Bapaknya] dari [Masruq] dari ['Aisyah] berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang menoleh dalam shalat.\" Maka Beliau bersabda: \"Itu adalah sambaran yang sangat cepat yang dilakukan oleh setan terhadap shalatnya hamba.\""},"710":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي خَمِيصَةٍ لَهَا أَعْلَامٌ فَقَالَ شَغَلَتْنِي أَعْلَامُ هَذِهِ اذْهَبُوا بِهَا إِلَى أَبِي جَهْمٍ وَأْتُونِي بِأَنْبِجَانِيَّةٍ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah], bahwa Nabi shallallahu 'alaihi wasallam shalat dengan mengenakan baju yang ada gambarnya, beliau lalu bersabda: \"Gambar-gambar pada pakaian ini menggangguku. Kembalikanlah kepada Abu Jahm, agar dia mengganti dengan pakaian yang terbuat dari bulu kasar yang tidak bergambar.\""},"711":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ قَالَ رَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ وَهُوَ يُصَلِّي بَيْنَ يَدَيْ النَّاسِ فَحَتَّهَا ثُمَّ قَالَ حِينَ انْصَرَفَ إِنَّ أَحَدَكُمْ إِذَا كَانَ فِي الصَّلَاةِ فَإِنَّ اللَّهَ قِبَلَ وَجْهِهِ فَلَا يَتَنَخَّمَنَّ أَحَدٌ قِبَلَ وَجْهِهِ فِي الصَّلَاةِرَوَاهُ مُوسَى بْنُ عُقْبَةَ وَابْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah mengabarkan kepada kami [Laits] dari [Nafi'] dari [Ibnu 'Umar] bahwa dia berkata, \"Nabi shallallahu 'alaihi wasallam melihat ludah di dinding arah kiblat masjid. Saat itu Beliau sedang shalat di hadapan orang banyak, beliau kemudian menggosoknya seraya mengatakan: \"Sesungguhnya seseorang dari kalian ketika berdiri shalat, dia sedang berhadapan dengan Allah. Maka itu janganlah dia meludah ke arah depannya ketika dia sedang shalat.\" Hadits ini dikuatkan oleh [Musa bin 'Uqbah] dan [Ibnu Abu Rawwad] dari [Nafi']."},"712":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ قَالَبَيْنَمَا الْمُسْلِمُونَ فِي صَلَاةِ الْفَجْرِ لَمْ يَفْجَأْهُمْ إِلَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَشَفَ سِتْرَ حُجْرَةِ عَائِشَةَ فَنَظَرَ إِلَيْهِمْ وَهُمْ صُفُوفٌ فَتَبَسَّمَ يَضْحَكُ وَنَكَصَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَلَى عَقِبَيْهِ لِيَصِلَ لَهُ الصَّفَّ فَظَنَّ أَنَّهُ يُرِيدُ الْخُرُوجَ وَهَمَّ الْمُسْلِمُونَ أَنْ يَفْتَتِنُوا فِي صَلَاتِهِمْ فَأَشَارَ إِلَيْهِمْ أَتِمُّوا صَلَاتَكُمْ فَأَرْخَى السِّتْرَ وَتُوُفِّيَ مِنْ آخِرِ ذَلِكَ الْيَوْمِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah telah menceritakan kepada kami [Laits bin Sa'd] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Anas bin Malik] berkata, \"Ketika Kaum Muslimin melaksanakan shalat Fajar tidak ada sesuatu yang mengagetkan mereka kecuali Rasulullah shallallahu 'alaihi wasallam yang tiba-tiba membuka tabir kamar Aisyah sambil memandang ke arah mereka. Saat itu mereka sudah berbaris dalam shaf, beliau tersenyum lalu tertawa. Maka Abu Bakar berniat mundur ke belakang untuk mempersilakan beliau masuk dalam shaf, karena menduga beliau akan keluar. Dan Kaum Muslimin hampir saja terfitnah (berpaling dan memutus) dalam shalat mereka. Namun ternyata Beliau memberi isyarat kepada mereka: \"Teruskanlah shalat kalian.\" Beliau kemudian menutup tabir, dan setelah itu beliau meninggal pada hari itu juga.\""},"713":{"ar":"حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَشَكَا أَهْلُ الْكُوفَةِ سَعْدًا إِلَى عُمَرَ رَضِيَ اللَّهُ عَنْهُ فَعَزَلَهُ وَاسْتَعْمَلَ عَلَيْهِمْ عَمَّارًا فَشَكَوْا حَتَّى ذَكَرُوا أَنَّهُ لَا يُحْسِنُ يُصَلِّي فَأَرْسَلَ إِلَيْهِ فَقَالَ يَا أَبَا إِسْحَاقَ إِنَّ هَؤُلَاءِ يَزْعُمُونَ أَنَّكَ لَا تُحْسِنُ تُصَلِّي قَالَ أَبُو إِسْحَاقَ أَمَّا أَنَا وَاللَّهِ فَإِنِّي كُنْتُ أُصَلِّي بِهِمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَخْرِمُ عَنْهَا أُصَلِّي صَلَاةَ الْعِشَاءِ فَأَرْكُدُ فِي الْأُولَيَيْنِ وَأُخِفُّ فِي الْأُخْرَيَيْنِ قَالَ ذَاكَ الظَّنُّ بِكَ يَا أَبَا إِسْحَاقَ فَأَرْسَلَ مَعَهُ رَجُلًا أَوْ رِجَالًا إِلَى الْكُوفَةِ فَسَأَلَ عَنْهُ أَهْلَ الْكُوفَةِ وَلَمْ يَدَعْ مَسْجِدًا إِلَّا سَأَلَ عَنْهُ وَيُثْنُونَ مَعْرُوفًا حَتَّى دَخَلَ مَسْجِدًا لِبَنِي عَبْسٍ فَقَامَ رَجُلٌ مِنْهُمْ يُقَالُ لَهُ أُسَامَةُ بْنُ قَتَادَةَ يُكْنَى أَبَا سَعْدَةَ قَالَ أَمَّا إِذْ نَشَدْتَنَا فَإِنَّ سَعْدًا كَانَ لَا يَسِيرُ بِالسَّرِيَّةِ وَلَا يَقْسِمُ بِالسَّوِيَّةِ وَلَا يَعْدِلُ فِي الْقَضِيَّةِ قَالَ سَعْدٌ أَمَا وَاللَّهِ لَأَدْعُوَنَّ بِثَلَاثٍ اللَّهُمَّ إِنْ كَانَ عَبْدُكَ هَذَا كَاذِبًا قَامَ رِيَاءً وَسُمْعَةً فَأَطِلْ عُمْرَهُ وَأَطِلْ فَقْرَهُ وَعَرِّضْهُ بِالْفِتَنِ وَكَانَ بَعْدُ إِذَا سُئِلَ يَقُولُ شَيْخٌ كَبِيرٌ مَفْتُونٌ أَصَابَتْنِي دَعْوَةُ سَعْدٍقَالَ عَبْدُ الْمَلِكِ فَأَنَا رَأَيْتُهُ بَعْدُ قَدْ سَقَطَ حَاجِبَاهُ عَلَى عَيْنَيْهِ مِنْ الْكِبَرِ وَإِنَّهُ لَيَتَعَرَّضُ لِلْجَوَارِي فِي الطُّرُقِ يَغْمِزُهُنَّ","id":"Telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami [Abu 'Awanah] berkata, telah menceritakan kepada kami ['Abdul Malik bin 'Umair] dari [Jabir bin Samrah] berkata, \"Penduduk Kufah mengadukan Sa'd (bin Abu Waqash) kepada 'Umar. Maka 'Umar menggantinya dengan 'Ammar. Mereka mengadukan Sa'd karena dianggap tidak baik dalam shalatnya. Maka Sa'd dikirim kepada 'Umar dan ditanya, \"Wahai Abu Ishaq, penduduk Kufah menganggap kamu tidak baik dalam shalat?\" [Abu Ishaq] menjawab, \"Demi Allah, aku memimpin shalat mereka sebagaimana shalatnya Rasulullah shallallahu 'alaihi wasallam. Tidaklah aku mengurangi sedikitpun dalam melaksanakan shalat 'Isya bersama mereka. Aku memanjangkan bacaan pada dua rakaat pertama dan aku pendekkan pada dua rakaat yang akhir.\" 'Umar berkata, \"wahai Abu Ishaq, kami juga menganggap begitu terhadapmu.\" Kemudian 'Umar mengutus seorang atau beberapa orang bersama Sa'd ke Kufah. Orang itu kemudian bertanya kepada para penduduk tentang Sa'd, tidak ada satupun masjid yang dikunjungi tanpa menanyakan tentang Sa'd, mereka semua mengagumi Sa'd dan mengenalnya dengan baik. Hingga akhirnya sampai ke sebuah masjid milik bani 'Abs, lalu salah seorang dari mereka yang bernama Usamah bin Qatadah dengan nama panggilan Abu Sa'dah berkata, \"Jika kalian minta pendapat kami, maka kami katakan bahwa Sa'd adalah seorang yang tidak memudahkan pasukan, bila membagi tidak sama dan tidak adil dalam mengambil keputusan.\" Maka Sa'd berkata, \"Demi Allah, sungguh aku akan berdo'a dengan tiga do'a; Ya Allah jika dia, hambamu ini, berdusta, dan mengatakan ini dengan maksud riya' atau sum'ah, maka panjangkanlah umurnya, panjangkanlah kefakirannya dan campakkanlah dia dengan berbagai fitnah.\" Setelah beberapa masa kemudian, orang tersebut bila ditanya mengapa keadaannya jadi sengsara begitu, maka ia menjawab, \"Aku orang tua renta yang terkena fitnah akibat do'anya Sa'd.\" 'Abdul Malik berkata, \"Aku sendiri melihat kedua alisnya telah panjang ke bawah menutupi kedua matanya, dan sungguh dia tersia-siakan saat berada di jalan-jalan.\""},"714":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami ['Ali bin 'Adullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin Ash Shamit], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat bagi yang tidak membaca Faatihatul Kitab (Al Fatihah).\""},"715":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَدَخَلَ رَجُلٌ فَصَلَّى فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ وَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ يُصَلِّي كَمَا صَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ ثَلَاثًا فَقَالَ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أُحْسِنُ غَيْرَهُ فَعَلِّمْنِي فَقَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَكَبِّرْ ثُمَّ اقْرَأْ مَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا وَافْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [Bapaknya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam masuk ke masjid, lalu ada juga seorang laki-laki masuk Masjid dan langsung shalat kemudian memberi salam kepada Nabi shallallahu 'alaihi wasallam. Beliau menjawab dan berkata kepadanya, \"Kembalilah dan ulangi shalatmu karena kamu belum shalat!\" Maka orang itu mengulangi shalatnya seperti yang dilakukannya pertama tadi kemudian datang menghadap kepada Nabi shallallahu 'alaihi wasallam dan memberi salam. Namun Beliau kembali berkata: \"Kembalilah dan ulangi shalatmu karena kamu belum shalat!\" Beliau memerintahkan orang ini sampai tiga kali hingga akhirnya laki-laki tersebut berkata, \"Demi Dzat yang mengutus Tuan dengan hak, aku tidak bisa melakukan yang lebih baik dari itu. Maka ajarkkanlah aku!\" Beliau lantas berkata: \"Jika kamu berdiri untuk shalat maka mulailah dengan takbir, lalu bacalah apa yang mudah buatmu dari Al Qur'an kemudian rukuklah sampai benar-benar rukuk dengan thuma'ninah (tenang), lalu bangkitlah (dari rukuk) hingga kamu berdiri tegak, lalu sujudlah sampai hingga benar-benar thuma'ninah, lalu angkat (kepalamu) untuk duduk hingga benar-benar duduk dengan thuma'ninah. Maka lakukanlah dengan cara seperti itu dalam seluruh shalat (rakaat) mu.\""},"716":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ قَالَ سَعْدٌكُنْتُ أُصَلِّي بِهِمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَيْ الْعَشِيِّ لَا أَخْرِمُ عَنْهَا أَرْكُدُ فِي الْأُولَيَيْنِ وَأَحْذِفُ فِي الْأُخْرَيَيْنِ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ ذَلِكَ الظَّنُّ بِكَ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari ['Abdul Malik bin 'Umair] dari [Jabir bin Samrah] berkata, [Sa'd] berkata, \"Aku pernah mengimami mereka di antara dua shalat pada malam hari (Maghrib atau Isya) sebagaimana shalatnya Rasulullah shallallahu 'alaihi wasallam, dan aku mengurangi sedikitpun. Aku memanjangkan bacaan pada dua rakaat pertama dan aku pendekkan pada dua rakaat yang akhir.\" 'Umar? radliallahu 'anhu lalu berkata, \"Begitulah anggapan kami terhadapmu.\""},"717":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الظُّهْرِ بِفَاتِحَةِ الْكِتَابِ وَسُورَتَيْنِ يُطَوِّلُ فِي الْأُولَى وَيُقَصِّرُ فِي الثَّانِيَةِ وَيُسْمِعُ الْ��يَةَ أَحْيَانًا وَكَانَ يَقْرَأُ فِي الْعَصْرِ بِفَاتِحَةِ الْكِتَابِ وَسُورَتَيْنِ وَكَانَ يُطَوِّلُ فِي الْأُولَى وَكَانَ يُطَوِّلُ فِي الرَّكْعَةِ الْأُولَى مِنْ صَلَاةِ الصُّبْحِ وَيُقَصِّرُ فِي الثَّانِيَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam pada dua rakaat pertama dalam shalat Zhuhur membaca Al Fatihah dan dua surah, beliau memanjangkan rakaat pertama dan memendekkan pada rakaat kedua, dan terkadang beliau memperdengarkan bacaannya. Dalam shalat Ashar beliau membaca Al Fatihah dan dua surah, dan memanjangkan pada rakaat yang pertama. Demikian pula dalam shalat Shubuh, beliau memanjangkan bacaan pada rakaat pertama dan memendekkakan pada rakaat kedua.\""},"718":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي عُمَارَةُ عَنْ أَبِي مَعْمَرٍ قَالَ سَأَلْنَا خَبَّابًاأَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ نَعَمْ قُلْنَا بِأَيِّ شَيْءٍ كُنْتُمْ تَعْرِفُونَ قَالَ بِاضْطِرَابِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] telah menceritakan kepadaku ['Umarah] dari [Abu Ma'mar] berkata, \"Kami bertanya kepada [Khabbab], apakah Rasulullah shallallahu 'alaihi wasallam membaca surah dalam shalat Zhuhur dan 'Ashar?\" Dia menjawab, \"Ya.\" Kami tanyakan lagi, \"Bagaimana kalian bisa mengetahuinya?\" Dia menjawab, \"Dari gerakan jenggot beliau.\""},"719":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ قَالَ قُلْتُ لِخَبَّابِ بْنِ الْأَرَتِّأَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ نَعَمْ قَالَ قُلْتُ بِأَيِّ شَيْءٍ كُنْتُمْ تَعْلَمُونَ قِرَاءَتَهُ قَالَ بِاضْطِرَابِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari ['Umarah] dari [Abu Ma'mar] berkata, \"Aku bertanya kepada [Khabbab bin Al Arat], 'Apakah Rasulullah shallallahu 'alaihi wasallam membaca surah dalam shalat Zhuhur dan 'Ashar? ' Dia menjawab, \"Ya.\" Kami tanyakan lagi, \"Bagaimana kalian bisa mengetahui bacaan Beliau?\" Dia menjawab, \"Dari gerakan jenggot Beliau.\""},"720":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ هِشَامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الرَّكْعَتَيْنِ مِنْ الظُّهْرِ وَالْعَصْرِ بِفَاتِحَةِ الْكِتَابِ وَسُورَةٍ سُورَةٍ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] dari [Hisyam] dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pada dua rakaat pertama dalam shalat Zhuhur dan 'Ashar membaca Al Fatihah dan surah masing-masing, dan terkadang Beliau memperdengarkannya kepada kami ayat yang dibacanya.\""},"721":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَ إِنَّ أُمَّ الْفَضْلِسَمِعَتْهُ وَهُوَ يَقْرَأُ وَالْمُرْسَلَاتِ عُرْفًا فَقَالَتْ يَا بُنَيَّ وَاللَّهِ لَقَدْ ذَكَّرْتَنِي بِقِرَاءَتِكَ هَذِهِ السُّورَةَ إِنَّهَا لَآخِرُ مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهَا فِي الْمَغْرِبِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Ibnu 'Abbas? radliallahu 'anhu] dia mengatakan bahwa [Ummu Al Fadll] pernah mendengarnya membaca Wal mursalaati 'urfa. Maka Ummu Al Fadll pun berkata, \"Wahai ananda, bacaan surahmu ini telah mengingatkan aku. Sungguh itu adalah surah terakhir yang aku dengar dibaca oleh Rasulullah shallallahu 'alaihi wasallam ketika beliau membacanya pada shalat Maghrib.\""},"722":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ قَالَ قَالَ لِي زَيْدُ بْنُ ثَابِتٍمَا لَكَ تَقْرَأُ فِي الْمَغْرِبِ بِقِصَارٍ وَقَدْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِطُولَى الطُّولَيَيْنِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari ['Urwah bin Az Zubair] dari [Marwan bin Al Hakam] berkata, \" [Zaid bin Tsabit] berkata kepdaku, \"Kenapa kamu dalam shalat Maghrib membaca surah-surah yang pendek? Sungguh aku pernah mendengar Nabi shallallahu 'alaihi wasallam membaca dengan surah-surah yang panjang.\""},"723":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي الْمَغْرِبِ بِالطُّورِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam dalam shalat Maghrib membaca \"Ath-Thur.\""},"724":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ بَكْرٍ عَنْ أَبِي رَافِعٍ قَالَ صَلَّيْتُ مَعَ أَبِي هُرَيْرَةَالْعَتَمَةَ فَقَرَأَ إِذَا السَّمَاءُ انْشَقَّتْ فَسَجَدَ فَقُلْتُ لَهُ قَالَ سَجَدْتُ خَلْفَ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَزَالُ أَسْجُدُ بِهَا حَتَّى أَلْقَاهُ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Mu'tamir] dari [Bapaknya] dari [Bakar] dari [Abu Rafi'] berkata, \"Aku shalat 'Isya bersama [Abu Hurairah], lalu ia membaca 'IDZAS SAMAA'UNSYAQQAT' lalu dia sujud, maka hal itu kemudian aku tanyakan kepadanya. Maka dia menjawab, \"Aku pernah sujud bersama di belakang Abu Al Qashim (Nabi shallallahu 'alaihi wasallam) dalam ayat tersebut, dan aku akan selalu sujud di dalamnya hingga aku berjumpa dengannya.\""},"725":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ قَالَ سَمِعْتُ الْبَرَاءَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ فَقَرَأَ فِي الْعِشَاءِ فِي إِحْدَى الرَّكْعَتَيْنِ بِالتِّينِ وَالزَّيْتُونِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Adi] berkata, \"Aku mendengar [Al Bara'], bahwa Nabi shallallahu 'alaihi wasallam ketika safar (bepergian) pada shalat 'Isya membaca pada salah satu dari dua rakaatnya dengan 'WAT TIINI WAZ ZAITUUN'.\""},"726":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنِي التَّيْمِيُّ عَنْ بَكْرٍ عَنْ أَبِي رَافِعٍ قَالَ صَلَّيْتُ مَعَ أَبِي هُرَيْرَةَالْعَتَمَةَ فَقَرَأَ إِذَا السَّمَاءُ انْشَقَّتْ فَسَجَدَ فَقُلْتُ مَا هَذِهِ قَالَ سَجَدْتُ بِهَا خَلْفَ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَزَالُ أَسْجُدُ بِهَا حَتَّى أَلْقَاهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepadaku [At Taimi] dari [Bakar] dari [Abu Rafi'] berkata, \"Aku shalat 'Isya bersama [Abu Hurairah], lalu ia membaca 'IDZAS SAMAA'UNSYAQQAT' lalu ia sujud. Maka aku pun bertanya kepadanya kenapa melakukan hal tersebut. Dia lantas menjawab, \"Aku pernah sujud di belakang Abu Al Qashim (Nabi shallallahu 'alaihi wasallam) setelah membaca surah tersebut, dan aku akan selalu sujud di dalamnya hingga aku berjumpa dengannya.\""},"727":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى قَالَ حَدَّثَنَا مِسْعَرٌ قَالَ حَدَّثَنَا عَدِيُّ بْنُ ثَابِتٍ سَمِعَ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ وَالتِّينِ وَالزَّيْتُونِ فِي الْعِشَاءِ وَمَا سَمِعْتُ أَحَدًا أَحْسَنَ صَوْتًا مِنْهُ أَوْ قِرَاءَةً","id":"Telah menceritakan kepada kami [Khallad bin Yahya] berkata, telah menceritakan kepada kami [Mis'ar] berkata, telah menceritakan kepada kami ['Adi bin Tsabit] bahwa dia mendengan [Al Bara] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam membaca 'WAT TIINI WAZ ZAITUUN' pada shalat 'Isya. Dan belum pernah aku mendengar seseorang yang suaranya atau bacaan lebih baik dari beliau.\""},"728":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عَوْنٍ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ الثَّقَفِيِّ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَ قَالَقَالَ عُمَرُ لِسَعْدٍ لَقَدْ شَكَوْكَ فِي كُلِّ شَيْءٍ حَتَّى الصَّلَاةِ قَالَ أَمَّا أَنَا فَأَمُدُّ فِي الْأُولَيَيْنِ وَأَحْذِفُ فِي الْأُخْرَيَيْنِ وَلَا آلُو مَا اقْتَدَيْتُ بِهِ مِنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَدَقْتَ ذَاكَ الظَّنُّ بِكَ أَوْ ظَنِّي بِكَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'ah] dari [Abu 'Aun Muhammad bin Ubaidullah Ats Tsaqafi] berkata, Aku mendengar [Jabir bin Samrah] berkata, \"Umar berkata kepada [Sa'd], \"Orang-orang banyak mengeluhkan tentangmu hingga dalam masalah shalat!\" Maka Sa'd menjelaskan, \"Dalam shalat aku selalu memanjangkan bacaan pada dua rakaat pertama dan aku pendekkan pada dua rakaat yang akhir. Dan tidak ada yang aku ubah dari apa yang aku dapat ambil dari Rasulullah shallallahu 'alaihi wasallam.\" 'Umar berkata, \"Kamu benar. Aku juga menganggap kamu seperti itu.\""},"729":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا سَيَّارُ بْنُ سَلَامَةَ قَالَدَخَلْتُ أَنَا وَأَبِي عَلَى أَبِي بَرْزَةَ الْأَسْلَمِيِّ فَسَأَلْنَاهُ عَنْ وَقْتِ الصَّلَوَاتِ فَقَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الظُّهْرَ حِينَ تَزُولُ الشَّمْسُ وَالْعَصْرَ وَيَرْجِعُ الرَّجُلُ إِلَى أَقْصَى الْمَدِينَةِ وَالشَّمْسُ حَيَّةٌ وَنَسِيتُ مَا قَالَ فِي الْمَغْرِبِ وَلَا يُبَالِي بِتَأْخِيرِ الْعِشَاءِ إِلَى ثُلُثِ اللَّيْلِ وَلَا يُحِبُّ النَّوْمَ قَبْلَهَا وَلَا الْحَدِيثَ بَعْدَهَا وَيُصَلِّي الصُّبْحَ فَيَنْصَرِفُ الرَّجُلُ فَيَعْرِفُ جَلِيسَهُ وَكَانَ يَقْرَأُ فِي الرَّكْعَتَيْنِ أَوْ إِحْدَاهُمَا مَا بَيْنَ السِّتِّينَ إِلَى الْمِائَةِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Sayyar bin Salamah] berkata, \"Aku dan bapakku datang menemui [Abu Barzah Al Aslami], lalu kami bertanya kepadanya tangtang waktu-waktu shalat.\" Dia lalu berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur ketika matahari sudah condong, shalat 'Ashar saat seseorang kembali ke ujung Kota Madinah sementara matahari masih panas, dan aku lupa apa yang dijelaskannya tentang shalat Maghrib. Dan tidak jarang Beliau mengakhirkan pelaksanaan shalat 'Isya hingga sepertiga malam yang akhir, beliau tidak menyukai tidur sebelum shalat Isya dan mengobrol sesudahnya. Dan Beliau melaksanakan shalat Shubuh pada waktu dimana bila sudah selesai, seseorang akan dapat mengenali siapa yang shalat di sampingnya. Beliau membaca surah dalam shalat Shubuh pada kedua rakaatnya, atau salah satunya kira-kira enam puluh hingga seratus ayat.\""},"730":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُفِي كُلِّ صَلَاةٍ يُقْرَأُ فَمَا أَسْمَعَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْمَعْنَاكُمْ وَمَا أَخْفَى عَنَّا أَخْفَيْنَا عَنْكُمْ وَإِنْ لَمْ تَزِدْ عَلَى أُمِّ الْقُرْآنِ أَجْزَأَتْ وَإِنْ زِدْتَ فَهُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku ['Atha] bahwa dia mendengar [Abu Hurairah] berkata, \"Pada setiap rakaat ada bacaannya. Apa yang Rasulullah shallallahu 'alaihi wasallam perdengarkan (keraskan) bacaannya kepada kami maka kamipun akan perdengarkan kepada kalian, dan apa yang Beliau sembunyikan (tidak mengeraskan bacaan) kepada kami, maka kamipun tidak mengeraskannya kepada kalian. Jika kalian tidak tambah selain Al Fatihah, maka itu sudah cukup. Namun bila kalian tambah setelahnya itu lebih baik.\""},"731":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ هُوَ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَانْطَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَائِفَةٍ مِنْ أَصْحَابِهِ عَامِدِينَ إِلَى سُوقِ عُكَاظٍ وَقَدْ حِيلَ بَيْنَ الشَّيَاطِينِ وَبَيْنَ خَبَرِ السَّمَاءِ وَأُرْسِلَتْ عَلَيْهِمْ الشُّهُبُ فَرَجَعَتْ الشَّيَاطِينُ إِلَى قَوْمِهِمْ فَقَالُوا مَا لَكُمْ فَقَالُوا حِيلَ بَيْنَنَا وَبَيْنَ خَبَرِ السَّمَاءِ وَأُرْسِلَتْ عَلَيْنَا الشُّهُبُ قَالُوا مَا حَالَ بَيْنَكُمْ وَبَيْنَ خَبَرِ السَّمَاءِ إِلَّا شَيْءٌ حَدَثَ فَاضْرِبُوا مَشَارِقَ الْأَرْضِ وَمَغَارِبَهَا فَانْظُرُوا مَا هَذَا الَّذِي حَالَ بَيْنَكُمْ وَبَيْنَ خَبَرِ السَّمَاءِ فَانْصَرَفَ أُولَئِكَ الَّذِينَ تَوَجَّهُوا نَحْوَ تِهَامَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِنَخْلَةَ عَامِدِينَ إِلَى سُوقِ عُكَاظٍ وَهُوَ يُصَلِّي بِأَصْحَابِهِ صَلَاةَ الْفَجْرِ فَلَمَّا سَمِعُوا الْقُرْآنَ اسْتَمَعُوا لَهُ فَقَالُوا هَذَا وَاللَّهِ الَّذِي حَالَ بَيْنَكُمْ وَبَيْنَ خَبَرِ السَّمَاءِ فَهُنَالِكَ حِينَ رَجَعُوا إِلَى قَوْمِهِمْ وَقَالُوا يَا قَوْمَنَا{ إِنَّا سَمِعْنَا قُرْآنًا عَجَبًا يَهْدِي إِلَى الرُّشْدِ فَآمَنَّا بِهِ وَلَنْ نُشْرِكَ بِرَبِّنَا أَحَدًا }فَأَنْزَلَ اللَّهُ عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ قُلْ أُوحِيَ إِلَيَّ أَنَّهُ اسْتَمَعَ نَفَرٌ مِنْ الْجِنِّ }وَإِنَّمَا أُوحِيَ إِلَيْهِ قَوْلُ الْجِنِّ","id":"Telah menceritakan kepada kami [Musadad] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] -dia adalah Ja'far bin Abu Wahsyiyyah- dari [Sa'id bin Jubair] dari ['Abdullah bin 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam bersama sekelompok sahabat berangkat menuju pasar 'Ukazh. Saat itu telah ada penghalang antara setan dan berita-berita langit dimana telah dikirim kabut kepada setan sebagai penghalang. Maka setan-setan kembali menemui kaumnya, lalu kaumnya berkata, \"Apa yang terjadi dengan kalian?\" Setan-setan tersebut menjawab, \"Telah ada penghalang antara kami dan berita-berita langit dengan dikirimnya kabut.\" Kaumnya berkata, \"Tidak ada penghalang antara kalian dan berita-berita langit kecuali telah ada sesuatu yang terjadi. Pergilah kalian ke seluruh penjuru timur bumi dan baratnya, lalu perhatikanlah apa penghalang yang ada antara kalian dan berita-berita langit!\" Maka berangkatlah setan-setan yang ada di Tihamah untuk mendatangi Nabi shallallahu 'alaihi wasallam dan para sahabat Beliau yang sedang berada di pasar 'Ukazh. Saat itu beliau dan para sahabat sedang melaksanakan shalat fajar. Ketika setan-setan itu mendengar Al Qur'an, mereka menyimaknya dengan baik hingga mereka pun berkata, \"Demi Allah, inilah yang menjadi penghalang antara kalian dan berita-berita langit.\" Dan perkataan ini pula yang disampaikan ketika mereka kembali kepada kaum mereka. Lantas mereka berkata kepada kaumnya, \"Wahai kaum kami, sesungguhnya kami telah mendengarkan Al Quran yang menakjubkan. (Yang) memberi petunjuk kepada jalan yang benar, lalu kami beriman kepadanya. Dan kami sekali-kali tidak akan mempersekutukan seseorangpun dengan Tuhan kami) ' (Qs. Al Jin: 1-2). Maka kemudian Allah menurunkan wahyu kepada Nabi-Nya shallallahu 'alaihi wasallam: '(Katakanlah (hai Muhammad): \"Telah diwahyukan kepadamu bahwasanya: telah mendengarkan sekumpulan jin (akan Al Qur'an)) ' (Qs. Al Jin: 1). Yakni diwahyukan kepada beliau perkataan jin.\""},"732":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا أُمِرَ وَسَكَتَ فِيمَا أُمِرَ{ وَمَا كَانَ رَبُّكَ نَسِيًّا }{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam membaca (dengan suara dikeraskan) sesuai apa yang diperintahkan dan juga diam (tidak mengeraskan) sesuai apa yang diperintahkan '(Dan tidaklah Rabbmu lupa) ' (Qs. Maryam: 64). '(Sesungguhnya telah ada pada diri Rasulullah itu suri teladan yang baik bagimu) ' (Qs. Al Ahzab: 21)."},"733":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا وَائِلٍ قَالَجَاءَ رَجُلٌ إِلَى ابْنِ مَسْعُودٍ فَقَالَ قَرَأْتُ الْمُفَصَّلَ اللَّيْلَةَ فِي رَكْعَةٍ فَقَالَ هَذًّا كَهَذِّ الشِّعْرِ لَقَدْ عَرَفْتُ النَّظَائِرَ الَّتِي كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُنُ بَيْنَهُنَّ فَذَكَرَ عِشْرِينَ سُورَةً مِنْ الْمُفَصَّلِ سُورَتَيْنِ فِي كُلِّ رَكْعَةٍ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] berkata, aku mendengar [Abu Wa'il] berkata, \"Seorang laki-laki datang kepada [Ibnu Mas'ud] lalu berkata, \"Tadi malam aku membaca surat-surat Al Musfashal dalam satu rakaat.\" Ibnu Mas'ud berkata, \"Hah! (cepat sekali kamu dalam membaca), ini seperti membaca syair! Sungguh aku mengetahui surah-surah sepadan (panjangnya) yang Nabi shallallahu 'alaihi wasallam gabungkan saat membaca.\" Ibnu Mas'ud kemudian menyebutkan dua puluh surah dari Al Mufashshal (yang dibaca oleh Nabi shallallahu 'alaihi wasallam), yakni dua surah untuk setiap rakaat.\" "},"734":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الظُّهْرِ فِي الْأُولَيَيْنِ بِأُمِّ الْكِتَابِ وَسُورَتَيْنِ وَفِي الرَّكْعَتَيْنِ الْأُخْرَيَيْنِ بِأُمِّ الْكِتَابِ وَيُسْمِعُنَا الْآيَةَ وَيُطَوِّلُ فِي الرَّكْعَةِ الْأُولَى مَا لَا يُطَوِّلُ فِي الرَّكْعَةِ الثَّانِيَةِ وَهَكَذَا فِي الْعَصْرِ وَهَكَذَا فِي الصُّبْحِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammam] dari [Yahya] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya], bahwa Nabi shallallahu 'alaihi wasallam dalam shalat Zhuhur membaca Al Fathihah dan dua surah pada dua rakaat pertama. Dan pada dua rakaat akhir membaca Al Fatihah, yang terkadang ayat yang beliau baca terdengar. Beliau memanjangkannya pada rakaat pertama, dan pada rakaat keduanya tidak sepanjang pada rakaat pertama. Beliau lakukan seperti ini juga dalam shalat 'Ashar, begitu pula pada shalat Shubuh.\""},"735":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ قُلْتُ لِخَبَّابٍأَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ نَعَمْ قُلْنَا مِنْ أَيْنَ عَلِمْتَ قَالَ بِاضْطِرَابِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Abu Ma'mar], aku bertanya kepada [Khabbab], \"Apakah Rasulullah shallallahu 'alaihi wasallam membaca surah dalam shalat Zhuhur dan 'Ashar?\" Dia menjawab, \"Ya.\" Kami tanyakan lagi, \"Bagaimana kamu bisa mengetahuinya?\" Dia menjawab, \"Dari gerakan jenggot Beliau.\""},"736":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ بِأُمِّ الْكِتَابِ وَسُورَةٍ مَعَهَا فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الظُّهْرِ وَصَلَاةِ الْعَصْرِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا وَكَانَ يُطِيلُ فِي الرَّكْعَةِ الْأُولَى","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Yahya bin Abu Katsir] telah menceritakan kepadaku ['Abdullah bin Abu Qatadah] dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam membaca Al Fathihah dan dua surah pada dua rakaat pertama dalam shalat Zhuhur dan 'Ashar. Terkadang beliau memperdengarkan (mengeraskan bacaan) ayat yang dibacanya, dan beliau biasa memanjangkannya pada rakaat pertama.\""},"737":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُطَوِّلُ فِي الرَّكْعَةِ الْأُولَى مِنْ صَلَاةِ الظُّهْرِ وَيُقَصِّرُ فِي الثَّانِيَةِ وَيَفْعَلُ ذَلِكَ فِي صَلَاةِ الصُّبْحِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya], bahwa Nabi shallallahu 'alaihi wasallam dalam shalat Zhuhur memanjangkan bacaan pada rakaat pertama dan memendekkannya pada rakaat kedua. Beliau lakukan pula seperti itu pada shalat Shubuh.\""},"738":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُمَا أَخْبَرَاهُ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّنَ الْإِمَامُ فَأَمِّنُوا فَإِنَّهُ مَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَقَالَ ابْنُ شِهَابٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ آمِينَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwa keduanya mengabarkan kepadanya dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika Imam membaca 'Amiin', maka bacalah 'Amiin', karena barangsiapa bacaan 'Amiin' nya bersamaan dengan bacaan Malaikat, maka dosanya yang telah lalu akan diampuni.\" Ibnu Syihab berkata, \"Rasulullah shallallahu 'alaihi wasallam juga membaca amin.\""},"739":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ أَحَدُكُمْ آمِينَ وَقَالَتْ الْمَلَائِكَةُ فِي السَّمَاءِ آمِينَ فَوَافَقَتْ إِحْدَاهُمَا الْأُخْرَى غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian 'Amiin' dan para Malaikat yang ada di langit juga membaca 'Amiin', lalu bacaan salah satunya bersamaan dengan bacaan yang lain, maka dosanya yang telah lalu akan diampuni.\""},"740":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ فَإِنَّهُ مَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِتَابَعَهُ مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنُعَيْمٌ الْمُجْمِرُ عَنْ أَبِي هُر��يْرَةَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Sumayya] mantan budak Abu Bakar, dari [Abu Shalih As Siman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Imam membaca GHAIRIL MAGHDLUUBI 'ALAIHIM WALADL DLAALLIIN, maka ucapkanlah 'AMIIN'. Karena siapa yang ucapan 'AMIIN' nya bersamaan dengan 'AMIIN' nya Malaikat, maka dosanya yang telah lalu akan diampuni.\" Hadits ini dikuatkan oleh [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, dan [Nu'aim Al Mujmir] dari [Abu Hurairah].\""},"741":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ الْأَعْلَمِ وَهُوَ زِيَادٌ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَأَنَّهُ انْتَهَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ رَاكِعٌ فَرَكَعَ قَبْلَ أَنْ يَصِلَ إِلَى الصَّفِّ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ زَادَكَ اللَّهُ حِرْصًا وَلَا تَعُدْ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammam] dari [Al A'lam] -yaitu Ziyad- dari [Al Hasan] dari [Abu Bakrah], bahwa dia pernah mendapati Nabi shallallahu 'alaihi wasallam sedang rukuk, maka dia pun ikut rukuk sebelum sampai ke dalam barisan shaf. Kemudian dia menceritakan kejadian tersebut kepada Nabi shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Semoga Allah menambah semangat kepadamu, namun jangan diulang kembali.\""},"742":{"ar":"حَدَّثَنَا إِسْحَاقُ الْوَاسِطِيُّ قَالَ حَدَّثَنَا خَالِدٌ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَصَلَّى مَعَ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ بِالْبَصْرَةِ فَقَالَ ذَكَّرَنَا هَذَا الرَّجُلُ صَلَاةً كُنَّا نُصَلِّيهَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَنَّهُ كَانَ يُكَبِّرُ كُلَّمَا رَفَعَ وَكُلَّمَا وَضَعَ","id":"Telah menceritakan kepada kami [Ishaq Al Wasithi] berkata, telah menceritakan kepada kami [Khalid] dari [Al Jurairi] dari [Abu Al A'la] dari [Mutharrif] dari ['Imran bin Hushain] berkata, \"Dia shalat bersama 'Ali? radliallahu 'anhu di Bashrah. Lalu ia berkata, \"Orang ini mengingatkan kami tentang shalat yang kami lakukan bersama Rasulullah shallallahu 'alaihi wasallam. Dia menyebutkan bahwa Beliau bertakbir setiap mengangkat tangan dan setiap menurunkan tangan.\""},"743":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّهُ كَانَ يُصَلِّي بِهِمْ فَيُكَبِّرُ كُلَّمَا خَفَضَ وَرَفَعَ فَإِذَا انْصَرَفَ قَالَ إِنِّي لَأَشْبَهُكُمْ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah], bahwa dia shalat mengimami para sahabat, Abu Hurairah lalu takbir setiap menurunkan tangan dan setiap mengangkat tangan. Selesai shalat ia berkata, \"Sungguh, aku adalah orang yang shalatnya paling mirip dengan Rasulullah shallallahu 'alaihi wasallam daripada kalian semua.\""},"744":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ قَالَصَلَّيْتُ خَلْفَ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ أَنَا وَعِمْرَانُ بْنُ حُصَيْنٍ فَكَانَ إِذَا سَجَدَ كَبَّرَ وَإِذَا رَفَعَ رَأْسَهُ كَبَّرَ وَإِذَا نَهَضَ مِنْ الرَّكْعَتَيْنِ كَبَّرَ فَلَمَّا قَضَى الصَّلَاةَ أَخَذَ بِيَدِي عِمْرَانُ بْنُ حُصَيْنٍ فَقَالَ قَدْ ذَكَّرَنِي هَذَا صَلَاةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ لَقَدْ صَلَّى بِنَا صَلَاةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Hammad] dari [Ghailan bin Jarir] dari [Mutharrif bin 'Abdullah] berkata, \"Aku dan 'Imran bin Hushain shalat di belakang 'Ali bin Abu Thalib? radliallahu 'anhu. Ali bertakbir ketika sujud, ketika mengangkat kepalanya, dan ketika bangkit dari dua rakaat (menuju rakaat tiga). Selesai ['Imran bin Hushain] memegang tanganku seraya berkata, \"Sunguh dia telah mengingatkan aku tentang shalatnya Muhammad shallallahu 'alaihi wasallam.\" Atau dia berkata, \"Sungguh dia telah shalat bersama kami dengan shalatnya Muhammad shallallahu 'alaihi wasallam.\""},"745":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ عِكْرِمَةَ قَالَرَأَيْتُ رَجُلًا عِنْدَ الْمَقَامِ يُكَبِّرُ فِي كُلِّ خَفْضٍ وَرَفْعٍ وَإِذَا قَامَ وَإِذَا وَضَعَ فَأَخْبَرْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُ قَالَ أَوَلَيْسَ تِلْكَ صَلَاةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أُمَّ لَكَ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] berkata, telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari ['Ikrimah] berkata, \"Aku melihat seseorang shalat di dekat Maqam (Masjidil Haram), lalu dia bertakbir pada setiap menurunkan tangan, setiap mengangkat tangan dan ketika berdiri dan turun.\" Aku lalu kabarkan hal itu kepada [Ibnu 'Abbas] radliallahu 'anhu, maka ia berkata, \"Bagaimana kamu ini, bukankah memang begitu caranya Nabi shallallahu 'alaihi wasallam melaksanakan shalatnya!\""},"746":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ قَالَصَلَّيْتُ خَلْفَ شَيْخٍ بِمَكَّةَ فَكَبَّرَ ثِنْتَيْنِ وَعِشْرِينَ تَكْبِيرَةً فَقُلْتُ لِابْنِ عَبَّاسٍ إِنَّهُ أَحْمَقُ فَقَالَ ثَكِلَتْكَ أُمُّكَ سُنَّةُ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ مُوسَى حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا عِكْرِمَةُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah mengabarkan kepada kami [Hammam] dari [Qatadah] dari ['Ikrimah] berkata, \"Aku shalat di belakang seorang syaikh di Makkah. Orang itu bertakbir sejumlah dua puluh dua kali. Lalu aku katakan kepada Ibnu Abbas, 'Betapa bodohnya orangitu!\" Maka [Ibnu 'Abbas] pun berkata, \"Celaka kamu. Sungguh dia telah mempraktekkan sunnah yang dicontohlan oleh Abu Al Qasim shallallahu 'alaihi wasallam.\" [Musa] berkata, telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami ['Ikrimah]."},"747":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ يُكَبِّرُ حِينَ يَقُومُ ثُمَّ يُكَبِّرُ حِينَ يَرْكَعُ ثُمَّ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ حِينَ يَرْفَعُ صُلْبَهُ مِنْ الرَّكْعَةِ ثُمَّ يَقُولُ وَهُوَ قَائِمٌ رَبَّنَا لَكَ الْحَمْدُقَالَ عَبْدُ اللَّهِ بْنُ صَالِحٍ عَنْ اللَّيْثِ وَلَكَ الْحَمْدُ ثُمَّ يُكَبِّرُ حِينَ يَهْوِي ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأْسَهُ ثُمَّ يُكَبِّرُ حِينَ يَسْجُدُ ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأْسَهُ ثُمَّ يَفْعَلُ ذَلِكَ فِي الصَّلَاةِ كُلِّهَا حَتَّى يَقْضِيَهَا وَيُكَبِّرُ حِينَ يَقُومُ مِنْ الثِّنْتَيْنِ بَعْدَ الْجُلُوسِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Abu Bakar bin 'Abdurrahman] bahwa dia mendengar [Abu Hurairah] berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam shalat, beliau takbir saat memulai berdiri (takbiratul Ikram), kemudian ketika akan rukuk sambil membaca: 'SAMI'ALLAHU LIMAN HAMIDAH (semoga Allah mendengar orang yang memuji-Nya) ' ketika mengangkat punggungnya dari rukuk, dalam saat posisi berdiri baliau membaca: RABBANAA LAKAL HAMDU (Ya Rabb kami, milik-Mu lah segala pujian) '.\" ['Abdullah bin Shalih] dari [Al Laits] menyebutkan, 'WA LAKAL HAMDU', kemudian bertakbir ketika turun (sujud), kemudian bertakbir ketika mengangkat kepala (dari sujud), lalu bertakbir ketika sujud dan ketika mengangkat kepalanya (dari sujud), kemudian Beliau melakukan seperti itu dalam shalat seluruhnya hingga selesai. Dan beliau juga bertakbir ketika bangkit dari dua rakaat setelah duduk (tasyahud awal).\""},"748":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي يَعْفُورٍ قَالَ سَمِعْتُ مُصْعَبَ بْنَ سَعْدٍ يَقُولُصَلَّيْتُ إِلَى جَنْبِ أَبِي فَطَبَّقْتُ بَيْنَ كَفَّيَّ ثُمَّ وَضَعْتُهُمَا بَيْنَ فَخِذَيَّ فَنَهَانِي أَبِي وَقَالَ كُنَّا نَفْعَلُهُ فَنُهِينَا عَنْهُ وَأُمِرْنَا أَنْ نَضَعَ أَيْدِينَا عَلَى الرُّكَبِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ya'fur] berkata, Aku mendengar [Mush'ab bin Sa'd] berkata, \"Aku shalat di samping [ayahku], lalu aku rapatkan tanganku dan aku letakkan di atas pahaku. Maka ayahku pun melarangnya seraya berkata, \"Kami pernah mengerjakan seperti itu lalu kami dilarang (oleh Nabi shallallahu 'alaihi wasallam), dan kami diperintahkan untuk meletakkan tangan kami pada lutut-lutut kami.\""},"749":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ قَالَ رَأَى حُذَيْفَةُرَجُلًا لَا يُتِمُّ الرُّكُوعَ وَالسُّجُودَ قَالَ مَا صَلَّيْتَ وَلَوْ مُتَّ مُتَّ عَلَى غَيْرِ الْفِطْرَةِ الَّتِي فَطَرَ اللَّهُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] berkata, \"Aku mendengar [Zaid bin Wahb] berkata, \" [Hudzaifah] melihat seseorang shalat namun tidak menyempurnakan rukuk dan sujudnya. Maka dia berkata, \"Kamu belum shalat. Seandainya kamu meninggal dunia, maka kamu mati dalam keadaan di luar fithrah (agama), padahal Allah telah menciptakan Muhammad shallallahu 'alaihi wasallam berada diatasnya.\""},"750":{"ar":"حَدَّثَنَا بَدَلُ بْنُ الْمُحَبَّرِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي الْحَكَمُ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ قَالَكَانَ رُكُوعُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسُجُودُهُ وَبَيْنَ السَّجْدَتَيْنِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ مَا خَلَا الْقِيَامَ وَالْقُعُودَ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah menceritakan kepada kami [Badal bin Al Muhabbar] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku [Al Hakam] dari [Ibnu Abu Laila] dari [Al Bara'] berkata, \"Rukuk Nabi shallallahu 'alaihi wasallam, sujudnya, (duduk) antara dua sujud, dan ketika mengangkat kepala dari rukuk, tidaklah berbeda antara berdiri (i'tidal) dan duduknya melainkan semuanya sama (dalam thu'maninah).\""},"751":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ أَخْبَرَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَدَخَلَ رَجُلٌ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِ السَّلَامَ فَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ ثَلَاثًا فَقَالَ وَالَّذِي بَعَثَكَ بِالْحَقِّ فَمَا أُحْسِنُ غَيْرَهُ فَعَلِّمْنِي قَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَكَبِّرْ ثُمَّ اقْرَأْ مَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ افْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah mengabarkan kepadaku [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah menceritakan kepada kami [Sa'id Al Maqburi] dari [Bapaknya] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam masuk ke dalam Masjid, lalu ada seorang laki-laki masuk ke dalam Masjid dan shalat, kemudian orang itu datang dan memberi salam kepada Nabi shallallahu 'alaihi wasallam. Lalu Nabi shallallahu 'alaihi wasallam menjawab salamnya kemudian bersabda: \"Kembali dan ulangilah shalatmu, karena kamu belum shalat!\" Orang itu kemudian mengulangi shalat dan kembali datang menghadap kepada Nabi shallallahu 'alaihi wasallam sambil memberi salam. Namun beliau kembali bersabda: \"Kembali dan ulangilah shalatmu karena kamu belum shalat!\" Beliau memerintahkan orang ini sampai tiga kali dan akhirnya, sehingga ia berkata, \"Demi Dzat yang mengutus tuan dengan kebenaran, aku tidak bisa melakukan yang lebih baik dari itu. Maka ajarilah aku.\" Beliau pun bersabda: \"Jika kamu mengerjakan shalat maka bertakbirlah, lalu bacalah ayat yang mudah dari Al Qur'an. Kemudian rukuklah hingga benar-benar rukuk dengan tenang, lalu bangkitlah (dari rukuk) hingga kamu berdiri tegak, setelah itu sujudlah sampai benar-benar sujud, lalu angkat (kepalamu) untuk duduk hingga benar-benar duduk, Setelah itu sujudlah sampai benar-benar sujud, Kemudian lakukanlah seperti cara tersebut di seluruh shalat (rakaat) mu.\""},"752":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Adl Dluha] dari [Masruq] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam membaca do'a dalam rukuk dan sujudnya dengan bacaan: \"SUBHAANAKALLAHUMMA RABBANAA WA BIHAMDIKA ALLAHUMMAGHFIRLII (Maha suci Engkau wahai Tuhan kami, segala pujian bagi-Mu. Ya Allah, ampunilah aku) '.\""},"753":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ يُكَبِّرُ وَإِذَا قَامَ مِنْ السَّجْدَتَيْنِ قَالَ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam membaca: 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya) ', maka beliau melanjutkan dengan: 'RABBANAA WA LAKAL HAMDU (Wahai Rabb kami, bagi-Mu lah segala pujian) '. Jika Nabi shallallahu 'alaihi wasallam rukuk dan mengangkat kepalanya (dari sujud), beliau bertakbir, dan jika bangkit dari dua sujud (dua rakaat), beliau mengucapkan 'Allahu Akbar'.\""},"754":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ فَإِنَّهُ مَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Imam mengucapkan 'SAMI'ALLAHU LIMAN HAMIDAH (semoga Allah mendengar pujian orang yang memuji-Nya) ', maka ucapkanlah: 'ALLAHUMMA RABBANAA LAKAL HAMDU (Wahai Rabb kami, bagi-Mu lah segala pujian) '.\" Karena barangsiapa yang ucapannya bersamaan dengan ucapan Malaikat, maka dosanya yang telah lalu akan diampuni.\""},"755":{"ar":"بَاب حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَأُقَرِّبَنَّ صَلَاةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقْنُتُ فِي الرَّكْعَةِ الْآخِرَةِ مِنْ صَلَاةِ الظُّهْرِ وَصَلَاةِ الْعِشَاءِ وَصَلَاةِ الصُّبْحِ بَعْدَ مَا يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَيَدْعُو لِلْمُؤْمِنِينَ وَيَلْعَنُ الْكُفَّارَ","id":"Bab. Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] berkata, \"Aku akan contohkan shalatnya Nabi shallallahu 'alaihi wasallam.\" Abu Hurairah? radliallahu 'anhu membaca do'a qunut pada rakaat terakhir dalam shalat Zhuhur, shalat 'Isya dan shalat Shubuh setelah mengucapkan 'SAMI'ALLAHU LIMAN HAMIDAH (semoga Allah mendengar pujian orang yang memuji-Nya) '.\" Maka dia mendo'akan Kaum Mu'minin dan melaknat orang-orang kafir.\""},"756":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ الْقُنُوتُ فِي الْمَغْرِبِ وَالْفَجْرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Al Aswad] berkata, telah menceritakan kepada kami [Isma'il] dari [Khalid Al Hadzdza'] dari [Abu Qilabah] dari [Anas bin Malik] radliallahu 'anhu berkata, \"Doa qunut itu ada dalam shalat Maghrib dan Shubuh.\""},"757":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ قَالَكُنَّا يَوْمًا نُصَلِّي وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَهُ رَبَّنَا وَلَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ قَالَ مَنْ الْمُتَكَلِّمُ قَالَ أَنَا قَالَ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Nu'aim bin 'Abdullah Al Mujmir] dari ['Ali bin Yahya bin Khallad Az Zuraqi] dari [Bapaknya] dari [Rifa'ah bin Rafi' Az Zuraqi] berkata, \"Pada suatu hari kami shalat di belakang Nabi shallallahu 'alaihi wasallam. Ketika mengangkat kepalanya dari rukuk beliau mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar punjian orang yang memuji-Nya) '. Kemudian ada seorang laki-laki yang berada di belakang beliau membaca; 'RABBANAA WA LAKAL HAMDU HAMDAN KATSIIRAN THAYYIBAN MUBAARAKAN FIIHI (Wahai Tuhan kami, bagi-Mu segala pujian, aku memuji-Mu dengan pujian yang banyak, yang baik dan penuh berkah) '.\" Selesai shalat beliau bertanya: \"Siapa orang yang membaca kalimat tadi?\" Orang itu menjawab, \"Saya.\" Beliau bersabda: \"Aku melihat lebih dari tiga puluh Malaikat berebut siapa di antara mereka yang lebih dahulu untuk menuliskan kalimat tersebut.\""},"758":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ قَالَ كَانَ أَنَسٌيَنْعَتُ لَنَا صَلَاةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يُصَلِّي وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَامَ حَتَّى نَقُولَ قَدْ نَسِيَ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Tsabit] berkata, \" [Anas] pernah menceritakan sifat shalat Nabi shallallahu 'alaihi wasallam kepada kami, jika beliau shalat dan mengangkat kepalanya dari rukuk, maka beliau berdiri (lama) hingga kami mengatakan 'beliau telah lupa'.\""},"759":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رُكُوعُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسُجُودُهُ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَبَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dari [Al Bara'] berkata, \"Rukuknya Nabi shallallahu 'alaihi wasallam, sujudnya dan ketika mengangkat kepala dari rukuk, serta duduk antara dua sujud, semuanya hampir sama (lama dan thunam'ninah).\""},"760":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ كَانَ مَالِكُ بْنُ الْحُوَيْرِثِيُرِينَا كَيْفَ كَانَ صَلَاةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَاكَ فِي غَيْرِ وَقْتِ صَلَاةٍ فَقَامَ فَأَمْكَنَ الْقِيَامَ ثُمَّ رَكَعَ فَأَمْكَنَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَنْصَبَ هُنَيَّةً قَالَ فَصَلَّى بِنَا صَلَاةَ شَيْخِنَا هَذَا أَبِي بُرَيْدٍ وَكَانَ أَبُو بُرَيْدٍ إِذَا رَفَعَ رَأْسَهُ مِنْ السَّجْدَةِ الْآخِرَةِ اسْتَوَى قَاعِدًا ثُمَّ نَهَضَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] berkata, \" [Malik bin Al Huwirits] pernah memperlihatkan kepada kami tata cara shalat Rasulullah shallallahu 'alaihi wasallam. Ia lakukan itu bukan pas waktu shalat. Dia lalu berdiri hingga dengan thuma'ninah, lalu rukuk dengan thuma'ninah, lalu mengangkat kepalanya dan berdiam diri sejenak, kemudian dia berkata, \"Guru (syaikh) kami ini Abu Buraid pernah shalat memimpin kami.\" Jika Abu Buraid mengangkat kepalanya dari sujud yang akhir, maka dia duduk dengan lurus sejenak lalu bangkit berdiri.\""},"761":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَكَانَ يُكَبِّرُ فِي كُلِّ صَلَاةٍ مِنْ الْمَكْتُوبَةِ وَغَيْرِهَا فِي رَمَضَانَ وَغَيْرِهِ فَيُكَبِّرُ حِينَ يَقُومُ ثُمَّ يُكَبِّرُ حِينَ يَرْكَعُ ثُمَّ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ يَقُولُ رَبَّنَا وَلَكَ الْحَمْدُ قَبْلَ أَنْ يَسْجُدَ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ حِينَ يَهْوِي سَاجِدًا ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأْسَهُ مِنْ السُّجُودِ ثُمَّ يُكَبِّرُ حِينَ يَسْجُدُ ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأْسَهُ مِنْ السُّجُودِ ثُمَّ يُكَبِّرُ حِينَ يَقُومُ مِنْ الْجُلُوسِ فِي الِاثْنَتَيْنِ وَيَفْعَلُ ذَلِكَ فِي كُلِّ رَكْعَةٍ حَتَّى يَفْرُغَ مِنْ الصَّلَاةِ ثُمَّ يَقُولُ حِينَ يَنْصَرِفُ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَقْرَبُكُمْ شَبَهًا بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَتْ هَذِهِ لَصَلَاتَهُ حَتَّى فَارَقَ الدُّنْيَا","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Abu Bakar bin 'Abdurrahman bin Al Harits bin Hisyam] dan [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] bertakbir dalam setiap shalat yang wajib dan yang lainnya baik pada bulan Ramadan maupun di luar Ramadan. Dia bertakbir ketika berdiri dan ketika akan rukuk, kemudian dia mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya) ', kemudian sebelum sujud dia membaca: 'RABBANAA WA LAKAL HAMDU (Wahai Rabb kami, bagi-Mu segala puji) ', lalu mengucapkan: 'Allahu Akbar' ketika akan turun sujud. Kemudian bertakbir ketika mengangkat kepalanya dari sujud, kemudian bertakbir lagi ketika akan sujud, kemudian bertakbir ketika mengangkat kepalanya dari sujud, dan ketika bangkit berdiri dari duduk setelah dua rakaat (tasyahud awal) ia juga bertakbir kembali. Dan dalam setiap rakaat shalat dia mengerjakan seperti itu, lalu setelah selesai ia berkata, \"Demi Dzat yang jiwaku berada di tangan-Nya, sungguh aku telah mencontohkan kepada kalian shalat seperti shalatnya Rasulullah shallallahu 'alaihi wasallam. Sungguh inilah cara shalatnya hingga beliau meninggalkan dunia ini.\""},"762":{"ar":"قَالَا وَقَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُوَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ يَرْفَعُ رَأْسَهُ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ يَدْعُو لِرِجَالٍ فَيُسَمِّيهِمْ بِأَسْمَائِهِمْ فَيَقُولُ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا عَلَيْهِمْ سِنِينَ كَسِنِي يُوسُفَوَأَهْلُ الْمَشْرِقِ يَوْمَئِذٍ مِنْ مُضَرَ مُخَالِفُونَ لَهُ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya) keduanya berkata; [Abu Hurairah] radliallahu 'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam ketika mengangkat kepalanya dari rukuk sambil mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH, RABBANAA WA LAKAL HAMDU (Semoga Allah mendengar pujian orang yang memuji-Nya. Wahai Rabb kami, dan milik-Mu lah segala pujian) ', kemudian beliau berdo'a: \"Ya Allah, selamatkanlah Al Walid bin Al Walid, Salamah bin Hisyam, 'Ayyasy bin Abu Rabi'ah orang-orang lemah dari kaum Mukminin. Ya Allah, timpakanlah kerasnya siksa-Mu kepada Mudlar dan jadikanlah siksa-Mu untuk mereka berupa paceklik seperti paceklik yang terjadi pada zaman Nabi Yusuf.\" Pada waktu itu, orang-orang penduduk Masyriq menyelisih atau menentang Mudlar.\""},"763":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ غَيْرَ مَرَّةٍ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُسَقَطَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ فَرَسٍ وَرُبَّمَا قَالَ سُفْيَانُ مِنْ فَرَسٍ فَجُحِشَ شِقُّهُ الْأَيْمَنُ فَدَخَلْنَا عَلَيْهِ نَعُودُهُ فَحَضَرَتْ الصَّلَاةُ فَصَلَّى بِنَا قَاعِدًا وَقَعَدْنَاوَقَالَ سُفْيَانُ مَرَّةً صَلَّيْنَا قُعُودًا فَلَمَّا قَضَى الصَّلَاةَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ وَإِذَا سَجَدَ فَاسْجُدُوا قَالَ سُفْيَانُ كَذَا جَاءَ بِهِ مَعْمَرٌ قُلْتُ نَعَمْ قَالَ لَقَدْ حَفِظَ كَذَا قَالَ الزُّهْرِيُّ وَلَكَ الْحَمْدُ حَفِظْتُ مِنْ شِقِّهِ الْأَيْمَنِ فَلَمَّا خَرَجْنَا مِنْ عِنْدِ الزُّهْرِيِّ قَالَ ابْنُ جُرَيْجٍ وَأَنَا عِنْدَهُ فَجُحِشَ سَاقُهُ الْأَيْمَنُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] tidak hanya sekali dari [Az Zuhri] berkata, \"Aku mendengar [Anas bin Malik] radliallahu 'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam terjatuh dari kudanya, dimungkinkan Sufyan juga menyebutkan, \"Beliau jatuh dari kudanya hingga bagian lambung kananannya terluka. Lalu kami pun menjenguk beliau, tidak lama kemudian masuk waktu shalat, beliau lalu shalat mengimami kami sambil duduk, kemudian kami shalat di belakangnya dengan duduk.\" Sekali waktu waktu Sufyan menyebutkan, \"Kami shalat dengan duduk. Setalah selesai shalat beliau bersabda: \"Hanyasanya dijadikannya imam adalah agar diikuti, jika dia takbir maka takbirlah, jika dia rukuk maka rukuklah, jika ia mengangkat kepala maka angkatlah kepala kalian, dan jika ia mengucapkan 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya) ', maka ucapkanlah oleh kalian 'RABBANAA WA LAKAL HAMDU (Ya Rabb kami, milik Engkaulah segala pujian) '. Dan jika dia sujud maka sujudlah kalian.\" Sufyan berkata, \"Apakah begitu yang dibawa oleh Ma'mar? Aku jawab, \"Ya.\" Lalu Sufyan berkata, \"Sungguh dia telah menjaga (memelihara) masalah ini.\" Az Zuhri berkata, \"Segala puji bagi Engkau ya Allah. Sungguh aku masih ingat bahwa beliau terhempas pada bagian kanan lambungnya.\" Setelah kami berpisah dari Az Zuhri, [Ibnu Juraij] berkata, \"Saat itu aku ada di sisi beliau, lalu terjatuhlah beliau pada lambung bagian kanannya.\""},"764":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَعَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُمَاأَنَّ النَّاسَ قَالُوا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُمَارُونَ فِي الْقَمَرِ لَيْلَةَ الْبَدْرِ لَيْسَ دُونَهُ سَحَابٌ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ فَهَلْ تُمَارُونَ فِي الشَّمْسِ لَيْسَ دُونَهَا سَحَابٌ قَالُوا لَا قَالَ فَإِنَّكُمْ تَرَوْنَهُ كَذَلِكَ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ فَيَقُولُ مَنْ كَانَ يَعْبُدُ شَيْئًا فَلْيَتَّبِعْ فَمِنْهُمْ مَنْ يَتَّبِعُ الشَّمْسَ وَمِنْهُمْ مَنْ يَتَّبِعُ الْقَمَرَ وَمِنْهُمْ مَنْ يَتَّبِعُ الطَّوَاغِيتَ وَتَبْقَى هَذِهِ الْأُمَّةُ فِيهَا مُنَافِقُوهَا فَيَأْتِيهِمْ اللَّهُ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ هَذَا مَكَانُنَا حَتَّى يَأْتِيَنَا رَبُّنَا فَإِذَا جَاءَ رَبُّنَا عَرَفْنَاهُ فَيَأْتِيهِمْ اللَّهُ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَيَدْعُوهُمْ فَيُضْرَبُ الصِّرَاطُ بَيْنَ ظَهْرَانَيْ جَهَنَّمَ فَأَكُونُ أَوَّلَ مَنْ يَجُوزُ مِنْ الرُّسُلِ بِأُمَّتِهِ وَلَا يَتَكَلَّمُ يَوْمَئِذٍ أَحَدٌ إِلَّا الرُّسُلُ وَكَلَامُ الرُّسُلِ يَوْمَئِذٍ اللَّهُمَّ سَلِّمْ سَلِّمْ وَفِي جَهَنَّمَ كَلَالِيبُ مِثْلُ شَوْكِ السَّعْدَانِ هَلْ رَأَيْتُمْ شَوْكَ السَّعْدَانِ قَالُوا نَعَمْ قَالَ فَإِنَّهَا مِثْلُ شَوْكِ السَّعْدَانِ غَيْرَ أَنَّهُ لَا يَعْلَمُ قَدْرَ عِظَمِهَا إِلَّا اللَّهُ تَخْطَفُ النَّاسَ بِأَعْمَالِهِمْ فَمِنْهُمْ مَنْ يُوبَقُ بِعَمَلِهِ وَمِنْهُمْ مَنْ يُخَرْدَلُ ثُمَّ يَنْجُو حَتَّى إِذَا أَرَادَ اللَّهُ رَحْمَةَ مَنْ أَرَادَ مِنْ أَهْلِ النَّارِ أَمَرَ اللَّهُ الْمَلَائِكَةَ أَنْ يُخْرِجُوا مَنْ كَانَ يَعْبُدُ اللَّهَ فَيُخْرِجُونَهُمْ وَيَعْرِفُونَهُمْ بِآثَارِ السُّجُودِ وَحَرَّمَ اللَّهُ عَلَى النَّارِ أَنْ تَأْكُلَ أَثَرَ السُّجُودِ فَيَخْرُجُونَ مِنْ النَّارِ فَكُلُّ ابْنِ آدَمَ تَأْكُلُهُ النَّارُ إِلَّا أَثَرَ السُّجُودِ فَيَخْرُجُونَ مِنْ النَّارِ قَدْ امْتَحَشُوا فَيُصَبُّ عَلَيْهِمْ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ ثُمَّ يَفْرُغُ اللَّهُ مِنْ الْقَضَاءِ بَيْنَ الْعِبَادِ وَيَبْقَى رَجُلٌ بَيْنَ الْجَنَّةِ وَالنَّارِ وَهُوَ آخِرُ أَهْلِ النَّارِ دُخُولًا الْجَنَّةَ مُقْبِلٌ بِوَجْهِهِ قِبَلَ النَّارِ فَيَقُولُ يَا رَبِّ اصْرِفْ وَجْهِي عَنْ النَّارِ قَدْ قَشَبَنِي رِيحُهَا وَأَحْرَقَنِي ذَكَاؤُهَا فَيَقُولُ هَلْ عَسَيْتَ إِنْ فُعِلَ ذَلِكَ بِكَ أَنْ تَسْأَلَ غَيْرَ ذَلِكَ فَيَقُولُ لَا وَعِزَّتِكَ فَيُعْطِي اللَّهَ مَا يَشَاءُ مِنْ عَهْدٍ وَمِيثَاقٍ فَيَصْرِفُ اللَّهُ وَجْهَهُ عَنْ النَّارِ فَإِذَا أَقْبَلَ بِهِ عَلَى الْجَنَّةِ رَأَى بَهْجَتَهَا سَكَتَ مَا شَاءَ اللَّهُ أَنْ يَسْكُتَ ثُمَّ قَالَ يَا رَبِّ قَدِّمْنِي عِنْدَ بَابِ الْجَنَّةِ فَيَقُولُ اللَّهُ لَهُ أَلَيْسَ قَدْ أَعْطَيْتَ الْعُهُودَ وَالْمِيثَاقَ أَنْ لَا تَسْأَلَ غَيْرَ الَّذِي كُنْتَ سَأَلْتَ فَيَقُولُ يَا رَبِّ لَا أَكُونُ أَشْقَى خَلْقِكَ فَيَقُولُ فَمَا عَسَيْتَ إِنْ أُعْطِيتَ ذَلِكَ أَنْ لَا تَسْأَلَ غَيْرَهُ فَيَقُولُ لَا وَعِزَّتِكَ لَا أَسْأَلُ غَيْرَ ذَلِكَ فَيُعْطِي رَبَّهُ مَا شَاءَ مِنْ عَهْدٍ وَمِيثَاقٍ فَيُقَدِّمُهُ إِلَى بَابِ الْجَنَّةِ فَإِذَا بَلَغَ بَابَهَا فَرَأَى زَهْرَتَهَا وَمَا فِيهَا مِنْ النَّضْرَةِ وَالسُّرُورِ فَيَسْكُتُ مَا شَاءَ اللَّهُ أَنْ يَسْكُتَ فَيَقُولُ يَا رَبِّ أَدْخِلْنِي الْجَنَّةَ فَيَقُولُ اللَّهُ وَيْحَكَ يَا ابْنَ آدَمَ مَا أَغْدَرَكَ أَلَيْسَ قَدْ أَعْطَيْتَ الْعُهُودَ وَالْمِيثَاقَ أَنْ لَا تَسْأَلَ غَيْرَ الَّذِي أُعْطِيتَ فَيَقُولُ يَا رَبِّ لَا تَجْعَلْنِي أَشْقَى خَلْقِكَ فَيَضْحَكُ اللَّهُ عَزَّ وَجَلَّ مِنْهُ ثُمَّ يَأْذَنُ لَهُ فِي دُخُولِ الْجَنَّةِ فَيَقُولُ تَمَنَّ فَيَتَمَنَّى حَتَّى إِذَا انْقَطَعَ أُمْنِيَّتُهُ قَالَ اللَّهُ عَزَّ وَجَلَّ مِنْ كَذَا وَكَذَا أَقْبَلَ يُذَكِّرُهُ رَبُّهُ حَتَّى إِذَا انْتَهَتْ بِهِ الْأَمَانِيُّ قَالَ اللَّهُ تَعَالَى لَكَ ذَلِكَ وَمِثْلُهُ مَعَهُقَالَ أَبُو سَعِيدٍ الْخُدْرِيُّ لِأَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ لَكَ ذَلِكَ وَعَشَرَةُ أَمْثَالِهِ قَالَ أَبُو هُرَيْرَةَ لَمْ أَحْفَظْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا قَوْلَهُ لَكَ ذَلِكَ وَمِثْلُهُ مَعَهُ قَالَ أَبُو سَعِيدٍ إِنِّي سَمِعْتُهُ يَقُولُ ذَلِكَ لَكَ وَعَشَرَةُ أَمْثَالِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan ['Atha' bin Yazid Al Laitsi] bahwa [Abu Hurairah] mengabarkan kepada keduanya, bahwa orang-orang berkata, \"Wahai Rasulullah, apakah kita akan melihat Rabb kita pada hari kiamat nanti?\" Beliau menjawab: \"Apakah kalian dapat membantah (bahwa kalian dapat melihat) bulan pada malam purnama, bila tidak ada awan yang menghalanginya?\" Mereka menjawab, \"Tidak, wahai Rasulullah.\" Beliau bertanya lagi: \"Apakah kalian dapat membantah (bahwa kalian dapat melihat) matahari, bila tidak ada awan yang menghalanginya?\" Mereka menjawab, \"Tidak.\" Beliau lantas bersabda: \"Sungguh kalian akan dapat melihat-Nya seperti itu juga. Manusia akan dikumpulkan pada hari kiamat, lalu Allah Subhaanahu Wa Ta'ala berfirman: 'Barangsiapa menyembah seseuatu, maka ia akan ikut dengannya.' Maka di antara mereka ada yang mengikuti matahari, di antara mereka ada yang mengikuti bulan dan di antara mereka ada pula yang mengikuti thaghut-thaghut. Maka tinggallah ummat ini, yang diantaranya ada para munafiknya. Maka Allah mendatangi mereka dan lalu berfirman: 'Aku adalah Rabb kalian.' Mereka berkata, 'Inilah tempat kedudukan kami hingga datang Rabb kami. Apabila Rabb kami telah datang pasti kami mengenalnya.' Maka Allah mendatangi mereka seraya berfirman: 'Akulah Rabb kalian.' Allah kemudian memanggil mereka, lalu dibentangkanlah Ash Shirath di atas neraka Jahannam. Dan akulah orang yang pertama berhasil melewatinya di antara para Rasul bersama ummatnya. Pada hari itu tidak ada seorangpun yang dapat berbicara kecuali para Rasul, dan ucapan para Rasul adalah: 'Ya Allah selamatkanlah, selamatkanlah.' Dan di dalam Jahannam ada besi yang ujungnya bengkok seperti duri Sa'dan (tumbuhan yang berduri tajam). Pernahkah kalian melihat duri Sa'dan?\" Mereka menjawab: \"Ya, pernah.\" Beliau melanjutkan: \"Sungguh dia seperti duri Sa'dan, hanya saja tidak ada yang mengetahui ukuran besarnya duri tersebut kecuali Allah. Duri tersebut akan menusuk-nusuk manusia berdasarkan amal amal mereka. Di antara mereka ada yang dikoyak-koyak hingga binasa disebabkan amalnya, ada pula yang dipotong-potong kemudian selamat melewatinya. Hingga apabila Allah berkehendak memberikan rahmat-Nya bagi siapa yang dikehendaki-Nya dari penghuni neraka, maka Allah memerintahkan Malaikat untuk mengeluarkan siapa saja yang pernah menyembah Allah. Maka para Malikat mengeluarkan mereka, yang mereka dikenal berdasarkan tanda bekas-bekas sujud (atsarus sujud). Dan Allah telah mengharamkan kepada neraka untuk memakan (membakar) atsarus sujud, lalu keluarlah mereka dari neraka. Setiap anak keturunan Adam akan dibakar oleh neraka kecuali mereka yang memiliki atsarus sujud. Maka mereka keluar dalam keadaan sudah hangus terbakar (gosong), lalu mereka disiram dengan air kehidupan kemudian jadilah mereka tumbuh seperti tumbuhnya benih di tepian aliran sungai. Setelah itu selesailah Allah memutuskan perkara di antara hamba-hambaNya. Dan yang tinggal hanyalah seorang yang berada antara surga dan neraka, dan dia adalah orang terakhir yang memasuki surga di antara penghuni neraka yang berhak memasukinya, dia sedang menghadapkan wajahnya ke neraka seraya berkata, 'Ya Rabb, palingkanlah wajahku dari neraka! Sungguh anginnya neraka telah meracuni aku dan baranya telah memanggang aku.' Lalu Allah berfirman: 'Apakah seandainya kamu diberi kesempatan kali yang lain kamu tidak akan meminta yang lain lagi? ' Orang itu menjawab: 'Tidak, demi kemuliaan-Mu, ya Allah! ' Maka Allah memberikan kepadanya janji dan ikatan perjanjian sesuai apa yang dikehendati orang tersebut. Kemudian Allah memalingkan wajah orang tersebut dari neraka. Maka ketika wajahnya dihadapkan kepada surga, dia meliahat taman-taman dan keindahan surga lalu terdiam dengan tertegun sesuai apa yang Allah kehendaki. Kemudian orang itu berkata, 'Ya Rabb, dekatkan aku ke pintu surga! ' Allah Azza Wa Jalla berfirman: 'Bukankah kamu telah berjanji dan mengikat perjanjian untuk tidak meminta sesuatu setelah permintaan kamu sebelumnya?\" Orang itu menjawab, 'Ya Rabb, aku tidak mau menjadi ciptaanM-u yang paling celaka.' Allah kembali bertanya: 'Apakah kamu bila telah diberikan permintaanmu sekarang ini, nantinya kamu tidak akan meminta yang lain lagi?\" Orang itu menjawab, 'Tidak, demi kemuliaan-Mu. Aku tidak akan meminta yang lain setelah ini.' Maka Rabbnya memberikan kepadanya janji dan ikatan sesuai apa yang dikehendati orang tersebut. Lalu orang tersebut didekatkan ke pintu surga. Maka manakala orang itu sudah sampai di pintu surga, dia melihat keindahan surga dan taman-taman yang hijau serta kegembiraan yang terdapat didalamnya, orang itu terdiam dengan tertegun sesuai apa yang Allah kehendaki. Kemudian orang itu berkata, 'Ya Rabb, masukkanlah aku ke surga! ' Allah berfirman: 'Celakalah kamu dari sikap kamu yang tidak menepati janji. Bukankah kamu telah berjanji dan mengikat perjanjian untuk tidak meminta sesuatu setelah kamu diberikan apa yang kamu pinta?\" Orang itu berkata, 'Ya Rabb, janganlah Engkau menjadikan aku ciptaan-Mu yang paling celaka.' Maka Allah Azza Wa Jalla tertawa mendengarnya. Lalu Allah mengizinkan orang itu memasuki surga. Setelahitu Allah Azza Wa Jalla berfirman: 'Bayangkanlah! ' Lalu orang itu membayangkan hingga setelah selesai apa yang ia bayangkan, Allah berfirman kepadanya: 'Dari sini.' Dan demikianlah Rabbnya mengingatkan orang tersebut hingga manakala orang tersebut selesai membayangkan, Allah berfirman lagi: \"Ini semua untuk kamu dan yang serupa dengannya.\" [Abu Sa'id Al Khudri] berkata kepada Abu Hurairah, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman: 'Ini semua untukmu dan sepuluh macam yang serupa dengannya.' [Abu Hurairah] berkata, \"Aku tidak mengingat dari Rasulullah shallallahu 'alaihi wasallam kecuali sabdanya: \"Ini semua untuk kamu dan yang serupa dengannya.\" Abu Sa'id Al Khudri berkata, \"Sungguh aku mendengar Beliau menyebutkan: 'Ini semua untukmu dan sepuluh macam yang serupa dengannya'.\""},"765":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنِي بَكْرُ بْنُ مُضَرَ عَنْ جَعْفَرٍ عَنْ ابْنِ هُرْمُزَ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ ابْنِ بُحَيْنَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى فَرَجَ بَيْنَ يَدَيْهِ حَتَّى يَبْدُوَ بَيَاضُ إِبْطَيْهِوَقَالَ اللَّيْثُ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepadaku [Bakar bin Mudlar] dari [Ja'far] dari [Ibnu Hurmuz] dari ['Abdullah bin Malik bin Buhainah], bahwa jika Nabi shallallahu 'alaihi wasallam melaksanakan shalat, beliau membentangkan kedua lengannya hingga tampak putih ketiaknya.\" [Al Laits] berkata; [Ja'far bin Rabi'ah] menceritakan kepadaku seperti itu.\""},"766":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَرَأَى رَجُلًا لَا يُتِمُّ رُكُوعَهُ وَلَا سُجُودَهُ فَلَمَّا قَضَى صَلَاتَهُ قَالَ لَهُ حُذَيْفَةُ مَا صَلَّيْتَ قَالَ وَأَحْسِبُهُ قَالَ وَلَوْ مُتَّ مُتَّ عَلَى غَيْرِ سُنَّةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ash Shalt bin Muhammad] berkata, telah menceritakan kepada kami [Mahdi bin Maimun] dari [Washil] dari [Abu Wa'il] dari [Hudzaifah], bahwa dia melihat seorang laki-laki shalat namun tidak menyempurnakan rukuk dan sujudnya. Setelah laki-laki tersebut selesai dari shalatnya, Hudzaifah berkata kepadanya, \"Kamu belumlah shalat.\" Abu Wail berkata, \"Menurutku ia mengatakan, \"Seandainya engkau mati, maka engkau mati bukan di atas sunnah Muhammad shallallahu 'alaihi wasallam.\""},"767":{"ar":"حَدَّثَنَا قَبِيصَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ ��َبَّاسٍأُمِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةِ أَعْضَاءٍ وَلَا يَكُفَّ شَعَرًا وَلَا ثَوْبًا الْجَبْهَةِ وَالْيَدَيْنِ وَالرُّكْبَتَيْنِ وَالرِّجْلَيْنِ","id":"Telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu 'Abbas]: \"Nabi shallallahu 'alaihi wasallam diperintahkan untuk melaksanakan sujud dengan tujuh anggota sujud; muka, kedua telapak tangan, kedua lutut dan kedua kaki tidak boleh terhalang oleh rambut atau pakaian.\""},"768":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْنَا أَنْ نَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ وَلَا نَكُفَّ ثَوْبًا وَلَا شَعَرًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru] dari [Thawus] dari [Ibnu 'Abbas] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kami diperintahkan untuk melaksanakan sujud dengan tujuh tulang (anggota sujud), dan dilarang menahan rambut atau pakaian (sehingga menghalangi anggota sujud).\""},"769":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ حَدَّثَنَا الْبَرَاءُ بْنُ عَازِبٍ وَهُوَ غَيْرُ كَذُوبٍ قَالَكُنَّا نُصَلِّي خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ لَمْ يَحْنِ أَحَدٌ مِنَّا ظَهْرَهُ حَتَّى يَضَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَبْهَتَهُ عَلَى الْأَرْضِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari ['Abdullah bin Yazid Al Khaththami] telah menceritakan kepada kami [Al Bara' bin 'Azib] -dan dia bukanlah pendusta- bahwa dia berkata, \"Kami pernah shalat di belakang Nabi shallallahu 'alaihi wasallam, ketika beliau mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya) ', tidak seorang pun dari kami yang membungkukkan punggungnya hingga Nabi shallallahu 'alaihi wasallam meletakkan keningnya di atas tanah.\""},"770":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ عَلَى الْجَبْهَةِ وَأَشَارَ بِيَدِهِ عَلَى أَنْفِهِ وَالْيَدَيْنِ وَالرُّكْبَتَيْنِ وَأَطْرَافِ الْقَدَمَيْنِ وَلَا نَكْفِتَ الثِّيَابَ وَالشَّعَرَ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] berkata, telah menceritakan kepada kami [Wuhaib] dari ['Abdullah bin Thawus] dari [Bapaknya] dari [Ibnu 'Abbas] radliallahu 'anhu, ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan untuk melaksanakan sujud dengan tujuh tulang (anggota sujud); kening -beliau lantas memberi isyarat dengan tangannya menunjuk hidung- kedua telapak tangan, kedua lutut dan ujung jari dari kedua kaki dan tidak boleh menahan rambut atau pakaian (sehingga menghalangi anggota sujud).\""},"771":{"ar":"حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا هَمَّامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ انْطَلَقْتُ إِلَى أَبِي سَعِيدٍ الْخُدْرِيِّفَقُلْتُ أَلَا تَخْرُجُ بِنَا إِلَى النَّخْلِ نَتَحَدَّثُ فَخَرَجَ فَقَالَ قُلْتُ حَدِّثْنِي مَا سَمِعْتَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لَيْلَةِ الْقَدْرِ قَالَ اعْتَكَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَ الْأُوَلِ مِنْ رَمَضَانَ وَاعْتَكَفْنَا مَعَهُ فَأَتَاهُ جِبْرِيلُ فَقَالَ إِنَّ الَّذِي تَطْلُبُ أَمَامَكَ فَاعْتَكَفَ الْعَشْرَ الْأَوْسَطَ فَاعْتَكَفْنَا مَعَهُ فَأَتَاهُ جِبْرِيلُ فَقَالَ إِنَّ الَّذِي تَطْلُبُ أَمَامَكَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا صَبِيحَةَ عِشْرِينَ مِنْ رَمَضَانَ فَقَالَ مَنْ كَانَ اعْتَكَفَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَرْجِعْ فَإِنِّي أُرِيتُ لَيْلَةَ الْقَدْرِ وَإِنِّي نُسِّيتُهَا وَإِنَّهَا فِي الْعَشْرِ الْأَوَاخِرِ فِي وِتْرٍ وَإِنِّي رَأَيْتُ كَأَنِّي أَسْجُدُ فِي طِينٍ وَمَاءٍ وَكَانَ سَقْفُ الْمَسْجِدِ جَرِيدَ النَّخْلِ وَمَا نَرَى فِي السَّمَاءِ شَيْئًا فَجَاءَتْ قَزْعَةٌ فَأُمْطِرْنَا فَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى رَأَيْتُ أَثَرَ الطِّينِ وَالْمَاءِ عَلَى جَبْهَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَرْنَبَتِهِ تَصْدِيقَ رُؤْيَاهُ","id":"Telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami [Hammam] dari [Yahya] dari [Abu Salamah] berkata, Aku pergi menemui [Abu Sa'id Al Khudri], lalu aku bertanya kepadanya, \"Maukah anda pergi bersama kami ke bawah pohon kurma lalu kita berbincang-bincang di sana?\" Ia pun pergi dan bercakap-cakap bersama kami. Aku kemudian berkata, \"Ceritakanlah kepadaku apa yang pernah anda dengar dari Nabi shallallahu 'alaihi wasallam tentang Lailatul Qadar.\" Dia lalu menjelaskan, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan i'tikaf pada sepuluh malam yang awal dari Ramadan, dan kami juga ikut beri'tikaf bersama beliau. Lalu datanglah Malaikat Jibril berkata, \"Sesungguhnya apa yang kamu cari ada di depan kamu (pada malam berikutnya).\" Maka Beliau beri'tikaf pada sepuluh malam pertengahannnya dan kami pun ikut beri'tikaf bersama Beliau. Kemudian Malaikat Jibril datang lagi dan berkata, \"Sesungguhnya apa yang kamu cari ada di depan kamu (pada malam berikutnya).\" Maka Nabi shallallahu 'alaihi wasallam berdiri memberi khuthbah kepada kami pada pagi hari di hari ke dua puluh dari bulan Ramadan, sabdanya: \"Barangsiapa sudah beri'tikaf bersama Nabi shallallahu 'alaihi wasallam maka pulanglah, karena aku diperlihatkan (dalam mimpi) Lailatul Qadar namun aku dilupakan waktunya yang pasti. Namun dia ada pada sepuluh malam-malam akhir dan pada malam yang ganjil. Sungguh aku melihat dalam mimpi, bahwa aku sujud di atas tanah dan air (yang becek).\" Pada masa itu atap masjid masih terbuat dari daun dan pelepah pohon kurma, dan kami tidak melihat sesuatu di atas langit hingga kemudian datang awan dan turunlah air hujan. Maka Nabi shallallahu 'alaihi wasallam shalat bersama kami hingga aku melihat sisa-sisa tanah dan air pada wajah dan ujung hidung Rasulullah shallallahu 'alaihi wasallam sebagai bukti kebenaran mimpi beliau.\""},"772":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَ النَّاسُ يُصَلُّونَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ عَاقِدُوا أُزْرِهِمْ مِنْ الصِّغَرِ عَلَى رِقَابِهِمْ فَقِيلَ لِلنِّسَاءِ لَا تَرْفَعْنَ رُءُوسَكُنَّ حَتَّى يَسْتَوِيَ الرِّجَالُ جُلُوسًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Abu Hazim] dari [Sahal bin Sa'd] berkata, \"Orang-orang shalat bersama Nabi shallallahu 'alaihi wasallam dengan mengikatkan kain mereka di leher-leher karena kainnya kecil. Lalu dikatakan kepada Kaum Wanita: \"Janganlah kalian mengangkat kepala kalian hingga para laki-laki telah duduk.\""},"773":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادٌ وَهْوَ ابْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُمِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ وَلَا يَكُفَّ ثَوْبَهُ وَلَا شَعَرَهُ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam diperintahkan untuk melaksanakan sujud dengan tujuh anggota sujud, tidak boleh mengumpulkan rambutnya atau pakaiannya (sehingga menghalangi anggota sujud).\""},"774":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةٍ لَا أَكُفُّ شَعَرًا وَلَا ثَوْبًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari ['Amru] dari [Thawus] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku diperintahkan untuk melaksanakan sujud dengan tujuh anggota sujud, dan dilarang mengumpulkan rambut atau pakaian (sehingga menghalangi anggota sujud).\""},"775":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي مَنْصُورُ بْنُ الْمُعْتَمِرِ عَنْ مُسْلِمٍ هُوَ ابْنُ صُبَيْحٍ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ أَنْ يَقُولَ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي يَتَأَوَّلُ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan] berkata, telah menceritakan kepadaku [Manshur bin Al Mu'tamir] dari [Muslim] -yaitu Ibnu Shubaih Abu Adl Dluha- dari [Masruq] dari ['Aisyah] berkata, \"Saat rukuk dan sujud Nabi shallallahu 'alaihi wasallam memperbanyak membaca do'a: 'SUBHAANAKALLAHUMMA RABBANAA WA BIHAMDIKA ALLAHUMMAGHFIRLII (Maha suci Engkau wahai Tuhan kami, segala puji bangi-Mu, ya Allah ampunilah aku) ', sebagai pengamalan perintah Al Qur'an.\""},"776":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ أَنَّ مَالِكَ بْنَ الْحُوَيْرِثِ قَالَ لِأَصْحَابِهِأَلَا أُنَبِّئُكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَذَاكَ فِي غَيْرِ حِينِ صَلَاةٍ فَقَامَ ثُمَّ رَكَعَ فَكَبَّرَ ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ هُنَيَّةً ثُمَّ سَجَدَ ثُمَّ رَفَعَ رَأْسَهُ هُنَيَّةً فَصَلَّى صَلَاةَ عَمْرِو بْنِ سَلِمَةَ شَيْخِنَا هَذَا قَالَ أَيُّوبُ كَانَ يَفْعَلُ شَيْئًا لَمْ أَرَهُمْ يَفْعَلُونَهُ كَانَ يَقْعُدُ فِي الثَّالِثَةِ وَالرَّابِعَةِ قَالَ فَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقَمْنَا عِنْدَهُ فَقَالَ لَوْ رَجَعْتُمْ إِلَى أَهْلِيكُمْ صَلُّوا صَلَاةَ كَذَا فِي حِينِ كَذَا صَلُّوا صَلَاةَ كَذَا فِي حِينِ كَذَا فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Malik bin Al Huwairits] ia berkata kepada para sahabatnya, \"Maukah kalian aku sampaikan cara shalat Rasulullah shallallahu 'alaihi wasallam?\" padahal saat itu bukan pada waktu shalat. Malik kemudian berdiri lalu rukuk dan bertakbir, kemudian mengangkat kepalanya lalu berdiri dan berdiam sejenak. Kemudian dia sujud, lalu mengangkat kepalanya, lalu (duduk) sejenak. Dia shalat seperti shalatnya 'Amru bin Salamah, guru kita ini.\" Ayyub berkata, \"Dia mengerjakan sesuatu yang tidak pernah aku lihat orang-orang melakukannya, dia duduk pada setiap akan berdiri ke rakaat ketiga dan keempat. Maka kami menemui Nabi shallallahu 'alaihi wasallam dan berdiam di sisi beliau. Beliau kemudian bersabda: \"Jika kalian kembali kepada keluarga kalian, maka shalatlah dengan cara ini pada waktu begini, dan shalat ini pada waktu begini. Jika telah datang waktu shalat maka hendaklah seseorang dari kalian adzan, dan hendaklah yang mengimami shalat adalah yang paling tua di antara kalian.\""},"777":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنَا أَبُو أَحْمَدَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الزُّبَيْرِيُّ قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ قَالَكَانَ سُجُودُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُكُوعُهُ وَقُعُودُهُ بَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdurrahim] berkata, telah menceritakan kepada kami [Abu Ahmad Muhammad bin 'Abdullah Az Zubairi] berkata, telah menceritakan kepada kami [Mis'ar] dari [Al Hakam] dari ['Abdurrahman bin Abu Laila] dari [Al Bara'] berkata, \"Sujudnya Nabi shallallahu 'alaihi wasallam, rukuk, dan duduknya antara dua sujud semuanya hampir sama (panjangnya).\""},"778":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَإِنِّي لَا آلُو أَنْ أُصَلِّيَ بِكُمْ كَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا قَالَ ثَابِتٌ كَانَ أَنَسُ بْنُ مَالِكٍ يَصْنَعُ شَيْئًا لَمْ أَرَكُمْ تَصْنَعُونَهُ كَانَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَامَ حَتَّى يَقُولَ الْقَائِلُ قَدْ نَسِيَ وَبَيْنَ السَّجْدَتَيْنِ حَتَّى يَقُولَ الْقَائِلُ قَدْ نَسِيَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas bin Malik] berkata, \"Aku tidak akan segan-segan untuk mencontohkan kepada kalian cara shalat sebagaimana aku melihat Nabi shallallahu 'alaihi wasallam melakanakan shalat bersama kami.\" Tsabit berkata, \"Anas bin Malik mengerjakan sesuatu yang belum pernah aku melihat kalian mengerjakannya. Dia mengangkat kepala dari rukuk lalu berdiri (lama sekali) hingga ada seseorang berkata, 'Dia lupa', dan jika duduk di antara dua sujud dia berdiam lama hingga ada seseorang berkata, 'Dia lupa'.\""},"779":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْتَدِلُوا فِي السُّجُودِ وَلَا يَبْسُطْ أَحَدُكُمْ ذِرَاعَيْهِ انْبِسَاطَ الْكَلْبِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] berkata, Aku mendengar [Qatadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seimbanglah kalian salam sujud, dan janganlah salah seorang dari kalian membentangkan kedua sikunya sebagaimana anjing membentangkan tangannya.\""},"780":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ قَالَ أَخْبَرَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ قَالَ أَخْبَرَنَا مَالِكُ بْنُ الْحُوَيْرِثِ اللَّيْثِيُّأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَإِذَا كَانَ فِي وِتْرٍ مِنْ صَلَاتِهِ لَمْ يَنْهَضْ حَتَّى يَسْتَوِيَ قَاعِدًا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah] berkata, telah mengabarkan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami [Khalid Al Hadzdza'] dari [Abu Qilabah] berkata, telah mengabarkan kepada kami [Malik bin Al Huwairits AL Laitsi], bahwa dia melihat Nabi shallallahu 'alaihi wasallam melaksanakan shalat, jika sampai pada rakaat yang ganjil, maka beliau tidak bangkit berdiri hingga duduk sejenak.\""},"781":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ جَاءَنَا مَالِكُ بْنُ الْحُوَيْرِثِفَصَلَّى بِنَا فِي مَسْجِدِنَا هَذَا فَقَالَ إِنِّي لَأُصَلِّي بِكُمْ وَمَا أُرِيدُ الصَّلَاةَ وَلَكِنْ أُرِيدُ أَنْ أُرِيَكُمْ كَيْفَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَالَ أَيُّوبُ فَقُلْتُ لِأَبِي قِلَابَةَ وَكَيْفَ كَانَتْ صَلَاتُهُ قَالَ مِثْلَ صَلَاةِ شَيْخِنَا هَذَا يَعْنِي عَمْرَو بْنَ سَلِمَةَ قَالَ أَيُّوبُ وَكَانَ ذَلِكَ الشَّيْخُ يُتِمُّ التَّكْبِيرَ وَإِذَا رَفَعَ رَأْسَهُ عَنْ السَّجْدَةِ الثَّانِيَةِ جَلَسَ وَاعْتَمَدَ عَلَى الْأَرْضِ ثُمَّ قَامَ","id":"Telah menceritakan kepada kami [Mu'allaa bin Asad] berkata, telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Abu Qilabah] berkata, \" [Malik bin Al Huwairits] datang kepada kami lalu shalat bersama di masjid milik ini, kemudian berkata, \"Aku bukan ingin melaksanakan shalat, tapi aku akan menerangkan kepada kalian bagaimana Nabi shallallahu 'alaihi wasallam melaksanakan shalat.\" Ayyub berkata, \"Lalu aku bertanya kepada Abu Qilabah, \"Bagaimana cara shalat dia?\" Abu Qilabah menjawab, \"Seperti shalatnya guru (syaikh) kita ini, yaitu 'Amru bin Salamah.\" Ayyub berkata, \"Guru kita itu selalu menyempurnakan takbir. Dan jika mengangkat kepalanya dari sujud yang kedua dia duduk di atas tanah, kemudian baru berdiri.\""},"782":{"ar":"حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ قَالَ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ قَالَ صَلَّى لَنَا أَبُو سَعِيدٍفَجَهَرَ بِالتَّكْبِيرِ حِينَ رَفَعَ رَأْسَهُ مِنْ السُّجُودِ وَحِينَ سَجَدَ وَحِينَ رَفَعَ وَحِينَ قَامَ مِنْ الرَّكْعَتَيْنِ وَقَالَ هَكَذَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Shalih] berkata, telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits] berkata, \" [Abu Sa'id] memimpin kami shalat, dia lalu mengeraskan bacaan takbirnya ketika mengangkat kepala dari sujud, ketika mau sujud, ketika mengangkat (kepala dari sujud) dan ketika bangkit berdiri dari rakaat kedua, setelah itu ia berkata, \"Begitulah aku melihat Rasulullah shallallahu 'alaihi wasallam.\""},"783":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ مُطَرِّفٍ قَالَ صَلَّيْتُ أَنَا وَعِمْرَانُصَلَاةً خَلْفَ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ فَكَانَ إِذَا سَجَدَ كَبَّرَ وَإِذَا رَفَعَ كَبَّرَ وَإِذَا نَهَضَ مِنْ الرَّكْعَتَيْنِ كَبَّرَ فَلَمَّا سَلَّمَ أَخَذَ عِمْرَانُ بِيَدِي فَقَالَ لَقَدْ صَلَّى بِنَا هَذَا صَلَاةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ لَقَدْ ذَكَّرَنِي هَذَا صَلَاةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Ghailan bin Jarir] dari [Mutharrif] berkata, \"Aku dan 'Imran pernah shalat di belakang 'Ali bin Abu Thalib? radliallahu 'anhu, jika sujud ia bertakbir, jika rukuk ia bertakbir, jika mengangkat (kepala dari sujud) ia bertakbir, jika bangkit berdiri dari rakaat ia juga bertabir. Selesai salam, ['Imran] memegang tanganku lalu berkata, \"Sungguh dia telah shalat bersama kita dengan tata cara shalatnya Muhammad shallallahu 'alaihi wasallam.\" Atau dia berkata, \"Sungguh dengan shalatnya ini dia telah mengingatkan aku tentang shalatnya Muhammad shallallahu 'alaihi wasallam.\""},"784":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّهُ أَخْبَرَهُ أَنَّهُ كَانَ يَرَى عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَايَتَرَبَّعُ فِي الصَّلَاةِ إِذَا جَلَسَ فَفَعَلْتُهُ وَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّ فَنَهَانِي عَبْدُ اللَّهِ بْنُ عُمَرَ وَقَالَ إِنَّمَا سُنَّةُ الصَّلَاةِ أَنْ تَنْصِبَ رِجْلَكَ الْيُمْنَى وَتَثْنِيَ الْيُسْرَى فَقُلْتُ إِنَّكَ تَفْعَلُ ذَلِكَ فَقَالَ إِنَّ رِجْلَيَّ لَا تَحْمِلَانِي","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari ['Abdurrahman bin Al Qasim] dari ['Abdullah bin 'Abdullah] ia mengabarkan kepadanya, bahwa dia pernah melihhat ['Abdullah bin 'Umar] radliallahu 'anhuma mengerjakan shalat dengan cara bersimpuh dengan kedua kakinya ketika duduk. Maka aku juga melakukan hal serupa. Saat itu aku masih berusia muda. Namun 'Abdullah bin 'Umar melarangku berbuat seperti itu. Ia mengatakan, \"Sesungguhnya yang sesuai sunnah adalah kamu menegakkan telapak kakimu yang kanan sedangkan yang kiri kamu masukkan dibawahnya (melipat).\" Aku pun berkata, \"Tapi aku melihat anda melakukan hal itu!\" Dia menjawab, \"Kakiku tidak mampu.\""},"785":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدٍ عَنْ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ وَحَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ وَيَزِيدَ بْنِ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ أَنَّهُ كَانَ جَالِسًا مَعَ نَفَرٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا صَلَاةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو حُمَيْدٍ السَّاعِدِيُّأَنَا كُنْتُ أَحْفَظَكُمْ لِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُهُ إِذَا كَبَّرَ جَعَلَ يَدَيْهِ حِذَاءَ مَنْكِبَيْهِ وَإِذَا رَكَعَ أَمْكَنَ يَدَيْهِ مِنْ رُكْبَتَيْهِ ثُمَّ هَصَرَ ظَهْرَهُ فَإِذَا رَفَعَ رَأْسَهُ اسْتَوَى حَتَّى يَعُودَ كُلُّ فَقَارٍ مَكَانَهُ فَإِذَا سَجَدَ وَضَعَ يَدَيْهِ غَيْرَ مُفْتَرِشٍ وَلَا قَابِضِهِمَا وَاسْتَقْبَلَ بِأَطْرَافِ أَصَابِعِ رِجْلَيْهِ الْقِبْلَةَ فَإِذَا جَلَسَ فِي الرَّكْعَتَيْنِ جَلَسَ عَلَى رِجْلِهِ الْيُسْرَى وَنَصَبَ الْيُمْنَى وَإِذَا جَلَسَ فِي الرَّكْعَةِ الْآخِرَةِ قَدَّمَ رِجْلَهُ الْيُسْرَى وَنَصَبَ الْأُخْرَى وَقَعَدَ عَلَى مَقْعَدَتِهِوَسَمِعَ اللَّيْثُ يَزِيدَ بْنَ أَبِي حَبِيبٍ وَيَزِيدُ مِنْ مُحَمَّدِ بْنِ حَلْحَلَةَ وَابْنُ حَلْحَلَةَ مِنْ ابْنِ عَطَاءٍ قَالَ أَبُو صَالِحٍ عَنْ اللَّيْثِ كُلُّ فَقَارٍ وَقَالَ ابْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ أَنَّ مُحَمَّدَ بْنَ عَمْرٍو حَدَّثَهُ كُلُّ فَقَارٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari [Khalid] dari [Sa'id] dari [Muhammad bin 'Amru bin Halhalah] dari [Muhammad bin 'Amru bin 'Atha'], dan telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dan [Yazid bin Muhammad] dari [Muhammad bin 'Amru bin Halhalah] dari [Muhammad bin 'Amru bin 'Atha'], bahwasanya dia duduk bersama beberapa orang sahabat Nabi shallallahu 'alaihi wasallam, mereka bercerita tentang shalatnya Nabi shallallahu 'alaihi wasallam. Maka berkatalah [Abu Hamid As Sa'idi], \"Aku adalah orang yang paling hafal dengan shalatnya Rasulullah shallallahu 'alaihi wasallam, jika shalat aku melihat beliau takbir dengan mengangkat kedua tangannya sejajar dengan pundaknya, jika rukuk maka beliau menempatkan kedua tangannya pada lutut dan meluruskan punggungnya. Jika mengangkat kepalanya, beliau berdiri lurus hingga seluruh tulung punggungnya kembali pada tempatnya semula. Dan jika sujud maka beliau meletakkan tangannya dengan tidak menempelkan lengannya ke tanah atau badannya, dan dalam posisi sujud itu beliau menghadapkan jari-jari kakinya ke arah kiblat. Apabila duduk pada rakaat kedua, beliau duduk di atas kakinya yang kiri dan menegakkan kakinya yang kanan. Dan jika duduk pada rakaat terakhir, maka beliau memasukkan kaki kirinya (di bawah kaki kananya) dan menegakkan kaki kanannya dan beliau duduk pada tempat duduknya.\" Dan [Al Laits] telah mendengar dari [Yazid bin Abu Habib], dan Yazid dari [Muhammad bin Halhalah], dan Ibnu Halhalah dari [Ibnu 'Atha']. [Abu Shalih] menyebutkan dari [Al Laits], \"Seluruh tulung punggung.\" [Ibnu Al Mubarak] berkata dari [Yahya bin Ayyub] ia berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] bahwa [Muhammad bin 'Amru] menceritakan kepadanya, \"Seluruh tulung punggung.\""},"786":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ هُرْمُزَ مَوْلَى بَنِي عَبْدِ الْمُطَّلِبِ وَقَالَ مَرَّةً مَوْلَى رَبِيعَةَ بْنِ الْحَارِثِ أَنَّ عَبْدَ اللَّهِ ابْنَ بُحَيْنَةَ وَهُوَ مِنْ أَزْدِ شَنُوءَةَ وَهُوَ حَلِيفٌ لِبَنِي عَبْدِ مَنَافٍ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ الظَّهْرَ فَقَامَ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ لَمْ يَجْلِسْ فَقَامَ النَّاسُ مَعَهُ حَتَّى إِذَا قَضَى الصَّلَاةَ وَانْتَظَرَ النَّاسُ تَسْلِيمَهُ كَبَّرَ وَهُوَ جَالِسٌ فَسَجَدَ سَجْدَتَيْنِ قَبْلَ أَنْ يُسَلِّمَ ثُمَّ سَل��َمَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah menceritakan kepadaku ['Abdurrahman bin Hurmuz] mantan budak Bani 'Abdul Muthalib -sekali waktu ia menyebutkan- mantan budak Rabi'ah bin Al Harits, bahwa ['Abdullah Ibnu Buhainah] dia berasal dari suku Azdi Sya'unah, sekutunya Bani 'Abdu Manaf, dan dia adalah seorang sahabat Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam pernah shalat Zhuhur bersama mereka, lalu beliau berdiri pada dua rakaat yang pertama dan tidak duduk (untuk tasyahud), dan orang-orang ikut berdiri. Sehingga ketika shalat akan selesai, dan orang-orang menanti salamnya, beliau bertakbir dalam posisi duduk, lalu sujud dua kali sebelum salam, setelahitu baru beliau salam.\""},"787":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا بَكْرٌ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ ابْنِ بُحَيْنَةَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَقَامَ وَعَلَيْهِ جُلُوسٌ فَلَمَّا كَانَ فِي آخِرِ صَلَاتِهِ سَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Bakar] dari [Ja'far bin Rabi'ah] dari [Al A'raj] dari [Abdullah bin Malik Ibnu Buhainah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah shalat Zhuhur bersama kami, lalu beliau berdiri yang semestinya beliau duduk. Kemudian di akhir shalatnya, beliau sujud dua kali dalam posisi duduk.\""},"788":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقِ بْنِ سَلَمَةَ قَالَ قَالَ عَبْدُ اللَّهِكُنَّا إِذَا صَلَّيْنَا خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا السَّلَامُ عَلَى جِبْرِيلَ وَمِيكَائِيلَ السَّلَامُ عَلَى فُلَانٍ وَفُلَانٍ فَالْتَفَتَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ هُوَ السَّلَامُ فَإِذَا صَلَّى أَحَدُكُمْ فَلْيَقُلْ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ فَإِنَّكُمْ إِذَا قُلْتُمُوهَا أَصَابَتْ كُلَّ عَبْدٍ لِلَّهِ صَالِحٍ فِي السَّمَاءِ وَالْأَرْضِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Al A'masy] dari [Syaqiq bin Salamah] berkata, berkata, \" [Abdullah] berkata, \"Jika kami shalat di belakang Nabi shallallahu 'alaihi wasallam, kami membaca: 'ASSALAAMU 'ALAA JIBRIL WA MIKAA'IL. ASSALAAMU 'ALAA FULAN WA FULAN (Semoga kesejahteraan terlimpahkan kepada malaikat Jibril dan Mika'il, dan semoga kesejahteraan terlimpahkan kepada si anu dan si anu) '. Lalu Rasulullah shallallahu 'alaihi wasallam menoleh ke arah kami seraya bersabda: \"Sesungguhnya Allah, Dialah As-Salaam. Maka jika seseorang dari kalian shalat, hendaklah ia membaca: 'ATTAHIYYAATU LILLAHI WASHSHALAWAATU WATHTHAYYIBAAT. ASSALAAMU 'ALAIKA AYYUHANNABIYYU WA RAHMATULLAHI WA BARAKAATUH. ASSALAAMU 'ALAINAA WA 'ALAA 'IBAADILLAHISH SHAALIHIIN (Segala penghormatan hanya milik Allah, juga segala pengagungan dan kebaikan. Semoga kesejahteraan terlimpahkan kepada engkau wahai Nabi dan juga rahmat dan berkah-Nya. Dan juga semoga kesejahteraan terlimpahkan kepada kami dan kepada hamba-hamba Allah yang shalih) '. Sesungguhnya jika kalian mengucapkan seperti ini, maka kalian telah mengucapkan salam kepada seluruh hamba Allah yang shalih di langit maupun di bumi. (Dan lanjutkanlah dengan bacaan): 'ASYHADU ALLAA ILAAHA ILLALLAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Aku bersaksi tidak ada tuhan yang berhak disembah selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya').\""},"789":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنَا عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فِي الصَّلَاةِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَفِتْنَةِ الْمَمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْمَأْثَمِ وَالْمَغْرَمِ فَقَالَ لَهُ قَائِلٌ مَا أَكْثَرَ مَا تَسْتَعِيذُ مِنْ الْمَغْرَمِ فَقَالَ إِنَّ الرَّجُلَ إِذَا غَرِمَ حَدَّثَ فَكَذَبَ وَوَعَدَ فَأَخْلَفَوَعَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَعِيذُ فِي صَلَاتِهِ مِنْ فِتْنَةِ الدَّجَّالِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepada kami ['Urwah bin Az Zubair] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, dia telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam di dalam shalat membaca do'a: 'ALLAHUMMA INNII A'UUDZU BIKA MIN 'ADZAABIL QABRI, WA A'UUDZU BIKA MIN FITNATIL MASIIHID DAJJAAL, WA A'UUDZU BIKA MIN FITNATIL MAHYAA WA FITNATIL MAMAAT. ALLAHUMMA INNII A'UUDZU BIKA MINAL MA'TSAMI WAL MAGHRAM (Ya Allah, aku berlindung kepada-Mu dari siksa kubur dan aku berlindung kepada-Mu dari fitnah Al Masihid Dajjal, dan aku berlindung kepada-Mu dari fitnah kehidupan dan fitnah kematian. Ya Allah, aku berlindung kepada-Mu dari perbuatan dosa dan hutang) '. Tiba-tiba ada seseorang berkata kepada beliau, \"Kenapa tuan banyak meminta perlindungan dari hutang?\" Beliau menjawab, \"Sesungguhnya seseorang apabila berhutang dia akan cenderung berkata dusta dan berjanji lalu mengingkarinya.\" Dan dari Az Zuhri ia berkata, 'Urwah bin Az Zubair telah mengabarkan kepadaku, bahwa 'Aisyah? radliallahu 'anha berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam dalam shalatnya meminta perlindungan dari fitnah Dajjal.\""},"790":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمْنِي دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي قَالَ قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّك أَنْتَ الْغَفُورُ الرَّحِيمُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Abdullah bin 'Amru] dari [Abu Bakar Ash Shiddiq] radliallahu 'anhu, ia berkata kepada Rasulullah shallallahu 'alaihi wasallam: \"Ajarkanlah aku suatu do'a yang bisa aku panjatkan saat shalat!\" Maka Beliau pun berkata: \"Bacalah 'ALLAHUMMA INNII ZHALAMTU NAFSII ZHULMAN KATSIIRAN WA LAA YAGHFIRUDZ DZUNUUBA ILLAA ANTA FAGHFIRLII MAGHFIRATAN MIN 'INDIKA WARHAMNII INNAKA ANTAL GHAFUURUR RAHIIM (Ya Allah, sungguh aku telah menzhalimi diriku sendiri dengan kezhaliman yang banyak, sedangkan tidak ada yang dapat mengampuni dosa-dosa kecuali Engkau. Maka itu ampunilah aku dengan suatu pengampunan dari sisi-Mu, dan rahmatilah aku. Sesungguhnya Engkau Maha Pengampun lagi Maha Penyayang) '.\""},"791":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْأَعْمَشِ حَدَّثَنِي شَقِيقٌ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا إِذَا كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ قُلْنَا السَّلَامُ عَلَى اللَّهِ مِنْ عِبَادِهِ السَّلَامُ عَلَى فُلَانٍ وَفُلَانٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا السَّلَامُ عَلَى اللَّهِ فَإِنَّ اللَّهَ هُوَ السَّلَامُ وَلَكِنْ قُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ فَإِنَّكُمْ إِذَا قُلْتُمْ أَصَابَ كُلَّ عَبْدٍ فِي السَّمَاءِ أَوْ بَيْنَ السَّمَاءِ وَالْأَرْضِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَتَخَيَّرُ مِنْ الدُّعَاءِ أَعْجَبَهُ إِلَيْهِ فَيَدْعُو","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Al A'masy] telah menceritakan kepadaku [Syaqiq] dari ['Abdullah] berkata, \"Jika kami shalat bersama Nabi shallallahu 'alaihi wasallam, kami mengucapkan: \"ASSALAAMU 'ALAALLAH MIN 'IBAADIHIS SALAAMU 'ALAA FULAAN WA FULAAN (Semoga kesejahteraan terlimpahkan kepada Allah dari hamba-hamba Nya, dan semoga kesejahteraan terlimpahkan kepada si anu dan si anu) '. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengucapkan: 'ASSALAAMU 'ALAALLAH (Semoga kesejahteraan terlimpahkan kepada Allah) ', karena sesungguhnya Allah, Dialah As-Salaam. Akan tetapi bacalah: 'ATTAHIYYAATU LILLAHI WASHSHALAAWAATU WATHTHAYYIBAAT ASSALAAMU 'ALAIKA AYYUHANNABIYYU WA RAHMATULLAHI WA BARAKAATUH ASSALAAMU 'ALAINAA WA 'ALAA 'IBAADILLAHISH SHAALIHIIN (Segala penghormatan hanya milik Allah, juga segala pengagungan dan kebaikan. Semoga kesejahteraan terlimpahkan kepada engkau wahai Nabi dan juga rahmat dan berkah-Nya. Semoga kesejahteraan terlimpahkan kepada kami dan kepada hamba-hamba Allah yang shalih). Karena apabila kalian mengucapkan seperti ini, maka berarti kalian telah mengucapkan salam kepada seluruh yang ada di langit atau yang berada di antara langit dan bumi.\" (Dan lanjutkanlah dengan bacaan): 'ASYHADU ALLAA ILAAHA ILLALLAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Aku bersaksi tidak ada tuhan yang berhak disembah selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya) '. Lalu ia memilih doa yang paling ia sukai kemudian berdoa dengannya.\""},"792":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ سَأَلْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ فَقَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ فِي الْمَاءِ وَالطِّينِ حَتَّى رَأَيْتُ أَثَرَ الطِّينِ فِي جَبْهَتِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] berkata, \"Aku bertanya kepada [Abu Sa'id Al Khudri] (tentang Lailatul Qadar). Lalu ia menjawab, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam sujud di atas air dan lumpur hingga aku bisa melihat bekas lumpur itu di dahi beliau.\""},"793":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ هِنْدٍ بِنْتِ الْحَارِثِ أَنَّ أُمَّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ قَامَ النِّسَاءُ حِينَ يَقْضِي تَسْلِيمَهُ وَمَكَثَ يَسِيرًا قَبْلَ أَنْ يَقُومَقَالَ ابْنُ شِهَابٍ فَأُرَى وَاللَّهُ أَعْلَمُ أَنَّ مُكْثَهُ لِكَيْ يَنْفُذَ النِّسَاءُ قَبْلَ أَنْ يُدْرِكَهُنَّ مَنْ انْصَرَفَ مِنْ الْقَوْمِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Az Zuhri] dari [Hind binti Al Harits] bahwa [Ummu Salamah] radliallahu 'anha berkata, \"Apabila Rasulullah shallallahu 'alaihi wasallam mengucapkan salam, maka seketika selesainya salam beliau itu pula mereka langsung bangkit, sementara beliau berdiam diri sebentar sebelum berdiri.\" Ibnu Syihab berkata, \"Menurutku -dan hanya Allah yang tahu- beliau melakukan itu agar kaum wanita punya kesempatan untuk pergi sehingga seseorang yang berlalu pulang dari kalangan laki-laki tidak bertemu dengan mereka.\""},"794":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَصَلَّيْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْنَا حِينَ سَلَّمَ","id":"Telah menceritakan kepada kami [Hibban bin Musa] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Itban bin Malik] berkata, \"Kami pernah shalat bersama Nabi shallallahu 'alaihi wasallam, maka kami salam ketika beliau salam.\""},"795":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِوَزَعَمَ أَنَّهُ عَقَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَقَلَ مَجَّةً مَجَّهَا مِنْ دَلْوٍ كَانَ فِي دَارِهِمْ قَالَ سَمِعْتُ عِتْبَانَ بْنَ مَالِكٍ الْأَنْصارِيَّ ثُمَّ أَحَدَ بَنِي سَالِمٍ قَالَ كُنْتُ أُصَلِّي لِقَوْمِي بَنِي سَالِمٍ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي أَنْكَرْتُ بَصَرِي وَإِنَّ السُّيُولَ تَحُولُ بَيْنِي وَبَيْنَ مَسْجِدِ قَوْمِي فَلَوَدِدْتُ أَنَّكَ جِئْتَ فَصَلَّيْتَ فِي بَيْتِي مَكَانًا حَتَّى أَتَّخِذَهُ مَسْجِدًا فَقَالَ أَفْعَلُ إِنْ شَاءَ اللَّهُ فَغَدَا عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ مَعَهُ بَعْدَ مَا اشْتَدَّ النَّهَارُ فَاسْتَأْذَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذِنْتُ لَهُ فَلَمْ يَجْلِسْ حَتَّى قَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ مِنْ بَيْتِكَ فَأَشَارَ إِلَيْهِ مِنْ الْمَكَانِ الَّذِي أَحَبَّ أَنْ يُصَلِّيَ فِيهِ فَقَامَ فَصَفَفْنَا خَلْفَهُ ثُمَّ سَلَّمَ وَسَلَّمْنَا حِينَ سَلَّمَ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Mahmud bin Ar Rabi'], dia mengklaim bahwa ia telah membuat perjanjian dengan Rasulullah shallallahu 'alaihi wasallam dan meminta keberkahan kewat air yang diambil dari sumur yang ada di dalam mereka. Dia berkata, Aku mendengar ['Itban bin Malik Al Anshari] kemudian seseorang dari suku Bani Salim berkata, \"Aku pernah memimpin shalat kaumku, Bani Salim. Pada kemudian hari aku menemui Nabi shallallahu 'alaihi wasallam, lalu aku berkata kepada beliau, \"Wahai Rasulullah, aku adalah orang yang sudah lemah penglihatan sedangkan genangan-genangan dari saluran air sering menghalangi antara aku dan masjid kaumku. Seandainya tuan berkenan, bolehlah tuan datang berkunjung lalu shalat di rumahku pada suatu tempat yang akan aku jadikan masjid.\" Maka Beliau berkata, \"Aku akan datang, Insyaallah.\" Kemudian beliau datang kepadaku bersama Abu Bakar di waktu siang yang terik. Nabi shallallahu 'alaihi wasallam lalu minta izin masuk dan aku pun mengizinkannya. Sebelum duduk beliau langsung bersabda: \"Mana tempat yang kau sukai untuk aku shalat padanya di rumahmu ini?\" Maka Itban memberi isyarat kepada Beliau tempat yang disukainya supaya Beliau shalat di tempat tersebut. Beliau lalu berdiri shalat dan kamipun berdiri shalat mengatur shaf di belakangnya. Kemudian Beliau mengakhiri shalat dengan salam, maka kamipun mengucapkan salam setelah Beliau salam.\""},"796":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرٌو أَنَّ أَبَا مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ أَخْبَرَهُ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَفْعَ الصَّوْتِ بِالذِّكْرِ حِينَ يَنْصَرِفُ النَّاسُ مِنْ الْمَكْتُوبَةِ كَانَ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ ابْنُ عَبَّاسٍ كُنْتُ أَعْلَمُ إِذَا انْصَرَفُوا بِذَلِكَ إِذَا سَمِعْتُهُ","id":"Telah menceritakan kepada kami [Ishaq bin Nashir] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku ['Amru] bahwa [Abu Ma'bad] mantan budak Ibnu 'Abbas, mengabarkan kepadanya bahwa [Ibnu 'Abbas] radliallahu 'anhuma mengabarkan kepadanya, bahwa mengeraskan suara dalam berdzikir setelah orang selesai menunaikah shalat fardlu terjadi di zaman Nabi shallallahu 'alaihi wasallam. Ibnu 'Abbas mengatakan, \"Aku mengetahui bahwa mereka telah selesai dari shalat itu karena aku mendengarnya.\""},"797":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو قَالَ أَخْبَرَنِي أَبُو مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنْتُ أَعْرِفُ انْقِضَاءَ صَلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالتَّكْبِيرِقَالَ عَلِيٌّ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ كَانَ أَبُو مَعْبَدٍ أَصْدَقَ مَوَالِي ابْنِ عَبَّاسٍ قَالَ عَلِيٌّ وَاسْمُهُ نَافِذٌ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] berkata, telah mengabarkan kepadaku [Abu Ma'bad] dari [Ibnu 'Abbas] radliallahu 'anhuma berkata, \"Aku mengetahui selesainya shalat Nabi shallallahu 'alaihi wasallam dari suara takbir.\" 'Ali berkata, telah menceritakan kepada kami Sufyan dari 'Amru ia berkata, \"Abu Ma'bad adalah salah satu budak Ibnu 'Abbas yang paling jujur.\" 'Ali berkata, \"Nama aslinya adalah Nafidz.\""},"798":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ قَالَ حَدَّثَنَا مُعْتَمِرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ الْفُقَرَاءُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا ذَهَبَ أَهْلُ الدُّثُورِ مِنْ الْأَمْوَالِ بِالدَّرَجَاتِ الْعُلَا وَالنَّعِيمِ الْمُقِيمِ يُصَلُّونَ كَمَا نُصَلِّي وَيَصُومُونَ كَمَا نَصُومُ وَلَهُمْ فَضْلٌ مِنْ أَمْوَالٍ يَحُجُّونَ بِهَا وَيَعْتَمِرُونَ وَيُجَاهِدُونَ وَيَتَصَدَّقُونَ قَالَ أَلَا أُحَدِّثُكُمْ إِنْ أَخَذْتُمْ أَدْرَكْتُمْ مَنْ سَبَقَكُمْ وَلَمْ يُدْرِكْكُمْ أَحَدٌ بَعْدَكُمْ وَكُنْتُمْ خَيْرَ مَنْ أَنْتُمْ بَيْنَ ظَهْرَانَيْهِ إِلَّا مَنْ عَمِلَ مِثْلَهُ تُسَبِّحُونَ وَتَحْمَدُونَ وَتُكَبِّرُونَ خَلْفَ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ فَاخْتَلَفْنَا بَيْنَنَا فَقَالَ بَعْضُنَا نُسَبِّحُ ثَلَاثًا وَثَلَاثِينَ وَنَحْمَدُ ثَلَاثًا وَثَلَاثِينَ وَنُكَبِّرُ أَرْبَعًا وَثَلَاثِينَ فَرَجَعْتُ إِلَيْهِ فَقَالَ تَقُولُ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَاللَّهُ أَكْبَرُ حَتَّى يَكُونَ مِنْهُنَّ كُلِّهِنَّ ثَلَاثًا وَثَلَاثِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar] berkata, telah menceritakan kepada kami [Mu'tamir] dari ['Ubaidullah] dari [Sumayyah] dari [Abu Shalih] dari [Abu Hurairah] berkata, \"Pernah datang para fuqara kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Orang-orang kaya, dengan harta benda mereka itu, mereka mendapatkan kedudukan yang tinggi, juga kenikmatan yang abadi. Karena mereka melaksanakan shalat seperti juga kami melaksanakan shalat. Mereka shaum sebagaimana kami juga shaum. Namun mereka memiliki kelebihan disebabkan harta mereka, sehingga mereka dapat menunaikan 'ibadah haji dengan harta tersebut, juga dapat melaksnakan 'umrah bahkan dapat berjihad dan bersedekah.\" Maka beliau pun bersabda: \"Maukah aku sampaikan kepada kalian sesuatu yang apabila kalian ambil (sebagai amal ibadah) kalian akan dapat melampaui (derajat) orang-orang yang sudah mengalahkan kalian tersebut, dan tidak akan ada yang dapat mengalahkan kalian dengan amal ini sehingga kalian menjadi yang terbaik di antara kalian dan di tengah-tengah mereka kecuali bila ada orang yang mengerjakan seperti yang kalian amalkan ini. Yaitu kalian membaca tasbih (Subhaanallah), membaca tahmid (Alhamdulillah) dan membaca takbir (Allahu Akbar) setiap selesai dari shalat sebanyak tiga puluh tiga kali.\" Kemudian setelah itu di antara kami terdapat perbedaan pendapat. Di antara kami ada yang berkata, \"Kita bertasbih tiga puluh tiga kali, lalu bertahmid tiga puluh tiga kali, lalu bertakbir empat puluh tiga kali.\" Kemudian aku kembali menemui Beliau shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Bacalah 'Subhaanallah walhamdulillah wallahu Akbar' hingga dari itu semuanya berjumlah tiga puluh tiga kali.\""},"799":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ أَمْلَى عَلَيَّ الْمُغِيرَةُ بْنُ شُعْبَةَ فِي كِتَابٍ إِلَى مُعَاوِيَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي دُبُرِ كُلِّ صَلَاةٍ مَكْتُوبَةٍ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّوَقَالَ شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ بِهَذَا وَعَنْ الْحَكَمِ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ وَرَّادٍ بِهَذَا وَقَالَ الْحَسَنُ الْجَدُّ غِنًى","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari ['Abdul Malik bin 'Umair] dari [Warrad] penulisnya Al Mughirah bin Syu'bah, berkata, \" [Al Mughirah bin Syu'bah] meminta aku untuk menulis (hadits) buat dikirim kepada Mu'awiyyah bahwa Nabi shallallahu 'alaihi wasallam berdo'a setiap selesai dari shalat fardlu: 'LAA ILAAHA ILLALLAH WAHDAHU LAA SYARIIKA LAHU, LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI'IN QADIIR. ALLAHUMMA LAA MAANI'A LIMA A'THAITA WA LAA MU'THIYA LIMA MANA'TA WA LAA YANFA'U DZAL JADDI MINKAL JADDU (Tidak ada tuhan yang berhak disembah selain Allah, yang Tunggal dan tidak ada sekutu bagi-Nya. Milik-Nya segala kerajaan, dan milik-Nya segala pujian. Dan Dia Maha Kuasa atas segala sesuatu. Ya Allah, tidak ada yang dapat menahan dari apa yang Engkau berikan dan dan tidak ada yang dapat memberi dari apa yang Engkau tahan. Dan tidak bermanfaat kekayaan orang yang kaya di hadapan-Mu sedikitpun) '.\" [Syu'bah] berkata dari ['Abdul Malik bin 'Umair] dengan lafadz seperti ini. Dan dari [Al Hakam] dari [Al Qasim bin Mukhaimirah] dari [Warrad] dengan seperti ini juga. Al Hasan berkata, \"Al Jaddu artinyaadalah kekayaan.\""},"800":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى صَلَاةً أَقْبَلَ عَلَيْنَا بِوَجْهِهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Jarir bin Hazim] berkata, telah menceritakan kepada kami [Abu Raja'] dari [Samrah bin Jundub] berkata, \"Jika Nabi shallallahu 'alaihi wasallam selesai dari menunaikan shalat, beliau menghadapkan wajahnya ke arah kami.\""},"801":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ بِالْحُدَيْبِيَةِ عَلَى إِثْرِ سَمَاءٍ كَانَتْ مِنْ اللَّيْلَةِ فَلَمَّا انْصَرَفَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ هَلْ تَدْرُونَ مَاذَا قَالَ رَبُّكُمْ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَصْبَحَ مِنْ عِبَادِي مُؤْمِنٌ بِي وَكَافِرٌ فَأَمَّا مَنْ قَالَ مُطِرْنَا بِفَضْلِ اللَّهِ وَرَحْمَتِهِ فَذَلِكَ مُؤْمِنٌ بِي وَكَافِرٌ بِالْكَوْكَبِ وَأَمَّا مَنْ قَالَ بِنَوْءِ كَذَا وَكَذَا فَذَلِكَ كَافِرٌ بِي وَمُؤْمِنٌ بِالْكَوْكَبِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Shalih bin Kaisan] dari ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] dari [Zaid bin Khalid Al Juhaini] bahwasanya dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memimpin kami shalat Shubuh di Hudaibiyyah pada suatu malam sehabis turun hujan. Setelah selesai Beliau menghadapkan wajahnya kepada orang banyak lalu bersabda: \"Tahukah kalian apa yang sudah difirmankan oleh Rabb kalian?\" Orang-orang menjawab, \"Allah dan rasul-Nya lebih mengetahui.\" Beliau bersabda: '(Allah berfirman): 'Di pagi ini ada hamba-hamba Ku yang beriman kepada-Ku dan ada yang kafir. Orang yang berkata, 'Hujan turun kepada kita karena karunia Allah dan rahmat-Nya', maka dia adalah yang beriman kepada-Ku dan kafir kepada bintang-bintang. Adapun yang berkata, '(Hujan turun disebabkan) bintang ini atau itu', maka dia telah kafir kepada-Ku dan beriman kepada bintang-bintang'.\""},"802":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ يَزِيدَ بْنَ هَارُونَ قَالَ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَخَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ ذَاتَ لَيْلَةٍ إِلَى شَطْرِ اللَّيْلِ ثُمَّ خَرَجَ عَلَيْنَا فَلَمَّا صَلَّى أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ إِنَّ النَّاسَ قَدْ صَلَّوْا وَرَقَدُوا وَإِنَّكُمْ لَنْ تَزَالُوا فِي صَلَاةٍ مَا انْتَظَرْتُمْ الصَّلَاةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] dia mendengar [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Humaid] dari [Anas bin Malik] berkata, \"Pada suatu malam Rasulullah shallallahu 'alaihi wasallam pernah mengakhirkan shalat hingga pertengahan malam, lalu beliau keluar menemui kami (untuk melaksanakan shalat). Selesai shalat beliau menghadap ke arah kami dan bersabda: \"Manusia sudah selesai melaksanakan shalat lalu mereka tidur. Dan kalian akan tetqap dalan hitungan shalat selama kalian masih menunggu (pelaksanaan) shalat.\""},"803":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ هِنْدٍ بِنْتِ الْحَارِثِ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَلَّمَ يَمْكُثُ فِي مَكَانِهِ يَسِيرًاقَالَ ابْنُ شِهَابٍ فَنُرَى وَاللَّهُ أَعْلَمُ لِكَيْ يَنْفُذَ مَنْ يَنْصَرِفُ مِنْ النِّسَاءِ وَقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا نَافِعُ بْنُ يَزِيدَ قَالَ أَخْبَرَنِي جَعْفَرُ بْنُ رَبِيعَةَ أَنَّ ابْنَ شِهَابٍ كَتَبَ إِلَيْهِ قَالَ حَدَّثَتْنِي هِنْدُ بِنْتُ الْحَارِثِ الْفِرَاسِيَّةُ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ مِنْ صَوَاحِبَاتِهَا قَالَتْ كَانَ يُسَلِّمُ فَيَنْصَرِفُ النِّسَاءُ فَيَدْخُلْنَ بُيُوتَهُنَّ مِنْ قَبْلِ أَنْ يَنْصَرِفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَتْنِي هِنْدُ الْفِرَاسِيَّةُ وَقَالَ عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ حَدَّثَتْنِي هِنْدُ الْفِرَاسِيَّةُ وَقَالَ الزُّبَيْدِيُّ أَخْبَرَنِي الزُّهْرِيُّ أَنَّ هِنْدَ بِنْتَ الْحَارِثِ الْقُرَشِيَّةَ أَخْبَرَتْهُ وَكَانَتْ تَحْتَ مَعْبَدِ بْنِ الْمِقْدَادِ وَهُوَ حَلِيفُ بَنِي زُهْرَةَ وَكَانَتْ تَدْخُلُ عَلَى أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَتْنِي هِنْدُ الْقُرَشِيَّةُ وَقَالَ ابْنُ أَبِي عَتِيقٍ عَنْ الزُّهْرِيِّ عَنْ هِنْدٍ الْفِرَاسِيَّةِ وَقَالَ اللَّيْثُ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ حَدَّثَهُ عَنْ ابْنِ شِهَابٍ عَنْ امْرَأَةٍ مِنْ قُرَيْشٍ حَدَّثَتْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Az Zuhri] dari [Hind binti Al Harits] dari [Ummu Salamah], bahwa Nabi shallallahu 'alaihi wasallam jika selesai salam, beliau tetap berdiam di tempatnya sejenak.\" Ibnu Syihab berkata, \"Menurut kami -dan Allah yang lebih tahu, hal itu agar wanita yang akan pergi punya kesempatan.\" Dan [Ibnu Abu Maryam] berkata; telah mengabarkan kepada kami [Nafi' bin Yazid] berkata, telah mengabarkan kepadaku [Ja'far bin Rabi'ah] bahwa [Ibnu Syihab] menulis surat kepadanya; telah menceritakan kepadaku [Hind binti Al Harits Al Firasiyyah] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam -dia adalah teman Ummu Salamah- ia berkata, \"Ketika beliu salam, para wanita bergegas kembali ke rumah-rumah mereka masing-masing sebelum Rasulullah shallallahu 'alaihi wasallam beranjak pergi.\" [Ibnu Wahab] berkata; dari [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Hind Al Firasiyyah]. Dan ['Utsman bin 'Umar] berkata; telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah menceritakan kepadaku [Hind Al Firasiyyah]. Dan [Az Zubaidi] berkata; telah mengabarkan kepadaku [Az Zuhri] bahwa [Hind binti Al Harits Al Firasiyyah] mengabarkan kepadanya - saat itu wanita ini adalah isteri Ma'bad bin Al Miqdad, sekutunya Bani Zuhrah- Hind sering mengunjungi isteri-isrti Nabi shallallahu 'alaihi wasallam. Dan [Syu'aib] berkata; dari [Az Zuhri] telah menceritakan kepadaku [Hind Al Firasiyyah]. Dan [Ibnu Abu 'Atiq] berkata; dari [Az Zuhri] dari [Hind Al Firasiyyah]. Dan [Al Laits] berkata; telah menceritakan kepadaku [Yahya bin Sa'id] ia menceritakan kepadanya dari [Ibnu Syihab] dari [seorang wanita] suku Quraisy, ia menceritakan kepadanya dari Nabi shallallahu 'alaihi wasallam.\""},"804":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُمَرَ بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ قَالَصَلَّيْتُ وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ الْعَصْرَ فَسَلَّمَ ثُمَّ قَامَ مُسْرِعًا فَتَخَطَّى رِقَابَ النَّاسِ إِلَى بَعْضِ حُجَرِ نِسَائِهِ فَفَزِعَ النَّاسُ مِنْ سُرْعَتِهِ فَخَرَجَ عَلَيْهِمْ فَرَأَى أَنَّهُمْ عَجِبُوا مِنْ سُرْعَتِهِ فَقَالَ ذَكَرْتُ شَيْئًا مِنْ تِبْرٍ عِنْدَنَا فَكَرِهْتُ أَنْ يَحْبِسَنِي فَأَمَرْتُ بِقِسْمَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid bin Maimun] berkata, telah menceritakan kepada kami ['Isa bin Yunus] dari ['Umar bin Sa'id] berkata, telah mengabarkan kepadaku [Ibnu Abu Mulaikah] dari ['Uqbah] berkata, \"Aku pernah shalat 'Ashar di belakang Nabi shallallahu 'alaihi wasallam di kota Madinah. Setelah salam, tiba-tiba beliau berdiri dengan tergesa-gesa sambil melangkahi leher-leher orang banyak menuju sebagian kamar isteri-isterinya. Orang-orang pun merasa heran dengan ketergesa-gesaan beliau. Setelah itu beliau keluar kembali menemui orang banyak, dan beliau lihat orang-orang merasa heran. Maka beliau pun bersabda: \"Aku teringat dengan sebatang emas yang ada pada kami. Aku khawatir itu dapat menggangguku, maka aku perintahkan untuk dibagi-bagikan.\""},"805":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ الْأَسْوَدِ قَالَ قَالَ عَبْدُ اللَّهِلَا يَجْعَلْ أَحَدُكُمْ لِلشَّيْطَانِ شَيْئًا مِنْ صَلَاتِهِ يَرَى أَنَّ حَقًّا عَلَيْهِ أَنْ لَا يَنْصَرِفَ إِلَّا عَنْ يَمِينِهِ لَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَثِيرًا يَنْصَرِفُ عَنْ يَسَارِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari ['Umarah bin 'Umair] dari [Al Aswad] berkata, [Abdullah] berkata, \"Janganlah salah seorang dari kalian memberi peluang sedikitpun kepada setan untuk menggangu shalatnya.\" Dia berpendapat bahwa tidak boleh seseorang beranjak pergi kecuali dari sebelah kanannya, dan aku melihat Nabi shallallahu 'alaihi wasallam sering beranjak pergi dari sebelah kirinya.\""},"806":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي غَزْوَةِ خَيْبَرَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ يَعْنِي الثُّومَ فَلَا يَقْرَبَنَّ مَسْجِدَنَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepadaku [Nafi'] dari [Ibnu 'Umar] radliallahu 'anhuma, bahwa Nabi shallallahu 'alaihi wasallam bersabda saat terjadinya perang Khaibar: \"Barangsiapa memakan dari pohon ini, yaitu bawang putih, maka jangan sekali-kali dia mendekati masjid kami.\""},"807":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ يُرِيدُ الثُّومَ فَلَا يَغْشَانَا فِي مَسَاجِدِنَاقُلْتُ مَا يَعْنِي بِهِ قَالَ مَا أُرَاهُ يَعْنِي إِلَّا نِيئَهُ وَقَالَ مَخْلَدُ بْنُ يَزِيدَ عَنْ ابْنِ جُرَيْجٍ إِلَّا نَتْنَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Abu 'Ashim] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku ['Atha] berkata, \"Aku mendengar [Jabir bin 'Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakan dari pohon ini, - maksudnya bawang putih-, maka hendaklah dia tidak mendatangi kami di masjid-masjid kami.\" Aku bertanya, \"Apa yang beliau maksudkan itu?\" Maka Jabir menjawab, \"Aku tidak melihat maksud beliau yang lain kecuali yang mentah (belum dimasak).\" [Makhallad bin Yazid] menyebutkan dari [Ibnu Juraij], \"Kecuali yang mentah.\""},"808":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ زَعَمَ عَطَاءٌ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِزَعَمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ ثُومًا أَوْ بَصَلًا فَلْيَعْتَزِلْنَا أَوْ قَالَ فَلْيَعْتَزِلْ مَسْجِدَنَا وَلْيَقْعُدْ فِي بَيْتِهِ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِقِدْرٍ فِيهِ خ��ضِرَاتٌ مِنْ بُقُولٍ فَوَجَدَ لَهَا رِيحًا فَسَأَلَ فَأُخْبِرَ بِمَا فِيهَا مِنْ الْبُقُولِ فَقَالَ قَرِّبُوهَا إِلَى بَعْضِ أَصْحَابِهِ كَانَ مَعَهُ فَلَمَّا رَآهُ كَرِهَ أَكْلَهَا قَالَ كُلْ فَإِنِّي أُنَاجِي مَنْ لَا تُنَاجِيوَقَالَ أَحْمَدُ بْنُ صَالِحٍ عَنْ ابْنِ وَهْبٍ أُتِيَ بِبَدْرٍ وَقَالَ ابْنُ وَهْبٍ يَعْنِي طَبَقًا فِيهِ خَضِرَاتٌ وَلَمْ يَذْكُرِ اللَّيْثُ وَأَبُو صَفْوَانَ عَنْ يُونُسَ قِصَّةَ الْقِدْرِ فَلَا أَدْرِي هُوَ مِنْ قَوْلِ الزُّهْرِيِّ أَوْ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] bahwa ['Atha] menyakini bahwa [Jabir bin 'Abdullah] meyakini bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakan bawang putih atau bawang merah hendaklah dia menjauhi kami.\" Atau beliau mengatakan: \"Hendaklah dia menjauhi masjid kami dan hendaklah dia duduk berdiam di rumahnya.\" Dan bahwasanya Nabi shallallahu 'alaihi wasallam pernah diberikan periuk yang di dalamnya sayuran seperti kol. Kemudian beliau mencium arama sesuatu, beliau lalu menanyakannya dan beliau pun diberi kabar tentang beau tersebut. Maka beliau bersabda: \"Sodorkanlah!\" yakni kepada para sahabat yang bersamanya. Ketika beliau melihat mereka enggan memakannya, beliau pun bersabda: \"Makanlah! Sesungghuhnya aku berbicara dengan orang yang bukan engkau ajak bicara.\" [Ahmad bin Shalih] menyebutkan dari [Ibnu Wahab], \"Saat perang badar beliau diberi..\". Ibnu menyebutkan, \"Yakni mangkuk berisi sayuran.\" Namun [Al Laits] dan [Abu Shafwan] dari [Yunus] tidak menyebutkan perihal mangkuk tersebut, dan aku tidak tahu ucapan tadi perkataan Az Zuhri atau memang redaksi hadits begitu.\""},"809":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ قَالَ سَأَلَ رَجُلٌ أَنَسَ بْنَ مَالِكٍمَا سَمِعْتَ نَبِيَّ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الثُّومِ فَقَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ فَلَا يَقْرَبْنَا أَوْ لَا يُصَلِّيَنَّ مَعَنَا","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] dari ['Abdul 'Aziz] berkata, \"Seorang laki-laki bertanya kepada [Anas bin Malik], \"Pernyataan apa yang pernah kamu dengar dari Nabi shallallahu 'alaihi wasallam tentang bawang putih?\" Anas bin Malik menjawab, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakan dari pohon ini, maka jangan sekali-kali dia mendekati kami atau shalat bersama kami.\""},"810":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ سُلَيْمَانَ الشَّيْبَانِيَّ قَالَ سَمِعْتُ الشَّعْبِيَّ قَالَ أَخْبَرَنِي مَنْ مَرَّمَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرٍ مَنْبُوذٍ فَأَمَّهُمْ وَصَفُّوا عَلَيْهِ فَقُلْتُ يَا أَبَا عَمْرٍو مَنْ حَدَّثَكَ فَقَالَ ابْنُ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepadaku [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] berkata, Aku mendengar [Sulaiman Asy Syaibani] berkata, Aku mendengar [Asy Sya'bi] berkata, \"Telah mengabarkan kepadaku [orang yang berjalan] besama Nabi shallallahu 'alaihi wasallam melewati sebuah kuburan yang terpisah, kemudian Beliau memimpin mereka shalat dan orang-orang membuat shaf lalu shalat untuk kuburan tersebut.\" Maka aku tanyakan, \"Wahai Abu 'Amru, siapa yang menceritakan kepadamu tentang ini?\" Dia menjawab, \"Ibnu 'Abbas.\""},"811":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي صَفْوَانُ بْنُ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْغُسْلُ يَوْمَ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepadaku [Shafwan bin Sulaim] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mandi pada hari Jum'at adalah wajib bagi orang yang sudah bermimpi (baligh).\""},"812":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ أَخْبَرَنِي كُرَيْبٌ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ لَيْلَةً فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا كَانَ فِي بَعْضِ اللَّيْلِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَضَّأَ مِنْ شَنٍّ مُعَلَّقٍ وُضُوءًا خَفِيفًا يُخَفِّفُهُ عَمْرٌو وَيُقَلِّلُهُ جِدًّا ثُمَّ قَامَ يُصَلِّي فَقُمْتُ فَتَوَضَّأْتُ نَحْوًا مِمَّا تَوَضَّأَ ثُمَّ جِئْتُ فَقُمْتُ عَنْ يَسَارِهِ فَحَوَّلَنِي فَجَعَلَنِي عَنْ يَمِينِهِ ثُمَّ صَلَّى مَا شَاءَ اللَّهُ ثُمَّ اضْطَجَعَ فَنَامَ حَتَّى نَفَخَ فَأَتَاهُ الْمُنَادِي يَأْذَنُهُ بِالصَّلَاةِ فَقَامَ مَعَهُ إِلَى الصَّلَاةِ فَصَلَّى وَلَمْ يَتَوَضَّأْقُلْنَا لِعَمْرٍو إِنَّ نَاسًا يَقُولُونَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَنَامُ عَيْنُهُ وَلَا يَنَامُ قَلْبُهُ قَالَ عَمْرٌو سَمِعْتُ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ إِنَّ رُؤْيَا الْأَنْبِيَاءِ وَحْيٌ ثُمَّ قَرَأَ{ إِنِّي أَرَى فِي الْمَنَامِ أَنِّي أَذْبَحُكَ }","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah mengabarkan kepada kami [Sufyan] dari ['Amru] berkata, telah mengabarkan kepadaku [Kuraib] dari [Ibnu 'Abbas] radliallahu 'anhuma berkata, \"Suatu malam aku pernah menginap di rumah bibiku, Maimunah? radliallahu 'anha. Lalu Nabi shallallahu 'alaihi wasallam tidur dan bangun kembali di sebagian waktu malam, beliau berwudlu dari geriba yang sudah yang digantung secara ringan -'Amru teramat mensedikitkan (air yang dipakai) -. Kemudian beliau berdiri shalat, aku lalu bangun; berwudlu sebagaimana beliau wudlu. Kemudian aku datang dan berdiri di sisi kiri beliau, namun beliau kemudian menggeser aku ke sebelah kanannya. Beliau lalu shalat menurut apa yang Allah kehendaki (lamanya), kemudian beliau berbaring tertidur hingga mendengkur. Setelah itu datanglah seorang mu'adzin yang memberitahukan bahwa waktu shalat shubuh telah tiba. Beliau kemudian berangkat bersama mu'adzin tersebut untuk menunaikan shalat dengan tidak berwudlu lagi.\" Kami tanyakan kepada 'Amru: \"Orang-orang mengatakan bahwa Nabi shallallahu 'alaihi wasallam (jika tidur), mata beliau tidur namun hatinya tidak.\" Maka 'Amru menjawab, \"Aku mendengar 'Ubaid bin 'Umair berkata, \"Sesungguhnya mimpinya para Nabi adalah wahyu.\" Lalu dia membaca firman Allah: '(Sesungguhnya Aku melihat dalam mimpi bahwa Aku menyembelihmu) ' (Qs. Ash Shaffaat: 102)."},"813":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ جَدَّتَهُ مُلَيْكَةَ دَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَتْهُ فَأَكَلَ مِنْهُ فَقَالَ قُومُوا فَلِأُصَلِّيَ بِكُمْ فَقُمْتُ إِلَى حَصِيرٍ لَنَا قَدْ اسْوَدَّ مِنْ طُولِ مَا لَبِثَ فَنَضَحْتُهُ بِمَاءٍ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْيَتِيمُ مَعِي وَالْعَجُوزُ مِنْ وَرَائِنَا فَصَلَّى بِنَا رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa neneknya, Mulaikah, mengundang Rasulullah shallallahu 'alaihi wasallam untuk menghadiri hidangan yang ia masak untuknya. Beliau lantas memakannya lalu bersabda: \"Berdirilah kalian, aku akan pimpin shalat kalian.\" Maka aku berdiri di tikar milik kami yang sudah hitam lusuh akibat sering digunakan. Tikar itu kemudian aku perciki dengan air, lalu Rasulullah shallallahu 'alaihi wasallam berdiri diatasnya. Maka aku dan anak yatim yang tinggal bersama kami merapatkan shaf di belakang beliau sedangkan nenek kami berdiri di belakang kami. Nabi shallallahu 'alaihi wasallam kemudian shalat memimpim kami sebanyak dua rakaat.\""},"814":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَأَقْبَلْتُ رَاكِبًا عَلَى حِمَارٍ أَتَانٍ وَأَنَا يَوْمَئِذٍ قَدْ نَاهَزْتُ الِاحْتِلَامَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِالنَّاسِ بِمِنًى إِلَى غَيْرِ جِدَارٍ فَمَرَرْتُ بَيْنَ يَدَيْ بَعْضِ الصَّفِّ فَنَزَلْتُ وَأَرْسَلْتُ الْأَتَانَ تَرْتَعُ وَدَخَلْتُ فِي الصَّفِّ فَلَمْ يُنْكِرْ ذَلِكَ عَلَيَّ أَحَدٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Ibnu 'Abbas] radliallahu 'anhuma, bahwa dia berkata, \"Pada suatu hari aku datang sambil menunggang keledai betina dan pada saat itu usiaku hampir baligh. Saat itu Rasulullah shallallahu 'alaihi wasallam sedang shalat bersama orang banyak di Mina tanpa ada dinding di hadapannya. Maka aku lewat di depan sebagian shaf. Lalu aku turun dan aku biarkan keledaiku mencari makan, aku lantas masuk ke dalam barisan shaf dan tidak ada seorangpun yang menegurku.\""},"815":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ قَالَتْ أَعْتَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَيَّاشٌ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْعِشَاءِ حَتَّى نَادَاهُ عُمَرُ قَدْ نَامَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَيْسَ أَحَدٌ مِنْ أَهْلِ الْأَرْضِ يُصَلِّي هَذِهِ الصَّلَاةَ غَيْرُكُمْ وَلَمْ يَكُنْ أَحَدٌ يَوْمَئِذٍ يُصَلِّي غَيْرَ أَهْلِ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengakhirkan shalat 'Isya' ketika malam sudah larut.\" ['Ayyasy] berkata; telah menceritakan kepada kami ['Abdul A'la] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] radliallahu 'anhuma, berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengakhirkan shalat 'Isya' ketika malam sudah larut, hingga akhirnya 'Umar berseru kepada Beliau, \"Para wanita dan anak-anak sudah tidur.\" Beliau lalu keluar seraya bersabda: \"Tidak ada seorangpun dari penduduk bumi mengerjakan shalat ini selain kalian.\" Dan pada saat itu tidak ada satu orangpun yang melaksanakan shalat selain penduduk Madinah.\""},"816":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَابِسٍ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاقَالَ لَهُ رَجُلٌ شَهِدْتَ الْخُرُوجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَلَوْلَا مَكَانِي مِنْهُ مَا شَهِدْتُهُ يَعْنِي مِنْ صِغَرِهِ أَتَى الْعَلَمَ الَّذِي عِنْدَ دَارِ كَثِيرِ بْنِ الصَّلْتِ ثُمَّ خَطَبَ ثُمَّ أَتَى النِّسَاءَ فَوَعَظَهُنَّ وَذَكَّرَهُنَّ وَأَمَرَهُنَّ أَنْ يَتَصَدَّقْنَ فَجَعَلَتْ الْمَرْأَةُ تُهْوِي بِيَدِهَا إِلَى حَلْقِهَا تُلْقِي فِي ثَوْبِ بِلَالٍ ثُمَّ أَتَى هُوَ وَبِلَالٌ الْبَيْتَ","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku ['Abdurrahman bin 'Abis] berkata, Aku mendengar ada seseorang bertanya kepada [Ibnu 'Abbas] radliallahu 'anhuma, \"Apakah engkau pernah ikut keluar (shalat) bersama Rasulullah shallallahu 'alaihi wasallam?\" Dia menjawab, \"Ya. Sekiranya bukan karena kedudukanku di sisi Beliau, niscaya aku tidak mungkin (bisa) ikut -karena umurnya masih kecil-. Beliau mendatangi tempat yang agak tinggi dekat rumah Katsir bin Ash Shalt lalu memberikan ceramah, kemudian mendatangi para wanita. Beliau lantas memberi nasihat kepada mereka, mengingatkan dan memerintahkan mereka agar bersedekah. Maka para wanita tersebut memberikan apa yang ada pada tangan dan leher mereka (emas perhiasan) lalu dimasukkan ke dalam kain Bilal, setelah itu beliau dan Bilal menuju Ka'bah.\""},"817":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعَتَمَةِ حَتَّى نَادَاهُ عُمَرُ نَامَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا يَنْتَظِرُهَا أَحَدٌ غَيْرُكُمْ مِنْ أَهْلِ الْأَرْضِ وَلَا يُصَلَّى يَوْمَئِذٍ إِلَّا بِالْمَدِينَةِ وَكَانُوا يُصَلُّونَ الْعَتَمَةَ فِيمَا بَيْنَ أَنْ يَغِيبَ الشَّفَقُ إِلَى ثُلُثِ اللَّيْلِ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah] radliallahu 'anha berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengakhirkan shalat 'Isya' ketika malam sudah larut, hingga 'Umar berseru pun kepada beliau, \"Para wanita dan anak-anak sudah tidur!\" Maka keluarlah Rasulullah seraya bersabda: \"Tidak ada seorangpun yang menunggu pelaksanaan shalat 'Isya ini dari penduduk bumi selain kalian.\" Dan pada hari itu tidak ada satu orangpun yang melaksanakan shalat selain penduduk Madinah. Mereka melakanakan shalat 'Isya antara telah berlalunya waktu syafaq hingga sepertiga awal malam.\""},"818":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ حَنْظَلَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَأْذَنَكُمْ نِسَاؤُكُمْ بِاللَّيْلِ إِلَى الْمَسْجِدِ فَأْذَنُوا لَهُنَّتَابَعَهُ شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Hanzhalah] dari [Salim bin 'Abdullah] dari [Ibnu 'Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika isteri-isteri kalian minta izin ke masjid di waktu malam, maka berilah mereka izin.\" Hadits ini dikuatkan oleh [Syu'bah] dari [Al A'masy] dari [Mujahid] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam.\""},"819":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَتْنِي هِنْدُ بِنْتُ الْحَارِثِ أَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهَاأَنَّ النِّسَاءَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنَّ إِذَا سَلَّمْنَ مِنْ الْمَكْتُوبَةِ قُمْنَ وَثَبَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ صَلَّى مِنْ الرِّجَالِ مَا شَاءَ اللَّهُ فَإِذَا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ الرِّجَالُ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami ['Utsman bin 'Umar] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] berkata, telah menceritakan kepadaku [Hind binti Al Harits] bahwa [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya, bahwa para wanita di zaman Rasulullah shallallahu 'alaihi wasallam jika mereka telah selesai dari shalat fardlu, maka mereka segera beranjak pergi. Sedangkan Rasulullah shallallahu 'alaihi wasallam dan kaum laki-laki yang shalat bersama beliau tetap diam di tempat sampai waktu yang Allah kehendaki. Ketika Rasulullah shallallahu 'alaihi wasallam berdiri dan beranjak pergi maka mereka pun mengikutinya.\""},"820":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُصَلِّي الصُّبْحَ فَيَنْصَرِفُ النِّسَاءُ مُتَلَفِّعَاتٍ بِمُرُوطِهِنَّ مَا يُعْرَفْنَ مِنْ الْغَلَسِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman] dari ['Aisyah] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat Shubuh, maka para wanita yang ikut berjama'ah datang dengan menutup wajah mereka dengan tanpa diketahui oleh seorangpun karena hari masih gelap.\""},"821":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِسْكِينٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ بَكْرٍ أَخْبَرَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ الْأَنْصَارِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَقُومُ إِلَى الصَّلَاةِ وَأَنَا أُرِيدُ أَنْ أُطَوِّلَ فِيهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ فِي صَلَاتِي كَرَاهِيَةَ أَنْ أَشُقَّ عَلَى أُمِّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Miskin] berkata, telah menceritakan kepada kami [Bisyir bin Bakar] telah mengabarkan kepada kami [Al Auza'i] telah menceritakan kepadaku [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah Al Anshari] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku pernah berdiri melaksanakan shalat dan aku ingin memanjangkannya, namun kemudian aku mendengar tangisan bayi. Maka aku pendekkan shalatku karena aku khawatir akan memberatkan ibunya.\""},"822":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَوْ أَدْرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحْدَثَ النِّسَاءُ لَمَنَعَهُنَّ كَمَا مُنِعَتْ نِسَاءُ بَنِي إِسْرَائِيلَ قُلْتُ لِعَمْرَةَ أَوَمُنِعْنَ قَالَتْ نَعَمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari ['Amrah] dari ['Aisyah] radliallahu 'anha berkata, \"Seandainya Rasulullah shallallahu 'alaihi wasallam mengetahui apa yang telah terjadi dengan para wanita sekarang ini, niscaya beliau akan melarang mereka sebagaimana dilarangnya para wanita bani Isra'il.\" Yahya berkata, \"Aku bertanya 'Amrah, \"Apakah mereka dilarang? 'Amrah menjawab, \"Ya.\""},"823":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ هِنْدٍ بِنْتِ الْحَارِثِ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ قَامَ النِّسَاءُ حِينَ يَقْضِي تَسْلِيمَهُ وَيَمْكُثُ هُوَ فِي مَقَامِهِ يَسِيرًا قَبْلَ أَنْ يَقُومَقَالَ نَرَى وَاللَّهُ أَعْلَمُ أَنَّ ذَلِكَ كَانَ لِكَيْ يَنْصَرِفَ النِّسَاءُ قَبْلَ أَنْ يُدْرِكَهُنَّ أَحَدٌ مِنْ الرِّجَالِ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Hind binti Al Harits] dari [Ummu Salamah] radliallahu 'anhu, ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mengucapkan salam, maka para wanita langsung beranjak pergi ketika beliau selesai mengucapkan salamnya. Sementara beliau tetap di tempatnya sejenak sebelum beranjak pergi. Menurut kami -dan hadits hanya Allah yang tahu- beliau lakukan itu agar para wanita bisa segera pergi sebelum diketahui oleh seorangpun dari jama'ah laki-laki.\""},"824":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ أُمِّ سُلَيْمٍ فَقُمْتُ وَيَتِيمٌ خَلْفَهُ وَأُمُّ سُلَيْمٍ خَلْفَنَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Ishaq bin 'Abdullah] dari [Anas bin Malik] radliallahu 'anhu, ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat di rumah Ummu Sulaim, maka aku dan anak yatim ikut di belakang beliau sedangkan Ummu Sulaim berdiri di belakang kami.\""},"825":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا فُلَيْحٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الصُّبْحَ بِغَلَسٍ فَيَنْصَرِفْنَ نِسَاءُ الْمُؤْمِنِينَ لَا يُعْرَفْنَ مِنْ الْغَلَسِ أَوْ لَا يَعْرِفُ بَعْضُهُنَّ بَعْضًا","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Fulaih] dari ['Abdurrahman bin Al Qasim] dari [Bapaknya] dari ['Aisyah] radliallahu 'anha, bahwasanya Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat Shubuh di waktu yang masih gelap, sehingga kaum Mukminah berlalu pergi tidak ada yang dapat mengenalinya, atau sebagian mereka tidak bisa mengetahui sebagian yang lain.\""},"826":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَأْذَنَتْ امْرَأَةُ أَحَدِكُمْ فَلَا يَمْنَعْهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Ma'mar] dari [Az Zuhri] dari [Salim bin 'Abdullah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika isteri salah seorang dari kalian minta izin (untuk ke Masjid), hendaklah ia larang.\""},"827":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ هُرْمُزَ الْأَعْرَجَ مَوْلَى رَبِيعَةَ بْنِ الْحَارِثِ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَحْنُ الْآخِرُونَ السَّابِقُونَ يَوْمَ الْقِيَامَةِ بَيْدَ أَنَّهُمْ أُوتُوا الْكِتَابَ مِنْ قَبْلِنَا ثُمَّ هَذَا يَوْمُهُمْ الَّذِي فُرِضَ عَلَيْهِمْ فَاخْتَلَفُوا فِيهِ فَهَدَانَا اللَّهُ فَالنَّاسُ لَنَا فِيهِ تَبَعٌ الْيَهُودُ غَدًا وَالنَّصَارَى بَعْدَ غَدٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] berkata, telah menceritakan kepada kami [Abu Az Zinad] banwa ['Abdurrahman bin Hurmuz Al A'raj] mantan budak Rabi'ah bin Al Harits, menceritakan kepadanya bahwasanya dia mendengar [Abu Hurairah] radliallahu 'anhu, bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita datang terakhir dan pertama pada hari kiamat, meskipun mereka diberi Kitab sebelum kita. Dan ini adalah hari dimana mereka mendapat kewajiban, namun kemudian mereka berselisih di dalamnya. Allah lalu memberi hidayah kepada kita, maka semua manusia akan mengikuti kita (hari ini), besok hari untuk Yahudi dan Nashrani hari setelahnya lagi.\""},"828":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ أَحَدُكُمْ الْجُمُعَةَ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorangii kalian mendatangi shalat jum'at hendaklah ia mandi.\""},"829":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ قَالَ أَخْبَرَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ عُمَرَ بْنَ الْخَطَّابِبَيْنَمَا هُوَ قَائِمٌ فِي الْخُطْبَةِ يَوْمَ الْجُ��ُعَةِ إِذْ دَخَلَ رَجُلٌ مِنْ الْمُهَاجِرِينَ الْأَوَّلِينَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَاهُ عُمَرُ أَيَّةُ سَاعَةٍ هَذِهِ قَالَ إِنِّي شُغِلْتُ فَلَمْ أَنْقَلِبْ إِلَى أَهْلِي حَتَّى سَمِعْتُ التَّأْذِينَ فَلَمْ أَزِدْ أَنْ تَوَضَّأْتُ فَقَالَ وَالْوُضُوءُ أَيْضًا وَقَدْ عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ بِالْغُسْلِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad bin Asma'] berkata, telah mengabarkan kepada kami [Juwairiyah bin Asma'] dari [Malik] dari [Az Zuhri] dari [Salim bin 'Abdullah bin 'Umar] dari [Ibnu Umar] radliallahu 'anhuma, bahwa ketika ['Umar bin Al Khaththab] berdiri khuthbah pada hari Jum'at, tiba-tiba ada seorang laki-laki Muhajirin Al Awwalin (generasi pertama), sahabat Nabi shallallahu 'alaihi wasallam, masuk (ke dalam Masjid). Maka 'Umar pun bertanya, \"Jam berapakah ini?\" Sahabat tersebut menjawab, \"Aku sibuk, dan aku belum sempat pulang ke rumah hingga akhirnya aku mendengar adzan dan aku hanya bisa berwudlu.\" Umar berkata, \"Hanya berwudlu' saja! Sungguh kamu sudah mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk mandi (di hari Jum'at).\""},"830":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غُسْلُ يَوْمِ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Shafwan bin Sulaim] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudri] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandi pada hari Jum'at adalah wajib bagi setiap orang yang sudah baligh.\""},"831":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بَكرِ بْنِ الْمُنكَدِرِ قَالَ حَدَّثَنِي عَمْرُو بْنُ سُلَيْمٍ الْأَنْصَارِيُّ قَالَ أَشْهَدُ عَلَى أَبِي سَعِيدٍ قَالَأَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْغُسْلُ يَوْمَ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ وَأَنْ يَسْتَنَّ وَأَنْ يَمَسَّ طِيبًا إِنْ وَجَدَقَالَ عَمْرٌو أَمَّا الْغُسْلُ فَأَشْهَدُ أَنَّهُ وَاجِبٌ وَأَمَّا الِاسْتِنَانُ وَالطِّيبُ فَاللَّهُ أَعْلَمُ أَوَاجِبٌ هُوَ أَمْ لَا وَلَكِنْ هَكَذَا فِي الْحَدِيثِ قَالَ أَبُو عَبْد اللَّهِ هُوَ أَخُو مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَلَمْ يُسَمَّ أَبُو بَكْرٍ هَذَا رَوَاهُ عَنْهُ بُكَيْرُ بْنُ الْأَشَجِّ وَسَعِيدُ بْنُ أَبِي هِلَالٍ وَعِدَّةٌ وَكَانَ مُحَمَّدُ بْنُ الْمُنْكَدِرِ يُكْنَى بِأَبِي بَكْرٍ وَأَبِي عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah bin Ja'far] berkata, telah menceritakan kepada kami [Harami bin 'Umarah] berkata, telah menceritakan kepadaku [Syu'bah] dari [Abu Bakar bin Al Munkadir] berkata, telah menceritakan kepadaku ['Amru bin Sulaim Al Anshari] berkata, \"Aku bersaksi atas [Abu Sa'id Al Khudri] ia berkata, \"Aku bersaksi atas Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Mandi pada hari Jum'at merupakan kewajiban bagi orang yang sudah bermimpi (baligh), dan agar bersiwak (menggosok gigi) dan memakai wewangian bila memilikinya.\" 'Amru berkata, \"Adapun mandi, aku bersaksi bahwa itu adalah wajib. Sedangkan bersiwak dan memakai wewangian -dan Allah yang lebih tahu- aku tidak tahu ia wajib atau tidak, tapi begitulah yang ada dalam hadits.\" Abu 'Abdullah -yaitu saudara Muhammad bin Al Munkadir, dan tidak disbeut dengan nama Abu Bakar- berkata, 'Hadits ini diriwayatkan darinya oleh [Bukair bin Al Asyaj] dan [Sa'id bin Abu Hilal] dan masih banyak lagi.' Dan Muhammad bin Al Munkadir punya nama panggilan Abu Bakar dan 'Abdullah.\""},"832":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ غُسْلَ الْجَنَابَةِ ثُمَّ رَاحَ فَكَأَنَّمَا قَرَّبَ بَدَنَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّانِيَةِ فَكَأَنَّمَا قَرَّبَ بَقَرَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّالِثَةِ فَكَأَنَّمَا قَرَّبَ كَبْشًا أَقْرَنَ وَمَنْ رَاحَ فِي السَّاعَةِ الرَّابِعَةِ فَكَأَنَّمَا قَرَّبَ دَجَاجَةً وَمَنْ رَاحَ فِي السَّاعَةِ الْخَامِسَةِ فَكَأَنَّمَا قَرَّبَ بَيْضَةً فَإِذَا خَرَجَ الْإِمَامُ حَضَرَتْ الْمَلَائِكَةُ يَسْتَمِعُونَ الذِّكْرَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Sumayya] mantan budak Abu Bakar bin 'Abdurrahman, dari [Abu Shalih As Saman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mandi pada hari Jum'at sebagaimana mandi janabah, lalu berangkat menuju Masjid, maka dia seolah berkurban seekor unta. Dan barangiapa datang pada kesempatan (saat) kedua maka dia seolah berkurban seekor sapi. Dan barangiapa datang pada kesempatan (saat) ketiga maka dia seolah berkurban seekor kambing yang bertanduk. Dan barangiapa datang pada kesempatan (saat) keempat maka dia seolah berkurban seekor ayam. Dan barangiapa datang pada kesempatan (saat) kelima maka dia seolah berkurban sebutir telur. Dan apabila imam sudah keluar (untuk memberi khuthbah), maka para Malaikat hadir mendengarkan dzikir (khuthbah tersebut).\""},"833":{"ar":"بَاب حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى هُوَ ابْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ عُمَرَ رَضِيَ اللَّهُ عَنْهُبَيْنَمَا هُوَ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ دَخَلَ رَجُلٌ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ لِمَ تَحْتَبِسُونَ عَنْ الصَّلَاةِ فَقَالَ الرَّجُلُ مَا هُوَ إِلَّا أَنْ سَمِعْتُ النِّدَاءَ تَوَضَّأْتُ فَقَالَ أَلَمْ تَسْمَعُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَاحَ أَحَدُكُمْ إِلَى الْجُمُعَةِ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] -yaitu Ibnu Abu Katsir- dari [Abu Salamah] dari [Abu Hurairah] bahwa ['Umar] radliallahu 'anhu ketika berdiri memberikah khuthbah pada hari Jum'at, tiba-tiba ada seorang laki-laki masuk (Masjid). 'Umar lalu bertanya, \"Kenapa anda terlambat shalat?\" Laki-laki itu menjawab: \"Aku tidak tahu hingga aku mendengar adzan, maka aku pun hanya berwudlu.\" Maka \"Umar berkata, \"Bukankah kamu sudah mendengar bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Jika salah seorang dari kalian berangkat shalat jum'at hendaklah mandi.\""},"834":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ قَالَ أَخْبَرَنِي أَبِي عَنْ ابْنِ وَدِيعَةَ عَنْ سَلْمَانَ الْفَارِسِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْتَسِلُ رَجُلٌ يَوْمَ الْجُمُعَةِ وَيَتَطَهَّرُ مَا اسْتَطَاعَ مِنْ طُهْرٍ وَيَدَّهِنُ مِنْ دُهْنِهِ أَوْ يَمَسُّ مِنْ طِيبِ بَيْتِهِ ثُمَّ يَخْرُجُ فَلَا يُفَرِّقُ بَيْنَ اثْنَيْنِ ثُمَّ يُصَلِّي مَا كُتِبَ لَهُ ثُمَّ يُنْصِتُ إِذَا تَكَلَّمَ الْإِمَامُ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id Al Maqburi] berkata, telah mengabarkan kepadaku [Bapakku] dari [Ibnu Wadi'ah] dari [Salman Al Farsi] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki mandi pada hari Jum'at lalu bersuci semaksimal mungkin, memakai wewangian miliknya atau minyak wangi keluarganya, lalu keluar rumah menuju Masjid, ia tidak memisahkan dua orang pada tempat duduknya lalu dia shalat yang dianjurkan baginya dan diam mendengarkan khutbah Imam, kecuali dia akan diampuni dosa-dosanya yang ada antara Jum'atnya itu dan Jum'at yang lainnya.\""},"835":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ طَاوُسٌ قُلْتُ لِابْنِ عَبَّاسٍ ذَكَرُواأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اغْتَسِلُوا يَوْمَ الْجُمُعَةِ وَاغْسِلُوا رُءُوسَكُمْ وَإِنْ لَمْ تَكُونُوا جُنُبًا وَأَصِيبُوا مِنْ الطِّيبِ قَالَ ابْنُ عَبَّاسٍ أَمَّا الْغُسْلُ فَنَعَمْ وَأَمَّا الطِّيبُ فَلَا أَدْرِي","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri], [Thawus] berkata, Aku berkata kepada [Ibnu 'Abbas], \"Orang-orang menyebutkan bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Mandilah pada hari Jum'at dan basuhlah kepala kalian sekalipun tidak sedang junub, dan pakailah wewangian.\" Ibnu 'Abbas berkata, \"Adapun mandi, memang benar bahwa itu adalah wajib, sedangkan memakai wewangian aku tidak tahu.\""},"836":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ مَيْسَرَةَ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ ذَكَرَ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغُسْلِ يَوْمَ الْجُمُعَةِ فَقُلْتُ لِابْنِ عَبَّاسٍ أَيَمَسُّ طِيبًا أَوْ دُهْنًا إِنْ كَانَ عِنْدَ أَهْلِهِ فَقَالَ لَا أَعْلَمُهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, ia katakan; telah mengabarkan kepadaku [Ibrahim bin Maisarah] dari [Thawus] dari [Ibnu 'Abbas] radliallahu 'anhuma, bahwa dia menyebutkan sabda Nabi shallallahu 'alaihi wasallam perihal mandi pada hari Jum'at. Maka aku pun bertanya kepada Ibnu 'Abbas, 'Apakah beliau memakai wewangian ketika berada bersama keluarga Beliau? ' ia menjawab, 'Aku tidak tahu'.\""},"837":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَأَى حُلَّةً سِيَرَاءَ عِنْدَ بَابِ الْمَسْجِدِ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ اشْتَرَيْتَ هَذِهِ فَلَبِسْتَهَا يَوْمَ الْجُمُعَةِ وَلِلْوَفْدِ إِذَا قَدِمُوا عَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ ثُمَّ جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا حُلَلٌ فَأَعْطَى عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ مِنْهَا حُلَّةً فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ كَسَوْتَنِيهَا وَقَدْ قُلْتَ فِي حُلَّةِ عُطَارِدٍ مَا قُلْتَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَمْ أَكْسُكَهَا لِتَلْبَسَهَا فَكَسَاهَا عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ أَخًا لَهُ بِمَكَّةَ مُشْرِكًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa 'Umar bin Al Khaththab melihat pakaian sutera di depan pintu masjid, maka ia pun berkata, \"Wahai Rasulullah, seandainya tuan beli pakaian ini lalu tuan kenakan pada hari Jum'at atau saat menyambut utusan (delegasi) bila datang menghadap tuan.\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Sesungguhnya orang yang memakai pakaian seperti ini tidak akan mendapat bagian di akhirat.\" Kemudian datang hadiah untuk Rasulullah shallallahu 'alaihi wasallam yang diantaranya ada pakain sutera. Beliau lalu memberikan pakaian sutera tersebut kepada 'Umar bin Al Khaththab? radliallahu 'anhu, maka berkatalah 'Umar, \"Wahai Rasulullah, tuan telah memberikan pakaian ini untukku, padahal tuan telah menjelaskan konsekwensi orang yang memakainya!\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku memberikannya kepadamu bukan untuk kamu pakai.\" Maka 'Umar bin Al Khaththab memberikan pakaian sutera tersebut kepada saudaranya yang musyrik di kota Makkah.\""},"838":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي أَوْ عَلَى النَّاسِ لَأَمَرْتُهُمْ بِالسِّوَاكِ مَعَ كُلِّ صَلَاةٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak memberatkan ummatku atau manusia, niscaya aku akan perintahkan kepada mereka untuk bersiwak (menggosok gigi) pada setiap kali hendak shalat.\""},"839":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ الْحَبْحَابِ حَدَّثَنَا أَنَسٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرْتُ عَلَيْكُمْ فِي السِّوَاكِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami [Syu'aib bn Al Habhab] telah menceritakan kepada kami [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah terlalu sering memperingatkan kalian untuk selalu bersiwak.\""},"840":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَحُصَيْنٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ ��للَّيْلِ يَشُوصُ فَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Manshur] dan [Hushain] dari [Abu Wa'il] dari [Hudzifah] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam bangun untuk shalat malam, beliau menggosok mulutnya.\""},"841":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ قَالَ قَالَ هِشَامُ بْنُ عُرْوَةَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍ وَمَعَهُ سِوَاكٌ يَسْتَنُّ بِهِ فَنَظَرَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ أَعْطِنِي هَذَا السِّوَاكَ يَا عَبْدَ الرَّحْمَنِ فَأَعْطَانِيهِ فَقَصَمْتُهُ ثُمَّ مَضَغْتُهُ فَأَعْطَيْتُهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَنَّ بِهِ وَهُوَ مُسْتَسْنِدٌ إِلَى صَدْرِي","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Sulaiman bin Bilal] berkata, [Hisyam bin 'Urwah] berkata, telah mengabarkan kepadaku [Bapakku] dari ['Aisyah] radliallahu 'anha, ia berkata, \"'Abdurrahman bin Abu Bakar datang dengan membawa siwak yang dia gunakan untuk membersihkan giginya, Rasulullah shallallahu 'alaihi wasallam lalu memandang ke arahnya. Maka aku pun berkata kepadanya, \"Wahai 'Abdurrahman, berikanlah siwak itu kepadaku.\" 'Abdurrahman kemudian memberikannya kepadaku, kemudian aku pecahkan dengan gigiku dan mengunyahnya (hingga lembut). Setelah itu siwak tersebut aku berikan kepada Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah menggosok giginya dengan menyandar pada dadaku.\""},"842":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ هُرْمُزَ الْأَعْرَجُ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْجُمُعَةِ فِي صَلَاةِ الْفَجْرِ الم تَنْزِيلُ السَّجْدَةَ وَهَلْ أَتَى عَلَى الْإِنْسَانِ حِينٌ مِنْ الدَّهْرِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sufyan] dari [Sa'd bin Ibrahim] dari ['Abdurrahman] -yaitu Ibnu Hurmuz Al A'raj dari [Abu Hurairah] radliallahu 'anhu berkata, \"Nabi shallallahu 'alaihi wasallam dalam shalat Fajar membaca: \"ALIF LAAM MIIM TANZIIL (Surah As Sajadah), dan 'HAL ATAA 'ALAL INSAANI HIINUM MINAD DAHRI (Surah Al Insaan).\""},"843":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَبِي جَمْرَةَ الضُّبَعِيِّ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَإِنَّ أَوَّلَ جُمُعَةٍ جُمِّعَتْ بَعْدَ جُمُعَةٍ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِ عَبْدِ الْقَيْسِ بِجُوَاثَى مِنْ الْبَحْرَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] berkata, telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Abu Jamrah Adl Dluba'i] dari [Ibnu 'Abbas] bahwa dia berkata, \"Sesungguhnya (shalat) Jum'at yang pertama kali dilaksanakan setelah (shalat) Jum'at) di Masjid Rasulullah shallallahu 'alaihi wasallam adalah di Masjid 'Abdul Qais di kampung Juwatsa, negeri Bahrain.\""},"844":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنَا سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّكُمْ رَاعٍ وَزَادَ اللَّيْثُ قَالَ يُونُسُ كَتَبَ رُزَيْقُ بْنُ حُكَيْمٍ إِلَى ابْنِ شِهَابٍ وَأَنَا مَعَهُ يَوْمَئِذٍ بِوَادِي الْقُرَى هَلْ تَرَى أَنْ أُجَمِّعَ وَرُزَيْقٌ عَامِلٌ عَلَى أَرْضٍ يَعْمَلُهَا وَفِيهَا جَمَاعَةٌ مِنْ السُّودَانِ وَغَيْرِهِمْ وَرُزَيْقٌ يَوْمَئِذٍ عَلَى أَيْلَةَ فَكَتَبَ ابْنُ شِهَابٍ وَأَنَا أَسْمَعُ يَأْمُرُهُ أَنْ يُجَمِّعَ يُخْبِرُهُ أَنَّ سَالِمًا حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ الْإِمَامُ رَاعٍ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ وَالرَّجُلُ رَاعٍ فِي أَهْلِهِ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالْمَرْأَةُ رَاعِيَةٌ فِي بَيْتِ زَوْجِهَا وَمَسْئُولَةٌ عَنْ رَعِيَّتِهَا وَالْخَادِمُ رَاعٍ فِي مَالِ سَيِّدِهِ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ قَالَ وَحَسِبْتُ أَنْ قَدْ قَالَ وَالرَّجُلُ رَاعٍ فِي مَالِ أَبِيهِ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ وَكُلُّكُمْ رَاعٍ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ","id":"Telah menceritakan kepada kami [Bisyr bin Muhammad Al Marwazi] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] berkata, telah mengabarkan kepada kami [Salim bin 'Abdullah] dari [Ibnu 'Umar] radliallahu 'anhuma, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap kalian adalah pemimpin.\" [Al Laits] menambahkan; [Yunus] berkata; Ruzaiq bin Hukaim menulis surat kepada [Ibnu Syihab], dan pada saat itu aku bersamanya di Wadi Qura (pinggiran kota), \"Apa pendapatmu jika aku mengumpulkan orang untuk shalat Jum'at?\" -Saat itu Ruzaiq bertugas di suatu tempat dimana banyak jama'ah dari negeri Sudan dan yang lainnya, yaitu di negeri Ailah-. Maka Ibnu Syihab membalasnya dan aku mendengar dia memerintahkan (Ruzaiq) untuk mendirikan shalat Jum'at. Lalu mengabarkan bahwa [Salim] telah menceritakan kepadanya, bahwa ['Abdullah bin 'Umar] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap kalian adalah pemimpin, dan setiap pemimpin akan dimintai pertanggung jawaban atas yang dipimpinnya. Imam adalah pemimpin yang akan diminta pertanggung jawaban atas rakyatnya. Seorang suami adalah pemimpin dan akan dimintai pertanggung jawaban atas keluarganya. Seorang isteri adalah pemimpin di dalam urusan rumah tangga suaminya, dan akan dimintai pertanggung jawaban atas urusan rumah tangga tersebut. Seorang pembantu adalah pemimpin dalam urusan harta tuannya, dan akan dimintai pertanggung jawaban atas urusan tanggung jawabnya tersebut.\" Aku menduga Ibnu 'Umar menyebutkan: \"Dan seorang laki-laki adalah pemimpin atas harta bapaknya, dan akan dimintai pertanggung jawaban atasnya. Setiap kalian adalah pemimpin dan setiap pemimpin akan dimintai pertanggung jawaban atas yang dipimpinnya.\""},"845":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ جَاءَ مِنْكُمْ الْجُمُعَةَ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah menceritakan kepadaku [Salim bin 'Abdullah] bahwa dia mendengar ['Abdullah bin 'Umar] radliallahu 'anhuma berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa di antara kalian yang mendatangi shalat Jum'at, maka hendaklah dia mandi?\""},"846":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غُسْلُ يَوْمِ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Shafwan bin Sulaim] dari ['Atha' bin Yaar] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandi pada hari Jum'at adalah wajib bagi setiap orang yang sudah baligh.\""},"847":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ الْآخِرُونَ السَّابِقُونَ يَوْمَ الْقِيَامَةِ أُوتُوا الْكِتَابَ مِنْ قَبْلِنَا وَأُوتِينَاهُ مِنْ بَعْدِهِمْ فَهَذَا الْيَوْمُ الَّذِي اخْتَلَفُوا فِيهِ فَهَدَانَا اللَّهُ فَغَدًا لِلْيَهُودِ وَبَعْدَ غَدٍ لِلنَّصَارَى فَسَكَتَ ثُمَّ قَالَ حَقٌّ عَلَى كُلِّ مُسْلِمٍ أَنْ يَغْتَسِلَ فِي كُلِّ سَبْعَةِ أَيَّامٍ يَوْمًا يَغْسِلُ فِيهِ رَأْسَهُ وَجَسَدَهُرَوَاهُ أَبَانُ بْنُ صَالِحٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلَّهِ تَعَالَى عَلَى كُلِّ مُسْلِمٍ حَقٌّ أَنْ يَغْتَسِلَ فِي كُلِّ سَبْعَةِ أَيَّامٍ يَوْمًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Ibnu Thawus] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita datang terakhir dan akan pertama pada hari kiamat. Mereka diberi Kitab sebelum kita dan kita diberi sesudah mereka. Inilah hari (Jum'at) dimana mereka berselisih tentangnya namun Allah memberi petunjuk kepada kita. Maka esok hari untuk Yahudi dan lusa untuk Nashrani.\" Beliau lalu diam, setelah itu beliau bersabda lagi: \"Sudah menjadi kewajiban bagi setiap Muslim untuk mandi pada satu hari dari setiap tujuh hari, pada hari itu dia basuh kepala dan tubuhnya.\" Diriwayatkan oleh [Aban bin Shalih] dari [Mujahid] dari [Thawus] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagi setiap Muslim sudah menjadi kewajiban karena Allah Ta'ala untuk mandi pada satu hari dari setiap tujuh hari.\""},"848":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا وَرْقَاءُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ائْذَنُوا لِلنِّسَاءِ بِاللَّيْلِ إِلَى الْمَسَاجِدِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Warqa'] dari ['Amru bin Dinar] dari [Mujahid] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Izinkanlah para wanita (bila minta izin) pergi ke masjid di malam hari.\""},"849":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَتْ امْرَأَةٌ لِعُمَرَ تَشْهَدُ صَلَاةَ الصُّبْحِ وَالْعِشَاءِ فِي الْجَمَاعَةِ فِي الْمَسْجِدِ فَقِيلَ لَهَا لِمَ تَخْرُجِينَ وَقَدْ تَعْلَمِينَ أَنَّ عُمَرَ يَكْرَهُ ذَلِكَ وَيَغَارُ قَالَتْ وَمَا يَمْنَعُهُ أَنْ يَنْهَانِي قَالَ يَمْنَعُهُ قَوْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَمْنَعُوا إِمَاءَ اللَّهِ مَسَاجِدَ اللَّهِ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Nafi'] dari [Ibnu 'Umar]: \"Isteri Umar ikut menghadiri shalat Shubuh dan 'Isya berjama'ah di masjid.\" Lalu dikatakan kepadanya, \"Kenapa kamu pergi ke masjid padahal kamu telah mengetahui bahwa 'Umar tidak menyukainya?\" Wanita itu berkata, \"Apa yang menghalangi dia untuk melarangku?\" Penanya itu berkata, \"Yang mencegahnya adalah sabda Rasulullah shallallahu 'alaihi wasallam: 'Janganlah kalian larang para wanita mendatangi masjid-masjid Allah.\""},"850":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنِي عَبْدُ الْحَمِيدِ صَاحِبُ الزِّيَادِيِّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ ابْنُ عَمِّ مُحَمَّدِ بْنِ سِيرِينَ قَالَ ابْنُ عَبَّاسٍلِمُؤَذِّنِهِ فِي يَوْمٍ مَطِيرٍ إِذَا قُلْتَ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَلَا تَقُلْ حَيَّ عَلَى الصَّلَاةِ قُلْ صَلُّوا فِي بُيُوتِكُمْ فَكَأَنَّ النَّاسَ اسْتَنْكَرُوا قَالَ فَعَلَهُ مَنْ هُوَ خَيْرٌ مِنِّي إِنَّ الْجُمْعَةَ عَزْمَةٌ وَإِنِّي كَرِهْتُ أَنْ أُحْرِجَكُمْ فَتَمْشُونَ فِي الطِّينِ وَالدَّحَضِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah mengabarkan kepadaku ['Abdul Hamid] sahabatnya Az Ziyadi, berkata; telah menceritakan kepada kami ['Abdullah bin Al Harits] anak pamannya Muhammad bin Sirin, [Ibnu 'Abbas] berkata kepada Mu'adzinnya saat hari turun hujan, \"Jika kamu sudah mengucapkan 'ASYHADU ANNA MUHAMMADAR RASULULLAH', janganlah kamu sambung dengan HAYYA 'ALASHSHALAAH (Marilah mendirikan shalat) '. Tapi serukanlah, 'SHALLUU FII BUYUUTIKUM (Shalatlah di tempat tinggal masing-masing) '.\" Lalu orang-orang seakan mengingkarinya. Maka Ibnu 'Abbas pun berkata, \"Sesungguhnya hal yang demikian ini pernah dilakukan oleh orang yang lebih baik dariku. Sesungguhnya shalat Jum'at adalah kewajiban dan aku tidak suka untuk mengeluarkan kalian, sehingga kalian berjalan di tanah yang penuh dengan air dan lumpur.\""},"851":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ أَنَّ مُحَمَّدَ بْنَ جَعْفَرِ بْنِ الزُّبَيْرِ حَدَّثَهُ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ النَّاسُ يَنْتَابُونَ يَوْمَ الْجُمُعَةِ مِنْ مَنَازِلِهِمْ وَالْعَوَالِيِّ فَيَأْتُونَ فِي الْغُبَارِ يُصِيبُهُمْ الْغُبَارُ وَالْعَرَقُ فَيَخْرُجُ مِنْهُمْ الْعَرَقُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْسَانٌ مِنْهُمْ وَهُوَ عِنْدِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّكُمْ تَطَهَّرْتُمْ لِيَوْمِكُمْ هَذَا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami ['Abdullah bin Wahab] berkata, telah mengabarkan kepadaku ['Amru bin Al Harits] dari ['Ubaidullah bin Abu Ja'far] bahwa [Muhammad bin Ja'far bin Az Zubair] menceritakan kepadanya dari ['Urwah bin Az Zubair] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Orang-orang datang berbondong-bondong pada hari Jum'at dari tempat tinggal mereka dan pinggiran kota yang jauh, mereka datang melewati padang pasir yang berdebu sehingga mereka pun berdebu dan berkeringat. Lalu seorang dari mereka mendatangi Rasulullah shallallahu 'alaihi wasallam yang saat itu beliau sedang bersamaku, beliau lantas bersabda: \"Seandainya kalian mandi dahulu.\""},"852":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّهُ سَأَلَ عَمْرَةَ عَنْ الْغُسْلِ يَوْمَ الْجُمُعَةِ فَقَالَتْ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاكَانَ النَّاسُ مَهَنَةَ أَنْفُسِهِمْ وَكَانُوا إِذَا رَاحُوا إِلَى الْجُمُعَةِ رَاحُوا فِي هَيْئَتِهِمْ فَقِيلَ لَهُمْ لَوْ اغْتَسَلْتُمْ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Yahya bin Sa'id] bahwa dia bertanya kepada ['Amrah] tentang mandi pada hari Jum'at. Maka dia menjawab, \"' [Aisyah? radliallahu 'anha] berkata, \"Orang-orang bekerja untuk memenuhi kebutuhan diri mereka masing-masing, ketika menghadiri shalat Jum'at, mereka tetap dalam keadaan mereka masing-masing (dengan pakaian kerjanya), maka dikatakan kepada mereka, \"Seandainya kalian mandi terlebih dahulu.\""},"853":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عُثْمَانَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْجُمُعَةَ حِينَ تَمِيلُ الشَّمْسُ","id":"Telah menceritakan kepada kami [Suraij bin An Nu'man] berkata, telah menceritakan kepada kami [Fulaih bin Sulaiman] dari ['Utsman bin 'Abdurrahman bin 'Utsman At Taimi] dari [Anas bin Malik] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat Jum'at ketika matahari sudah tergelincir.\""},"854":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا نُبَكِّرُ بِالْجُمُعَةِ وَنَقِيلُ بَعْدَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Humaid] dari [Anas bin Malik] berkata, \"Kami bersegera (berpagi-pagi dan awal wwaktu) dalam mengerjakan shalat Jum'at, dan tidur siang setelahnya.\""},"855":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ قَالَ حَدَّثَنَا أَبُو خَلْدَةَ هُوَ خَالِدُ بْنُ دِينَارٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَدَّ الْبَرْدُ بَكَّرَ بِالصَّلَاةِ وَإِذَا اشْتَدَّ الْحَرُّ أَبْرَدَ بِالصَّلَاةِ يَعْنِي الْجُمُعَةَقَالَ يُونُسُ بْنُ بُكَيْرٍ أَخْبَرَنَا أَبُو خَلْدَةَ فَقَالَ بِالصَّلَاةِ وَلَمْ يَذْكُرْ الْجُمُعَةَ وَقَالَ بِشْرُ بْنُ ثَابِتٍ حَدَّثَنَا أَبُو خَلْدَةَ قَالَ صَلَّى بِنَا أَمِيرٌ الْجُمُعَةَ ثُمَّ قَالَ لِأَنَسٍ رَضِيَ اللَّهُ عَنْهُ كَيْفَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الظُّهْرَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] berkata, telah menceritakan kepada kami [Harami bin 'Umarah] berkata, telah menceritakan kepada kami [Abu Khaldah] -yaitu Khalid bin Dinar- berkata, Aku mendengar [Anas bin Malik] berkata, \"Jika hari terasa sejuk Nabi shallallahu 'alaihi wasallam menyegerakan pelaksanaan shalat, dan bila udara panas beliau mengakhirkannya, yakni shalat Jum'at.\" [Yunus bin Bukair] berkata; telah mengabarkan kepada kami [Abu Khaldah] menyebutkan dengan lafadz 'shalat' saja dan tidak menyebutkan kata 'jum'at'. [Bisyr bin Tsabit] berkata; telah menceritakan kepada kami [Abu Khaldah] ia berkata, \"Ada seorang amir (pemimpin) shalat bersama kami kemudian bertanya kepada Anas? radliallahu 'anhu, \"Bagaimana cara Nabi shallallahu 'alaihi wasallam shalat Zhuhur?\""},"856":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي مَرْيَمَ الْأَنْصَارِيُّ قَالَ حَدَّثَنَا عَبَايَةُ بْنُ رِفَاعَةَ قَالَ أَدْرَكَنِي أَبُو عَبْسٍ وَأَنَا أَذْهَبُ إِلَى الْجُمُعَةِ فَقَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اغْبَرَّتْ قَدَمَاهُ فِي سَبِيلِ اللَّهِ حَرَّمَهُ اللَّهُ عَلَى النَّارِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Yazid bin Abu Maryam Al Anshari] berkata, telah menceritakan kepada kami ['Abayah bin Rifa'ah] berkata, \" [Abu 'Abas] berjumpa denganku saat aku sedang berangkat untuk shalat Jum'at, lalu ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang kedua kakinya berdebu di jalan Allah, maka Allah mengharamkan orang itu untuk masuk neraka.\""},"857":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ الزُّهْرِيُّ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَأْتُوهَا تَسْعَوْنَ وَأْتُوهَا تَمْشُونَ عَلَيْكُمْ السَّكِينَةُ فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا فَاتَكُمْ فَأَتِمُّوا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b], [Az Zuhri] berkata dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Dan telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika shalat sudak ditegakkan (iqamatnya) janganlah kalian mendatnginya dengan tergesa-gesa. Datangilah dengan berjalan tenang. Maka apa yang kalian dapatkan shalatlah, dan mana yang ketinggalan sempurnakanlah.\""},"858":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنِي أَبُو قُتَيْبَةَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ لَا أَعْلَمُهُ إِلَّا عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُوا حَتَّى تَرَوْنِي وَعَلَيْكُمْ السَّكِينَةُ","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] berkata, telah menceritakan kepadaku [Abu Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] yang aku tidak mengetahuinya kecuali dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian berdiri hingga kalian melihat aku. Dan wajib bagi kalian (mengerjakannya dengan) tenang.\""},"859":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ ابْنِ وَدِيعَةَ حَدَّثَنَا سَلْمَانُ الْفَارِسِيُّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ وَتَطَهَّرَ بِمَا اسْتَطَاعَ مِنْ طُهْرٍ ثُمَّ ادَّهَنَ أَوْ مَسَّ مِنْ طِيبٍ ثُمَّ رَاحَ فَلَمْ يُفَرِّقْ بَيْنَ اثْنَيْنِ فَصَلَّى مَا كُتِبَ لَهُ ثُمَّ إِذَا خَرَجَ الْإِمَامُ أَنْصَتَ غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id Al Maqburi] dari [Bapaknya] dari [Ibnu Wadi'ah] telah menceritakan kepada kami [Salman Al Farsi] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mandi pada hari Jum'at lalu bersuci semaksimal mungkin, lalu memakai minyak atau wewangian lalu keluar rumah menuju masjid, ia tidak memisahkan antara dua orang pada tempat duduknya, kemudian ia mengerjakan shalat yang dianjurkan baginya, lalu bila imam sudah datang dia berdiam mendengarkan, maka dia akan diampuni dosa-dosanya yang ada antara Jum'atnya itu dan Jum'at yang lainnya.\""},"860":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَّامٍ قَالَ أَخْبَرَنَا مَخْلَدُ بْنُ يَزِيدَ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ نَافِعًا يَقُولُ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقِيمَ الرَّجُلُ أَخَاهُ مِنْ مَقْعَدِهِ وَيَجْلِسَ فِيهِ قُلْتُ لِنَافِعٍ الْجُمُعَةَ قَالَ الْجُمُعَةَ وَغَيْرَهَا","id":"Telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Salam- berkata, telah mengabarkan kepada kami [Makhlad bin Yazid] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, Aku mendengar [Nafi'] berkata, Aku mendengar [Ibnu 'Umar] berkata, \"Nabi shallallahu 'alaihi wasallam melarang seseorang meminta kawannya berdiri dari tempat duduknya lalu dia menempati tempat duduk tersebut.\" Aku bertanya kepada Nafi', \"Apakah ini berlaku pada saat shalat Jum'at?\" Dia menjawab, \"Untuk shalat Jum'at dan yang lainnya.\""},"861":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَكَانَ النِّدَاءُ يَوْمَ الْجُمُعَةِ أَوَّلُهُ إِذَا جَلَسَ الْإِمَامُ عَلَى الْمِنْبَرِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَلَمَّا كَانَ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ وَكَثُرَ النَّاسُ زَادَ النِّدَاءَ الثَّالِثَ عَلَى الزَّوْرَاءِقَالَ أَبُو عَبْد اللَّهِ الزَّوْرَاءُ مَوْضِعٌ بِالسُّوقِ بِالْمَدِينَةِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [As Sa'ib bin Yazid] berkata, \"Adzan panggilan shalat Jum'at pada mulanya dilakukan ketika imam sudah duduk di atas mimbar. Hal ini dipraktekkan sejak zaman Nabi shallallahu 'alaihi wasallam, Abu Bakar dan 'Umar? radliallahu 'anhuma. Ketika masa 'Utsman? radliallahu 'anhu dan manusia sudah semakin banyak, maka dia menambah adzan ketiga di Az Zaura'.\" Abu 'Abdullah berkata, \"Az Zaura' adalah bangunan yang ada di pasar di Kota Madinah.\""},"862":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ الْمَاجِشُونُ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَأَنَّ الَّذِي زَادَ التَّأْذِينَ الثَّالِثَ يَوْمَ الْجُمُعَةِ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ حِينَ كَثُرَ أَهْلُ الْمَدِينَةِ وَلَمْ يَكُنْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُؤَذِّنٌ غَيْرَ وَاحِدٍ وَكَانَ التَّأْذِينُ يَوْمَ الْجُمُعَةِ حِينَ يَجْلِسُ الْإِمَامُ يَعْنِي عَلَى الْمِنْبَرِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Salamah Al Majisyun] dari [Az Zuhri] dari [As Sa'ib bin Yazid], \"Sesungguhnya orang yang menambah adzan ketiga pada shalat Jum'at adalah 'Utsman bin 'Affan? radliallahu 'anhu, ketika penduduk Madinah semakin banyak. Dan tidak ada mu'adzin bagi Nabi shallallahu 'alaihi wasallam kecuali satu. Dan adzan shalat Jum'at dilaksanakan ketika Imam sudah duduk, yakni duduk di atas mimbar.\""},"863":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا أَبُو بَكْرِ بْنُ عُثْمَانَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَوَهُوَ جَالِسٌ عَلَى الْمِنْبَرِ أَذَّنَ الْمُؤَذِّنُ قَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ قَالَ مُعَاوِيَةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ مُعَاوِيَةُ وَأَنَا فَقَالَ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَقَالَ مُعَاوِيَةُ وَأَنَا فَلَمَّا أَنْ قَضَى التَّأْذِينَ قَالَ يَا أَيُّهَا النَّاسُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى هَذَا الْمَجْلِسِ حِينَ أَذَّنَ الْمُؤَذِّنُ يَقُولُ مَا سَمِعْتُمْ مِنِّي مِنْ مَقَالَتِي","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Abu Bakar bin 'Utsman bin Sahl bin Hunaif] dari [Abu Umamah bin Sahl bin Hunaif] berkata, Aku mendengar [Mu'awiyyah bin Abu Suyan] ketika dia sedang duduk di atas mimbar dan mu'adzan sedang mengumandangkan adzan: 'Allahu Akbar Allahu Akbar', Mu'awiyyah mengucapkan, 'Allahu Akbar Allahu Akbar'. Ketika mu'adzin membaca 'Asyhadu anlaa ilaaha illallah', Mu'awiyyah dan aku mengucapkan seperti yang diucapkan mu'adzin. Dan ketika mu'adzin membaca 'Asyhadu anna Muhammadar rasulullah, ' Mu'awiyyah dan aku mengucapkan seperti yang diucapkan mu'adzin. Ketika adzan sudah selesai Mu'awiyyah berkata, \"Wahai manusia, sungguh ketika adzan dikumandangkan aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam mengatakan dari tempat ini seperti yang kalian dengar dari (bacaan) ucapanku tadi.\""},"864":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ أَخْبَرَهُأَنَّ التَّأْذِينَ الثَّانِيَ يَوْمَ الْجُمُعَةِ أَمَرَ بِهِ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ حِينَ كَثُرَ أَهْلُ الْمَسْجِدِ وَكَانَ التَّأْذِينُ يَوْمَ الْجُمُعَةِ حِينَ يَجْلِسُ الْإِمَامُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] bahwa [As Sa'ib bin Yazid] mengabarkan kepadanya, bahwa adzan yang kedua pada hari Jum'at diperintahkan oleh 'Utsman bin 'Affan? radliallahu 'anhu ketika penduduk Madinah semakin banyak. Adapun sebelumnya, adzan hari Jum'at dikumandangkan ketika Imam sudah duduk.\""},"865":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ السَّائِبَ بْنَ يَزِيدَ يَقُولُإِنَّ الْأَذَانَ يَوْمَ الْجُمُعَةِ كَانَ أَوَّلُهُ حِينَ يَجْلِسُ الْإِمَامُ يَوْمَ الْجُمُعَةِ عَلَى الْمِنْبَرِ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَلَمَّا كَانَ فِي خِلَافَةِ عُثْمَانَ بْنِ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ وَكَثُرُوا أَمَرَ عُثْمَانُ يَوْمَ الْجُمُعَةِ بِالْأَذَانِ الثَّالِثِ فَأُذِّنَ بِهِ عَلَى الزَّوْرَاءِ فَثَبَتَ الْأَمْرُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] berkata, Aku mendengar [As Sa'ib bin Yazid] berkata, \"Pada mulanya adzan pada hari Jum'at dikumandangkan ketika Imam sudah duduk di atas mimbar. Yaitu apa yang biasa dipraktekkan sejak zaman Nabi shallallahu 'alaihi wasallam, Abu Bakar dan 'Umar? radliallahu 'anhu. Pada masa Khilafah 'Utsman bin 'Affan? radliallahu 'anhu ketika manusia sudah semakin banyak, maka pada hari Jum'at dia mememerintahkan adzan yang ketiga. Sehingga dikumandangkanlah adzan (ketiga) tersebut di Az Zaura'. Kemudian berlakulah urusan tersebut menjadi ketetapan.\""},"866":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدٍ الْقَارِيُّ الْقُرَشِيُّ الْإِسْكَنْدَرَانِيُّ قَالَ حَدَّثَنَا أَبُو حَازِمِ بْنُ دِينَارٍأَنَّ رِجَالًا أَتَوْا سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ وَقَدْ امْتَرَوْا فِي الْمِنْبَرِ مِمَّ عُودُهُ فَسَأَلُوهُ عَنْ ذَلِكَ فَقَالَ وَاللَّهِ إِنِّي لَأَعْرِفُ مِمَّا هُوَ وَلَقَدْ رَأَيْتُهُ أَوَّلَ يَوْمٍ وُضِعَ وَأَوَّلَ يَوْمٍ جَلَسَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى فُلَانَةَ امْرَأَةٍ مِنْ الْأَنْصَارِ قَدْ سَمَّاهَا سَهْلٌ مُرِي غُلَامَكِ النَّجَّارَ أَنْ يَعْمَلَ لِي أَعْوَادًا أَجْلِسُ عَلَيْهِنَّ إِذَا كَلَّمْتُ النَّاسَ فَأَمَرَتْهُ فَعَمِلَهَا مِنْ طَرْفَاءِ الْغَابَةِ ثُمَّ جَاءَ بِهَا فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهَا فَوُضِعَتْ هَا هُنَا ثُمَّ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَيْهَا وَكَبَّرَ وَهُوَ عَلَيْهَا ثُمَّ رَكَعَ وَهُوَ عَلَيْهَا ثُمَّ نَزَلَ الْقَهْقَرَى فَسَجَدَ فِي أَصْلِ الْمِنْبَرِ ثُمَّ عَادَ فَلَمَّا فَرَغَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ أَيُّهَا النَّاسُ إِنَّمَا صَنَعْتُ هَذَا لِتَأْتَمُّوا وَلِتَعَلَّمُوا صَلَاتِي","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman bin Muhammad bin 'Abdullah bin 'Abdul Qari Al Qurasyi Al Iskandarani] berkata, telah menceritakan kepada kami [Abu Hazim bin Dinar] bahwa ada orang-orang mendatangi [Sahl bin Sa'd As Sa'idi] yang berdebat tentang mimbar dan bahan membuatnya? Mereka menanyakan hal itu kepadanya. Sahl lalu berkata, \"Demi Allah, akulah orang yang paling mengerti tentang masalah ini. Sungguh aku telah melihat hari pertama mimbar tersebut dipasang dan hari saat Rasulullah shallallahu 'alaihi wasallam duduk di atasnya. Rasulullah shallallahu 'alaihi wasallam mengutus orang untuk menemui seorang wanita Anshar, yang namanya sudah disebutkan oleh Sahl, Sahl lalu berkata, \"Perintahkanlah budak lelakimu yang tukang kayu itu untuk membuat mimbar bertangga, sehingga saat berbicara dengan orang banyak aku bisa duduk di atasnya.\" Maka kemudian wanita itu memerintahkan budak lelakinya membuat mimbar yang terbuat dari batang kayu hutan. Setelah diberikan kepada wanita itu, lalu itu mengirimnya untuk Rasulullah shallallahu 'alaihi wasallam. Maka Beliau memerintahkan orang untuk meletakkan mimbar tersebut di sini. Lalu aku melihat Rasulullah shallallahu 'alaihi wasallam shalat diatasnya. Beliau bertakbir dalam posisi di atas mimbar lalu rukuk dalam posisi masih di atas mimbar. Kemudian Beliau turun dengan mundur ke belakang, lalu sujud di dasar mimbar, kemudian Beliau mengulangi lagi (hingga shalat selesai). Setelah selesai, beliau menghadap kepada orang banyak lalu bersabda: \"Wahai sekalian manusia, sesungguhnya aku berbuat seperti tadi agar kalian mengikuti dan agar kalian dapat mengambil pelajaran tentang tata cara shalatku.\""},"867":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي ابْنُ أَنَسٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَكَانَ جِذْعٌ يَقُومُ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا وُضِعَ لَهُ الْمِنْبَرُ سَمِعْنَا لِلْجِذْعِ مِثْلَ أَصْوَاتِ الْعِشَارِ حَتَّى نَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَ يَدَهُ عَلَيْهِقَالَ سُلَيْمَانُ عَنْ يَحْيَى أَخْبَرَنِي حَفْصُ بْنُ عُبَيْدِ اللَّهِ بْنِ أَنَسٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah mengabarkan kepadaku [Yahya bin Sa'id] berkata, telah mengabarkan kepada kami [Ibnu Anas] bahwa dia mendengar [Jabir bin 'Abdullah] berkata, \"Pada mulanya Nabi shallallahu 'alaihi wasallam menggunakan batang kayu sebagai tongkat yang biasa beliau gunakan untuk bersandar. Ketika sudah dibuatkan mimbar untuk Beliau, kami mendengar sesuatu dari batang kayu tersebut seperti suara unta hendak beranak, hingga akhirnya Nabi shallallahu 'alaihi wasallam turun lalu meletakkan tangan Beliau pada kayu tersebut.\" [Sulaiman] berkata, dari [Yahya] berkata, telah mengabarkan kepadaku [Hafsh bin 'Ubaidullah bin Anas] bahwa dia mendengar dari [Jabir bin 'Abdullah].\""},"868":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى الْمِنْبَرِ فَقَالَ مَنْ جَاءَ إِلَى الْجُمُعَةِ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Salim] dari [Bapaknya] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda saat sedang berkhuthbah di atas mimbar: \"Siapa yang mendatangi shalat Jum'at, hendaklah dia mandi.\""},"869":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا ثُمَّ يَقْعُدُ ثُمَّ يَقُومُ كَمَا تَفْعَلُونَ الْآنَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin 'Umar Al Qawariri] berkata, telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Nafi'] dari [Ibnu 'Umar] radliallahu 'anhuma, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhuthbah sambil berdiri, kemudian duduk lalu berdiri kembali seperti yang kalian lakukan di zaman sekarang ini.\""},"870":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ حَدَّثَنَا عَطَاءُ بْنُ يَسَارٍ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَسَ ذَاتَ يَوْمٍ عَلَى الْمِنْبَرِ وَجَلَسْنَا حَوْلَهُ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Hilal bin Abu Maimunah] telah menceritakan kepada kami ['Atha' bin Yasar] bahwasanya dia mendengar [Abu Sa'id Al Khudri] radliallahu 'anhu berkata, \"Pada suatu hari Nabi shallallahu 'alaihi wasallam duduk di atas mimbar dan kami duduk di sekitarnya.\""},"871":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ جَرِيرِ بْنِ حَازِمٍ قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ حَدَّثَنَا عَمْرُو بْنُ تَغْلِبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِمَالٍ أَوْ سَبْيٍ فَقَسَمَهُ فَأَعْطَى رِجَالًا وَتَرَكَ رِجَالًا فَبَلَغَهُ أَنَّ الَّذِينَ تَرَكَ عَتَبُوا فَحَمِدَ اللَّهَ ثُمَّ أَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَوَاللَّهِ إِنِّي لَأُعْطِي الرَّجُلَ وَأَدَعُ الرَّجُلَ وَالَّذِي أَدَعُ أَحَبُّ إِلَيَّ مِنْ الَّذِي أُعْطِي وَلَكِنْ أُعْطِي أَقْوَامًا لِمَا أَرَى فِي قُلُوبِهِمْ مِنْ الْجَزَعِ وَالْهَلَعِ وَأَكِلُ أَقْوَامًا إِلَى مَا جَعَلَ اللَّهُ فِي قُلُوبِهِمْ مِنْ الْغِنَى وَالْخَيْرِ فِيهِمْ عَمْرُو بْنُ تَغْلِبَ فَوَاللَّهِ مَا أُحِبُّ أَنَّ لِي بِكَلِمَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُمْرَ النَّعَمِتَابَعَهُ يُونُسُ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar] berkata, telah menceritakan kepada kami [Abu 'Ashim] dari [Jarir bin Hazim] berkata, aku mendengar [Al Hasan] berkata, telah menceritakan kepada kami ['Amru bin Taghlib], bahwa Rasulullah shallallahu 'alaihi wasallam pernah diberi hadiah berupa harta atau tawanan wanita, beliau lalu membagi-bagikannya. Ada orang yang diberi dan ada yang tidak. Kemudian sampai berita kepada beliau bahwa orang-orang yang tidak diberi, mereka mencela (beliau). Maka mengucapkan puja dan puji kepada Allah lalu bersabda: \"Amma ba'du. Demi Allah, memang aku telah memberi seseorang dan tidak kepada yang lain. Orang yang tidak aku beri sesungguhnya lebih aku cintai daripada orang yang aku beri. Namun aku memberi sekelompok kaum karena aku melihat hati-hati mereka masih sangat bersedih dan punya rasa takut. Dan aku biarkan sekelompok orang karena Allah telah menjadikan hati-hati mereka penuh dengan perasaan cukup dan penuh kebaikan. Di antara mereka adalah 'Amru bin Taghlib.\" 'Amru bin Taghlib berkata, \"Demi Allah, tidak ada yang lebih aku sukai dari unta yang paling baik dibandingkan ucapan Rasulullah shallallahu 'alaihi wasallam kepadaku tadi.\" Hadits ini dikuatkan oleh [Yunus].\""},"872":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ ذَاتَ لَيْلَةٍ مِنْ جَوْفِ اللَّيْلِ فَصَلَّى فِي الْمَسْجِدِ فَصَلَّى رِجَالٌ بِصَلَاتِهِ فَأَصْبَحَ النَّاسُ فَتَحَدَّثُوا فَاجْتَمَعَ أَكْثَرُ مِنْهُمْ فَصَلَّوْا مَعَهُ فَأَصْبَحَ النَّاسُ فَتَحَدَّثُوا فَكَثُرَ أَهْلُ الْمَسْجِدِ مِنْ اللَّيْلَةِ الثَّالِثَةِ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّوْا بِصَلَاتِهِ فَلَمَّا كَانَتْ اللَّيْلَةُ الرَّابِعَةُ عَجَزَ الْمَسْجِدُ عَنْ أَهْلِهِ حَتَّى خَرَجَ لِصَلَاةِ الصُّبْحِ فَلَمَّا قَضَى الْفَجْرَ أَقْبَلَ عَلَى النَّاسِ فَتَشَهَّدَ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّهُ لَمْ يَخْفَ عَلَيَّ مَكَانُكُمْ لَكِنِّي خَشِيتُ أَنْ تُفْرَضَ عَلَيْكُمْ فَتَعْجِزُوا عَنْهَاقَالَ أَبُو عَبْد اللَّهِ تَابَعَهُ يُونُسُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah mengabarkan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Urwah] bahwa ['Aisyah] radliallahu 'anha mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam pada suatu malam keluar di tengah malam untuk melaksanakan shalat di masjid, orang-orang kemudian mengikuti beliau dan shalat dibelakangnya. Pada waktu paginya orang-orang membicarakan kejadian tersebut. Kemudian pada malam berikutnya orang-orang yang berkumpul bertambah banyak lalu ikut shalat dengan Beliau. Dan pada waktu paginya orang-orang kembali membicarakan kejadian tersebut. Kemudian pada malam yang ketiga orang-orang yang hadir di masjid semakin bertambah banyak lagi, lalu Rasulullah shallallahu 'alaihi wasallam keluar untuk shalat dan mereka shalat bersama beliau. Kemudian pada malam yang keempat, masjid sudah penuh dengan jama'ah hingga akhirnya beliau keluar hanya untuk shalat Shubuh. Setelah beliau selesai shalat Fajar, beliau menghadap kepada orang banyak membaca syahadat lalu bersabda: \"Amma ba'du, sesungguhnya aku bukannya tidak tahu keberadaan kalian (semalam). Akan tetapi aku takut shalat tersebut akan diwajibkan atas kalian, sementara kalian tidak mampu.\" Abu 'Abdullah Al Bukhari berkata, \"Hadits ini dikuatkan oleh [Yunus].\""},"873":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ عَشِيَّةً بَعْدَ الصَّلَاةِ فَتَشَهَّدَ وَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُتَابَعَهُ أَبُو مُعَاوِيَةَ وَأَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَّا بَعْدُ تَابَعَهُ الْعَدَنِيُّ عَنْ سُفْيَانَ فِي أَمَّا بَعْدُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Urwah] dari [Abu Humaid As Sa'idi] bahwasanya dia mengabarkan kepadanya, bahwa setelah melaksanakan shalat di awal malam (Isya) Rasulullah shallallahu 'alaihi wasallam berdiri, lalu membaca syahadah dan puja pujnya kepada Allah dengan pujian yang layak (bagi Allah), beliau lalu mengucapkan: \"Amma ba'du.\" Hadits ini dikuatkan oleh [Abu Mu'awiyyah] dan [Abu Usamah] dari [Hisyam] dari [Bapaknya] dari [Abu Humaid As Sa'idi] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Amma ba'du.\" Dikuatkan juga oleh [Al 'Adani] dari [Sufyan] tentang ucapan 'Amma ba'du'.\""},"874":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ حِينَ تَشَهَّدَ يَقُولُ أَمَّا بَعْدُتَابَعَهُ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Ali bin Husain] dari [Al Miswar bin Makhramah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri, lalu ketika beliau mengucapkan syahadat, aku mendengar beliau mengucapkan: 'Amma ba'du'.\" Hadits ini dikuatkan oleh [Az Zubaidi] dari [Az Zuhri].\""},"875":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبَانَ قَالَ حَدَّثَنَا ابْنُ الْغَسِيلِ قَالَ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَعِدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمِنْبَرَ وَكَانَ آخِرَ مَجْلِسٍ جَلَسَهُ مُتَعَطِّفًا مِلْحَفَةً عَلَى مَنْكِبَيْهِ قَدْ عَصَبَ رَأْسَهُ بِعِصَابَةٍ دَسِمَةٍ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَيُّهَا النَّاسُ إِلَيَّ فَثَابُوا إِلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ هَذَا الْحَيَّ مِنْ الْأَنْصَارِ يَقِلُّونَ وَيَكْثُرُ النَّاسُ فَمَنْ وَلِيَ شَيْئًا مِنْ أُمَّةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَطَاعَ أَنْ يَضُرَّ فِيهِ أَحَدًا أَوْ يَنْفَعَ فِيهِ أَحَدًا فَلْيَقْبَلْ مِنْ مُحْسِنِهِمْ وَيَتَجَاوَزْ عَنْ مُسِيِّهِمْ","id":"Telah menceritakan kepada kami [Isma'il bin Aban] berkata, telah menceritakan kepada kami [Ibnu Al Ghasil] berkata, telah menceritakan kepada kami ['Ikrimah] dari [Ibnu 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam menaiki mimbar -yang merupakan kali terakhir beliau duduk di situ- dalam keadaan berselimut yang diletakkannya di atas kedua pundaknya dan mengikat kepalanya dengan ikat kepala berwarna hitam. Setelah memuji Allah dan mensucikan-Nya, beliau bersabda: \"Amma ba'du, wahai sekalian manusia berkumpullah di hadapanku.\" Maka orang-orang berkumpul mengelilingi beliau. Kemudian beliau melanjutkan: \"Amma ba'du, sesungguhnya orang yang masih hidup dari kalangan Anshar semakin sedikit, sedangkan orang-orang lain (selain Anshar) terus bertambah banyak. Maka barangsiapa mengurus sesuatu dari urusan ummat Muhammad lalu dia mampu mendatangkan madlarat kepada seseorang atau memberi manfaat kepada seseorang, maka terimalah orang-orang baik mereka (kaum Anshar) dan maafkanlah orang yang keliru dari kalangan mereka.\""},"876":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ خُطْبَتَيْنِ يَقْعُدُ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Bisyir bin Al Mufadldlal] berkata, telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Nafi'] dari ['Abdullah bin 'Umar] radliallahu 'anhuma, ia berkata, \"Nabi shallallahu 'alaihi wasallam berkhuthbah dengan dua kali khuthbah dan duduk di antara keduanya.\""},"877":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الْجُمُعَةِ وَقَفَتْ الْمَلَائِكَةُ عَلَى بَابِ الْمَسْجِدِ يَكْتُبُونَ الْأَوَّلَ فَالْأَوَّلَ وَمَثَلُ الْمُهَجِّرِ كَمَثَلِ الَّذِي يُهْدِي بَدَنَةً ثُمَّ كَالَّذِي يُهْدِي بَقَرَةً ثُمَّ كَبْشًا ثُمَّ دَجَاجَةً ثُمَّ بَيْضَةً فَإِذَا خَرَجَ الْإِمَامُ طَوَوْا صُحُفَهُمْ وَيَسْتَمِعُونَ الذِّكْرَ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Abu 'Abdullah Al Aghar] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Pada hari Jum'at para Malaikat hadir di pintu Masjid mencatat siapa orang yang datang paling awal dan seterusnya. Orang yang paling awal datang ke Masjid seperti orang yang berkurban dengan seekor unta, kemudian seperti orang yang berkurban dengan seekor sapi, kemudian seperti orang yang berkurban seekor kambing yang bertanduk, kemudian seperti orang yang berkurban seekor ayam, kemudian seperti orang yang berkurban sebutir telur. Dan apabila Imam sudah keluar (untuk memberi khutbah), maka para Malaikat menutup buku catatan mereka kemudian mendengarkan dzikir (khutbah).\""},"878":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَ رَجُلٌ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ يَوْمَ الْجُمُعَةِ فَقَالَ أَصَلَّيْتَ يَا فُلَانُ قَالَ لَا قَالَ قُمْ فَارْكَعْ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Jabir bin 'Abdullah] berkata, \"Seorang laki-laki datang saat Nabi shallallahu 'alaihi wasallam sedang memberikan khutbah di hadapan orang banyak pada hari Jum'at. Beliau lalu bertanya: \"Wahai fulan, apakah kamu sudah shalat?\" Orang itu menjawab, \"Belum.\" Maka beliau bersabda: \"Bangun dan shalatlah dua rakaat.\""},"879":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ جَابِرًا قَالَدَخَلَ رَجُلٌ يَوْمَ الْجُمُعَةِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ أَصَلَّيْتَ قَالَ لَا قَالَ قُمْ فَصَلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amru] bahwa dia telah mendengar [Jabir] berkata, \"Pada hari Jum'at seorang laki-laki datang ketika Nabi shallallahu 'alaihi wasallam sedang memberikan khutbah. Beliau lalu bertanya: \"Apakah kamu sudah shalat?\" Orang itu menjawab, \"Belum.\" Maka beliau pun bersabda: \"Bangun dan shalatlah dua rakaat.\""},"880":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ وَعَنْ يُونُسَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ قَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَ الْكُرَاعُ وَهَلَكَ الشَّاءُ فَادْعُ اللَّهَ أَنْ يَسْقِيَنَا فَمَدَّ يَدَيْهِ وَدَعَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari ['Abdul 'Aziz bin Shuhaib] dari [Anas] dan dari [Yunus] dari [Tsabit] dari [Anas] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam sedang menyampaikan khutbah pada hari Jum'at, tiba-tiba ada seorang laki-laki berdiri dan berkata, \"Wahai Rasulullah, telah binasa binatang ternak (unta) dan telah binasa kehidupan (telah menjadi sulit), maka berdo'alah kepada Allah agar menurunkan air untuk kami.\" Rasulullah lalu menengadahkan kedua telapak tangan dan berdo'a.\""},"881":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا أَبُو عَمْرٍو الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي إِسْحَاقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَصَابَتْ النَّاسَ سَنَةٌ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فِي يَوْمِ جُمُعَةٍ قَامَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَ الْمَالُ وَجَاعَ الْعِيَالُ فَادْعُ اللَّهَ لَنَا فَرَفَعَ يَدَيْهِ وَمَا نَرَى فِي السَّمَاءِ قَزَعَةً فَوَالَّذِي نَفْسِي بِيَدِهِ مَا وَضَعَهَا حَتَّى ثَارَ السَّحَابُ أَمْثَالَ الْجِبَالِ ثُمَّ لَمْ يَنْزِلْ عَنْ مِنْبَرِهِ حَتَّى رَأَيْتُ الْمَطَرَ يَتَحَادَرُ عَلَى لِحْيَتِهِ صَلَّى اللَّهُ ع��لَيْهِ وَسَلَّمَ فَمُطِرْنَا يَوْمَنَا ذَلِكَ وَمِنْ الْغَدِ وَبَعْدَ الْغَدِ وَالَّذِي يَلِيهِ حَتَّى الْجُمُعَةِ الْأُخْرَى وَقَامَ ذَلِكَ الْأَعْرَابِيُّ أَوْ قَالَ غَيْرُهُ فَقَالَ يَا رَسُولَ اللَّهِ تَهَدَّمَ الْبِنَاءُ وَغَرِقَ الْمَالُ فَادْعُ اللَّهَ لَنَا فَرَفَعَ يَدَيْهِ فَقَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا فَمَا يُشِيرُ بِيَدِهِ إِلَى نَاحِيَةٍ مِنْ السَّحَابِ إِلَّا انْفَرَجَتْ وَصَارَتْ الْمَدِينَةُ مِثْلَ الْجَوْبَةِ وَسَالَ الْوَادِي قَنَاةُ شَهْرًا وَلَمْ يَجِئْ أَحَدٌ مِنْ نَاحِيَةٍ إِلَّا حَدَّثَ بِالْجَوْدِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Abu 'Amru Al Auza'i] berkata, telah menceritakan kepadaku [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas bin Malik] berkata, \"Pasa masa Nabi shallallahu 'alaihi wasallam manusia tertimpa paceklik. Ketika Nabi shallallahu 'alaihi wasallam sedang memberikan khutbah pada hari Jum'at, tiba-tiba ada seorang Arab badui berdiri dan berkata, \"Wahai Rasulullah, harta benda telah binasa dan telah terjadi kelaparan, maka berdo'alah kepada Allah untuk kami.\" Beliau lalu mengangkat kedua telapak tangan berdoa, dan saat itu kami tidak melihat sedikitpun ada awan di langit. Namun demi Dzat yang jiwaku berada di tangan-Nya, sungguh beliau tidak menurunkan kedua tangannya kecuali gumpalan awan telah datang membumbung tinggi laksana pegunungan. Dan beliau belum turun dari mimbar hingga akhirnya aku melihat hujan turun membasahi jenggot beliau shallallahu 'alaihi wasallam. Maka pada hari itu, keesokan harinya dan lusa kami terus-terusan mendapatkan guyuran hujan dan hari-hari berikutnya hingga hari Jum'at berikutnya. Pada Jum'at berikut itulah orang Arab badui tersebut, atau orang yang lain berdiri seraya berkata, \"Wahai Rasulullah, banyak bangunan yang roboh, harta benda tenggelam dan hanyut, maka berdo'alah kepada Allah untuk kami.\" Beliau lalu mengangkat kedua telapak tangannya dan berdoa: 'ALLAHUMMA HAWAALAINAA WA LAA 'ALAINAA (Ya Allah, turunkanlah hujan di sekeliling kami dan jangan sampai menimbulkan kerusakan kepada kami) '. Belum lagi beliau memberikan isyarat dengan tangannya kepada gumpalan awan, melainkan awan tersebut hilang seketika. Saat itu kota Madinah menjadi seperti danau dan aliran-aliran air, Madinah juga tidak mendapatkan sinar matahari selama satu bulan. Dan tidak seorang pun yang datang dari segala pelosok kota kecuali akan menceritakan tentang terjadinya hujan yang lebat tersebut.\""},"882":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قُلْتَ لِصَاحِبِكَ يَوْمَ الْجُمُعَةِ أَنْصِتْ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu berkata kepada temanmu pada hari Jum'at 'diamlah', padahal Imam sedang memberikan khutbah maka sungguh kamu sudah berbuat sia-sia (tidak mendapat pahala).\""},"883":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ يَوْمَ الْجُمُعَةِ فَقَالَ فِيهِ سَاعَةٌ لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ وَهُوَ قَائِمٌ يُصَلِّي يَسْأَلُ اللَّهَ تَعَالَى شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُ وَأَشَارَ بِيَدِهِ يُقَلِّلُهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam membicarakan perihal hari Jum'at. Beliau mengatakan: \"Pada hari Jum'at itu ada satu saat, tidaklah seorang hamba Muslim mengerjakan shalat lalu dia berdo'a tepat pada saat tersebut melainkan Allah akan mengabulkan do'anya tersebut.\" Kemudian beliau memberi isyarat dengan tangannya yang menunjukkan sedikitnya saat tersebut.\""},"884":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ عَنْ حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ قَالَ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَبَيْنَمَا نَحْنُ نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَقْبَلَتْ عِيرٌ تَحْمِلُ طَعَامًا فَالْتَفَتُوا إِلَيْهَا حَتَّى مَا بَقِيَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا اثْنَا عَشَرَ رَجُلًا فَنَزَلَتْ هَذِهِ الْآيَةُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amru] berkata, telah menceritakan kepada kami [Za'idah] dari [Hushain] dari [Salim bin Abu Al Ja'd] berkata, telah menceritakan kepada kami [Jabir bin 'Abdullah] berkata, \"Ketika kami sedang shalat bersama Nabi shallallahu 'alaihi wasallam tiba-tiba datang rombongan dagang yang membawa makanan. Orang-orang pun melirik (dan berhamburan pergi) mendatangi rombongan tersebut, hingga tidak ada orang yang tersisa bersama Nabi shallallahu 'alaihi wasallam kecuali hanya dua belas orang. Maka turunlah ayat ini: '(Dan apabila mereka melihat perdagangan atau permainan, maka mereka bubar untuk menuju kepadanya dan mereka meninggalkan kamu ketika kamu sedang berdiri menyampaikan berkhutbah) ' (Qs. Al Jumu'ah: 12)."},"885":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي قَبْلَ الظُّهْرِ رَكْعَتَيْنِ وَبَعْدَهَا رَكْعَتَيْنِ وَبَعْدَ الْمَغْرِبِ رَكْعَتَيْنِ فِي بَيْتِهِ وَبَعْدَ الْعِشَاءِ رَكْعَتَيْنِ وَكَانَ لَا يُصَلِّي بَعْدَ الْجُمُعَةِ حَتَّى يَنْصَرِفَ فَيُصَلِّي رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam biasa melaksanakan dua rakaat sebelum zhuhur dan dua rakaat sesudahnya, dua rakaat setelag Maghrib di rumahnya, dan dua rakaat sesudah Isya. Dan beliau tidak mengerjakan shalat setelah Jum'at hingga beliau pulang, lalu shalat dua rakaat.\""},"886":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَتْ فِينَا امْرَأَةٌ تَجْعَلُ عَلَى أَرْبِعَاءَ فِي مَزْرَعَةٍ لَهَا سِلْقًا فَكَانَتْ إِذَا كَانَ يَوْمُ جُمُعَةٍ تَنْزِعُ أُصُولَ السِّلْقِ فَتَجْعَلُهُ فِي قِدْرٍ ثُمَّ تَجْعَلُ عَلَيْهِ قَبْضَةً مِنْ شَعِيرٍ تَطْحَنُهَا فَتَكُونُ أُصُولُ السِّلْقِ عَرْقَهُ وَكُنَّا نَنْصَرِفُ مِنْ صَلَاةِ الْجُمُعَةِ فَنُسَلِّمُ عَلَيْهَا فَتُقَرِّبُ ذَلِكَ الطَّعَامَ إِلَيْنَا فَنَلْعَقُهُ وَكُنَّا نَتَمَنَّى يَوْمَ الْجُمُعَةِ لِطَعَامِهَا ذَلِكَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah menceritakan kepada kami [Abu Ghassan] berkata, telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] berkata, \"Di tempat kami ada seorang wanita yang menanam ubi di sela-sela selokan kebunnya. Jika hari Jum'at tiba, dia mencabut pohon ubinya lalu direbusnya dalam periuk yang dicampur dengan segenggam gandum. Rebusan ubi dijadikan sebagai makanan pengganti sepotong daging. Setelah kami selesai melaksanakan shalat Jum'at, kami datang ke rumah wanita itu. Kami masuk mengucapkan salam lalu dia menyuguhkan makanan ubinya itu kepada kami, maka kami pun memakannya. Kami selalu mengharapkan kehadiran hari Jum'at karena ada makanan yang disuguhkannya itu.\""},"887":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍبِهَذَا وَقَالَ مَا كُنَّا نَقِيلُ وَلَا نَتَغَدَّى إِلَّا بَعْدَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] berkata, telah menceritakan kepada kami [Ibnu Abu Hazim] dari [Bapaknya] dari [Sahl] dengan riwayat seperti di atas, lalu dia berkata, \"Kami tidaklah beristirahat siang maupun makan siang kecuali setelah shalat Jum'at.\""},"888":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُقْبَةَ الشَّيْبَانِيُّ الْكُوفِيُّ قَالَ حَدَّثَنَا أَبُو إِسْحَاقَ الْفَزَارِيُّ عَنْ حُمَيْدٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُكُنَّا نُبَكِّرُ إِلَى الْجُمُعَةِ ثُمَّ نَقِيلُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Uqbah 'Asy Syaibani Al Kufi] berkata, telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Humaid] berkata, Aku mendengar [Anas] berkata, \"Kami lebih awal mendatangi shalat Jum'at lalu beristirahat siang (qailulah) setelahnya.\""},"889":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ تَكُونُ الْقَائِلَةُ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah menceritakan kepada kami [Abu Ghassan] berkata, telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] berkata, \"Kami shalat Jum'at bersama Nabi shallallahu 'alaihi wasallam kemudian kami beristirahat siang (qailulah) setelahnya.\""},"890":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ سَأَلْتُهُ هَلْ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي صَلَاةَ الْخَوْفِ قَالَ أَخْبَرَنِي سَالِمٌ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ نَجْدٍ فَوَازَيْنَا الْعَدُوَّ فَصَافَفْنَا لَهُمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي لَنَا فَقَامَتْ طَائِفَةٌ مَعَهُ تُصَلِّي وَأَقْبَلَتْ طَائِفَةٌ عَلَى الْعَدُوِّ وَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَنْ مَعَهُ وَسَجَدَ سَجْدَتَيْنِ ثُمَّ انْصَرَفُوا مَكَانَ الطَّائِفَةِ الَّتِي لَمْ تُصَلِّ فَجَاءُوا فَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِمْ رَكْعَةً وَسَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ فَقَامَ كُلُّ وَاحِدٍ مِنْهُمْ فَرَكَعَ لِنَفْسِهِ رَكْعَةً وَسَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, Aku bertanya kepadanya, \"Apakah Nabi shallallahu 'alaihi wasallam melaksanakan shalat khauf?\" Ia berkata; [Salim] telah mengabarkan kepadaku bahwa ['Abdullah bin 'Umar] radliallahu 'anhuma berkata, \"Aku pernah ikut suatu peperangan bersama Rasulullah shallallahu 'alaihi wasallam ke arah Najed, kami menghadap ke arah musuh dan membuat barisan untuk mereka. Rasulullah shallallahu 'alaihi wasallam lalu berdiri mengimami kami. Sekelompok orang yang bersama beliau melaksanakan shalat sementara sekelompok yang lain menghadap musuh. Nabi shallallahu 'alaihi wasallam lalu rukuk dan sujud dua kali bersama kelompok yang bersamanya, lalu mereka (kelompok yang telah shalat) bergeser menempati posisi kelompok yang belum shalat. Kemudian kelompok yang belum shalat tersebut datang dan masuk ke dalam shaf, Rasulullah shallallahu 'alaihi wasallam lalu rukuk bersama kelompok yang baru dan sujud dua kali, lalu beliau salam. Maka setiap kelompok dari kami menyelesaikan shalat mereka masing-masing dengan rukuk dan sujud dua kali.\""},"891":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْقُرَشِيُّ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ نَحْوًا مِنْ قَوْلِ مُجَاهِدٍ إِذَا اخْتَلَطُوا قِيَامًا وَزَادَ ابْنُ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ كَانُوا أَكْثَرَ مِنْ ذَلِكَ فَلْيُصَلُّوا قِيَامًا وَرُكْبَانًا","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Qurasyi] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar] seperti ucapan Mujahid, \"Bila mereka dalam keadaan genting, mereka shalat dengan berdiri.\" Ibnu 'Umar menambahkan dari Nabi shallallahu 'alaihi wasallam, \"Apabila musuh lebih banyak dari mereka (pasukan kaum Muslimin), maka mereka shalat dengan berdiri dan di atas kendaraan.\""},"892":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامَ النَّاسُ مَعَهُ فَكَبَّرَ وَكَبَّرُوا مَعَهُ وَرَكَعَ وَرَكَعَ نَاسٌ مِنْهُمْ مَعَهُ ثُمَّ سَجَدَ وَسَجَدُوا مَعَهُ ثُمَّ قَامَ لِلثَّانِيَةِ فَقَامَ الَّذِينَ سَجَدُوا وَحَرَسُوا إِخْوَانَهُمْ وَأَتَتْ الطَّائِفَةُ الْأُخْرَى فَرَكَعُوا وَسَجَدُوا مَعَهُ وَالنَّاسُ كُلُّهُمْ فِي صَلَاةٍ وَلَكِنْ يَحْرُسُ بَعْضُهُمْ بَعْضًا","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] berkata, telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Ibnu 'Abbas] radliallahu 'anhuma, berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat dan diikuti sekelompok orang bersamanya. Beliau lalu bertakbir dan mereka pun bertakbir bersama beliau. Kemudian beliau rukuk dan orang-orang yang bersamanya ikut rukuk. Kemudian beliau sujud dan orang-orang yang bersamanyanya pun sujud. Kemudian beliau berdiri untuk rakaat kedua, maka orang-orang yang sujud bersama beliau berdiri dan berjaga-jaga untuk saudara mereka. Kemudian datanglah sekelompok yang lain (yang sebelumnya berjaga dan belum shalat), mereka lalu rukuk dan sujud bersama beliau. Dan masing-masing orang melanjutkan shalat mereka namun dengan tetap berjaga-jaga satu sama lain.\""},"893":{"ar":"حَدَّثَنَا يَحْيَى بْنُ جَعْفَرٍ الْبُخَارِيُّ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ عَلِيِّ بْنِ مُبَارَكٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَ عُمَرُ يَوْمَ الْخَنْدَقِ فَجَعَلَ يَسُبُّ كُفَّارَ قُرَيْشٍ وَيَقُولُ يَا رَسُولَ اللَّهِ مَا صَلَّيْتُ الْعَصْرَ حَتَّى كَادَتْ الشَّمْسُ أَنْ تَغِيبَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا وَاللَّهِ مَا صَلَّيْتُهَا بَعْدُ قَالَ فَنَزَلَ إِلَى بُطْحَانَ فَتَوَضَّأَ وَصَلَّى الْعَصْرَ بَعْدَ مَا غَابَتْ الشَّمْسُ ثُمَّ صَلَّى الْمَغْرِبَ بَعْدَهَا","id":"Telah menceritakan kepada kami [Yahya bin Ja'fat Al Bukhari] berkata, telah menceritakan kepada kami [Waki'] dari ['Ali bin Mubarak] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir bin 'Abdullah] berkata, \"Pada hari peperangan Khandaq 'Umar bin Al Khaththab datang sambil mencaci orang-orang kafir Quraisy, ia katakan, \"Wahai Rasulullah, aku belum melaksanakan shalat 'Ashar hingga matahari sudah terbenam!\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Allah, akupun belum melakasanakannya.\" Maka kemudian beliau berdiri menuju aliran air (sungai), lalu berwudlu dan melaksanakan shalat 'Ashar setelah matahari terbenam, kemudian dilanjutkan dengan melaksanakan shalat Maghrib.\""},"894":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَا لَمَّا رَجَعَ مِنْ الْأَحْزَابِ لَا يُصَلِّيَنَّ أَحَدٌ الْعَصْرَ إِلَّا فِي بَنِي قُرَيْظَةَ فَأَدْرَكَ بَعْضَهُمْ الْعَصْرُ فِي الطَّرِيقِ فَقَالَ بَعْضُهُمْ لَا نُصَلِّي حَتَّى نَأْتِيَهَا وَقَالَ بَعْضُهُمْ بَلْ نُصَلِّي لَمْ يُرَدْ مِنَّا ذَلِكَ فَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُعَنِّفْ وَاحِدًا مِنْهُمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad bin Asma'] berkata, telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Ibnu 'Umar] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda kepada kami ketika beliau kembali dari perang Ahzab: \"Jangan sekali-kali salah seorang dari kalian shalat 'Ashar keculi di perkampungan Bani Quraizhah.\" Lalu tibalah waktu shalat ketika mereka masih di jalan, sebagian dari mereka berkata, 'Kami tidak akan shalat kecuali telah sampai tujuan', dan sebagian lain berkata, 'Bahkan kami akan melaksanakan shalat, sebab beliau tidaklah bermaksud demikian'. Maka kejadian tersebut diceritakan kepada Nabi shallallahu 'alaihi wasallam, dan beliau tidak mencela seorang pun dari mereka.\""},"895":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ وَثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الصُّبْحَ بِغَلَسٍ ثُمَّ رَكِبَ فَقَالَ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }فَخَرَجُوا يَسْعَوْنَ فِي السِّكَكِ وَيَقُولُونَ مُحَمَّدٌ وَالْخَمِيسُ قَالَ وَالْخَمِيسُ الْجَيْشُ فَظَهَرَ عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَتَلَ الْمُقَاتِلَةَ وَسَبَى الذَّرَارِيَّ فَصَارَتْ صَفِيَّةُ لِدِحْيَةَ الْكَلْبِيِّ وَصَارَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ تَزَوَّجَهَا وَجَعَلَ صَدَاقَهَا عِتْقَهَافَقَالَ عَبْدُ الْعَزِيزِ لِثَابِتٍ يَا أَبَا مُحَمَّدٍ أَنْتَ سَأَلْتَ أَنَسَ بْنَ مَالِكٍ مَا أَمْهَرَهَا قَالَ أَمْهَرَهَا نَفْسَهَا فَتَبَسَّمَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari ['Abdul 'Aziz bin Shuhaib] dan [Tsabit Al Banani] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat Shubuh dalam keadaan masih gelap, kemudian beliau mengendarai tunggangannya seraya bersabda: \"Allahu Akbar, hancurlah Khaibar! Sesungguhnya kami apabila mendatangi perkampungan suatu kaum, (maka amat buruklah pagi hari yang dialami orang-orang yang diperingatkan tersebut) (Qs. Ash Shaaffaat: 177). Orang-orang Khaibar keluar seraya berkata, \"Muhammad dan Al Khamis!\" Tabit berkata, \"Al Khamis artinya pasukan.\" Maka Rasulullah shallallahu 'alaihi wasallam pun mengalahkan mereka, membunuh pasukan dan menawan tawanan. Maka Shafiah menjadi bagian Dihyah Al Kalbi, kemudian ia menjadi milik Rasulullah shallallahu 'alaihi wasallam. Beliau kemudian menikahinya, dan maharnya adalah pembebasannya.\" 'Abdul 'Azizi berkata kepada Tsabit, \"Wahai Abu Muhammad, apakah kamu bertanya kepada Anas bin Malik, apa yang Beliau jadikan mahar untuk wanita tersebut?\" Tsabit menjawab, 'Maharnya adalah pembebasannya.' Ia pun tersenyum.\""},"896":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَأَخَذَ عُمَرُ جُبَّةً مِنْ إِسْتَبْرَقٍ تُبَاعُ فِي السُّوقِ فَأَخَذَهَا فَأَتَى بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ ابْتَعْ هَذِهِ تَجَمَّلْ بِهَا لِلْعِيدِ وَالْوُفُودِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَذِهِ لِبَاسُ مَنْ لَا خَلَاقَ لَهُ فَلَبِثَ عُمَرُ مَا شَاءَ اللَّهُ أَنْ يَلْبَثَ ثُمَّ أَرْسَلَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجُبَّةِ دِيبَاجٍ فَأَقْبَلَ بِهَا عُمَرُ فَأَتَى بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّكَ قُلْتَ إِنَّمَا هَذِهِ لِبَاسُ مَنْ لَا خَلَاقَ لَهُ وَأَرْسَلْتَ إِلَيَّ بِهَذِهِ الْجُبَّةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبِيعُهَا أَوْ تُصِيبُ بِهَا حَاجَتَكَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Salim bin 'Abdullah] bahwa ['Abdullah bin 'Umar] berkata, \"'Umar membawa baju jubah terbuat dari sutera yang dibelinya di pasar, jubah tersebut kemudian ia diberikan kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, belilah jubah ini sehingga tuan bisa memperbagus penampilan saat shalat 'Ied atau ketika menyambut para delegasi.\" Rasulullah shallallahu 'alaihi wasallam lalu berkata kepadanya: \"Ini adalah pakaian orang yang tidak akan mendapatkan bagian (di akhirat).\" Kemudian Umar tidak nampak untuk beberaa waktu lamanya menurut apa yang Allah kehendaki, Rasulullah shallallahu 'alaihi wasallam kemudian mengirimkan kepada 'Umar sebuah jubah yang terbuat dari sutera. Maka Umar pun membawanya menemui Rasulullah shallallahu 'alaihi wasallam seraya berkata: \"Wahai Rasulullah, tuan telah memberikan pakaian ini untukku, padahal tuan telah berkata, 'Ini adalah pakaian orang yang tidak akan mendapatkan bagian (di akhirat) '. Lalu mengapa tuan mengirimnya buat saya?\" Maka Rasulullah shallallahu 'alaihi wasallam pun berkata kepadanya: \"Juallah, atau beliau mengatakan, 'dengannya engkau bisa memenuhi kebutuhanmu.\""},"897":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنَا عَمْرٌو أَنَّ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ الْأَسَدِيَّ حَدَّثَهُ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي جَارِيَتَانِ تُغَنِّيَانِ بِغِنَاءِ بُعَاثَ فَاضْطَجَعَ عَلَى الْفِرَاشِ وَحَوَّلَ وَجْهَهُ وَدَخَلَ أَبُو بَكْرٍ فَانْتَهَرَنِي وَقَالَ مِزْمَارَةُ الشَّيْطَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ عَلَيْهِ رَسُولُ اللَّهِ عَلَيْهِ السَّلَام فَقَالَ دَعْهُمَا فَلَمَّا غَفَلَ غَمَزْتُهُمَا فَخَرَجَتَا وَكَانَ يَوْمَ عِيدٍ يَلْعَبُ السُّودَانُ بِالدَّرَقِ وَالْحِرَابِ فَإِمَّا سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِمَّا قَالَ تَشْتَهِينَ تَنْظُرِينَ فَقُلْتُ نَعَمْ فَأَقَامَنِي وَرَاءَهُ خَدِّي عَلَى خَدِّهِ وَهُوَ يَقُولُ دُونَكُمْ يَا بَنِي أَرْفِدَةَ حَتَّى إِذَا مَلِلْتُ قَالَ حَسْبُكِ قُلْتُ نَعَمْ قَالَ فَاذْهَبِي","id":"Telah menceritakan kepada kami [Ahmad bin 'Isa] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepada kami ['Amru] bahwa [Muhammad bin 'Abdurrahman Al Asadi] menceritakan kepadanya dari ['Urwah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk menemuiku saat ketika di sisiku ada dua budak wanita yang sedang bersenandung dengan lagu-lagu (tentang perang) Bu'ats. Maka beliau berbaring di atas tikar lalu memalingkan wajahnya, kemudian masuklah Abu Bakar mencelaku, ia mengatakan, \"Seruling-seruling setan (kalian perdengarkan) di hadapan Nabi shallallahu 'alaihi wasallam!\" Rasulullah shallallahu 'alaihi wasallam lantas memandang kepada Abu Bakar seraya berkata: \"Biarkanlah keduanya.\" Setelah beliau tidak menghiraukan lagi, aku memberi isyarat kepada kedua sahaya tersebut agar lekas pergi, lalu keduanya pun pergi. Saat Hari Raya 'Ied, biasanya ada dua budak Sudan yang memperlihatkan kebolehannya mempermainkan tombak dan perisai. Maka adakalanya aku sendiri yang meminta kepada Nabi shallallahu 'alaihi wasallam, atau beliau yang menawarkan kepadaku: \"Apakah kamu mau melihatnya?\" Maka aku jawab, \"Ya, mau.\" Maka beliau menempatkan aku berdiri di belakangnya, sementara pipiku bertemu dengan pipinya sambil beliau berkata: \"Teruskan hai Bani Arfadah!\" Demikianlah seterusnya sampai aku merasa bosan lalu beliau berkata: \"Apakah kamu merasa sudah cukup?\" Aku jawab, \"Ya, sudah.\" Beliau lalu berkata: \"Kalau begitu pergilah.\""},"898":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي زُبَيْدٌ قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ الْبَرَاءِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ إِنَّ أَوَّلَ مَا نَبْدَأُ مِنْ يَوْمِنَا هَذَا أَنْ نُصَلِّيَ ثُمَّ نَرْجِعَ فَنَنْحَرَ فَمَنْ فَعَلَ فَقَدْ أَصَابَ سُنَّتَنَا","id":"Telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku [Zubaid] berkata, Aku mendengar ['Asy Sya'bi] dari [Al Bara'] berkata, Aku mendengar Nabi shallallahu 'alaihi wasallam menyampaikan khutbah, sabdanya: \"Pertama kali yang akan kita kerjakan pada hari ini adalah shalat, kemudian kembali pulang dan menyembelih hewan kurban. Maka barangsiapa mengerjakan seperti ini bararti dia telah memenuhi sunnah kami.\""},"899":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ أَبُو بَكْرٍ وَعِنْدِي جَارِيَتَانِ مِنْ جَوَارِي الْأَنْصَارِ تُغَنِّيَانِ بِمَا تَقَاوَلَتْ الْأَنْصَارُ يَوْمَ بُعَاثَ قَالَتْ وَلَيْسَتَا بِمُغَنِّيَتَيْنِ فَقَالَ أَبُو بَكْرٍ أَمَزَامِيرُ الشَّيْطَانِ فِي بَيْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَلِكَ فِي يَوْمِ عِيدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا بَكْرٍ إِنَّ لِكُلِّ قَوْمٍ عِيدًا وَهَذَا عِيدُنَا","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Bapaknya] dari ['Aisyah] berkata, \"Abu Bakar masuk menemui aku saat itu di sisiku ada dua orang budak tetangga Kaum Anshar yang sedang bersenandung, yang mengingatkan kepada peristiwa pembantaian kaum Anshar pada perang Bu'ats.\" 'Aisyah menlanjutkan kisahnya, \"Kedua sahaya tersebut tidaklah begitu pandai dalam bersenandung. Maka Abu Bakar pun berkata, \"Seruling-seruling setan (kalian perdengarkan) di kediaman Rasulullah shallallahu 'alaihi wasallam!\" Peristiwa itu terjadi pada Hari Raya 'Ied. Maka bersabdalah Rasulullah shallallahu 'alaihi wasallam: \"Wahai Abu Bakar, sesungguhnya setiap kaum memiliki hari raya, dan sekarang ini adalah hari raya kita.\""},"900":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْدُو يَوْمَ الْفِطْرِ حَتَّى يَأْكُلَ تَمَرَاتٍوَقَالَ مُرَجَّأُ بْنُ رَجَاءٍ حَدَّثَنِي عُبَيْدُ اللَّهِ قَالَ حَدَّثَنِي أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَأْكُلُهُنَّ وِتْرًا","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdurrahim] telah menceritakan kepada kami [Sa'id bin Sulaiman] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami ['Ubaidullah bin Abu Bakar bin Anas] dari [Anas bin Malik] berkata, \"Pada hari raya Rasulullah shallallahu 'alaihi wasallam tidak berangkat untuk melaksanakan shalat hingga beliau makan beberapa butir kurma.\" [Murajja' bin Raja'] berkata; telah menceritakan kepadaku ['Ubaidullah] berkata, telah menceritakan kepadaku [Anas] dari Nabi shallallahu 'alaihi wasallam, \"Beliau makan beberapa kurma dengan bilangan ganjil.\""},"901":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيُعِدْ فَقَامَ رَجُلٌ فَقَالَ هَذَا يَوْمٌ يُشْتَهَى فِيهِ اللَّحْمُ وَذَكَرَ مِنْ جِيرَانِهِ فَكَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَّقَهُ قَالَ وَعِنْدِي جَذَعَةٌ أَحَبُّ إِلَيَّ مِنْ شَاتَيْ لَحْمٍ فَرَخَّصَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدْرِي أَبَلَغَتْ الرُّخْصَةُ مَنْ سِوَاهُ أَمْ لَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Muhammad bin Sirin] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyembelih sebelum shalat hendaklah dia mengulanginya.\" Lalu berdirilah seorang laki-laki seraya berkata, \"Ini adalah hari yang daging sangat diharap.\" Laki-laki itu kemudian menyebut-nyebut tentang tetangga-tetangganya, dan seakan Nabi shallallahu 'alaihi wasallam membenarkan orang itu. Lelaki itu berkata, \"Sungguh aku berkurban dengan seekor jadza'ah lebih aku sukai dari dua ekor kambing.\" Maka Nabi shallallahu 'alaihi wasallam memberikan keringanan buat orang tersebut. Aku (Anas) tidak tahu apakah keringanan itu juga berlaku untuk yang lain atau tidak.\" "},"902":{"ar":"حَدَّثَنَا عُثْمَانُ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَضْحَى بَعْدَ الصَّلَاةِ فَقَالَ مَنْ صَلَّى صَلَاتَنَا وَنَسَكَ نُسُكَنَا فَقَدْ أَصَابَ النُّسُكَ وَمَنْ نَسَكَ قَبْلَ الصَّلَاةِ فَإِنَّهُ قَبْلَ الصَّلَاةِ وَلَا نُسُكَ لَهُ فَقَالَ أَبُو بُرْدَةَ بْنُ نِيَارٍ خَالُ الْبَرَاءِ يَا رَسُولَ اللَّهِ فَإِنِّي نَسَكْتُ شَاتِي قَبْلَ الصَّلَاةِ وَعَرَفْتُ أَنَّ الْيَوْمَ يَوْمُ أَكْلٍ وَشُرْبٍ وَأَحْبَبْتُ أَنْ تَكُونَ شَاتِي أَوَّلَ مَا يُذْبَحُ فِي بَيْتِي فَذَبَحْتُ شَاتِي وَتَغَدَّيْتُ قَبْلَ أَنْ آتِيَ الصَّلَاةَ قَالَ شَاتُكَ شَاةُ لَحْمٍ قَالَ يَا رَسُولَ اللَّهِ فَإِنَّ عِنْدَنَا عَنَاقًا لَنَا جَذَعَةً هِيَ أَحَبُّ إِلَيَّ مِنْ شَاتَيْنِ أَفَتَجْزِي عَنِّي قَالَ نَعَمْ وَلَنْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami ['Utsman] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Asy Sya'bi] dari [Al Bara' bin 'Azib] radliallahu 'anhu, ia berkata, \"Nabi shallallahu 'alaihi wasallam menyampaikan khutbah pada hari Raya Qurban ('Iedul Adlha) setelah melaksankan shalat. Beliau bersabda: \"Barangsiapa melaksanakan shalat seperti shalat kami dan melaksanakan manasik seperti manasik kami maka dia telah melaksanakan manasik (menyembelih kurban). Dan barangsiapa menyembelih kurban sebelum shalat berarti dia malaksanakannya sebelum shalat, dan berarti dia belum melaksanakan manasik (berkurban).\" Abu Burdah bin Niyar, paman Al Bara', berkata, \"Wahai Rasulullah, aku telah menyembelih dua ekor kambing sebelum shalat, dan yang aku ketahui bahwa hari ini adalah hari kita bergembira dengan makan dan minum. Dan aku menyukai bila dua ekor kambingku itu menjadi yang pertama disembelih di rumahku lalu aku memasaknya dan menikmatinya sebelum aku berangkat untuk shalat!\" Beliau bersabda: \"Kambingmu setatusnya adalah kambing yang disembelih untuk diambil dagingnya (bukan daging kurban).\" Laki-laki itu berkata lagi, \"Wahai Rasulullah, kami masih memiliki anak kambing yang dia lebih kami cintai dari dua ekor kambing tadi. Apakah aku dibolehkan berkurban dengannya?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Ya. Akan tetapi tidak boleh untuk seorangpun setelah kamu.\""},"903":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَرْحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ يَوْمَ الْفِطْرِ وَالْأَضْحَى إِلَى الْمُصَلَّى فَأَوَّلُ شَيْءٍ يَبْدَأُ بِهِ الصَّلَاةُ ثُمَّ يَنْصَرِفُ فَيَقُومُ مُقَابِلَ النَّاسِ وَالنَّاسُ جُلُوسٌ عَلَى صُفُوفِهِمْ فَيَعِظُهُمْ وَيُوصِيهِمْ وَيَأْمُرُهُمْ فَإِنْ كَانَ يُرِيدُ أَنْ يَقْطَعَ بَعْثًا قَطَعَهُ أَوْ يَأْمُرَ بِشَيْءٍ أَمَرَ بِهِ ثُمَّ يَنْصَرِفُقَالَ أَبُو سَعِيدٍ فَلَمْ يَزَلْ النَّاسُ عَلَى ذَلِكَ حَتَّى خَرَجْتُ مَعَ مَرْوَانَ وَهُوَ أَمِيرُ الْمَدِينَةِ فِي أَضْحًى أَوْ فِطْرٍ فَلَمَّا أَتَيْنَا الْمُصَلَّى إِذَا مِنْبَرٌ بَنَاهُ كَثِيرُ بْنُ الصَّلْتِ فَإِذَا مَرْوَانُ يُرِيدُ أَنْ يَرْتَقِيَهُ قَبْلَ أَنْ يُصَلِّيَ فَجَبَذْتُ بِثَوْبِهِ فَجَبَذَنِي فَارْتَفَعَ فَخَطَبَ قَبْلَ الصَّلَاةِ فَقُلْتُ لَهُ غَيَّرْتُمْ وَاللَّهِ فَقَالَ أَبَا سَعِيدٍ قَدْ ذَهَبَ مَا تَعْلَمُ فَقُلْتُ مَا أَعْلَمُ وَاللَّهِ خَيْرٌ مِمَّا لَا أَعْلَمُ فَقَالَ إِنَّ النَّاسَ لَمْ يَكُونُوا يَجْلِسُونَ لَنَا بَعْدَ الصَّلَاةِ فَجَعَلْتُهَا قَبْلَ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepadaku [Zaid bin Aslam] dari ['Iyadl bin 'Abdullah bin Abu Sarah] dari [Abu Sa'id Al Khudri] berkata, \"Pada hari raya Idul Firi dan Adlha Rasulullah shallallahu 'alaihi wasallam keluar menuju tempat shalat (lapangan), dan pertama kali yang beliau kerjakan adalah shalat hingga selesai. Kemudian beliau berdiri menghadap orang banyak sedangkan mereka dalam keadaan duduk di barisan mereka. Beliau memberi pengajaran, wasiat dan memerintahkan mereka. Dan apabila beliau ingin mengutus pasukan, maka beliau sampaikan atau beliau perintahkan (untuk mempersiapkannya), setelah itu beliau berlalu pergi.\" Abu Sa'id Al Khudri berkata, \"Manusia senantiasa melaksanakan (tata cara shalat hari raya) seperti apa yang beliau laksanakan, hingga pada suatu hari aku keluar bersama Marwan -yang saat itu sebagai Amir di Madinah- pada hari raya Adlha atau Fithri. Ketika kami sampai di tempat shalat, ternyata di sana sudah ada mimbar yang dibuat oleh Katsir bin Ash Shalt. Ketika Marwan hendak menaiki mimbar sebelum pelaksanaan shalat, aku tarik pakaiannya dan dia balik menariknya, kemudian ia naik dan khuthbah sebelum shalat. Maka aku katakan kepadanya, \"Demi Allah, kamu telah merubah (sunnah)!\" Lalu dia menjawab, \"Wahai Abu Sa'id. Apa yang engkau ketahui itu telah berlalu.\" Aku katakan, \"Demi Allah, apa yang aku ketahui lebih baik dari apa yang tidak aku ketahui.\" Lalu dia berkata, \"Sesungguhnya orang-orang tidak akan duduk (mendengarkan khutbah kami) setelah shalat. Maka aku buat (khutbah) sebelum shalat.\""},"904":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي فِي الْأَضْحَى وَالْفِطْرِ ثُمَّ يَخْطُبُ بَعْدَ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidullah] dari [Nafi'] dari ['Abdullah bin 'Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat 'Idul Adlha dan 'Idul Fitri kemudian berkhutbah setelah shalat.\""},"905":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُهُ يَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمَ الْفِطْرِ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, ia berkata; telah mengabarkan kepadaku ['Atha'] dari [Jabir bin 'Abdullah] berkata, Aku mendengarnya berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar pada hari Raya 'Idul Fitri, beliau memulainya dengan shalat kemudian khutbah.\""},"906":{"ar":"قَالَ وَأَخْبَرَنِي عَطَاءٌ أَنَّ ابْنَ عَبَّاسٍأَرْسَلَ إِلَى ابْنِ الزُّبَيْرِ فِي أَوَّلِ مَا بُويِعَ لَهُ إِنَّهُ لَمْ يَكُنْ يُؤَذَّنُ بِالصَّلَاةِ يَوْمَ الْفِطْرِ إِنَّمَا الْخُطْبَةُ بَعْدَ الصَّلَاةِ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya) perawi berkata, telah menceritakan kepadaku ['Atha'] bahwa [Ibnu 'Abbas] menyampaikan kepada Ibnu Az Zubair pada awal dia dibai'at sebagai khalifah, bahwa tidak ada adzan dalam shalat Hari Raya 'Idul Fithri (di zaman Nabi shallallahu 'alaihi wasallam), dan bahwasanya khutbah dilaksanakan setelah shalat.\""},"907":{"ar":"و أَخْبَرَنِي عَطَاءٌ عَنْ ابْنِ عَبَّاسٍ وَعَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَالَمْ يَكُنْ يُؤَذَّنُ يَوْمَ الْفِطْرِ وَلَا يَوْمَ الْأَضْحَى","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya), telah mengabarkan kepadaku ['Atha'] dari [Ibnu 'Abbas], dan dari [Jabir bin 'Abdullah] keduanya berkata, \"Dalam shalat Idul Fitri dan Idul Adlha tidak ada adzan.\""},"908":{"ar":"وَعَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُهُ يَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَبَدَأَ بِالصَّلَاةِ ثُمَّ خَطَبَ النَّاسَ بَعْدُ فَلَمَّا فَرَغَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ فَأَتَى النِّسَاءَ فَذَكَّرَهُنَّ وَهُوَ يَتَوَكَّأُ عَلَى يَدِ بِلَالٍ وَبِلَالٌ بَاسِطٌ ثَوْبَهُ يُلْقِي فِيهِ النِّسَاءُ صَدَقَةًقُلْتُ لِعَطَاءٍ أَتَرَى حَقًّا عَلَى الْإِمَامِ الْآنَ أَنْ يَأْتِيَ النِّسَاءَ فَيُذَكِّرَهُنَّ حِينَ يَفْرُغُ قَالَ إِنَّ ذَلِكَ لَحَقٌّ عَلَيْهِمْ وَمَا لَهُمْ أَنْ لَا يَفْعَلُوا","id":"Dan (masih dari jalur periwayatan yang sama dengan hadits sebelumnya) dari [Jabir bin 'Abdullah] ia berkata, aku mendengarnya berkata, \"Nabi shallallahu 'alaihi wasallam berdiri dan memulai dengan shalat, kemudian berkhutbah di hadapan manusia setelahnya. Setelah Nabi shallallahu 'alaihi wasallam selesai, beliau mendatangi tempat jama'ah wanita dan mengingatkan mereka. Beliau menyandar pada tangan Bilal, sementara Bilal sendiri membentangkan kain miliknya dimana para wanita memasukkan sedekahnya ke dalam kain tersebut.\" Aku (perawi) bertanya kepada 'Atha, \"Bagaimana menurutmu apakah boleh jika sekarang Imam mendatangi para wanita untuk memberi peringatan kepada mereka setelah selesai dari khutbah?\" 'Atha menjawab, \"Itu adalah hak mereka, dan mengapa mereka tidak diperbolehkan melakukannya?\""},"909":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي الْحَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَشَهِدْتُ الْعِيدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ رَضِيَ اللَّهُ عَنْهُمْ فَكُلُّهُمْ كَانُوا يُصَلُّونَ قَبْلَ الْخُطْبَةِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu 'Abbas] berkata, \"Aku menghadiri shalat Hari Raya bersama Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, 'Umar dan 'Utsman? radliallahu 'anhum, bahwa mereka semua melaksanakan shalat sebelum khutbah.\""},"910":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا يُصَلُّونَ الْعِيدَيْنِ قَبْلَ الْخُطْبَةِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, dan 'Umar? radliallahu 'anhu mereka melaksanakan shalat dua Hari Raya sebelum khutbah.\""},"911":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ الْفِطْرِ رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا ثُمَّ أَتَى النِّسَاءَ وَمَعَهُ بِلَالٌ فَأَمَرَهُنَّ بِالصَّدَقَةِ فَجَعَلْنَ يُلْقِينَ تُلْقِي الْمَرْأَةُ خُرْصَهَا وَسِخَابَهَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat Hari Raya 'Idul Fitri dua rakaat dan tidak shalat sebelum atau sesudahnya. Kemudian beliau mendatangi para wanita dan memerintahkan mereka untuk bersedekah. Maka para wanita memberikan sedekah hingga ada seorang wanita yang memberikan anting dan kalungnya.\""},"912":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا زُبَيْدٌ قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ مَا نَبْدَأُ فِي يَوْمِنَا هَذَا أَنْ نُصَلِّيَ ثُمَّ نَرْجِعَ فَنَنْحَرَ فَمَنْ فَعَلَ ذَلِكَ فَقَدْ أَصَابَ سُنَّتَنَا وَمَنْ نَحَرَ قَبْلَ الصَّلَاةِ فَإِنَّمَا هُوَ لَحْمٌ قَدَّمَهُ لِأَهْلِهِ لَيْسَ مِنْ النُّسْكِ فِي شَيْءٍ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ يُقَالُ لَهُ أَبُو بُرْدَةَ بْنُ نِيَارٍ يَا رَسُولَ اللَّهِ ذَبَحْتُ وَعِنْدِي جَذَعَةٌ خَيْرٌ مِنْ مُسِنَّةٍ فَقَالَ اجْعَلْهُ مَكَانَهُ وَلَنْ تُوفِيَ أَوْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Zubaid] berkata, aku mendengar [Asy Sya'bi] dari [Al Bara' bin 'Azib] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang pertama kali kami lakukan pada hari Raya ini adalah shalat. Kemudian kami pulang dan menyembelih kurban. Maka barangsiapa mengerjakan seperti itu berarti dia telah memenuhi sunnah kami. Dan barangsiapa menyembelih kurban sebelum pelaksanaan shalat 'Ied, maka itu hanyalah daging yang dipersembahkan untuk keluarganya dan tidak sedikitpun mendapatkan (pahala) ibadah kurban.\" Tiba-tiba ada seorang lelaki Anshar yang dipanggil dengan nama Abu Burdah bin Niyar berkata, \"Wahai Rasulullah, aku telah menyembelih hewan dan aku masih memiliki anak unta yang lebih baik dari unta yang lebih besar.\" Maka beliau bersabda: \"Jadikanlah ia sebagai pengganti dari apa yang telah kamu sembelih sebelum shalat, dan kamu akan mendapatkan bagian pahala yang cukup yang tidak akan didapati oleh orang selainmu.\""},"913":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى أَبُو السُّكَيْنِ قَالَ حَدَّثَنَا الْمُحَارِبِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سُوقَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَكُنْتُ مَعَ ابْنِ عُمَرَ حِينَ أَصَابَهُ سِنَانُ الرُّمْحِ فِي أَخْمَصِ قَدَمِهِ فَلَزِقَتْ قَدَمُهُ بِالرِّكَابِ فَنَزَلْتُ فَنَزَعْتُهَا وَذَلِكَ بِمِنًى فَبَلَغَ الْحَجَّاجَ فَجَعَلَ يَعُودُهُ فَقَالَ الْحَجَّاجُ لَوْ نَعْلَمُ مَنْ أَصَابَكَ فَقَالَ ابْنُ عُمَرَ أَنْتَ أَصَبْتَنِي قَالَ وَكَيْفَ قَالَ حَمَلْتَ السِّلَاحَ فِي يَوْمٍ لَمْ يَكُنْ يُحْمَلُ فِيهِ وَأَدْخَلْتَ السِّلَاحَ الْحَرَمَ وَلَمْ يَكُنْ السِّلَاحُ يُدْخَلُ الْحَرَمَ","id":"Telah menceritakan kepada kami [Zakaria bin Yahya Abu As Sukain] berkata, telah menceritakan kepada kami [Al Muharibi] berkata, telah menceritakan kepada kami [Muhammad bin Suqah] dari [Sa'id bin Jubair] berkata, \"Aku pernah besama Ibnu 'Umar saat dia terkena ujung panah pada bagian lekuk telapak kakinya. Dia lalu merapatkan kakinya pada tunggangannya, lalu aku turun dan melepaskannya. Kejadiaan itu terjadi di Mina. Kemudian peristiwa ini didengar oleh Al Hajjaj, maka dia pun menjenguknya seraya berkata, \"Seandainya kami ketahui siapa yang membuatmu terkena mushibah ini!\" Maka [Ibnu 'Umar] menyahut, \"Engkaulah yang membuat aku terkena mushibah ini.\" Al Hajjaj berkata, \"Bagaimana bisa!\" Ibnu 'Umar menjawab, \"Engkau yang membawa senjata di hari yang tidak diperbolehkan membawanya. Dan engkau pula yang membawa masuk senjata ke dalam Masjidil Haram padahal tidak diperbolehkan membawa masuk senjata ke dalam Masjidil Haram pada hari ini.\""},"914":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنِي إِسْحَاقُ بْنُ سَعِيدِ بْنِ عَمْرِو بْنِ سَعِيدِ بْنِ الْعَاصِ عَنْ أَبِيهِ قَالَدَخَلَ الْحَجَّاجُ عَلَى ابْنِ عُمَرَ وَأَنَا عِنْدَهُ فَقَالَ كَيْفَ هُوَ فَقَالَ صَالِحٌ فَقَالَ مَنْ أَصَابَكَ قَالَ أَصَابَنِي مَنْ أَمَرَ بِحَمْلِ السِّلَاحِ فِي يَوْمٍ لَا يَحِلُّ فِيهِ حَمْلُهُ يَعْنِي الْحَجَّاجَ","id":"Telah menceritakan kepada kami [Ahmad bin Ya'qub] berkata, telah menceritakan kepadaku [Ishaq bin Sa'id bin Al 'Ash] dari [Bapaknya] berkata, \"Al Hajjaj datang menemui Ibnu 'Umar, dan saat itu aku sedang bersamanya. Al Hajjaj lalu bertanya, \"Bagaimana keadaannya?\" Ibnu 'Umar menjawab, \"Baik.\" Al Hajjaj bertanya lagi, \"Siapa yang melukaimu?\" [Ibnu 'Umar] menjawab, 'Yang melukai aku adalah orang yang memerintahkan membawa senjata pada suatu hari yang mana pada hari itu dilarang membawanya.' Yaitu Al Hajjaj.\" "},"915":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ زُبَيْدٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ قَالَخَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ قَالَ إِنَّ أَوَّلَ مَا نَبْدَأُ بِهِ فِي يَوْمِنَا هَذَا أَنْ نُصَلِّيَ ثُمَّ نَرْجِعَ فَنَنْحَرَ فَمَنْ فَعَلَ ذَلِكَ فَقَدْ أَصَابَ سُنَّتَنَا وَمَنْ ذَبَحَ قَبْلَ أَنْ يُصَلِّيَ فَإِنَّمَا هُوَ لَحْمٌ عَجَّلَهُ لِأَهْلِهِ لَيْسَ مِنْ النُّسُكِ فِي شَيْءٍ فَقَامَ خَالِي أَبُو بُرْدَةَ بْنُ نِيَارٍ فَقَالَ يَا رَسُولَ اللَّهِ أَنَا ذَبَحْتُ قَبْلَ أَنْ أُصَلِّيَ وَعِنْدِي جَذَعَةٌ خَيْرٌ مِنْ مُسِنَّةٍ قَالَ اجْعَلْهَا مَكَا��َهَا أَوْ قَالَ اذْبَحْهَا وَلَنْ تَجْزِيَ جَذَعَةٌ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Zubaid] dari [Asy Sya'bi] dari [Al Bara'] berkata, \"Nabi shallallahu 'alaihi wasallam memberi khutbah kepada kami pada hari Nahr (penyembelihan kurban), beliau sabdakan: \"Sesungguhnya yang pertama kali kami lakukan pada hari Raya kami ini adalah shalat. Kemudian kami pulang dan melaksanakan penyembelihan kurban. Maka barangsiapa mengerjakan seperti itu berarti dia telah memenuhi sunnah kami. Dan barangsiapa menyembelih kurban sebelum pelaksanaan shalat 'Ied maka itu hanyalah daging yang dipersembahkan untuk keluarganya dan tidak sedikitpun mendapatkan (pahala) ibadah kurban.\" Tiba-tiba pamanku, Abu Burdah bin Niyar, berdiri dan berkata, \"Wahai Rasulullah, aku telah menyembelih hewan sebelum aku shalat, namun aku masih memiliki anak kambing yang lebih baik dari kambing yang telah berumur dua tahun.\" Maka beliau pun bersabda: \"Jadikanlah ia sebagai pengganti (dari apa yang telah kamu sembelih sebelum shalat).\" Atau beliau mengatakan: \"Sembelihlah, namun hal itu tidak mencukupi oleh orang selainmu.\""},"916":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا الْعَمَلُ فِي أَيَّامٍ أَفْضَلَ مِنْهَا فِي هَذِهِ قَالُوا وَلَا الْجِهَادُ قَالَ وَلَا الْجِهَادُ إِلَّا رَجُلٌ خَرَجَ يُخَاطِرُ بِنَفْسِهِ وَمَالِهِ فَلَمْ يَرْجِعْ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada amal yang lebih utama pada hari-hari (tasyriq) ini selian berkurban.\" Para sahabat berkata, \"Tidak juga jihad?\" Beliau menjawab: \"Tidak juga jihad. Kecuali seseorang yang keluar dari rumahnya dengan mengorbankan diri dan hartanya (di jalan Allah), lalu dia tidak kembali lagi.\""},"917":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الثَّقَفِيُّ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍوَنَحْنُ غَادِيَانِ مِنْ مِنًى إِلَى عَرَفَاتٍ عَنْ التَّلْبِيَةِ كَيْفَ كُنْتُمْ تَصْنَعُونَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ يُلَبِّي الْمُلَبِّي لَا يُنْكَرُ عَلَيْهِ وَيُكَبِّرُ الْمُكَبِّرُ فَلَا يُنْكَرُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Malik bin Anas] berkata, telah menceritakan kepadaku [Muhammad bin Abu Bakar Ats Tsaqafi] berkata, \"Aku bertanya kepada [Anas bin Malik] -saat itu kami berdua sedang berangkat dari Mina menuju 'Arafah- tentang talbiyyah, 'Bagaimana kalian melaksanakannya bersama Nabi shallallahu 'alaihi wasallam? ' Dia menjawab, \"Di antara kami ada seorang yang membaca talbiyyah, namun hal itu tidak diingkari, dan ada yang bertakbir namun hal itu juga tidak diingkari.\""},"918":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي عَنْ عَاصِمٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْكُنَّا نُؤْمَرُ أَنْ نَخْرُجَ يَوْمَ الْعِيدِ حَتَّى نُخْرِجَ الْبِكْرَ مِنْ خِدْرِهَا حَتَّى نُخْرِجَ الْحُيَّضَ فَيَكُنَّ خَلْفَ النَّاسِ فَيُكَبِّرْنَ بِتَكْبِيرِهِمْ وَيَدْعُونَ بِدُعَائِهِمْ يَرْجُونَ بَرَكَةَ ذَلِكَ الْيَوْمِ وَطُهْرَتَهُ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] berkata, telah menceritakan kepada kami [Bapakku] dari ['Ashim] dari [Hafshah] dari [Ummu 'Athiyyah] berkata, \"Pada hari Raya Ied kami diperintahkan untuk keluar sampai-sampai kami mengajak para anak gadis dari kamarnya dan juga para wanita yang sedang haid. Mereka duduk di belakang barisan kaum laki-laki dan mengucapkan takbir mengikuti takbirnya kaum laki-laki, dan berdoa mengikuti doanya kaum laki-laki dengan mengharap barakah dan kesucian hari raya tersebut.\""},"919":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ تُرْكَزُ الْحَرْبَةُ قُدَّامَهُ يَوْمَ الْفِطْرِ وَالنَّحْرِ ثُمَّ يُصَلِّي","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdul Wahhab] berkata, telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar], bahwa Nabi shallallahu 'alaihi wasallam menancapkan tombak pada hari Raya Fitri dan hari Raya kurban, kemudian beliau shalat.\""},"920":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا أَبُو عَمْرٍو الْأَوْزَاعِيُّ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْدُو إِلَى الْمُصَلَّى وَالْعَنَزَةُ بَيْنَ يَدَيْهِ تُحْمَلُ وَتُنْصَبُ بِالْمُصَلَّى بَيْنَ يَدَيْهِ فَيُصَلِّي إِلَيْهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Al Walid] berkata, telah menceritakan kepada kami [Abu Amru Al Auza'i] berkata, telah mengabarkan kepadaku [Nafi'] dari [Ibnu 'Umar], bahwa Nabi shallallahu 'alaihi wasallam berangkat menuju tempat shalat sedang di tangan beliau ada sebuat tongkat, tongkat tersebut beliau tancapkan di depannya lalu shalat menhhadap ke arahnya.\""},"921":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَمَرَنَا نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَنْ نُخْرِجَ الْعَوَاتِقَ وَذَوَاتِ الْخُدُورِوَعَنْ أَيُّوبَ عَنْ حَفْصَةَ بِنَحْوِهِ وَزَادَ فِي حَدِيثِ حَفْصَةَ قَالَ أَوْ قَالَتْ الْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ وَيَعْتَزِلْنَ الْحُيَّضُ الْمُصَلَّى","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] berkata, [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] berkata, \"Nabi kami shallallahu 'alaihi wasallam memerintahkan kami untuk mengeluarkan para gadis remaja kami dan wanita-wanita yang dipingit di rumah.\" Dan dari [Ayyub] dari [Hafshah] seperti riwayat ini juga. Dalam hadits Hafshah ditambahkan, beliau bersabda. Atau Ummu 'Athiyyah berkata, \"Para gadis remaja kami dan wanita-wanita yang dipingit di rumah, dan wanita-wanita hadi menjauhi tempat shalat.\""},"922":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَخَرَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فِطْرٍ أَوْ أَضْحَى فَصَلَّى ثُمَّ خَطَبَ ثُمَّ أَتَى النِّسَاءَ فَوَعَظَهُنَّ وَذَكَّرَهُنَّ وَأَمَرَهُنَّ بِالصَّدَقَةِ","id":"Telah menceritakan kepada kami ['Amru bin 'Abbas] berkata, telah menceritakan kepada kami ['Abdurrahman] telah menceritakan kepada kami [Sufyan] dari ['Abdurrahman bin 'Abis] berkata, Aku mendengar [Ibnu 'Abbas] berkata, \"Aku pernah keluar bersama Nabi shallallahu 'alaihi wasallam untuk shalat Hari Raya Fitri atau Adlha. Beliau melaksanakan shalat kemudian menyampaikan khutbah. Setelah itu, beliau mendatangi para wanita dan memberi pelajaran kepada mereka, mengingatkan dan memerintahkan agar bersedekah.\""},"923":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ زُبَيْدٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أَضْحًى إِلَى الْبَقِيعِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ وَقَالَ إِنَّ أَوَّلَ نُسُكِنَا فِي يَوْمِنَا هَذَا أَنْ نَبْدَأَ بِالصَّلَاةِ ثُمَّ نَرْجِعَ فَنَنْحَرَ فَمَنْ فَعَلَ ذَلِكَ فَقَدْ وَافَقَ سُنَّتَنَا وَمَنْ ذَبَحَ قَبْلَ ذَلِكَ فَإِنَّمَا هُوَ شَيْءٌ عَجَّلَهُ لِأَهْلِهِ لَيْسَ مِنْ النُّسُكِ فِي شَيْءٍ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي ذَبَحْتُ وَعِنْدِي جَذَعَةٌ خَيْرٌ مِنْ مُسِنَّةٍ قَالَ اذْبَحْهَا وَلَا تَفِي عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Zubaid] dari [Asy Sya'bi] dari [Al Bara'] berkata, \"Nabi shallallahu 'alaihi wasallam keluar pada hari Raya kurban menuju Baqi', beliau lalu melaksanakan shalat dua rakaat, setelahitu beliau menghadap ke arah kami dan bersabda: \"Sesungguhnya yang pertama dari 'ibadah kita pada Hari Raya kita ini adalah memulai dengan melaksanakan shalat, kemudian kembali ke rumah dan menyembelih hewan kurban. Barangsiapa melaksanakan seperti itu berarti telah sesuai dengan sunnah kita. Dan barangsiapa menyembelih kurban sebelum shalat, maka itu hanyalah sesuatu yang dipersembahkan untuk keluarganya dan tidak ada sedikitpun termasuk dari ibadah kita ini.\" Lalu berdirilah seorang laki-laki dan berkata, \"Wahai Rasulullah, aku telah menyembelih (sebelum shalat), namun aku masih memiliki anak kambing yang lebih baik dari kambing yang telah berumur dua tahun?\" Beliau pun bersabda: \"Sembelihlah. Namun ini tidak berlaku bagi seorang pun setelahmu.\""},"924":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَابِسٍ قَالَسَمِعْتُ ابْنَ عَبَّاسٍ قِيلَ لَهُ أَشَهِدْتَ الْعِيدَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَلَوْلَا مَكَانِي مِنْ الصِّغَرِ مَا شَهِدْتُهُ حَتَّى أَتَى الْعَلَمَ الَّذِي عِنْدَ دَارِ كَثِيرِ بْنِ الصَّلْتِ فَصَلَّى ثُمَّ خَطَبَ ثُمَّ أَتَى النِّسَاءَ وَمَعَهُ بِلَالٌ فَوَعَظَهُنَّ وَذَكَّرَهُنَّ وَأَمَرَهُنَّ بِالصَّدَقَةِ فَرَأَيْتُهُنَّ يَهْوِينَ بِأَيْدِيهِنَّ يَقْذِفْنَهُ فِي ثَوْبِ بِلَالٍ ثُمَّ انْطَلَقَ هُوَ وَبِلَالٌ إِلَى بَيْتِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepadaku ['Abdurrahman bin 'Abis] berkata, aku mendengar [Ibnu 'Abbas] ketika dikatakan kepadanya, \"Apakah engkau pernah menghadiri shalat 'Ied bersama Nabi shallallahu 'alaihi wasallam?\" Dia menjawab, \"Ya. Kalau seandainya bukan karena kedudukanku yang masih kecil, tentu aku tak akan turut serta, hingga beliau mendatangi tanda yang ada di sisi rumah Katsir bin Ash Shalt. Beliau lalu shalat dan memberikan khutbah. Setelah itu beliau mendatangi jama'ah para wanita bersama Bilal, beliau memberi pelajaran kepada para wanita tersebut, mengingatkan mereka dan memerintahkan agar bersedekah. Maka aku menyaksikan para wanita tersebut memberikan apa yang ada pada tangan mereka (emas perhiasan), mereka meletakkannya ke dalam kain yang di bawa oleh Bilal. Setelah itu beliau dan Bilal pergi menuju rumahnya.\""},"925":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ بْنِ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُهُ يَقُولُقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفِطْرِ فَصَلَّى فَبَدَأَ بِالصَّلَاةِ ثُمَّ خَطَبَ فَلَمَّا فَرَغَ نَزَلَ فَأَتَى النِّسَاءَ فَذَكَّرَهُنَّ وَهُوَ يَتَوَكَّأُ عَلَى يَدِ بِلَالٍ وَبِلَالٌ بَاسِطٌ ثَوْبَهُ يُلْقِي فِيهِ النِّسَاءُ الصَّدَقَةَقُلْتُ لِعَطَاءٍ زَكَاةَ يَوْمِ الْفِطْرِ قَالَ لَا وَلَكِنْ صَدَقَةً يَتَصَدَّقْنَ حِينَئِذٍ تُلْقِي فَتَخَهَا وَيُلْقِينَ قُلْتُ أَتُرَى حَقًّا عَلَى الْإِمَامِ ذَلِكَ وَيُذَكِّرُهُنَّ قَالَ إِنَّهُ لَحَقٌّ عَلَيْهِمْ وَمَا لَهُمْ لَا يَفْعَلُونَهُ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim bin Nashr] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku ['Atha'] dari [Jabir bin 'Abdullah] berkata, Aku mendengarnya berkata, \"Nabi shallallahu 'alaihi wasallam berdiri untuk melaksanakan shalat pada hari Raya Iedul Fitri, dan yang pertama kali beliau kerjakan adalah shalat, baru kemudian menyampaikan khutbah. Selesai khutbah beliau turun (dari mimbar) dan mendatangi jama'ah wanita untuk mengingatkan mereka dengan bersandar pada tangan Bilal, sementara Bilal sendiri membentangkan kain miliknya hingga para wanita tersebut memasukkan sedekahnya ke dalam kain tersebut.\" Aku bertanya kepada 'Atha, 'Apakah itu zakat fitri? ' ia menjawab, 'Bukan, tetapi sedekah yang mereka keluarkan pada saat itu, mereka memberikan anting dan gelang mereka.' Aku bertanya lagi, 'Bagaimana pendapatmu jika masa sekarang ini seorang Imam mendatangi jama'ah para wanita lalu mengingatkan mereka tentang itu? ' 'Atha menjawab, 'Yang demikian itu merupakan hak mereka (para Imam), dan apa alasanya mereka tidak boleh melakukannya? '"},"926":{"ar":"قَالَ ابْنُ جُرَيْجٍ وَأَخْبَرَنِي الْحَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَشَهِدْتُ الْفِطْرَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ رَضِيَ اللَّهُ عَنْهُمْ يُصَلُّونَهَا قَبْلَ الْخُطْبَةِ ثُمَّ يُخْطَبُ بَعْدُ خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنِّي أَنْظُرُ إِلَيْهِ حِينَ يُجَلِّسُ بِيَدِهِ ثُمَّ أَقْبَلَ يَشُقُّهُمْ حَتَّى جَاءَ النِّسَاءَ مَعَهُ بِلَالٌ فَقَالَ{ يَا أَيُّهَا النَّبِيُّ إِذَا جَاءَكَ الْمُؤْمِنَاتُ يُبَايِعْنَكَ }الْآيَةَ ثُمَّ قَالَ حِينَ فَرَغَ مِنْهَا آنْتُنَّ عَلَى ذَلِكِ قَالَتْ امْرَأَةٌ وَاحِدَةٌ مِنْهُنَّ لَمْ يُجِبْهُ غَيْرُهَا نَعَمْ لَا يَدْرِي حَسَنٌ مَنْ هِيَ قَالَ فَتَصَدَّقْنَ فَبَسَطَ بِلَالٌ ثَوْبَهُ ثُمَّ قَالَ هَلُمَّ لَكُنَّ فِدَاءٌ أَبِي وَأُمِّي فَيُلْقِينَ الْفَتَخَ وَالْخَوَاتِيمَ فِي ثَوْبِ بِلَالٍقَالَ عَبْدُ الرَّزَّاقِ الْفَتَخُ الْخَوَاتِيمُ الْعِظَامُ كَانَتْ فِي الْجَاهِلِيَّةِ","id":"[Ibnu Juraij] berkata; telah mengabarkan kepadaku [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu 'Abbas] radliallahu 'anhuma, ia berkata, \"Aku pernah menghadiri shalat 'Idul Fitri bersama Nabi shallallahu 'alaihi wasallam, Abu Bakar, 'Umar dan 'Utsman? radliallahu 'anhum. Mereka semua melaksanakan shalat sebelum khutbah, dan menyampaikan khutbah setelah shalat. Nabi shallallahu 'alaihi wasallam kemudian pergi dan aku melihat seakan beliau memberi isyarat dengan tangannya agar jama'ah tetap duduk di tempatnya. Kemudian beliau melewati dan membelah shaf-shaf mereka hingga sampai pada jama'ah para wanita, dan saat itu Bilal juga bersama beliau. Beliau kemudian membaca ayat: '(Hai Nabi, apabila datang kepadamu perempuan-perempuan yang beriman untuk mengadakan janji setia, …) ' (Qs. Al Mumtahanah: 12), selesai membaca ayat tersebut beliau mengatakan: \"Apakah kalian siap untuk itu?\" salah seorang wanita dari mereka -dan tidak ada yang berani menjawab selain dia- berkata, \"Ya.\" -namun Hasan tidak tahu siapa wanita tersebut. Perawi berkata, \"Kemudian mereka bersedekah dan Bilal membentangkan selembar kain, kemudian Bilal berkata, \"Demi bapak dan ibuku, kemarilah! Sungguh, itu akan menjadi tebusan bagi kalian.\" Mereka kemudian melemparkan gelang (besar) dan cincin mereka ke dalam kain yang dibawa oleh Bilal.\" [Abdurrazaq] berkata, \"Al Fatakh adalah cincin besar (gelang) yang bisa mereka pakai pada masa jahiliyah.\""},"927":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ قَالَتْكُنَّا نَمْنَعُ جَوَارِيَنَا أَنْ يَخْرُجْنَ يَوْمَ الْعِيدِ فَجَاءَتْ امْرَأَةٌ فَنَزَلَتْ قَصْرَ بَنِي خَلَفٍ فَأَتَيْتُهَا فَحَدَّثَتْ أَنَّ زَوْجَ أُخْتِهَا غَزَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثِنْتَيْ عَشْرَةَ غَزْوَةً فَكَانَتْ أُخْتُهَا مَعَهُ فِي سِتِّ غَزَوَاتٍ فَقَالَتْ فَكُنَّا نَقُومُ عَلَى الْمَرْضَى وَنُدَاوِي الْكَلْمَى فَقَالَتْ يَا رَسُولَ اللَّهِ أَعَلَى إِحْدَانَا بَأْسٌ إِذَا لَمْ يَكُنْ لَهَا جِلْبَابٌ أَنْ لَا تَخْرُجَ فَقَالَ لِتُلْبِسْهَا صَاحِبَتُهَا مِنْ جِلْبَابِهَا فَلْيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُؤْمِنِينَ قَالَتْ حَفْصَةُ فَلَمَّا قَدِمَتْ أُمُّ عَطِيَّةَ أَتَيْتُهَا فَسَأَلْتُهَا أَسَمِعْتِ فِي كَذَا وَكَذَا قَالَتْ نَعَمْ بِأَبِي وَقَلَّمَا ذَكَرَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا قَالَتْ بِأَبِي قَالَ لِيَخْرُجْ الْعَوَاتِقُ ذَوَاتُ الْخُدُورِ أَوْ قَالَ الْعَوَاتِقُ وَذَوَاتُ الْخُدُورِ شَكَّ أَيُّوبُ وَالْحُيَّضُ وَيَعْتَزِلُ الْحُيَّضُ الْمُصَلَّى وَلْيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُؤْمِنِينَ قَالَتْ فَقُلْتُ لَهَا الْحُيَّضُ قَالَتْ نَعَمْ أَلَيْسَ الْحَائِضُ تَشْهَدُ عَرَفَاتٍ وَتَشْهَدُ كَذَا وَتَشْهَدُ كَذَا","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami [Ayyub] dari [Hafshah binti Sirin] berkata, \"Dahulu kami melarang anak-anak gadis remaja kami keluar untuk ikut melaksanakan shalat di Hari Raya 'Ied. Lalu datanglah seorang wanita ke kampung Bani Khalaf, maka aku pun menemuinya. Lalu ia menceritakan bahwa suami dari saudara perempuannya pernah ikut perang bersama Nabi shallallahu 'alaihi wasallam sebanyak dua belas peperangan, dan saudara perempuannya itu pernah mendampingi suaminya dalam enam kali peperangan.\" Ia (saudara wanitanya itu) berkata, \"Kami merawat orang yang sakit dan mengobati orang-orang yang terluka.\" Saudara perempuanku bertanya kepada Rasulullah, \"Wahai Rasulullah, apakah berdosa bila seorang dari kami tidak keluar karena tidak memiliki jilbab?\" Beliau menjawab: \"Hendaklah temannya meminjamkan jilbabnya, sehingga mereka dapat menyaksikan kebaikan dan mendo'akan Kaum Muslimin.\" Hafshah berkata, \"Ketika [Ummu 'Athiyyah] datang, aku menemuinya dan kutanyakan kepadanya, 'Apakah kamu pernah mendengar tentang ini dan ini? ' Dia menjawab, 'Iya. Demi bapakku'. Dan setiap kali dia menceritakan tentang Nabi shallallahu 'alaihi wasallam, dia selalu mengatakan 'Demi bapakku'. Beliau bersabda: \"Keluarkanlah para gadis remaja yang dipingit dalam rumah.\" Atau beliau bersabda: \"Para gadis remaja dan wanita-wanita yang dipingit dalam rumah -Ayyub masih ragu- dan wanita yang sedang haid. Dan hendaklah wanita yang sedang haid dijauhkan dari tempat shalat, agar mereka dapat menyaksikan kebaikah dan mendo'akan Kaum Muslimin.\" Hafshah berkata, \"Aku bertanya kepadanya, 'Wanita yang sedang haid juga? ' Dia menjawab, 'Bukankah mereka juga hadir di 'Arafah dan menyaksikan ini dan itu? '.\""},"928":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ قَالَتْ أُمُّ عَطِيَّةَأُمِرْنَا أَنْ نَخْرُجَ فَنُخْرِجَ الْحُيَّضَ وَالْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ قَالَ ابْنُ عَوْنٍ أَوْ الْعَوَاتِقَ ذَوَاتِ الْخُدُورِ فَأَمَّا الْحُيَّضُ فَيَشْهَدْنَ جَمَاعَةَ الْمُسْلِمِينَ وَدَعْوَتَهُمْ وَيَعْتَزِلْنَ مُصَلَّاهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dari [Muhammad] berkata, \" [Ummu 'Athiyyah] berkata, \"Kami diperintahkan untuk keluar, maka kami keluarkan pula para wanita yang sedang haid, gadis remaja dan wanita-wanita yang dipingit dalam rumah.\" Ibnu Aun menyebutkan, \"Atau gadis-gadis remaja yang dipingit. Adapun wanita haid, maka mereka dapat menyaksikan (menghadiri) jama'ah kaum Muslimin dan mendo'akan mereka, dan hendaklah mereka menjauhi tempat shalat mereka (kaum laki-laki).\""},"929":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي كَثِيرُ بْنُ فَرْقَدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْحَرُ أَوْ يَذْبَحُ بِالْمُصَلَّى","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku [Katsir bin Farqad] dari [Nafi'] dari [Ibnu 'Umar], bahwa Nabi shallallahu 'alaihi wasallam biasa berkurban atau menyembelih hewan kurban di tempat shalat.\""},"930":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ الْمُعْتَمِرِ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بَعْدَ الصَّلَاةِ فَقَالَ مَنْ صَلَّى صَلَاتَنَا وَنَسَكَ نُسْكَنَا فَقَدْ أَصَابَ النُّسُكَ وَمَنْ نَسَكَ قَبْلَ الصَّلَاةِ فَتِلْكَ شَاةُ لَحْمٍ فَقَامَ أَبُو بُرْدَةَ بْنُ نِيَارٍ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ نَسَكْتُ قَبْلَ أَنْ أَخْرُجَ إِلَى الصَّلَاةِ وَعَرَفْتُ أَنَّ الْيَوْمَ يَوْمُ أَكْلٍ وَشُرْبٍ فَتَعَجَّلْتُ وَأَكَلْتُ وَأَطْعَمْتُ أَهْلِي وَجِيرَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ شَاةُ لَحْمٍ قَالَ فَإِنَّ عِنْدِي عَنَاقَ جَذَعَةٍ هِيَ خَيْرٌ مِنْ شَاتَيْ لَحْمٍ فَهَلْ تَجْزِي عَنِّي قَالَ نَعَمْ وَلَنْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Al Ahwash] berkata, telah menceritakan kepada kami [Manshur bin Al Mutamir] dari [Asy Sya'bi] dari [Al Bara' bin 'Azib] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberikan khutbah pada hari kurban setelah shalat. Beliau katakan: \"Barangsiapa shalat seperti shalat kita dan melaksanakan manasik (penyembelihan kurban) seperti kita berarti telah mendapatkan pahala berkurban. Dan barangsiapa menyembelih kurban sebelum shalat maka itu hanyalah kambing yang dinikmati dagingnya.\" Maka Abu Burdah bin Niyar berdiri dan berkata, \"Wahai Rasulullah, aku telah menyembelih sebelum aku keluar untuk shalat, dan aku mengetahui bahwa hari ini adalah hari makan dan minum, aku lalu menyegerakan penyembelihannya, kemudian aku berikan kepada keluarga dan para tetanggaku.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Itu hanyalah kambing yang dinikmati dagingnya.\" Abu Burdah bertanya lagi, \"Namun aku masih memiliki anak kambing yang lebih baik dari kambing yang telah aku sembelih itu. Apakah dibenarkan kalau aku menyembelihnya?\" Beliau menjawab: \"Ya. Akan tetapi tidak boleh untuk seorangpun setelah kamu.\""},"931":{"ar":"حَدَّثَنَا حَامِدُ بْنُ عُمَرَ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ أَنَّ أَنَسَ بْنَ مَالِكٍ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ النَّحْرِ ثُمَّ خَطَبَ فَأَمَرَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ أَنْ يُعِيدَ ذَبْحَهُ فَقَامَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ جِيرَانٌ لِي إِمَّا قَالَ بِهِمْ خَصَاصَةٌ وَإِمَّا قَالَ بِهِمْ فَقْرٌ وَإِنِّي ذَبَحْتُ قَبْلَ الصَّلَاةِ وَعِنْدِي عَنَاقٌ لِي أَحَبُّ إِلَيَّ مِنْ شَاتَيْ لَحْمٍ فَرَخَّصَ لَهُ فِيهَا","id":"Telah menceritakan kepada kami [Hamid bin 'Umar] dari [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] bahwa [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat hari Raya kurban kemudian menyampaikan khutbah, beliau katakan: \"Barangsiapa menyembelih hewan sebelum shalat, maka dia harus menyembelih ulang.\" Lalu berdirilah seorang laki-laki Anshar seraya berkata, \"Wahai Rasulullah, para tetanggaku!\" Orang itu entah berkata, \"Mereka sangat membutuhkan.\" atau \"Mereka orang-orang miskin. Dan aku telah menyembelih kurban sebelum shalat. Namun aku masih punya anak kambing yang lebih aku cintai dari pada kambing yang telah aku sembelih?\" Maka beliau pun memberikan keringanan untuk orang itu.\""},"932":{"ar":"حَدَّثَنَا مُسْلِمٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَسْوَدِ عَنْ جُنْدَبٍ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ ثُمَّ خَطَبَ ثُمَّ ذَبَحَ فَقَالَ مَنْ ذَبَحَ قَبْلَ أَنْ يُصَلِّيَ فَلْيَذْبَحْ أُخْرَى مَكَانَهَا وَمَنْ لَمْ يَذْبَحْ فَلْيَذْبَحْ بِاسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Muslim] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Aswad] dari [Jundub] berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat Hari Raya kurban lalu menyampaikan khutbah, beliau katakan: \"Barangsiapa menyembelih hewan sebelum shalat maka dia harus menyembelih hewan kurban lain sebagai penggantinya. Dan siapa yang belum menyembelihnya maka sembelihlah atas nama Allah.\""},"933":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ قَالَ أَخْبَرَنَا أَبُو تُمَيْلَةَ يَحْيَى بْنُ وَاضِحٍ عَنْ فُلَيْحِ بْنِ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ عِيدٍ خَالَفَ الطَّرِيقَتَابَعَهُ يُونُسُ بْنُ مُحَمَّدٍ عَنْ فُلَيْحٍ وَقَالَ مُحَمَّدُ بْنُ الصَّلْتِ عَنْ فُلَيْحٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ وَحَدِيثُ جَابِرٍ أَصَحُّ","id":"Telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Salam- berkata, telah mengabarkan kepada kami [Abu Tumailah Yahya bin Wadlih] dari [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits] dari [Jabir bin 'Abdullah] radliallahu 'anhuma, ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam shalat 'Ied, beliau mengambil jalan yang berbeda (antara berangkat dan kembali).\" Hadits ini dikuatkan oleh [Yunus bin Muhammad] dari [Fulaih]. Dan [Muhammad bin Ash Shalt] berkata dari [Fulaih] dari [Sa'id] dari [Abu Hurairah]. Dan hadits Jabir lebih shahih."},"934":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ دَخَلَ عَلَيْهَا وَعِنْدَهَا جَارِيَتَانِ فِي أَيَّامِ مِنَى تُدَفِّفَانِ وَتَضْرِبَانِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَغَشٍّ بِثَوْبِهِ فَانْتَهَرَهُمَا أَبُو بَكْرٍ فَكَشَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ وَجْهِهِ فَقَالَ دَعْهُمَا يَا أَبَا بَكْرٍ فَإِنَّهَا أَيَّامُ عِيدٍ وَتِلْكَ الْأَيَّامُ أَيَّامُ مِنًى وَقَالَتْ عَائِشَةُ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتُرُنِي وَأَنَا أَنْظُرُ إِلَى الْحَبَشَةِ وَهُمْ يَلْعَبُونَ فِي الْمَسْجِدِ فَزَجَرَهُمْ عُمَرُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُمْ أَمْنًا بَنِي أَرْفِدَةَ يَعْنِي مِنْ الْأَمْنِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah], bahwa Abu Bakar? radliallahu 'anhu pernah masuk menemuinya pada hari-hari saat di Mina (Tasyriq). Saat itu ada dua budak yang sedang bermain rebana, sementara Nabi shallallahu 'alaihi wasallam menutupi wajahnya dengan kain. Kemudian Abu Bakar melarang dan menghardik kedua sahaya itu, maka Nabi shallallahu 'alaihi wasallam melepas kain yang menutupi wajahnya seraya bersabda: \"Biarkanlah wahai Abu Bakar. Karena ini adalah Hari Raya 'Ied.\" Hari-hari itu adalah hari-hari Mina (Tasyriq).\" 'Aisyah berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam menutupi aku dengan (badannya) sedangkan aku menyaksikan budak-budak Habasyah yang sedang bermain di dalam masjid. Tiba-tiba 'Umar menghentikan mereka, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Biarkanlah mereka dengan jaminan Bani Arfidah, yaitu keamanan.\""},"935":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمَ الْفِطْرِ فَصَلَّى رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا وَمَعَهُ بِلَالٌ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku ['Adi bin Tsabit] berkata, aku mendengar [Sa'id bin Jubair] dari [Ibnu 'Abbas], bahwa Nabi shallallahu 'alaihi wasallam keluar pada Hari Raya 'Iedul Fitri, beliau melaksanakan shalat dua rakaat, tanpa melaksanakan shalat baik sebelum atau sesudahnya. Dan saat itu beliau bersama Bilal? radliallahu 'anhu.\""},"936":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ وَعَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ رَسُولُ اللَّهِ عَلَيْهِ السَّلَام صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خَشِيَ أَحَدُكُمْ الصُّبْحَ صَلَّى رَكْعَةً وَاحِدَةً تُوتِرُ لَهُ مَا قَدْ صَلَّىوَعَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ كَانَ يُسَلِّمُ بَيْنَ الرَّكْعَةِ وَالرَّكْعَتَيْنِ فِي الْوِتْرِ حَتَّى يَأْمُرَ بِبَعْضِ حَاجَتِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dan ['Abdullah bin Dinar] dari [Ibnu 'Umar], bahwa ada seseorang bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat malam. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua rakaat dua rakaat. Jika salah seorang dari kalian khawatir akan masuk waktu shubuh, hendaklah ia shalat satu rakaat sebagai witir (penutup) bagi shalat yang telah dilaksanakan sebelumnya.\" Dan dari Nafi' bahwa 'Abdullah bin 'Umar memberi salam di antara satu rakaat dan dua rakaat witir hingga dia menuntaskan sebagian keperluannya.\""},"937":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ وَهِيَ خَالَتُهُ فَاضْطَجَعْتُ فِي عَرْضِ وِسَادَةٍ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَرِيبًا مِنْهُ فَاسْتَيْقَظَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ ثُمَّ قَرَأَ عَشْرَ آيَاتٍ مِنْ آلِ عِمْرَانَ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ قَامَ يُصَلِّي فَصَنَعْتُ مِثْلَهُ فَقُمْتُ إِلَى جَنْبهِ فَوَضَعَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي يَفْتِلُهَا ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik bin Anas] dari [Makhramah bin Sulaiman] dari [Kuraib] bahwa [Ibnu 'Abbas] mengabarkan kepadanya, bahwa dia pernah bermalam di rumah Maimunah, bibinya dari pihak ibu. Ia mengatakan, \"Aku tidur pada sisi tikar sedangkan Rasulullah shallallahu 'alaihi wasallam dan isterinya berbaring pada bagian tengahnya. Beliau tidur hingga pertengahan malam atau kurang sedikit, kemudian beliau bangun dan mengusap sisa tidur pada wajahnya, membaca sepuluh ayat dari surah Ali 'Imran. Kemudian beliau berdiri mengambil geriba berisi air yang digantung, beliau berwudlu dengan wudlu yang sempurna lalu mendirikan shalat. Aku kemudian mengerjakan seperti apa yang beliau kerjakan, aku lantas berdiri disampingnya. Beliau kemudian meletakkan tangan kanannya di atas kepalaku, meraih telingaku dan menariknya (menggeser). Kemudian beliau shalat dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu shalat witir. Kemudian Beliau berbaring hingga seorang mu'adzin mendatanginya, kemudian beliau melaksanakan shalat dua rakaat lalu keluar melaksanakan shalat subuh.\""},"938":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا أَرَدْتَ أَنْ تَنْصَرِفَ فَارْكَعْ رَكْعَةً تُوتِرُ لَكَ مَا صَلَّيْتَقَالَ الْقَاسِمُ وَرَأَيْنَا أُنَاسًا مُنْذُ أَدْرَكْنَا يُوتِرُونَ بِثَلَاثٍ وَإِنَّ كُلًّا لَوَاسِعٌ أَرْجُو أَنْ لَا يَكُونَ بِشَيْءٍ مِنْهُ بَأْسٌ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepadaku ['Abdullah bin Wahb] berkata, telah mengabarkan kepadaku ['Amru bin Al Harits] bahwa ['Abdurrahman bin Al Qasim] menceritakan kepadanya dari [Bapaknya] dari ['Abdullah bin 'Umar] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Shalat malam dua rakaat dua rakaat, jika kamu hendak mengakhirinya, maka shalatlah satu rakaat sebagai penutup dari shalatmu sebelumnya.\" Al Qasim berkata, \"Semenjak kami ketahui, kami melihat orang-orang mengerjakan witir dengan tiga rakaat. Sesungguhnya urusan ini adalah kelonggaran yang aku berharap bukan menjadi perkara yang salah.\""},"939":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عُرْوَةُ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي إِحْدَى عَشْرَةَ رَكْعَةً كَانَتْ تِلْكَ صَلَاتَهُ تَعْنِي بِاللَّيْلِ فَيَسْجُدُ السَّجْدَةَ مِنْ ذَلِكَ قَدْرَ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً قَبْلَ أَنْ يَرْفَعَ رَأْسَهُ وَيَرْكَعُ رَكْعَتَيْنِ قَبْلَ صَلَاةِ الْفَجْرِ ثُمَّ يَضْطَجِعُ عَلَى شِقِّهِ الْأَيْمَنِ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُ لِلصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah menceritakan kepadaku ['Urwah] bahwa ['Aisyah] mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat sebelas rakaat, begitulah cara beliau shalat -yakni shalat tahajjut-. Dalam shalat tersebut beliau sujud seperti lamanya kalian membaca sekitar lima puluh ayat sebelum mengangkat kepalanya. Dan beliau mengerjakan shalat dua rakaat sebelum melaksanakan shalat subuh. Kemudian beliau berbaring pada sebelah tubuh sebelah kanan hingga datang mu'adzin (membangunkan) untuk shalat.\""},"940":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ قَالَ قُلْتُ لِابْنِ عُمَرَأَرَأَيْتَ الرَّكْعَتَيْنِ قَبْلَ صَلَاةِ الْغَدَاةِ أُطِيلُ فِيهِمَا الْقِرَاءَةَ فَقَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ مَثْنَى مَثْنَى وَيُوتِرُ بِرَكْعَةٍ وَيُصَلِّي الرَّكْعَتَيْنِ قَبْلَ صَلَاةِ الْغَدَاةِ وَكَأَنَّ الْأَذَانَ بِأُذُنَيْهِ قَالَ حَمَّادٌ أَيْ سُرْعَةً","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Anas bin Sirin] berkata, Aku bertanya kepada [Ibnu 'Umar], \"Apakah shalat dua rakaat sebelum shalat Fajar bacaannya dipanjangkan?\" Maka dia menjawab, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat malam dua rakaat dua rakaat lalu witir dengan satu rakaat, dan beliau mengerjakan shalat dua rakaat sebelum melaksanakan shalat Fajar, seakan adzan ada di sisi telinganya.\" Hammad berkata, \"Maksudnya beliau melaksanakan dua rakaat tersebut dengan cepat.\""},"941":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي مُسْلِمٌ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكُلَّ اللَّيْلِ أَوْتَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْتَهَى وِتْرُهُ إِلَى السَّحَرِ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepadaku [Muslim] dari [Masyruq] dari ['Aisyah] ia berkata, \"Sepanjang malam Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat witir dan berhenti pada waktu sahur.\""},"942":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنِي أَبِي عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا رَاقِدَةٌ مُعْتَرِضَةً عَلَى فِرَاشِهِ فَإِذَا أَرَادَ أَنْ يُوتِرَ أَيْقَظَنِي فَأَوْتَرْتُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah berdiri shalat malam sedangkan aku berbaring membentang di atas tikarnya. Apabila akan melaksanakan shalat witir, beliau membangunkan aku hingga aku pun mengerjakan shalat witir.\""},"943":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْعَلُوا آخِرَ صَلَاتِكُمْ بِاللَّيْلِ وِتْرًا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari ['Abdullah bin 'Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jadikanlah akhir shalat malam dengan ganjil (witir).\""},"944":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي بَكْرِ بْنِ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الخَطَّابِ عَنْ سَعِيدِ بْنِ يَسَارٍ أَنَّهُ قَالَكُنْتُ أَسِيرُ مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ بِطَرِيقِ مَكَّةَ فَقَالَ سَعِيدٌ فَلَمَّا خَشِيتُ الصُّبْحَ نَزَلْتُ فَأَوْتَرْتُ ثُمَّ لَحِقْتُهُ فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ أَيْنَ كُنْتَ فَقُلْتُ خَشِيتُ الصُّبْحَ فَنَزَلْتُ فَأَوْتَرْتُ فَقَالَ عَبْدُ اللَّهِ أَلَيْسَ لَكَ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِسْوَةٌ حَسَنَةٌ فَقُلْتُ بَلَى وَاللَّهِ قَالَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ عَلَى الْبَعِيرِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Abu Bakar bin 'Umar bin 'Abdurrahman bin 'Abdullah bin 'Umar bin Al Khaththab] dari [Sa'd bin Yasar] bahwa dia berkata, \"Aku bersama 'Abdullah bin 'Umar pernah berjalan di jalanan kota Makkah. Sa'id berkata, \"Ketika aku khawatir akan (masuknya waktu) Shubuh, maka aku pun singgah dan melaksanakan shalat witir. Kemudian aku menyusulnya, maka Abdullah bin Umar pun bertanya, \"Dari mana saja kamu?\" Aku menjawab, \"Tadi aku khawatir akan (masuknya waktu) Shubuh, maka aku singgah dan melaksanakan shalat witir.\" ['Abdullah bin 'Umar] berkata, \"Bukankah kamu telah memiliki suri tauladan yang baik pada diri Rasulullah shallallahu 'alaihi wasallam?\" Aku menjawab, \"Ya. Demi Allah.\" Abdullah bin Umar berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah shalat witir di atas untanya.\""},"945":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي السَّفَرِ عَلَى رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ بِهِ يُومِئُ إِيمَاءً صَلَاةَ اللَّيْلِ إِلَّا الْفَرَائِضَ وَيُوتِرُ عَلَى رَاحِلَتِهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Juwairiyyah bin Asma'] dari [Nafi'] dari [Ibnu 'Umar] berkata, \"Jika Nabi shallallahu 'alaihi wasallam dalam perjalanan, maka beliau mengerjakan shalat di atas tunggangannya kemana saja hewan itu menghadap, beliau mengerjakannya dengan isyarat, kecuali shalat fardlu. Dan beliau juga mengerjakan shalat witir di atas kendaraannya.\""},"946":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ سُئِلَ أَنَسُ بْنُ مَالِكٍأَقَنَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصُّبْحِ قَالَ نَعَمْ فَقِيلَ لَهُ أَوَقَنَتَ قَبْلَ الرُّكُوعِ قَالَ بَعْدَ الرُّكُوعِ يَسِيرًا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad bin Sirin] berkata, \" [Anas bin Malik] pernah ditanya, \"Apakah Nabi shallallahu 'alaihi wasallam melakukan qunut dalam shalat Shubuh?\" Dia berkata, \"Ya.\" Lalu dikatakan kepadanya, \"Apakah beliau melakukannya sebelum rukuk?\" Dia menjawab, \"Terkadang setelah rukuk.\""},"947":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَ حَدَّثَنَا عَاصِمٌ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍعَنْ الْقُنُوتِ فَقَالَ قَدْ كَانَ الْقُنُوتُ قُلْتُ قَبْلَ الرُّكُوعِ أَوْ بَعْدَهُ قَالَ قَبْلَهُ قَالَ فَإِنَّ فُلَانًا أَخْبَرَنِي عَنْكَ أَنَّكَ قُلْتَ بَعْدَ الرُّكُوعِ فَقَالَ كَذَبَ إِنَّمَا قَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الرُّكُوعِ شَهْرًا أُرَاهُ كَانَ بَعَثَ قَوْمًا يُقَالُ لَهُمْ الْقُرَّاءُ زُهَاءَ سَبْعِينَ رَجُلًا إِلَى قَوْمٍ مِنْ الْمُشْرِكِينَ دُونَ أُولَئِكَ وَكَانَ بَيْنَهُمْ وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدٌ فَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا يَدْعُو عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami ['Ashim] berkata, \"Aku pernah bertanya [Anas bin Malik] tentang qunut.\" Maka dia menjawab, \"Qunut itu benar adanya.\" Aku bertanya lagi, \"Apakah pelaksanaannya sebelum atau sesudah rukuk?\" Dia menjawab, \"Sebelum rukuK.\" Ashim berkata, \"Ada orang yang mengabarkan kepadaku bahwa engkau mengatakan bahwa pelaksanaannya setelah rukuk?\" Anas bin Malik menjawab, \"Orang itu dusta. Rasulullah shallallahu 'alaihi wasallam pernah melaksanakannya setelah rukuk selama satu bulan. Hal itu Beliau lakukan karena Beliau pernah mengutus sekelompok orang (ahli Al Qur'an) yang berjumlah sekitar tujuh puluh orang kepada Kaum Musyrikin selain mereka. Saat itu antara Rasulullah shallallahu 'alaihi wasallam dan kaum musyrikin ada perjanjian. Kemudian Rasulullah shallallahu 'alaihi wasallam melaksanakan doa qunut selama satu bulan untuk berdoa atas mereka (karena telah membunuh para utusannya).\""},"948":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ التَّيْمِيِّ عَنْ أَبِي مِجْلَزٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَنَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا يَدْعُو عَلَى رِعْلٍ وَذَكْوَانَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Za'idah] dari [At Taimi] dari [Abu Mijlaz] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah melaksanakan qunut selama satu bulan untuk mendo'akan (kebinasaan) atas suku Ri'la dan Dzakwan.\""},"949":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ الْقُنُوتُ فِي الْمَغْرِبِ وَالْفَجْرِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Qunut itu dilakukan pada shalat Maghrib dan Shubuh.\""},"950":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَسْقِي وَحَوَّلَ رِدَاءَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Abu Bakar] dari ['Abbad bin Tamim] dari [Pamannya] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah keluar melaksanakan shalat istisqa' dengan membalik selendangnya.\""},"951":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ الْآخِرَةِ يَقُولُ اللَّهُمَّ أَنْجِ عَيَّاشَ بْنَ أَبِي رَبِيعَةَ اللَّهُمَّ أَنْجِ سَلَمَةَ بْنَ هِشَامٍ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ اللَّهُمَّ أَنْجِ الْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ اللَّهُمَّ اجْعَلْهَا سِنِينَ كَسِنِي يُوسُفَ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غِفَارُ غَفَرَ اللَّهُ لَهَا وَأَسْلَمُ سَالَمَهَا اللَّهُقَالَ ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ هَذَا كُلُّهُ فِي الصُّبْحِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Mughirah bin 'Abdurrahman] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa jika Nabi shallallahu 'alaihi wasallam mengangkat kepalanya dari rukuk yang akhir, beliau membaca: \"ALLAHUMMA ANJI AYYASY IBNA ABII RABI'AH ALLAHUMMA ANJI SALAMAH IBNA HISYAM ALLAHUMMA ANJIL WALIDA IBNAL WALIID ALLAHUMMA ANJIL MUSTADL'AFIINA MINAL MU`MINIINA ALLAHUMMASDUD WATH`ATAKA 'ALAA MUDLAR ALLHUMMALHAA SINIINA YUSUF (Ya Allah selamatkanlah 'Ayyasy bin Abu Rabi'ah, Ya Allah selamatkanlah Salamah bin Hisyam, Ya Allah selamatkanlah Al Walib bin Al Walid, Ya Allah selamatkanlah orang-orang yang lemah dari orang-orang beriman. Ya Allah keraskanlah sikaan-Mu atas suKu Mudlar dan timpakanlah kepada mereka musim paceklik sebagaimana terjadi di zaman Yusuf).\" Nabi shallallahu 'alaihi wasallam juga berdoa: \"Suku Ghifar, semoga Allah mengampuni mereka. Suku Aslam, semoga Allah menyelamatkan mereka.\" [Ibnu Abu Az Zinad] menyebutkan dari [Bapaknya], \"Semua ini dilakukan pada shalat Shubuh.\""},"952":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ كُنَّا عِنْدَ عَبْدِ اللَّهِ فَقَالَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا رَأَى مِنْ النَّاسِ إِدْبَارًا قَالَ اللَّهُمَّ سَبْعٌ كَسَبْعِ يُوسُفَ فَأَخَذَتْهُمْ سَنَةٌ حَصَّتْ كُلَّ شَيْءٍ حَتَّى أَكَلُوا الْجُلُودَ وَالْمَيْتَةَ وَالْجِيَفَ وَيَنْظُرَ أَحَدُهُمْ إِلَى السَّمَاءِ فَيَرَى الدُّخَانَ مِنْ الْجُوعِ فَأَتَاهُ أَبُو سُفْيَانَ فَقَالَ يَا مُحَمَّدُ إِنَّكَ تَأْمُرُ بِطَاعَةِ اللَّهِ وَبِصِلَةِ الرَّحِمِ وَإِنَّ قَوْمَكَ قَدْ هَلَكُوا فَادْعُ اللَّهَ لَهُمْ قَالَ اللَّهُ تَعَالَى{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ }إِلَى قَوْلِهِ{ إِنَّكُمْ عَائِدُونَ يَوْمَ نَبْطِشُ الْبَطْشَةَ الْكُبْرَى إِنَّا مُنْتَقِمُونَ }فَالْبَطْشَةُ يَوْمَ بَدْرٍ وَقَدْ مَضَتْ الدُّخَانُ وَالْبَطْشَةُ وَاللِّزَامُ وَآيَةُ الرُّومِ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Adl Dluha] dari [Masyruq] berkata, \"Kami pernah bersama ['Abdullah] ketika dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda ketika melihat orang-orang berpaling (dari Islam): \"Ya Allah, timpakanlah kepada mereka masa paceklik tujuh tahun seperti kejadian zaman Yusuf.\" Maka terjadilah masa paceklik tersebut dimana tidak ada tunbuhan-tunbuhan yang tumbuh sehingga mereka memakan kulit, bangkai dan barang-barang busuk. Kemudian ada seorang dari mereka yang memandang ke langit melihat awan lantaran lapar. Lalu Abu Sufyan menemui beliau seraya berkata, \"Ya Muhammad, kamu adalah orang yang memerintahkan untuk taat kepada Allah dan menyambung silaturrahim, kaummu telah binasa, maka mintalah kepada Allah untuk mereka.\" Allah lalu berfirman: '(Maka tunggulah hari ketika langit membawa kabut yang nyata) hingga firman-Nya: '(Sesungguhnya kamu akan kembali (ingkar). (Ingatlah) hari (ketika) kami menghantam mereka dengan hantaman yang keras. Sesungguhnya kami adalah pemberi balasan) ' (Qs. Ad Dukhaan: 10-16). Siksaan (hantaman yang keras) adalah saat mereka terbunuh dalam perang Badar. Dan saat awan gelap sudah berlalu.\""},"953":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو قُتَيْبَةَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ ابْنَ عُمَرَيَتَمَثَّلُ بِشِعْرِ أَبِي طَالِبٍ وَأَبْيَضَ يُسْتَسْقَى الْغَمَامُ بِوَجْهِهِثِمَالُ الْيَتَامَى عِصْمَةٌ لِلْأَرَامِلِوَقَالَ عُمَرُ بْنُ حَمْزَةَ حَدَّثَنَا سَالِمٌ عَنْ أَبِيهِ رُبَّمَا ذَكَرْتُ قَوْلَ الشَّاعِرِ وَأَنَا أَنْظُرُ إِلَى وَجْهِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَسْقِي فَمَا يَنْزِلُ حَتَّى يَجِيشَ كُلُّ مِيزَابٍ وَأَبْيَضَ يُسْتَسْقَى الْغَمَامُ بِوَجْهِهِثِمَالُ الْيَتَامَى عِصْمَةٌ لِلْأَرَامِلِوَهُوَ قَوْلُ أَبِي طَالِبٍ","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] berkata, telah menceritakan kepada kami [Abu Qutaibah] berkata, telah menceritakan kepada kami ['Abdurrahman bin 'Abdullah bin Dinar] dari [Bapaknya] berkata, \"Aku mendengar [Ibnu 'Umar] menirukan sya'irnya Abu Thalib, \"#Wajahnya yang putih mengharap turunnya awan (hujan), #sumber kehidupan anak-anak yatim dan pelindung para janda.\" Dan [Umar bin Hamzah] berkata, telah menceritakan kepada kami [Salim] dari [Bapaknya], barangkali aku sebutkan kepadanya perkataan syair -sementara aku lihat wajah Nabi shallallahu 'alaihi wasallam meminta turunnya hujan. Maka beliau belum selesai, setiap aliran air telah penuh dengan air- Wajahnya yang putih mengharap turunnya awan (hujan), #sumber kehidupan anak-anak yatim dan pelindung para janda.\" Itulah perkataan Abu Thalib."},"954":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي عَبْدُ اللَّهِ بْنُ الْمُثَنَّى عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُكَانَ إِذَا قَحَطُوا اسْتَسْقَى بِالْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ فَقَالَ اللَّهُمَّ إِنَّا كُنَّا نَتَوَسَّلُ إِلَيْكَ بِنَبِيِّنَا فَتَسْقِينَا وَإِنَّا نَتَوَسَّلُ إِلَيْكَ بِعَمِّ نَبِيِّنَا فَاسْقِنَا قَالَ فَيُسْقَوْنَ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad] berkata, telah menceritakan kepada kami [Muhammad bin 'Abdullah Al Anshari] berkata, telah menceritakan kepadaku bapakku ['Abdullah bin Al Mutsanna] dari [Tsumamah bin 'Abdullah bin Anas] dari [Anas bin Malik] bahwa ['Umar bin Al Khaththab] radliallahu 'anhu ketika kaum muslimin tertimpa musibah, ia meminta hujan dengan berwasilah kepada 'Abbas bin 'Abdul Muththalib seraya berdo'a, \"Ya Allah, kami meminta hujan kepada-Mu dengan perantaraan Nabi kami, kemudian Engkau menurunkan hujan kepada kami. Maka sekarang kami memohon kepada-Mu dengan perantaraan paman Nabi kami,, maka turunkanlah hujan untuk kami.\" Anas berkata, \"Mereka pun kemudian mendapatkan hujan.\""},"955":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقَى فَقَلَبَ رِدَاءَهُ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Muhammad bin Abu Bakar] dari ['Abbad bin Tamim] dari ['Abdullah bin Zaid], bahwa Nabi shallallahu 'alaihi wasallam pernah berdoa meminta hujan dengan membalik selendangnya.\""},"956":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ أَنَّهُ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ يُحَدِّثُ أَبَاهُ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمُصَلَّى فَاسْتَسْقَى فَاسْتَقْبَلَ الْقِبْلَةَ وَقَلَبَ رِدَاءَهُ وَصَلَّى رَكْعَتَيْنِقَالَ أَبُو عَبْد اللَّهِ كَانَ ابْنُ عُيَيْنَةَ يَقُولُ هُوَ صَاحِبُ الْأَذَانِ وَلَكِنَّهُ وَهْمٌ لِأَنَّ هَذَا عَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ عَاصِمٍ الْمَازِنِيُّ مَازِنُ الْأَنْصَارِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Abu Bakr] bahwa dia mendengar ['Abbad bin Tamim] menceritakan kepada bapaknya dari pamannya ['Abdullah bin Zaid], bahwa Nabi shallallahu 'alaihi wasallam pernah keluar menuju tempat shalat kemudian melaksanakan shalat istisqa' (meminta hujan). Beliau menghadap kiblat dan membalik posisi selendangnya, lalu melaksanakan shalat dua rakaat.\" Abu 'Abdullah berkata, \"Ibnu 'Uyainah berkata, \"Dia adalah seorang mu'adzin tetapi dia ragu, karena orang ini -'Abdullah bin Zaid bin 'Ashim Al mazini- adalah Mazin Al Anshar.\""},"957":{"ar":"حَدَّثَنَا مُحَمَّدٌ قَالَ أَخْبَرَنَا أَبُو ضَمْرَةَ أَنَسُ بْنُ عِيَاضٍ قَالَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍيَذْكُرُ أَنَّ رَجُلًا دَخَلَ يَوْمَ الْجُمُعَةِ مِنْ بَابٍ كَانَ وِجَاهَ الْمِنْبَرِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْمَوَاشِي وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ يُغِيثُنَا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ فَقَالَ اللَّهُمَّ اسْقِنَا اللَّهُمَّ اسْقِنَا اللَّهُمَّ اسْقِنَا قَالَ أَنَسُ وَلَا وَاللَّهِ مَا نَرَى فِي السَّمَاءِ مِنْ سَحَابٍ وَلَا قَزَعَةً وَلَا شَيْئًا وَمَا بَيْنَنَا وَبَيْنَ سَلْعٍ مِنْ بَيْتٍ وَلَا دَارٍ قَالَ فَطَلَعَتْ مِنْ وَرَائِهِ سَحَابَةٌ مِثْلُ التُّرْسِ فَلَمَّا تَوَسَّطَتْ السَّمَاءَ انْتَشَرَتْ ثُمَّ أَمْطَرَتْ قَالَ وَاللَّهِ مَا رَأَيْنَا الشَّمْسَ سِتًّا ثُمَّ دَخَلَ رَجُلٌ مِنْ ذَلِكَ الْبَابِ فِي الْجُمُعَةِ الْمُقْبِلَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَهُ قَائِمًا فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْأَمْوَالُ وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ يُمْسِكْهَا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ ثُمَّ قَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا اللَّهُمَّ عَلَى الْآكَامِ وَالْجِبَالِ وَالْآجَامِ وَالظِّرَابِ وَالْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ قَالَ فَانْقَطَعَتْ وَخَرَجْنَا نَمْشِي فِي الشَّمْسِقَالَ شَرِيكٌ فَسَأَلْتُ أَنَسَ بْنَ مَالِكٍ أَهُوَ الرَّجُلُ الْأَوَّلُ قَالَ لَا أَدْرِي","id":"Telah menceritakan kepada kami [Muhammad] berkata, telah mengabarkan kepada saya [Abu Dlamrah Anas bin 'Iyadl] berkata, telah menceritakan kepada kami [Syarik bin 'Abdullah bin Abu Namir] bahwa dia mendengar [Anas bin Malik] menceritakan, bahwa ada seorang laki-laki masuk ke dalam Masjid pada hari Jum'at dari pintu yang berhadapan dengan mimbar, sedangkan saat itu Rasulullah shallallahu 'alaihi wasallam sedang menyampaikan khutbah. Orang itu kemudian menghadap ke arah Rasulullah shallallahu 'alaihi wasallam serata berkata, \"Wahai Rasulullah, harta benda telah habis dan jalan-jalan terputus. Maka mintalah kepada Allah agar menurunkan hujan buat kami!\" Anas berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya seraya berdoa: \"Ya Allah berilah kami hujan, Ya Allah berilah kami hujan, Ya Allah berilah kami hujan.\" Anas melanjutkan kisahnya, \"Demi Allah, sebelum itu kami tidak melihat sedikitpun awan baik yang tebal maupun yang tipis. Juga tidak ada antara tempat kami dan bukit itu rumah atau bangunan satupun. Tiba-tiba dari bukit itu tampaklah awan bagaikan perisai. Ketika sudah membumbung sampai ke tengah langit, awan itupun menyebar dan hujan pun turun.\" Anas melanjutkan, \"Demi Allah, sungguh kami tidak melihat matahari selama enam hari. Kemudian pada Jum'at berikutnya, orang itu masuk kembali dari pintu yang sama dan Rasulullah shallallahu 'alaihi wasallam sedang berdiri menyampaikan khutbahnya. Kemudian orang itu menghadap beliau seraya berkata, \"Wahai Rasulullah, harta benda telah binasa dan jalan-jalanpun terputus. Maka mintalah kepada Allah agar menahan hujan!\" Anas berkata, \"Rasulullah shallallahu 'alaihi wasallam lantas mengangkat kedua tangannya seraya berdoa: \"Ya Allah turunkanlah hujan di sekitar kami saja dan jangan membahayakan kami. Ya Allah turunkanlah di atas bukit-bukit, gunung-gunung, bendungan air (danau), dataran tinggi, jurang-jurang yang dalam serta pada tempat-tempat tumbuhnya pepohonan.\" Anas berkata, \"Maka hujan berhenti. Kami lalu keluar berjalan-jalan di bawah sinar matahari.\" Syarik berkata, \"Aku bertanya kepada Anas bin Malik, 'Apakah laki-laki itu adalah laki-laki yang pertama? ' Anas menjawab, 'Aku tak tahu'.\""},"958":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ شَرِيكٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ يَوْمَ جُمُعَةٍ مِنْ بَابٍ كَانَ نَحْوَ دَارِ الْقَضَاءِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا ثُمَّ قَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْأَمْوَالُ وَانْقَطَعْتِ السُّبُلُ فَادْعُ اللَّهَ يُغِيثُنَا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ ثُمَّ قَالَ اللَّهُمَّ أَغِثْنَا اللَّهُمَّ أَغِثْنَا اللَّهُمَّ أَغِثْنَا قَالَ أَنَسٌ وَلَا وَاللَّهِ مَا نَرَى فِي السَّمَاءِ مِنْ سَحَابٍ وَلَا قَزَعَةً وَمَا بَيْنَنَا وَبَيْنَ سَلْعٍ مِنْ بَيْتٍ وَلَا دَارٍ قَالَ فَطَلَعَتْ مِنْ وَرَائِهِ سَحَابَةٌ مِثْلُ التُّرْسِ فَلَمَّا تَوَسَّطَتْ السَّمَاءَ انْتَشَرَتْ ثُمَّ أَمْطَرَتْ فَلَا وَاللَّهِ مَا رَأَيْنَا الشَّمْسَ سِتًّا ثُمَّ دَخَلَ رَجُلٌ مِنْ ذَلِكَ الْبَابِ فِي الْجُمُعَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَهُ قَائِمًا فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْأَمْوَالُ وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ يُمْسِكْهَا عَنَّا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ ثُمَّ قَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا اللَّهُمَّ عَلَى الْآكَامِ وَالظِّرَابِ وَبُطُونِ الْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ قَالَ فَأَقْلَعَتْ وَخَرَجْنَا نَمْشِي فِي الشَّمْسِقَالَ شَرِيكٌ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ أَهُوَ الرَّجُلُ الْأَوَّلُ فَقَالَ مَا أَدْرِي","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Syarik] dari [Anas bin Malik] bahwa ada seorang memasuki masjid pada hari Jum'at dari pintu yang menghadap Darul Qadla' (rumah 'Umar bin Al Khaththab). Saat itu Rasulullah shallallahu 'alaihi wasallam sedang berdiri menyampaikan khutbah, orang itu lalu berdiri menghadap Rasulullah seraya berkata, \"Wahai Rasulullah, harta benda telah habis dan jalan-jalan terputus. Maka mintalah kepada Allah agar menurunkan hujan buat kami!\" Anas bin Malik berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya seraya berdoa: \"Ya Allah berilah kami hujan, Ya Allah berilah kami hujan, Ya Allah berilah kami hujan.\" Anas bin Malik melanjutkan, \"Demi Allah, sebelum itu kami tidak melihat sedikitpun awan baik yang tebal maupun yang tipis. Juga tidak ada antara tempat kami dan bukit itu rumah atau bangunan satupun. Tiba-tiba dari bukit itu tampaklah awan bagaikan perisai. Ketika sudah membumbung sampai ke tengah langit, awan itupun menyebar lalu turunlah hujan.\" Anas bin Malik berkata, \"Demi Allah, sungguh kami tidak melihat matahari selama enam hari. Kemudian pada Jum'at berikutnya, ada seorang laki-laki masuk kembali dari pintu yang sama sementara Rasulullah shallallahu 'alaihi wasallam sedang beridiri menyampaikan khutbahnya. Orang itu lalu berdiri menghadap beliau seraya berkata, \"Wahai Rasulullah, harta benda telah binasa dan jalan-jalan pun terputus. Maka mintalah kepada Allah agar menahan hujan dari kami!\" Maka Rasulullah shallallahu 'alaihi wasallam pun mengangkat kedua tangannya seraya berdoa: \"Ya Allah turunkanlah hujan di sekitar kami saja dan jangan membahayakan kami. Ya Allah turunkanlah di atas bukit-bukit, dataran tinggi, jurang-jurang yang dalam serta pada tempat-tempat tumbuhnya pepohonan.\" Anas bin Malik berkata, \"Maka hujan pun berhenti. Lalu kami keluar berjalan-jalan di bawah sinar matahari.\" Syarik berkata, \"Aku bertanya kepada Anas bin Malik, 'Apakah laki-laki tadi juga laki-laki yang pertama? ' Dia menjawab, 'Aku tak tahu'.\""},"959":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ جَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ قَحَطَ الْمَطَرُ فَادْعُ اللَّهَ أَنْ يَسْقِيَنَا فَدَعَا فَمُطِرْنَا فَمَا كِدْنَا أَنْ نَصِلَ إِلَى مَنَازِلِنَا فَمَا زِلْنَا نُمْطَرُ إِلَى الْجُمُعَةِ الْمُقْبِلَةِ قَالَ فَقَامَ ذَلِكَ الرَّجُلُ أَوْ غَيْرُهُ فَقَالَ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَصْرِفَهُ عَنَّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا قَالَ فَلَقَدْ رَأَيْتُ السَّحَابَ يَتَقَطَّعُ يَمِينًا وَشِمَالًا يُمْطَرُونَ وَلَا يُمْطَرُ أَهْلُ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas bin Malik] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang berkhutbah pada hari Jum'at, tiba-tiba ada seorang laki-laki mendatangi beliau seraya berkata, \"Wahai Rasulullah, hujan sudah lama tidak turun, berdo'alah kepada Allah agar menurunkan hujan buat kita.\" Maka beliau pun berdoa hingga hujan pun turun, dan hampir-hampir kami tidak bisa pulang ke rumah kami. Dan hujan terus turun hingga hari Jum'at berikutnya.\" Anas bin Malik berkata, \"Laki-laki itu atau lelaki lain berdiri lalu berkata, \"Wahai Rasulullah, berdo'alah kepada Allah agar hujan segera dialihkan dari kami.\" Maka Rasulullah shallallahu 'alaihi wasallam berdoa: \"Ya Allah turunkanlah hujan di sekitar kami saja dan jangan membahyakan kami.\" Anas bin Malik berkata, \"Sungguh aku melihat awan berpencar ke kanan dan kiri, lalu hujan turun namun tidak menghujani penduduk Madinah.\""},"960":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَكَتْ الْمَوَاشِي وَتَقَطَّعَتْ السُّبُلُ فَدَعَا فَمُطِرْنَا مِنْ الْجُمُعَةِ إِلَى الْجُمُعَةِ ثُمَّ جَاءَ فَقَالَ تَهَدَّمَتْ الْبُيُوتُ وَتَقَطَّعَتْ السُّبُلُ وَهَلَكَتْ الْمَوَاشِي فَادْعُ اللَّهَ يُمْسِكْهَا فَقَامَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اللَّهُمَّ عَلَى الْآكَامِ وَالظِّرَابِ وَالْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ فَانْجَابَتْ عَنْ الْمَدِينَةِ انْجِيَابَ الثَّوْبِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Syarik bin 'Abdullah] dari [Anas bin Malik] berkata, \"Ada seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata, \"Harta benda telah rusak dan jalan-jalan terputus, maka mintalah kepada Allah agar menurunkan air hujan.\" Maka beliau pun berdo' hingga turun hujan kepada kami dari hari Jum'at ke Jum'at berikutnya. Laki-laki itu kemudian datang lagi seraya berkata, \"Rumah-rumah telah roboh, jalan-jalan terputus dan harta benda rusak. Maka berdo'alah kepada Allah agar menahan hujan.\" Beliau kemudian berdiri dan berdoa: \"Ya Allah turunkanlah di atas bukit-bukit, dataran tinggi, jurang-jurang yang dalam serta pada tempat-tempat tumbuhnya pepohonan.\" Maka awan pun menjauh dari Madinah seperti kain.\""},"961":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْمَوَاشِي وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمُطِرُوا مِنْ جُمُعَةٍ إِلَى جُمُعَةٍ فَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تَهَدَّمَتْ الْبُيُوتُ وَتَقَطَّعَتْ السُّبُلُ وَهَلَكَتْ الْمَوَاشِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ عَلَى رُءُوسِ الْجِبَالِ وَالْآكَامِ وَبُطُونِ الْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ فَانْجَابَتْ عَنْ الْمَدِينَةِ انْجِيَابَ الثَّوْبِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Syarik bin 'Abdullah bin Abu Namir] dari [Anas bin Malik] berkata, \"Seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata, \"Wahai Rasulullah, harta benda telah rusak dan jalan-jalan terputus, maka berdo'alah kepada Allah.\" Rasulullah shallallahu 'alaihi wasallam lalu berdoa hingga hujan pun turun kepada kami dari hari Jum'at ke Jum'at berikutnya. Kemudian datang lagi seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, rumah-rumah telah roboh, jalan-jalan terputus dan harta benda rusak!\" Maka Rasulullah shallallahu 'alaihi wasallam pun berdoa: \"Ya Allah turunkanlah di puncak-puncak gunung, perbukitan, jurang-jurang yang dalam serta tempat-tempat tumbuhnya pepohonan.\" Maka awan itu pun menjauh dari Madinah seperti kain.\""},"962":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا مُعَافَى بْنُ عِمْرَانَ عَنْ الْأَوْزَاعِيِّ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا شَكَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلَاكَ الْمَالِ وَجَهْدَ الْعِيَالِ فَدَعَا اللَّهَ يَسْتَسْقِيوَلَمْ يَذْكُرْ أَنَّهُ حَوَّلَ رِدَاءَهُ وَلَا اسْتَقْبَلَ الْقِبْلَةَ","id":"Telah menceritakan kepada kami [Al Hasan bin Bisyr] berkata, telah menceritakan kepada kami [Mu'afa bin 'Imran] dari [Al Auza'i] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas bin Malik], bahwa ada seorang laki-laki mengadu kepada Nabi shallallahu 'alaihi wasallam, \"Harta benda telah binasa dan sanak keluarga sudah kesusahan!\" Kemudian beliau berdoa kepada Allah meminta hujan.\" Namun Anas tidak menyebutkan bahwa beliau membalik selendang dan menghadap kiblat.\""},"963":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْمَوَاشِي وَتَقَطَّعَتْ السُّبُلُ فَادْعُ اللَّهَ فَدَعَا اللَّهَ فَمُطِرْنَا مِنْ الْجُمُعَةِ إِلَى الْجُمُعَةِ فَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تَهَدَّمَتْ الْبُيُوتُ وَتَقَطَّعَتْ السُّبُلُ وَهَلَكَتْ الْمَوَاشِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ عَلَى ظُهُورِ الْجِبَالِ وَالْآكَامِ وَبُطُونِ الْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ فَانْجَابَتْ عَنْ الْمَدِينَةِ انْجِيَابَ الثَّوْبِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Syarik bin 'Abdullah bin Abu Namir] dari [Anas bin Malik] bahwa dia berkata, \"Seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata, \"Wahai Rasulullah, harta benda telah rusak dan jalan-jalan terputus, maka berdo'alah kepada Allah!\" Beliau lalu berdoa sehingga hujan pun turun kepada kami dari hari Jum'at ke Jum'at berikutnya. Kemudian datang lagi seseorang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, rumah-rumah telah roboh, jalan-jalan terputus dan harta benda menjadi rusak!\" Maka Rasulullah shallallahu 'alaihi wasallam berdoa: \"Ya Allah turunkanlah di puncak-puncak gunung, perbukitan, jurang-jurang yang dalam dan tempat-tempat tumbuhnya pepohonan.\" Maka awan menjauh dari Madinah seperti kain.\""},"964":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُفْيَانَ حَدَّثَنَا مَنْصُورٌ وَالْأَعْمَشُ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ أَتَيْتُ ابْنَ مَسْعُودٍ فَقَالَإِنَّ قُرَيْشًا أَبْطَئُوا عَنْ الْإِسْلَامِ فَدَعَا عَلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَتْهُمْ سَنَةٌ حَتَّى هَلَكُوا فِيهَا وَأَكَلُوا الْمَيْتَةَ وَالْعِظَامَ فَجَاءَهُ أَبُو سُفْيَانَ فَقَالَ يَا مُحَمَّدُ جِئْتَ تَأْمُرُ بِصِلَةِ الرَّحِمِ وَإِنَّ قَوْمَكَ هَلَكُوا فَادْعُ اللَّهَ فَقَرَأَ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ }ثُمَّ عَادُوا إِلَى كُفْرِهِمْ فَذَلِكَ قَوْلُهُ تَعَالَى{ يَوْمَ نَبْطِشُ الْبَطْشَةَ الْكُبْرَى إِنَّا مُنْتَقِمُونَ }يَوْمَ بَدْرٍقَالَ أَبُو عَبْد اللَّهِ وَزَادَ أَسْبَاطٌ عَنْ مَنْصُورٍ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسُقُوا الْغَيْثَ فَأَطْبَقَتْ عَلَيْهِمْ سَبْعًا وَشَكَا النَّاسُ كَثْرَةَ الْمَطَرِ قَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا فَانْحَدَرَتْ السَّحَابَةُ عَنْ رَأْسِهِ فَسُقُوا النَّاسُ حَوْلَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Sufyan] telah menceritakan kepada kami [Manshur] dan [Al A'masy] dari [Abu Adl Dluha] dari [Masyruq] berkata, \"Aku pernah menemui [Ibnu Mas'ud], lalu ia berkata, \"Orang-orang Quraisy telah berpaling dari (menolak) Islam, lalu Nabi shallallahu 'alaihi wasallam berdoa agar mereka terkena adzab. Maka terjadilah masa paceklik dimana tidak ada tumbuhan-tumbuhan yang hidup sehingga mereka memakan kulit, bangkai dan barang-barang yang telah busuk. Kemudian datang Abu Sufyan kepada beliau seraya berkata, \"Ya Muhammad, kamu telah datang untuk memerintahkan orang agar menyambung silaturrahim, sekarang kaummu telah binasa. Maka mintalah kepada Allah!\" Beliau kemudian membaca ayat: '(Maka tunggulah hari ketika langit membawa kabut yang nyata) ' (Qs. Adl Dlukhaan: 10). Namun kemudian mereka kembali kepada kekafiran mereka. Maka terjadilah seperti dalam firman-Nya: '(Ingatlah) hari (ketika) kami menghantam mereka dengan hantaman yang keras. Sesungguhnya kami adalah pemberi balasan) ' (Qs. Adl Dlukhaan: 16). Yakni pada saat perang Badar.\" Abu 'Abdullah berkata; [Asbath] menambahkan dari [Manshur], \"Maka Rasulullah shallallahu 'alaihi wasallam berdoa hingga mereka mendapatkan air hujan, dan hujan tersebut menyelimuti mereka selama tujuh hari. Kemudian orang-orang mengeluh karena hujan yang lebat terus menerus. Beliau kemudian berdoa: \"Ya Allah turunkanlah hujan di sekitar kami saja dan jangan membahyakan kami.\" Maka awan pun menyingkir dari atas kepala beliau, lalu orang-orang mendapatkan air dari sekeliling mereka.\""},"965":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ جُمُعَةٍ فَقَامَ النَّاسُ فَصَاحُوا فَقَالُوا يَا رَسُولَ اللَّهِ قَحَطَ الْمَطَرُ وَاحْمَرَّتْ الشَّجَرُ وَهَلَكَتْ الْبَهَائِمُ فَادْعُ اللَّهَ يَسْقِينَا فَقَالَ اللَّهُمَّ اسْقِنَا مَرَّتَيْنِ وَايْمُ اللَّهِ مَا نَرَى فِي السَّمَاءِ قَزَعَةً مِنْ سَحَابٍ فَنَشَأَتْ سَحَابَةٌ وَأَمْطَرَتْ وَنَزَلَ عَنْ الْمِنْبَرِ فَصَلَّى فَلَمَّا انْصَرَفَ لَمْ تَزَلْ تُمْطِرُ إِلَى الْجُمُعَةِ الَّتِي تَلِيهَا فَلَمَّا قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ صَاحُوا إِلَيْهِ تَهَدَّمَتْ الْبُيُوتُ وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ يَحْبِسْهَا عَنَّا فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا فَكَشَطَتْ الْمَدِينَةُ فَجَعَلَتْ تَمْطُرُ حَوْلَهَا وَلَا تَمْطُرُ بِالْمَدِينَةِ قَطْرَةٌ فَنَظَرْتُ إِلَى الْمَدِينَةِ وَإِنَّهَا لَفِي مِثْلِ الْإِكْلِيلِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar] telah menceritakan kepada kami [Mu'tamir] dari ['Ubaidullah] dari [Tsabit] dari [Anas bin Malik] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam berkhutbah pada hari Jum'at, lalu orang-orang berdiri dan berseru, \"Wahai Rasulullah, hujan sudah tidak turun hingga pepohonan memerah dan hewan-hewan banyak yang mati. Maka mintalah kepada Allah agar menurunkan hujan buat kami!\" Beliau lalu berdoa: \"Ya Allah, berilah kami air hujan.\" dua kali. Demi Allah, sebelumnya kami tidak melihat ada awan yang tipis sekalipun hingga muncul awan tebal, kemudian hujan pun turun. Setelah itu beliau turun dari mimbar dan melaksanakan shalat. Setelah selesai, hujan masih terus turun bahkan hingga Jum'at berikutnya. Maka ketika Nabi shallallahu 'alaihi wasallam berdiri menyampaikan khutbah, orang-orang kembali berseru kepada beliau: \"Rumah-rumah telah hancur, jalan-jalan terputus, berdo'alah kepada Allah agar menahan hujan dari kami!\" Nabi shallallahu 'alaihi wasallam lalu tersenyum seraya berdoa: \"Ya Allah turunkanlah hujan di sekitar kami saja dan jangan membahayakan kami.\" Maka Madinah menjadi terang kembali dan hujan hanya turun di sekitarnya, bahkan tidak ada hujan setetespun di Madinah. Kemudian aku melihat langit Madinah, dan nampak hujan hanya turun disekitarnya.\""},"966":{"ar":"وَقَالَ لَنَا أَبُو نُعَيْمٍ عَنْ زُهَيْرٍ عَنْ أَبِي إِسْحَاقَ خَرَجَ عَبْدُ اللَّهِ بْنُ يَزِيدَ الْأَنْصَارِيُّوَخَرَجَ مَعَهُ الْبَرَاءُ بْنُ عَازِبٍ وَزَيْدُ بْنُ أَرْقَمَ رَضِيَ اللَّهُ عَنْهُمْ فَاسْتَسْقَى فَقَامَ بِهِمْ عَلَى رِجْلَيْهِ عَلَى غَيْرِ مِنْبَرٍ فَاسْتَغْفَرَ ثُمَّ صَلَّى رَكْعَتَيْنِ يَجْهَرُ بِالْقِرَاءَةِ وَلَمْ يُؤَذِّنْ وَلَمْ يُقِمْقَالَ أَبُو إِسْحَاقَ وَرَأَى عَبْدُ اللَّهِ بْنُ يَزِيدَ الْأَنْصَارِيُّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah berbicara kepada kami [Abu Nu'aim] dari [Zuhair] dari [Abu Ishaq], ['Abdullah bin Yazid Al Anshari] keluar menuju lapangan bersama Al Bara' bin 'Azib dan Zaid bin Arqam? radliallahu 'anhum untuk melaksanakan shalat istisqa' (minta hujan). 'Abdullah bin Yazid Al Anshari lalu berdiri di atas kedua kakinya dan tidak di atas mimbar. Dia lalu beristighfar dan melaksanakan shalat dua rakaat dengan mengeraskan bacaannya, tanpa dengan adzan atau pun iqamah.\" Abu Ishaq berkata, \"'Abdullah bin Yazid Al Anshari pernah melihat Nabi shallallahu 'alaihi wasallam (melaksanakan seperti itu).\""},"967":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَبَّادُ بْنُ تَمِيمٍ أَنَّ عَمَّهُ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ بِالنَّاسِ يَسْتَسْقِي لَهُمْ فَقَامَ فَدَعَا اللَّهَ قَائِمًا ثُمَّ تَوَجَّهَ قِبَلَ الْقِبْلَةِ وَحَوَّلَ رِدَاءَهُ فَأُسْقُوا","id":"Telah berbicara kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah menceritakan kepadaku ['Abbad bin Tamim] bahwa [Pamannya] -salah seorang sahabat Nabi shallallahu 'alaihi wasallam- mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pernah keluar bersama manusia (melaksanakan shalat istisqa') memintakan hujan untuk mereka. Beliau kemudian berdiri menghadap kiblat dan berdoa dalam keadaan berdiri sambil membalikkan kain selendangnya. Setelah itu mereka pun mendapatkan hujan.\""},"968":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَسْقِي فَتَوَجَّهَ إِلَى الْقِبْلَةِ يَدْعُو وَحَوَّلَ رِدَاءَهُ ثُمَّ صَلَّى رَكْعَتَيْنِ جَهَرَ فِيهِمَا بِالْقِرَاءَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [Pamannya] berkata, \"Nabi shallallahu 'alaihi wasallam pernah keluar untuk melaksanakan shalat istisqa', beliau lalu berdoa dengan menghadap ke arah kiblat sambil membalikkan kain selendangnya. Kemudian beliau melaksanakan shalat dua rakaat dengan mengeraskan bacaannya pada kedua rakaat itu.\""},"969":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَرَجَ يَسْتَسْقِي قَالَ فَحَوَّلَ إِلَى النَّاسِ ظَهْرَهُ وَاسْتَقْبَلَ الْقِبْلَةَ يَدْعُو ثُمَّ حَوَّلَ رِدَاءَهُ ثُمَّ صَلَّى لَنَا رَكْعَتَيْنِ جَهَرَ فِيهِمَا بِالْقِرَاءَةِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [Pamannya] berkata, \"Aku pernah melihat Nabi shallallahu 'alaihi wasallam di hari saat beliau keluar minta turunnya hujan. Beliau kemudian menghadap ke arah kiblat dengan menghadapkan punggungnya ke arah manusia, beliau lalu berdoa sambil membalikkan kain selendangnya. Setelah itu beliau mengimami kami shalat dua rakaat dengan mengeraskan bacaan.\""},"970":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ عَنْ عَمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقَى فَصَلَّى رَكْعَتَيْنِ وَقَلَبَ رِدَاءَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Abu Bakar] bahwa dia mendengar ['Abbad bin Tamim] dari [Pamannya], bahwa Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat istisqa' (meminta hujan). Beliau lalu melakanakan shalat dua rakaat dan membalik selendangnya.\""},"971":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ عَنْ عَمِّهِ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُصَلَّى يَسْتَسْقِي وَاسْتَقْبَلَ الْقِبْلَةَ فَصَلَّى رَكْعَتَيْنِ وَقَلَبَ رِدَاءَهُقَالَ سُفْيَانُ فَأَخْبَرَنِي المَسْعُودِيُّ عَنْ أَبِي بَكْرٍ قَالَ جَعَلَ الْيَمِينَ عَلَى الشِّمَالِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Abu Bakar] bahwa dia mendengar ['Abbad bin Tamim] dari [Pamannya] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah keluar untuk melaksanakan shalat istisqa' (meminta hujan). Beliau lalu menghadap kiblat dan melakanakan shalat dua rakaat sambil membalik selendangnya.\" [Sufyan] berkata; telah mengabarkan kepadaku [Al Mas'udi] dari [Abu Bakar] berkata, \"Maksudnya selendangnya dipindah dari posisi pundak kanan ke pundak kiri.\""},"972":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ مُحَمَّدٍ أَنَّ عَبَّادَ بْنَ تَمِيمٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ الْأَنْصَارِيَّ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمُصَلَّى يُصَلِّي وَأَنَّهُ لَمَّا دَعَا أَوْ أَرَادَ أَنْ يَدْعُوَ اسْتَقْبَلَ الْقِبْلَةَ وَحَوَّلَ رِدَاءَهُقَالَ أَبُو عَبْد اللَّهِ عَبْدُ اللَّهِ بْنُ زَيْدٍ هَذَا مَازِنِيٌّ وَالْأَوَّلُ كُوفِيٌّ هُوَ ابْنُ يَزِيدَ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami ['Abdul Wahhab] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah mengabarkan kepadaku [Abu Bakar bin Muhammad] bahwa ['Abbad bin Tamim] mengabarkan kepadanya bahwa ['Abdullah bin Zaid Al Anshari] mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pernah keluar menuju tempat shalat untuk melaksanakan shalat (istisqa'). Ketika beliau berdoa, atau akan berdoa, beliau menghadap ke arah kiblat dan membalik selendangnya.\" Abu 'Abdullah berkata, \"'Abdullah bin Zaid ini adalah dari suku Al Maazini. Sedangkan yang pertama (rawi pada hadits ke 966) adalah dari Kufah, yaitu Ibnu Yazid.\""},"973":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى وَابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ دُعَائِهِ إِلَّا فِي الِاسْتِسْقَاءِ وَإِنَّهُ يَرْفَعُ حَتَّى يُر��ى بَيَاضُ إِبْطَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya] dan [Ibnu Abi 'Adi] dari [Sa'id] dari [Qatadah] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam tidak pernah mengangkat tangannya saat berdoa kecuali ketika berdoa dalam shalat istisqa'. Beliau mengangkat tangannya hingga terlihat putih kedua ketiaknya.\""},"974":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ مُقَاتِلٍ أَبُو الْحَسَنِ الْمَرْوَزِيُّ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَأَى الْمَطَرَ قَالَ اللَّهُمَّ صَيِّبًا نَافِعًاتَابَعَهُ الْقَاسِمُ بْنُ يَحْيَى عَنْ عُبَيْدِ اللَّهِ وَرَوَاهُ الْأَوْزَاعِيُّ وَعُقَيْلٌ عَنْ نَافِعٍ","id":"Telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Muqatil Abu Al Hasan Al Marwazi- berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami ['Ubaidullah] dari [Nafi'] dari [Al Qasim bin Muhammad] dari ['Aisyah], bahwa jika Rasulullah shallallahu 'alaihi wasallam melihat hujan, maka beliau berdoa: 'ALLAHUMMA SHAYYIBAA NAAFI'AA (Ya Allah, jadikanlah hujan ini bermanfaat) '.\" Hadits ini juga dikuatkan oleh [Al Qasim bin Yahya] dari ['Ubaidullah], dan diriwayatkan pula oleh [Al Auza'i] dan ['Uqail] dari [Nafi'].\""},"975":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَخْبَرَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا إِسْحَاقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ قَالَأَصَابَتْ النَّاسَ سَنَةٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ قَامَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَ الْمَالُ وَجَاعَ الْعِيَالُ فَادْعُ اللَّهَ لَنَا أَنْ يَسْقِيَنَا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ وَمَا فِي السَّمَاءِ قَزَعَةٌ قَالَ فَثَارَ سَحَابٌ أَمْثَالُ الْجِبَالِ ثُمَّ لَمْ يَنْزِلْ عَنْ مِنْبَرِهِ حَتَّى رَأَيْتُ الْمَطَرَ يَتَحَادَرُ عَلَى لِحْيَتِهِ قَالَ فَمُطِرْنَا يَوْمَنَا ذَلِكَ وَفِي الْغَدِ وَمِنْ بَعْدِ الْغَدِ وَالَّذِي يَلِيهِ إِلَى الْجُمُعَةِ الْأُخْرَى فَقَامَ ذَلِكَ الْأَعْرَابِيُّ أَوْ رَجُلٌ غَيْرُهُ فَقَالَ يَا رَسُولَ اللَّهِ تَهَدَّمَ الْبِنَاءُ وَغَرِقَ الْمَالُ فَادْعُ اللَّهَ لَنَا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ وَقَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا قَالَ فَمَا جَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشِيرُ بِيَدِهِ إِلَى نَاحِيَةٍ مِنْ السَّمَاءِ إِلَّا تَفَرَّجَتْ حَتَّى صَارَتْ الْمَدِينَةُ فِي مِثْلِ الْجَوْبَةِ حَتَّى سَالَ الْوَادِي وَادِي قَنَاةَ شَهْرًا قَالَ فَلَمْ يَجِئْ أَحَدٌ مِنْ نَاحِيَةٍ إِلَّا حَدَّثَ بِالْجَوْدِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] berkata, telah mengabarkan kepada kami ['Abdullah bin Al Mubarak] berkata, telah mengabarkan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Ishaq bin 'Abdullah bin Abu Thalhah Al Anshari] berkata, telah menceritakan kepadaku [Anas bin Malik] berkata, \"Di zaman Rasulullah shallallahu 'alaihi wasallam manusia pernah terkena musibah paceklik kekeringan. Pada hari Jum'at ketika Nabi shallallahu 'alaihi wasallam sedang memberikan khutbah, tiba-tiba seorang Arab badui berdiri dan berkata, \"Wahai Rasulullah, harta benda telah binasa dan telah terjadi kelaparan, maka berdo'alah kepada Allah agar menurunkan hujan untuk kita!\" Anas bin Malik berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam lalu berdoa dengan mengangkat kedua telapak tangannya. Dan saat itu tidak sedikitpun ada awan di langit.\" Anas bin Malik melanjutkan perkataannya, \"Maka awan seperti gunung bergerak. Beliau belum lagi turun dari mimbarnya hingga aku melihat air hujan membasahi jenggotnya. Maka pada hari itu kami mendapatkan hujan hingga esok harinya dan lusa, hingga hari Jum'at berikutnya. Pada hari Jum'at berikut itulah orang Arab badui tersebut, atau orang yang lain berdiri dan berkata, \"Wahai Rasulullah, banyak bangunan yang roboh, harta benda tenggelam dan hanyut, maka berdo'alah kepada Allah untuk kami!\" Rasulullah shallallahu 'alaihi wasallam lalu berdoa dengan mengangkat kedua telapak tangannya: 'ALLAHUMMA HAWAALAINAA WA LAA 'ALAINAA (Ya Allah, turunkanlah hujan di sekeling kami saja dan jangan sampai menimbulkan kerusakan kepada kami) '. Belum lagi beliau memberikan isyarat dengan tangannya ke langit, awan tersebut telah hilang. Saat itu kota Madinah menjadi seperti danau dan aliran-aliran air, bahkan tidak mendapatkan sinar matahari selama satu bulan.\" Anas bin Malik berkata, \"Tidak ada satupun orang yang datang dari segala pelosok kota kecuali akan menceritakan tentang terjadinya hujan yang lebat tersebut.\""},"976":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي حُمَيْدٌ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَتْ الرِّيحُ الشَّدِيدَةُ إِذَا هَبَّتْ عُرِفَ ذَلِكَ فِي وَجْهِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata, telah mengabarkan kepadaku [Humaid] bahwa dia mendengar [Anas bin Malik] berkata, \"Jika akan terjadi angin yang berhembus kencang, maka hal itu dapat diketahui pada wajah Nabi shallallahu 'alaihi wasallam.\""},"977":{"ar":"حَدَّثَنَا مُسْلِمٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نُصِرْتُ بِالصَّبَا وَأُهْلِكَتْ عَادٌ بِالدَّبُورِ","id":"Telah menceritakan kepada kami [Muslim] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ibnu 'Abbas], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Aku ditolong dengan perantaraan angin yang berhembus dari timur (belakang pintu Ka'bah) sedangkan kaum 'Aad dibinasakan dengan angin yang berhembus dari barat.\""},"978":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ قَالَ أَخْبَرَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يُقْبَضَ الْعِلْمُ وَتَكْثُرَ الزَّلَازِلُ وَيَتَقَارَبَ الزَّمَانُ وَتَظْهَرَ الْفِتَنُ وَيَكْثُرَ الْهَرْجُ وَهُوَ الْقَتْلُ الْقَتْلُ حَتَّى يَكْثُرَ فِيكُمْ الْمَالُ فَيَفِيضَ","id":"telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] berkata, telah mengabarkan kepada kami [Abu Az Zinad] dari ['Abdurrahman Al A'raj] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari kiamat kecuali setelah hilangnya ilmu, banyak terjadi gempa, waktu seakan berjalan dengan cepat, timbul berbagai macam fitnah, Al haraj -yaitu pembunuhan- dan harta melimpah ruah kepada kalian.\""},"979":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا حُسَيْنُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَاللَّهُمَّ بَارِكْ لَنَا فِي شَامِنَا وَفِي يَمَنِنَا قَالَ قَالُوا وَفِي نَجْدِنَا قَالَ قَالَ اللَّهُمَّ بَارِكْ لَنَا فِي شَامِنَا وَفِي يَمَنِنَا قَالَ قَالُوا وَفِي نَجْدِنَا قَالَ قَالَ هُنَاكَ الزَّلَازِلُ وَالْفِتَنُ وَبِهَا يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Husain bin Al Hasan] berkata, telah menceritakan kepada kami [Ibnu 'Aun] dari [Nafi'] dari [Ibnu 'Umar] berkata, \"Beliau berdoa: \"Ya Allah, berkatilah kami pada negeri Syam kami dan negeri Yaman kami.\" Ibnu 'Umar berkata, \"Para sahabat berkata, \"Juga untuk negeri Najed kami.\" Beliau kembali berdoa: \"Ya Allah, berkatilah kami pada negeri Syam kami dan negeri Yaman kami.\" Para sahabat berkata lagi, \"Juga untuk negeri Najed kami.\" Ibnu 'Umar berkata, \"Beliau lalu berdoa: \"Disanalah akan terjadi bencana dan fitnah, dan di sana akan muncul tanduk setan.\""},"980":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ بِالْحُدَيْبِيَةِ عَلَى إِثْرِ سَمَاءٍ كَانَتْ مِنْ اللَّيْلَةِ فَلَمَّا انْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ هَلْ تَدْرُونَ مَاذَا قَالَ رَبُّكُمْ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَصْبَحَ مِنْ عِبَادِي مُؤْمِنٌ بِي وَكَافِرٌ فَأَمَّا مَنْ قَالَ مُطِرْنَا بِفَضْلِ اللَّهِ وَرَحْمَتِهِ فَذَلِكَ مُؤْمِنٌ بِي كَافِرٌ بِالْكَوْكَبِ وَأَمَّا مَنْ قَالَ بِنَوْءِ كَذَا وَكَذَا فَذَلِكَ كَافِرٌ بِي مُؤْمِنٌ بِالْكَوْكَبِ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Malik] dari [Shalih bin Kaisan] dari ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] dari [Zaid bin Khalid Al Juhaini] bahwa dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memimpin kami shalat Shubuh di Hudaibiyyah pada suatu malam sehabis turun hujan. Selesai shalat beliau menghadapkan wajahnya kepada orang banyak lalu bersabda: \"Tahukah kalian apa yang sudah difirmankan oleh Rabb kalian?\" Orang-orang menjawab, \"Allah dan rasul-Nya lebih mengetahui.\" Beliau lalu bersabda: \"Allah berfirman: 'Di pagi ini ada hamba-hamba Ku yang menjadi Mukmin kepada-Ku dan ada pula yang kafir. Orang yang berkata, 'Hujan turun kepada kita karena karunia Allah dan rahmat-Nya', maka dia adalah yang beriman kepada-Ku dan kafir kepada bintang-bintang. Adapun yang berkata, 'Hujan turun disebabkan bintang ini dan itu', maka dia telah kafir kepada-Ku dan beriman kepada bintang-bintang'.\""},"981":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِفْتَاحُ الْغَيْبِ خَمْسٌ لَا يَعْلَمُهَا إِلَّا اللَّهُ لَا يَعْلَمُ أَحَدٌ مَا يَكُونُ فِي غَدٍ وَلَا يَعْلَمُ أَحَدٌ مَا يَكُونُ فِي الْأَرْحَامِ وَلَا تَعْلَمُ نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ وَمَا يَدْرِي أَحَدٌ مَتَى يَجِيءُ الْمَطَرُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada lima kunci ghaib yang tidak diketahui seorangpun kecuali oleh Allah; tidak seorangpun yang mengetahui apa yang akan terjadi esok hari, dan tidak seorangpun yang mengetahui apa yang tersembunyi dalam rahim, dan tak satu jiwa pun yang tahu apa yang akan diperbuatnya esok, dan tak satu jiwa pun yang tahu di bumi mana dia akan mati serta tidak seorangpun yang mengetahui kapan turunnya hujan.\""},"982":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْكَسَفَتْ الشَّمْسُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجُرُّ رِدَاءَهُ حَتَّى دَخَلَ الْمَسْجِدَ فَدَخَلْنَا فَصَلَّى بِنَا رَكْعَتَيْنِ حَتَّى انْجَلَتْ الشَّمْسُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ فَإِذَا رَأَيْتُمُوهُمَا فَصَلُّوا وَادْعُوا حَتَّى يُكْشَفَ مَا بِكُمْ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] berkata, telah menceritakan kepada kami [Khalid] dari [Yunus] dari [Al Hasan] dari [Abu Bakrah] berkata, \"Kami pernah duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam lalu terjadi gerhana matahari. Maka Nabi shallallahu 'alaihi wasallam berdiri menjulurkan selendangnya hingga masuk ke dalam masjid, kamipun ikut masuk ke dalam Masjid, beliau lalu mengimami kami shalat dua rakaat hingga matahari kembali nampak bersinar. Setelah itu beliau bersabda: \"Sesungguhnya matahari dan bulan tidak akan mengalami gerhana disebabkan karena matinya seseorang. Jika kalian melihat gerhana keduanya, maka dirikanlah shalat dan banyaklah berdoa hingga selesai gerhana yang terjadi pada kalian.\""},"983":{"ar":"حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حُمَيْدٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ قَالَ سَمِعْتُ أَبَا مَسْعُودٍ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ مِنْ النَّاسِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمُوهُمَا فَقُومُوا فَصَلُّوا","id":"Telah menceritakan kepada kami [Syihab bin 'Abbad] berkata, telah menceritakan kepada kami [Ibrahim bin Humaid] dari [Isma'il] dari [Qais] berkata, \"Aku mendengar [Abu Mas'ud] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari dan bulan tidak akan mengalami gerhana disebabkan karena matinya seorang dari manusia, tetapi keduanya adalah dua tanda dari tanda-tanda kebesaran Allah. Jika kalian melihat gerhana keduanya maka berdirilah untuk shalat.\""},"984":{"ar":"حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ حَدَّثَهُ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ كَانَ يُخْبِرُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمُوهَا فَصَلُّوا","id":"Telah menceritakan kepada kami [Ashbagh] berkata, telah mengabarkan kepadaku [Ibnu Wahb] berkata, telah mengabarkan kepadaku ['Amru] dari ['Abdurrahman bin Al Qasim] menceritakan dari [Bapaknya] dari [Ibnu 'Umar], bahwa dia mengabarkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya matahari dan bulan tidak akan mengalami gerhana disebabkan mati atau hidupnya seseorang, akan tetapi keduanya adalah dua tanda dari tanda-tanda kebesaran Allah. Maka jika kalian melihat gerhana keduanya, hendaklah shalatlah.\""},"985":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا شَيْبَانُ أَبُو مُعَاوِيَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ مَاتَ إِبْرَاهِيمُ فَقَالَ النَّاسُ كَسَفَتْ الشَّمْسُ لِمَوْتِ إِبْرَاهِيمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ فَصَلُّوا وَادْعُوا اللَّهَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata, telah menceritakan kepada kami [Syaiban Abu Mu'awiyyah] dari [Ziyad bin 'Alaqah] dari [Al Mughirah bin Syu'bah] berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, yaitu di hari meninggalnya putera beliau, Ibrahim. Orang-orang lalu berkata, \"Gerhana matahari ini terjadi karena meninggalnya Ibrahim!\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya matahari dan bulan tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang. Jika kalian melihat gerhana, maka shalat dan berdoalah kalian kepada Allah.\""},"986":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْخَسَفَتْ الشَّمْسُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ قَامَ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ فَعَلَ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ مَا فَعَلَ فِي الْأُولَى ثُمَّ انْصَرَفَ وَقَدْ انْجَلَتْ الشَّمْسُ فَخَطَبَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَادْعُوا اللَّهَ وَكَبِّرُوا وَصَلُّوا وَتَصَدَّقُوا ثُمَّ قَالَ يَا أُمَّةَ مُحَمَّدٍ وَاللَّهِ مَا مِنْ أَحَدٍ أَغْيَرُ مِنْ اللَّهِ أَنْ يَزْنِيَ عَبْدُهُ أَوْ تَزْنِيَ أَمَتُهُ يَا أُمَّةَ مُحَمَّدٍ وَاللَّهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلبَكَيْتُمْ كَثِيرًا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] bahwasanya dia berkata, \"Pernah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam lalu mendirikan shalat bersama orang banyak. Beliau berdiri dalam shalatnya dengan memanjangkan lama berdirinya, kemudian rukuk dengan memanjangkan rukuknya, kemudian berdiri dengan memanjangkan lama berdirinya, namun tidak selama yang pertama. Kemudian beliau rukuk dan memanjangkan lama rukuknya, namun tidak selama rukuknya yang pertama. Kemudian beliau sujud dengan memanjangkan lama sujudnya, beliau kemudian mengerjakan rakaat kedua seperti pada rakaat yang pertama. Saat beliau selesai melaksanakan shalat, matahari telah nampak kembali. Kemudian beliau menyampaikan khutbah kepada orang banyak, beliau memulai khutbahnya dengan memuji Allah dan mengangungkan-Nya, lalu bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda kebesaran Allah, dan tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang. Jika kalian melihat gerhana, maka banyaklah berdoa kepada Allah, bertakbirlah, dirikan shalat dan bersedekahlah.\" Kemudian beliau meneruskan sabdanya: \"Wahai ummat Muhammad! Demi Allah, tidak ada yang melebihi kecemburuan Allah kecuali saat Dia melihat hamba laki-laki atau hamba perempuan-Nya berzina. Wahai ummat Muhammad! Demi Allah, seandainya kalian mengetahui apa yang aku ketahui, niscaya kalian akan sedikit tertawa dan lebih banyak menangis.\""},"987":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ أَخْبَرَنَا يَحْيَى بْنُ صَالِحٍ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامِ بْنِ أَبِي سَلَّامٍ الْحَبَشِيُّ الدِّمَشْقِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ الزُّهْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا كَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُودِيَ إِنَّ الصَّلَاةَ جَامِعَةٌ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah mengabarkan kepada kami [Yahya bin Shalih] berkata, telah menceritakan kepada kami [Mu'awiyah bin Salam bin Abu Salam Al Habasyi Ad Dimsyqi] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] berkata, telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman bin 'Auf Az Zuhri] dari ['Abdullah bin 'Amru] berkata, \"Ketika terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka panggilannya dengan seruan, 'Ashshalaatul jaami'ah (Marilah mendirikan shalat secara bersama-sama) '.\""},"988":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنِي أَحْمَدُ بْنُ صَالِحٍ قَالَ حَدَّثَنَا عَنْبَسَةُ قَالَ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَسَفَتْ الشَّمْسُ فِي حَيَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ إِلَى الْمَسْجِدِ فَصَفَّ النَّاسُ وَرَاءَهُ فَكَبَّرَ فَاقْتَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِرَاءَةً طَوِيلَةً ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقَامَ وَلَمْ يَسْجُدْ وَقَرَأَ قِرَاءَةً طَوِيلَةً هِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى ثُمَّ كَبَّرَ وَرَكَعَ رُكُوعًا طَوِيلًا وَهُوَ أَدْنَى مِنْ الرُّكُوعِ الْأَوَّلِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ سَجَدَ ثُمَّ قَالَ فِي الرَّكْعَةِ الْآخِرَةِ مِثْلَ ذَلِكَ فَاسْتَكْمَلَ أَرْبَعَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ وَانْجَلَتْ الشَّمْسُ قَبْلَ أَنْ يَنْصَرِفَ ثُمَّ قَامَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ هُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَافْزَعُوا إِلَى الصَّلَاةِوَكَانَ يُحَدِّثُ كَثِيرُ بْنُ عَبَّاسٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا كَانَ يُحَدِّثُ يَوْمَ خَسَفَتْ الشَّمْسُ بِمِثْلِ حَدِيثِ عُرْوَةَ عَنْ عَائِشَةَ فَقُلْتُ لِعُرْوَةَ إِنَّ أَخَاكَ يَوْمَ خَسَفَتْ بِالْمَدِينَةِ لَمْ يَزِدْ عَلَى رَكْعَتَيْنِ مِثْلَ الصُّبْحِ قَالَ أَجَلْ لِأَنَّهُ أَخْطَأَ السُّنَّةَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepadaku [Al Laits] dari ['Uqail] dari [Ibnu Syihab]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Ahmad bin Shalih] berkata, telah menceritakan kepada kami ['Anbasah] berkata, telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku ['Urwah] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Pernah terjadi gerhana matahari pada masa Nabi shallallahu 'alaihi wasallam. Beliau keluar menuju masjid, lalu orang-orang membuat barisan di belakang beliau, beliau lalu takbir dan membaca surat yang panjang. Lalu beliau takbir dan rukuk dengan rukuk yang panjang, lalu mengucapkan SAMI'ALLAHU LIMAN HAMIDAH dan berdiri tanpa sujud. Kemudian beliau membaca bacaan yang panjang namun tidak sebagaimana bacaan yang pertama, lalu takbir dan rukuk dengan rukuk yang panjang namun tidak sebagaimana rukuk yang pertama, lalu mengucapkan SAMI'ALLAHU LIMAN HAMIDAH terus kemudian sujud. Setelah itu beliau melakukannya sepeti itu pada rakaat yang akhir hingga sempurnalah empat rukuk dalam empat sujud. Dan matahari nampak kembali sebelum shalat beliau selesai. Setelah itu beliau berdiri (menyampaikan khutbah) dengan memuji Allah dengan pujian yang patas untuk-Nya, beliau bersabda: \"Keduanya adalah dua tanda dari tanda-tanda kebesaran Allah, dan gerhana tidak akan terjadi hanya karena mati atau hidupnya seseorang. Jika kalian melihat (gerhan) keduanya, maka bersegeralah mendirikan shalat.\" [Katsir bin 'Abbas] menceritakan bahwa ['Abdullah bin 'Abbas] radliallahu 'anhuma menceritakan tentang hari terjadinya gerhana marahari seperti hadits 'Urwah dari 'Aisyah ini. Aku lalu berkata kepada 'Urwah, \"Sesungguhnya ketika terjadi gerhana di Madinah, saudaramu tidak pernah menambah lebih dari dua rakaat, seperti shalat shubuh.\" Dia menjawab, \"Benar. Dia telah ia telah menyelisihi sunnah.\""},"989":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ خَسَفَتْ الشَّمْسُ فَقَامَ فَكَبَّرَ فَقَرَأَ قِرَاءَةً طَوِيلَةً ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَقَامَ كَمَا هُوَ ثُمَّ قَرَأَ قِرَاءَةً طَوِيلَةً وَهِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهِيَ أَدْنَى مِنْ الرَّكْعَةِ الْأُولَى ثُمَّ سَجَدَ سُجُودًا طَوِيلًا ثُمَّ فَعَلَ فِي الرَّكْعَةِ الْآخِرَةِ مِثْلَ ذَلِكَ ثُمَّ سَلَّمَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَخَطَبَ النَّاسَ فَقَالَ فِي كُسُوفِ الشَّمْسِ وَالْقَمَرِ إِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَافْزَعُوا إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam ketika hari terjadinya gerhana matahari, beliau berdiri melaksanakan shalat. Beliau takbir, kemudian membaca dengan bacaan surah yang panjang, lalu rukuk dengan rukuk yang panjang, lalu mengangkat kepalanya seraya membaca SAMI'ALLAHU LIMAN HAMIDAH. Beliau lalu kembali berdiri sebagaimana sebelumnya dan membaca bacaan yang panjang, namun tidak sepanjang yang pertama, lalu rukuk dengan rukuk yang panjang, namun tidak sebagaimana rukuk yang pertama. Kemudian beliau sujud dengan sujud yang panjang. Kemudian beliau mengerjakan seperti itu pada rakaat yang akhir, lalu beliau salam sementara matahari sudah tampak kembali. Setelah itu beliau menyampaikan khutbah di hadapan manusia dan menyebutkan tentang gerhana matahari dan bulan, beliau katakan: \"Keduanya adalah dua tanda dari tanda-tanda kebesaran Allah yang tidak akan terjadi gerhana disebabkan karena mati atau hidupnya seseorang. Maka jika kalian melihat gerhana keduanya, hendaklah kalian segera mendirikan shalat.\""},"990":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّ اللَّهَ تَعَالَى يُخَوِّفُ بِهَا عِبَادَهُوَ قَالَ أَبُو عَبْد اللَّهِ وَلَمْ يَذْكُرْ عَبْدُ الْوَارِثِ وَشُعْبَةُ وَخَالِدُ بْنُ عَبْدِ اللَّهِ وَحَمَّادُ بْنُ سَلَمَةَ عَنْ يُونُسَ يُخَوِّفُ اللَّهُ بِهَا عِبَادَهُ وَتَابَعَهُ أَشْعَثُ عَنْ الْحَسَنِ وَتَابَعَهُ مُوسَى عَنْ مُبَارَكٍ عَنْ الْحَسَنِ قَالَ أَخْبَرَنِي أَبُو بَكْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَعَالَى يُخَوِّفُ بِهِمَا عِبَادَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Yunus] dari [Al Hasan] dari [Abu Bakrah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda kebesaran Allah, dan keduanya tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang. Akan tetapi dengan peristiwa itu Allah Ta'ala ingin membuat para hamba-Nya takut (dengan siksa-Nya).\" Abu 'Abdullah berkata, \" ['Abdul Warits] dan [Syu'bah] dan [Khalid bin 'Abdullah] dan [Hammad bin Salamah] dari [Yunus] tidak menyebutkan lafadz, 'Akan tetapi dengan peristiwa tersebut Allah Ta'ala ingin membuat para hamba-Nya takut (dengan siksa-Nya).\" Riwayat ini dikuatkan oleh ['Asy'ats] dari [Al Hasan], dan dikuatkan juga oleh [Musa] dari [Mubarak] dari [Al Hasan] ia berkata; telah mengabarkan kepadaku [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah Ta'ala dengan peristiwa itu Allah ingin membuat takut para hamba-Nya (dari siksa-Nya).\""},"991":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ يَهُودِيَّةً جَاءَتْ تَسْأَلُهَا فَقَالَتْ لَهَا أَعَاذَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ فَسَأَلَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُعَذَّبُ النَّاسُ فِي قُبُورِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِذًا بِاللَّهِ مِنْ ذَلِكَ ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ غَدَاةٍ مَرْكَبًا فَخَسَفَتْ الشَّمْسُ فَرَجَعَ ضُحًى فَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ ظَهْرَانَيْ الْحُجَرِ ثُمَّ قَامَ يُصَلِّي وَقَامَ النَّاسُ وَرَاءَهُ فَقَامَ قِيَامًا طَوِيلًا ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَسَجَدَ ثُمَّ قَامَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَسَجَدَ وَانْصَرَفَ فَقَالَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ ثُمَّ أَمَرَهُمْ أَنْ يَتَعَوَّذُوا مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa ada seorang wanita Yahudi datang bertanya kepadanya, ia katakan, \"Apakah Allah akan melindungi anda dari siksa kubur?\" Maka Aisyah menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah manusia akan disiksa dalam kubur mereka?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Aku berlindung darinya.\" Kemudian di pagi hari Rasulullah shallallahu 'alaihi wasallam pergi mengendarai tunggangannya, tiba-tiba terjadi gerhana matahari. Lalu beliau segera kembali saat masih waktu dluha, beliau melewati di antara kamar-kamar (isterinya), beliau kemudian mendirikan shalat dengan diikuti oleh orang-orang di belakangnya. Beliau berdiri dengan lama, lalu rukuk dengan rukuk yang panjang, lalu mengangkat (kepala) kemudian berdiri dengan panjang, namun tidak sepanjang yang pertama. Kemudian rukuk kembali dengan panjang namun tidak sepanjang rukuk yang pertama, kemudian beliau mengangkat kepalanya dan sujud. Kemudian beliau kembali berdiri dengan panjang namun tidak sepanjang yang pertama, lalu rukuk dengan panjang namun tidak sepanjang rukuk yang pertama, lalu mengangkat (kepala) dan berdiri dengan panjang namun tidak sepanjang yang pertama. Kemudian beliau rukuk dengan panjang namun tidak sepanjang rukuk yang pertama. Kemudian beliau mengangkat kepalanya, lalu sujud dan mengakhiri shalatnya. Kemudian beliau bersabda sebagaimana yang dikendaki Allah, kemudian memerintahkan orang-orang agar mereka memohon perlindungan dari siksa kubur.\""},"992":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو أَنَّهُ قَالَلَمَّا كَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُودِيَ إِنَّ الصَّلَاةَ جَامِعَةٌ فَرَكَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ فِي سَجْدَةٍ ثُمَّ قَامَ فَرَكَعَ رَكْعَتَيْنِ فِي سَجْدَةٍ ثُمَّ جَلَسَ ثُمَّ جُلِّيَ عَنْ الشَّمْسِ قَالَ وَقَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا مَا سَجَدْتُ سُجُودًا قَطُّ كَانَ أَطْوَلَ مِنْهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari ['Abdullah bin 'Amru] bahwa dia berkata, \"Saat terjadi gerhana matahari di zaman Rasulullah shallallahu 'alaihi wasallam, maka diserukan dengan panggilan, 'Ashshalaatul jaami'ah (Marilah mendirikan shalat secara bersama-sama) '. Nabi shallallahu 'alaihi wasallam lalu rukuk dua kali dalam satu kali sujud, kemudian berdiri kembali dan rukuk dua kali dengan satu kali sujud. Kemudian beliau duduk sementara matahari telah nampak kembali.\" 'Abdullah bin 'Amru berkata, 'Aisyah? radliallahu 'anha berkata, \"Tidak pernah aku melaksanakan satu sujudpun yang lebih panjang darinya.\""},"993":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَانْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ قِيَامًا طَوِيلًا نَحْوًا مِنْ قِرَاءَةِ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ ثُمَّ رَأَيْنَاكَ كَعْكَعْتَ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي رَأَيْتُ الْجَنَّةَ فَتَنَاوَلْتُ عُنْقُودًا وَلَوْ أَصَبْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَأُرِيتُ النَّارَ فَلَمْ أَرَ مَنْظَرًا كَالْيَوْمِ قَطُّ أَفْظَعَ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا بِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ يَكْفُرْنَ بِاللَّهِ قَالَ يَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ كُلَّهُ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari ['Abdullah bin 'Abbas] ia berkata, \"Telah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam kemudian melaksanakan shalat, beliau berdiri dengan sangat panjang (lama) sekadar bacaan surah Al Baqarah. Lalu beliau rukuk dengan rukuk yang panjang, lalu mengangkat (kepala) berdiri dengan panjang namun tidak sepanjang yang pertama. Kemudian rukuk kembali dengan panjang namun tidak sepanjang rukuk yang pertama. Kemudian sujud. Kemudian beliau kembali berdiri dengan panjang namun tidak sepanjang yang pertama, lalu rukuk dengan rukuk yang panjang namun tidak sepanjang rukuk yang pertama, lalu mengangkat (kepala) berdiri dengan panjang namun tidak sepanjang yang pertama. Kemudian beliau rukuk kembali dengan panjang namun tidak sepanjang rukuk yang pertama. Kemudian sujud. Kemudian beliau berlalu pergi sementara matahari sudah nampak kembali. Beliau kemudian bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda kebesaran Allah, dan keduanya tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang. Jika kalian melihatnya maka banyaklah mengingat Allah.\" Para sahabat bertanya, \"Wahai Rasulullah, kami melihat tuan merasakan sesuatu pada posisi tuan dan kami melihat seakan tuan menahan perasaan takut?\" Beliau menjawab: \"Sungguh aku melihat surga, dan didalamnya aku memperoleh setandan anggur. Seandainya aku mengambilnya tentu kalian akan memakannya sehingga urusan dunia akan terabaikan. Kemudian aku melihat neraka, dan aku belum pernah melihat suatu pemandangan yang lebih mengerikan dibanding hari ini, dan aku melihat kebanyakan penghuninya adalah kaum wanita.\" Para sahabat bertanya lagi, \"Mengapa begitu wahai Rasulullah?\" Beliau menjawab: \"Karena mereka sering kufur (mengingkari).\" Ditanyakan kepada beliau, \"Apakah mereka mengingkari Allah?\" Beliau menjawab: \"Mereka mengingkari pemberian suami, mengingkari kebaikan. Seandainya kamu berbuat baik terhadap salah seorang dari mereka sepanjang masa, lalu dia melihat satu saja kejelekan darimu maka dia akan berkata, 'Aku belum pernah melihat kebaikan darimu sedikitpun'.\""},"994":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ امْرَأَتِهِ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهَا قَالَتْأَتَيْتُ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ خَسَفَتْ الشَّمْسُ فَإِذَا النَّاسُ قِيَامٌ يُصَلُّونَ وَإِذَا هِيَ قَائِمَةٌ تُصَلِّي فَقُلْتُ مَا لِلنَّاسِ فَأَشَارَتْ بِيَدِهَا إِلَى السَّمَاءِ وَقَالَتْ سُبْحَانَ اللَّهِ فَقُلْتُ آيَةٌ فَأَشَ��رَتْ أَيْ نَعَمْ قَالَتْ فَقُمْتُ حَتَّى تَجَلَّانِي الْغَشْيُ فَجَعَلْتُ أَصُبُّ فَوْقَ رَأْسِي الْمَاءَ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا مِنْ شَيْءٍ كُنْتُ لَمْ أَرَهُ إِلَّا قَدْ رَأَيْتُهُ فِي مَقَامِي هَذَا حَتَّى الْجَنَّةَ وَالنَّارَ وَلَقَدْ أُوحِيَ إِلَيَّ أَنَّكُمْ تُفْتَنُونَ فِي الْقُبُورِ مِثْلَ أَوْ قَرِيبًا مِنْ فِتْنَةِ الدَّجَّالِ لَا أَدْرِي أَيَّتَهُمَا قَالَتْ أَسْمَاءُ يُؤْتَى أَحَدُكُمْ فَيُقَالُ لَهُ مَا عِلْمُكَ بِهَذَا الرَّجُلِ فَأَمَّا الْمُؤْمِنُ أَوْ الْمُوقِنُ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ فَيَقُولُ مُحَمَّدٌ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَنَا بِالْبَيِّنَاتِ وَالْهُدَى فَأَجَبْنَا وَآمَنَّا وَاتَّبَعْنَا فَيُقَالُ لَهُ نَمْ صَالِحًا فَقَدْ عَلِمْنَا إِنْ كُنْتَ لَمُوقِنًا وَأَمَّا الْمُنَافِقُ أَوْ الْمُرْتَابُ لَا أَدْرِي أَيَّتَهُمَا قَالَتْ أَسْمَاءُ فَيَقُولُ لَا أَدْرِي سَمِعْتُ النَّاسَ يَقُولُونَ شَيْئًا فَقُلْتُهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari isterinya [Fatimah binti Al Mundzir] dari [Asma' binti Abu Bakar] radliallahu 'anhuma, bahwasanya dia berkata, \"Aku pernah datang menemui 'Aisyah? radliallahu 'anha, isteri Nabi shallallahu 'alaihi wasallam, ketika terjadi gerhana matahari. Ternyata orang-orang sedang melaksanakan shalat dan saat itu ia juga ikut melaksanakannya. Setelah itu aku bertanya kepadanya, \"Apa yang dilakukan orang-orang?\" Aisyah memberi isyarat dengan tangannya ke langit seraya berkata, \"Maha suci Allah!\" Aku bertanya, \"Satu tanda saja?\" Lalu dia memberi isyarat tanda mengiyakan. Maka akupun ikut shalat sementara timbul perkara yang membingungkanku, hingga aku siram kepalaku dengan air. Selesai shalat Rasulullah shallallahu 'alaihi wasallam memuji Allah dan mensucikan-Nya, lalu bersabda: \"Tidak ada sesuatu yang belum diperlihatkan kepadaku, kecuali aku sudah melihatnya dari tempatku ini, hingga surga dan neraka. Kemudian diwahyukan kepadaku, bahwa Kalian akan terkena fitnah dalam kubur kalian seperti, atau seupa dengan fitnah Dajjal -Aku sendiri tidak tahu mana dari keduanya yang dikatakan oleh Asma'-. Salah seorang dari kalian akan dihadapkan lalu ditanya, 'Apa yang kamu ketahui tentang laki-laki ini? ' Orang beriman atau orang yang yakin -Aku tidak tahu mana dari keduanya yang dikatakan ileh Asma'- akan menjawab, 'Dia adalah Muhammad Rasulullah shallallahu 'alaihi wasallam, dia datang kepada kami membawa penjelasan dan petunjuk. Maka kami sambut, kami beriman kepadanya dan kami ikuti (ajarannya).' Maka kepada orang itu dikatakan, 'Tidurlah kamu dengan baik, sungguh kami telah mengetahui bahwa kamu adalah orang yang yaqin.' Adapun orang Munafik atau orang yang ragu - aku tidak tahu mana dari keduanya yang dikatakan oleh Asma'- akan menjawab, 'Aku tidak tahu siapa dia, aku mendengar orang-orang mengatakan sesuatu, maka aku pun ikut mengatakannya'.\""},"995":{"ar":"حَدَّثَنَا رَبِيعُ بْنُ يَحْيَى قَالَ حَدَّثَنَا زَائِدَةُ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْلَقَدْ أَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعَتَاقَةِ فِي كُسُوفِ الشَّمْسِ","id":"Telah menceritakan kepada kami [Rabi' bin Yahya] berkata, telah menceritakan kepada kami [Za'idah] dari [Hisyam] dari [Fatimah] dari [Asma'] berkata, \"Nabi shallallahu 'alaihi wasallam telah memerintahkan untuk membebaskan budak ketika terjadi gerhana matahari.\""},"996":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ يَهُودِيَّةً جَاءَتْ تَسْأَلُهَا فَقَالَتْ أَعَاذَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ فَسَأَلَتْ عَائِشَةُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُعَذَّبُ النَّاسُ فِي قُبُورِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِذًا بِاللَّهِ مِنْ ذَلِكَ ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ غَدَاةٍ مَرْكَبًا فَكَسَفَتْ الشَّمْسُ فَرَجَعَ ضُحًى فَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ ظَهْرَانَيْ الْحُجَرِ ثُمَّ قَامَ فَصَلَّى وَقَامَ النَّاسُ وَرَاءَهُ فَقَامَ قِيَامًا طَوِيلًا ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَسَجَدَ سُجُودًا طَوِيلًا ثُمَّ قَامَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ وَهُوَ دُونَ السُّجُودِ الْأَوَّلِ ثُمَّ انْصَرَفَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ ثُمَّ أَمَرَهُمْ أَنْ يَتَعَوَّذُوا مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman] dari ['Aisyah] radliallahu 'anha, bahwa ada seorang wanita Yahudi datang bertanya kepadanya, \"Apakah Allah akan melindungi anda dari siksa kubur?\" Aisyah lalu menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah manusia akan disiksa dalam kubur mereka?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Aku berlindung darinya.\" Kemudian di pagi hari Rasulullah shallallahu 'alaihi wasallam pergi mengendarai tunggangannya, tiba-tiba terjadi gerhana matahari. Lalu beliau segera kembali saat masih waktu dluha, beliau melewati di antara kamar-kamar (isterinya). Kemudian beliau mendirikan shalat dengan diikuti oleh orang-orang di belakangnya. Beliau berdiri dengan lama, lalu rukuk dengan rukuk yang panjang, lalu mengangkat (kepala) kemudian berdiri dengan panjang namun tidak sepanjang yang pertama. Kemudian rukuk kembali dengan yang panjang namun tidak sepanjang rukuk yang pertama, kemudian beliau mengangkat kepalanya dan sujud dengan sujud yang panjang. Kemudian beliau kembali berdiri dengan panjang namun tidak sepanjang yang pertama, lalu rukuk dengan panjang namun tidak sepanjang rukuk yang pertama, lalu mengangkat (kepala) dan berdiri dengan panjang namun tidak sepanjang yang pertama. Kemudian beliau rukuk dengan panjang namun tidak sepanjang rukuk yang pertama. Kemudian beliau mengangkat kepalanya, lalu sujud dan mengakhiri shalatnya. Kemudian beliau bersabda sebagaimana yang dikendaki Allah, kemudian memerintahkan orang-orang agar mereka memohon perlindungan dari siksa kubur.\""},"997":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنِي قَيْسٌ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّمْسُ وَالْقَمَرُ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمُوهُمَا فَصَلُّوا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il] berkata, telah menceritakan kepadaku [Qais] dari [Ibnu Mas'ud] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Matahari dan bulan tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang, akan tetapi keduanya adalah dua tanda dari tanda-tanda kebesaran Allah. Jika kalian melihat gerhana keduanya maka shalatlah.\""},"998":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ وَهِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ فَأَطَالَ الْقِرَاءَةَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِرَاءَةَ وَهِيَ دُونَ قِرَاءَتِهِ الْأُولَى ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ دُونَ رُكُوعِهِ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَصَنَعَ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ ثُمَّ قَامَ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ يُرِيهِمَا عِبَادَهُ فَإِذَا رَأَيْتُمْ ذَلِكَ فَافْزَعُوا إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dan [Hisyam bin 'Urwah] dari ['Urwah] dari ['Aisyah] berkata, \"Pernah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam. Maka beliau berdiri melaksanakan shalat bersama orang banyak, beliau memanjangkan bacaan, lalu rukuk dengan memanjangkan rukuk, kemudian mengangkat kepalanya, lalu membaca lagi dengan memanjangkan bacaannya namun tidak sebagaimana panjang bacaan yang pertama. Kemudian beliau rukuk lagi dengan memanjangkan rukuk, namun tidak sepanjang rukuk yang pertama, lalu mengangkat kepalanya kemudian sujud dua kali. Beliau kemudian berdiri kembali dan mengerjakan seperti pada rakaat pertama. Setelah itu beliau bangkit dan bersabda: \"Sesungguhnya matahari dan bulan tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang, akan tetapi keduanya adalah dua tanda dari tanda-tanda kebesaran Allah, yang Dia perlihatkan kepada hamba-hambaNya. Jika kalian melihat gerhana keduanya, maka segeralah mendirikan shalat.\""},"999":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَخَسَفَتْ الشَّمْسُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزِعًا يَخْشَى أَنْ تَكُونَ السَّاعَةُ فَأَتَى الْمَسْجِدَ فَصَلَّى بِأَطْوَلِ قِيَامٍ وَرُكُوعٍ وَسُجُودٍ رَأَيْتُهُ قَطُّ يَفْعَلُهُ وَقَالَ هَذِهِ الْآيَاتُ الَّتِي يُرْسِلُ اللَّهُ لَا تَكُونُ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنْ{ يُخَوِّفُ اللَّهُ بِهِ عِبَادَهُ }فَإِذَا رَأَيْتُمْ شَيْئًا مِنْ ذَلِكَ فَافْزَعُوا إِلَى ذِكْرِهِ وَدُعَائِهِ وَاسْتِغْفَارِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin 'Abdullah] dari [Abu Burdah] dari [Abu Musa] berkata, \"Ketika terjadi gerhana matahari, Nabi shallallahu 'alaihi wasallam berdiri dengan tergesa-gesa seolah akan terjadi hari kiamat. Beliau lantas mendatangi masjid dan shalat dengan berdiri, rukuk dan sujud yang paling panjang, yang pernah aku lihat dari yang beliau pernah lakukan. Kemudian beliau bersabda: \"Inilah dua tanda-tanda yang Allah kirimkan, ia tidak terjadi karena hidup atau matinya seseorang, tetapi '(Dia, Allah mempertakuti hamba-hambaNya dengannya) ' (Qs. Az ZUmar: 16). Maka jika kalian melihat sesuatu padanya (gerhana), maka segeralah untuk mengingat Allah, berdoa dan minta ampunan.\""},"1000":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا زَائِدَةُ قَالَ حَدَّثَنَا زِيَادُ بْنُ عِلَاقَةَ قَالَ سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُانْكَسَفَتْ الشَّمْسُ يَوْمَ مَاتَ إِبْرَاهِيمُ فَقَالَ النَّاسُ انْكَسَفَتْ لِمَوْتِ إِبْرَاهِيمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَادْعُوا اللَّهَ وَصَلُّوا حَتَّى يَنْجَلِيَ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Zaidah] berkata, telah menceritakan kepada kami [Ziyad bin 'Alaqah] berkata, \"Aku mendengar [Al Mughirah bin Syu'bah] berkata, \"Telah terjadi gerhana matahari ketika wafatnya Ibrahim. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda kebesaran Allah, dan ia tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang. Jika kalian melihat gerhana keduanya, maka berdo'alah kepada Allah dan dirikan shalat hingga (matahari) kembali nampak.\""}};
